INSERT INTO produce VALUES(1,'fruit','Mango','Mangifera indica','Tropical','Zaid','Amba','Aam','Mango','Maharashtra is one of India''s leading mango-producing states. The Konkan coast is especially famous for Alphonso (Hapus), prized worldwide for its aroma, sweetness, and saffron-orange flesh. Grown across Ratnagiri, Sindhudurg, and Raigad districts. Season: March–June.',unistr('Maharashtra is one of India''s leading mango-producing states. The Konkan coast is especially famous for Alphonso (Hapus), prized worldwide for its aroma, sweetness, and saffron-orange flesh. Grown across Ratnagiri, Sindhudurg, and Raigad districts. Season: March–June.\u000a\u000aScientific name: Mangifera indica\u000a\u000aCategory: Tropical\u000a\u000aSeason: Zaid\u000a\u000aMarathi name: Amba\u000a\u000aHindi name: Aam\u000a\u000aEnglish name: Mango'),'active',NULL);
INSERT INTO produce VALUES(2,'fruit','Grapes','Vitis vinifera','Tropical','Rabi','Draksha','Angoor','Grapes','Maharashtra, particularly Nashik district, is India''s largest grape-producing region, accounting for ~70% of national output. Nashik is called the "Wine Capital of India". Grapes are grown from October–November (pruning) with harvest January–March. Major export crop.',unistr('Maharashtra, particularly Nashik district, is India''s largest grape-producing region, accounting for ~70% of national output. Nashik is called the "Wine Capital of India". Grapes are grown from October–November (pruning) with harvest January–March. Major export crop.\u000a\u000aScientific name: Vitis vinifera\u000a\u000aCategory: Tropical\u000a\u000aSeason: Rabi\u000a\u000aMarathi name: Draksha\u000a\u000aHindi name: Angoor\u000a\u000aEnglish name: Grapes'),'active',NULL);
INSERT INTO produce VALUES(3,'fruit','Orange','Citrus sinensis / Citrus reticulata','Citrus','Rabi','Santra','Santra','Orange','Nagpur is the "Orange City" — Maharashtra''s Vidarbha region produces the famous GI-tagged Nagpur Mandarin, India''s most well-known orange variety, harvested November–January.',unistr('Nagpur is the "Orange City" — Maharashtra''s Vidarbha region produces the famous GI-tagged Nagpur Mandarin, India''s most well-known orange variety, harvested November–January.\u000a\u000aScientific name: Citrus sinensis / Citrus reticulata\u000a\u000aCategory: Citrus\u000a\u000aSeason: Rabi\u000a\u000aMarathi name: Santra\u000a\u000aHindi name: Santra\u000a\u000aEnglish name: Orange'),'active',NULL);
INSERT INTO produce VALUES(4,'fruit','Banana','Musa acuminata / Musa balbisiana','Tropical','Year-round','Kela','Kela','Banana','Jalgaon district is India''s banana capital — Maharashtra ranks first nationally in banana production. Jalgaon bananas have a GI tag. Bananas are cultivated year-round under drip irrigation.',unistr('Jalgaon district is India''s banana capital — Maharashtra ranks first nationally in banana production. Jalgaon bananas have a GI tag. Bananas are cultivated year-round under drip irrigation.\u000a\u000aScientific name: Musa acuminata / Musa balbisiana\u000a\u000aCategory: Tropical\u000a\u000aSeason: Year-round\u000a\u000aMarathi name: Kela\u000a\u000aHindi name: Kela\u000a\u000aEnglish name: Banana'),'active',NULL);
INSERT INTO produce VALUES(5,'fruit','Guava','Psidium guajava','Tropical','Year-round','Peru','Amrood','Guava','Guava is widely grown across Nashik, Pune, Solapur and Marathwada districts of Maharashtra. Rich in Vitamin C and lycopene; two crops per year possible.',unistr('Guava is widely grown across Nashik, Pune, Solapur and Marathwada districts of Maharashtra. Rich in Vitamin C and lycopene; two crops per year possible.\u000a\u000aScientific name: Psidium guajava\u000a\u000aCategory: Tropical\u000a\u000aSeason: Year-round\u000a\u000aMarathi name: Peru\u000a\u000aHindi name: Amrood\u000a\u000aEnglish name: Guava'),'active',NULL);
INSERT INTO produce VALUES(6,'fruit','Pomegranate','Punica granatum','Sub-tropical','Year-round','Dalimb','Anar','Pomegranate','Maharashtra is the largest pomegranate producer in India, contributing ~80% of national output. Solapur, Sangli, Pune, Nashik, Ahmednagar and Osmanabad are major growing districts. Bhagwa variety has a GI tag and is a prized export fruit.',unistr('Maharashtra is the largest pomegranate producer in India, contributing ~80% of national output. Solapur, Sangli, Pune, Nashik, Ahmednagar and Osmanabad are major growing districts. Bhagwa variety has a GI tag and is a prized export fruit.\u000a\u000aScientific name: Punica granatum\u000a\u000aCategory: Sub-tropical\u000a\u000aSeason: Year-round\u000a\u000aMarathi name: Dalimb\u000a\u000aHindi name: Anar\u000a\u000aEnglish name: Pomegranate'),'active',NULL);
INSERT INTO produce VALUES(7,'fruit','Custard Apple','Annona squamosa / Annona reticulata','Tropical','Kharif','Sitafal','Sitafal','Custard Apple','Custard apple is an important commercial fruit in Maharashtra, grown in dry regions of Nashik, Aurangabad, Osmanabad, Solapur and Pune. Season is September–November.',unistr('Custard apple is an important commercial fruit in Maharashtra, grown in dry regions of Nashik, Aurangabad, Osmanabad, Solapur and Pune. Season is September–November.\u000a\u000aScientific name: Annona squamosa / Annona reticulata\u000a\u000aCategory: Tropical\u000a\u000aSeason: Kharif\u000a\u000aMarathi name: Sitafal\u000a\u000aHindi name: Sitafal\u000a\u000aEnglish name: Custard Apple'),'active',NULL);
INSERT INTO produce VALUES(8,'fruit','Papaya','Carica papaya','Tropical','Year-round','Papai','Papita','Papaya','Papaya is grown extensively across Maharashtra for fresh fruit and raw papaya processing. Pune, Nashik, Jalgaon and Aurangabad are major producing districts.',unistr('Papaya is grown extensively across Maharashtra for fresh fruit and raw papaya processing. Pune, Nashik, Jalgaon and Aurangabad are major producing districts.\u000a\u000aScientific name: Carica papaya\u000a\u000aCategory: Tropical\u000a\u000aSeason: Year-round\u000a\u000aMarathi name: Papai\u000a\u000aHindi name: Papita\u000a\u000aEnglish name: Papaya'),'active',NULL);
INSERT INTO produce VALUES(9,'fruit','Sapota','Manilkara zapota','Tropical','Year-round','Chiku','Chiku','Sapota / Chikoo','Maharashtra is a major Sapota producer; Palghar, Nashik, Pune and Thane districts are major growing areas. Fruit is available year-round with peak seasons February–May and August–November.',unistr('Maharashtra is a major Sapota producer; Palghar, Nashik, Pune and Thane districts are major growing areas. Fruit is available year-round with peak seasons February–May and August–November.\u000a\u000aScientific name: Manilkara zapota\u000a\u000aCategory: Tropical\u000a\u000aSeason: Year-round\u000a\u000aMarathi name: Chiku\u000a\u000aHindi name: Chiku\u000a\u000aEnglish name: Sapota / Chikoo'),'active',NULL);
INSERT INTO produce VALUES(10,'fruit','Coconut','Cocos nucifera','Tropical','Year-round','Naral','Nariyal','Coconut','Coconut is a major crop of the Konkan coast — Ratnagiri, Sindhudurg, Raigad, Palghar and Thane. Used for copra, oil, tender coconut water, and in Maharashtrian cuisine.',unistr('Coconut is a major crop of the Konkan coast — Ratnagiri, Sindhudurg, Raigad, Palghar and Thane. Used for copra, oil, tender coconut water, and in Maharashtrian cuisine.\u000a\u000aScientific name: Cocos nucifera\u000a\u000aCategory: Tropical\u000a\u000aSeason: Year-round\u000a\u000aMarathi name: Naral\u000a\u000aHindi name: Nariyal\u000a\u000aEnglish name: Coconut'),'active',NULL);
INSERT INTO produce VALUES(11,'fruit','Jackfruit','Artocarpus heterophyllus','Tropical','Zaid','Phanas','Kathal','Jackfruit','Jackfruit grows in the humid Konkan belt; both unripe (vegetable use) and ripe fruit are consumed. Ratnagiri, Sindhudurg, Raigad and Thane are major areas. Season May–August.',unistr('Jackfruit grows in the humid Konkan belt; both unripe (vegetable use) and ripe fruit are consumed. Ratnagiri, Sindhudurg, Raigad and Thane are major areas. Season May–August.\u000a\u000aScientific name: Artocarpus heterophyllus\u000a\u000aCategory: Tropical\u000a\u000aSeason: Zaid\u000a\u000aMarathi name: Phanas\u000a\u000aHindi name: Kathal\u000a\u000aEnglish name: Jackfruit'),'active',NULL);
INSERT INTO produce VALUES(12,'fruit','Amla','Phyllanthus emblica','Sub-tropical','Rabi','Avala','Amla','Indian Gooseberry','Amla (Indian Gooseberry) is grown in Nashik, Aurangabad, Pune and Marathwada. Richest natural source of Vitamin C; harvested November–February. Important in Ayurveda and food processing (pickles, candy, juice).',unistr('Amla (Indian Gooseberry) is grown in Nashik, Aurangabad, Pune and Marathwada. Richest natural source of Vitamin C; harvested November–February. Important in Ayurveda and food processing (pickles, candy, juice).\u000a\u000aScientific name: Phyllanthus emblica\u000a\u000aCategory: Sub-tropical\u000a\u000aSeason: Rabi\u000a\u000aMarathi name: Avala\u000a\u000aHindi name: Amla\u000a\u000aEnglish name: Indian Gooseberry'),'active',NULL);
INSERT INTO produce VALUES(13,'fruit','Strawberry','Fragaria × ananassa','Subtropical Highland','Rabi','Strawberry','Strawberry','Strawberry','Mahabaleshwar (Satara district) and Panchgani produce 85% of India''s strawberries. Cool highland climate (1,400m elevation) ideal; season November–March. GI tag pending; major tourist attraction.',unistr('Mahabaleshwar (Satara district) and Panchgani produce 85% of India''s strawberries. Cool highland climate (1,400m elevation) ideal; season November–March. GI tag pending; major tourist attraction.\u000a\u000aScientific name: Fragaria × ananassa\u000a\u000aCategory: Subtropical Highland\u000a\u000aSeason: Rabi\u000a\u000aMarathi name: Strawberry\u000a\u000aHindi name: Strawberry\u000a\u000aEnglish name: Strawberry'),'active',NULL);
INSERT INTO produce VALUES(14,'fruit','Fig','Ficus carica','Sub-tropical','Zaid','Anjeer','Anjeer','Fig','Pune, particularly Purandar taluka, is the "Fig Capital" of India. Maharashtra has a GI tag for Purandar Fig. Season: January–March (main) and June–August (secondary).',unistr('Pune, particularly Purandar taluka, is the "Fig Capital" of India. Maharashtra has a GI tag for Purandar Fig. Season: January–March (main) and June–August (secondary).\u000a\u000aScientific name: Ficus carica\u000a\u000aCategory: Sub-tropical\u000a\u000aSeason: Zaid\u000a\u000aMarathi name: Anjeer\u000a\u000aHindi name: Anjeer\u000a\u000aEnglish name: Fig'),'active',NULL);
INSERT INTO produce VALUES(15,'fruit','Ber','Ziziphus mauritiana','Sub-tropical','Rabi','Bor','Ber','Indian Jujube / Ber','Ber is a drought-tolerant fruit grown in dry zones of Maharashtra — Solapur, Osmanabad, Latur, Aurangabad. Season November–February. Rich in Vitamin C and minerals; good for dry regions.',unistr('Ber is a drought-tolerant fruit grown in dry zones of Maharashtra — Solapur, Osmanabad, Latur, Aurangabad. Season November–February. Rich in Vitamin C and minerals; good for dry regions.\u000a\u000aScientific name: Ziziphus mauritiana\u000a\u000aCategory: Sub-tropical\u000a\u000aSeason: Rabi\u000a\u000aMarathi name: Bor\u000a\u000aHindi name: Ber\u000a\u000aEnglish name: Indian Jujube / Ber'),'active',NULL);
INSERT INTO produce VALUES(16,'grain','Rice','Oryza sativa','Cereal','Kharif','Bhat / Tandul','Chawal','Rice','Rice is the primary Kharif food grain of Maharashtra, grown mainly in Konkan (Ratnagiri, Sindhudurg, Raigad), Western Ghats foothills, and Vidarbha. Maharashtra grows aromatic traditional varieties alongside high-yielding types. Total area ~1.5 million hectares.',unistr('Rice is the primary Kharif food grain of Maharashtra, grown mainly in Konkan (Ratnagiri, Sindhudurg, Raigad), Western Ghats foothills, and Vidarbha. Maharashtra grows aromatic traditional varieties alongside high-yielding types. Total area ~1.5 million hectares.\u000a\u000aScientific name: Oryza sativa\u000a\u000aCategory: Cereal\u000a\u000aSeason: Kharif\u000a\u000aMarathi name: Bhat / Tandul\u000a\u000aHindi name: Chawal\u000a\u000aEnglish name: Rice'),'active',NULL);
INSERT INTO produce VALUES(17,'grain','Wheat','Triticum aestivum / Triticum durum','Cereal','Rabi','Gahu','Gehun','Wheat','Wheat is Maharashtra''s principal Rabi crop; grown in Nashik, Pune, Ahmednagar, Aurangabad, Solapur and Vidarbha under irrigated conditions. Sown October–November, harvested February–March. Maharashtra grows both bread wheat and durum (for semolina/pasta).',unistr('Wheat is Maharashtra''s principal Rabi crop; grown in Nashik, Pune, Ahmednagar, Aurangabad, Solapur and Vidarbha under irrigated conditions. Sown October–November, harvested February–March. Maharashtra grows both bread wheat and durum (for semolina/pasta).\u000a\u000aScientific name: Triticum aestivum / Triticum durum\u000a\u000aCategory: Cereal\u000a\u000aSeason: Rabi\u000a\u000aMarathi name: Gahu\u000a\u000aHindi name: Gehun\u000a\u000aEnglish name: Wheat'),'active',NULL);
INSERT INTO produce VALUES(18,'grain','Jowar','Sorghum bicolor','Millet / Cereal','Kharif','Jwarī','Jowar','Sorghum','Maharashtra is India''s largest Jowar-producing state. Jowar (bhakri) is the staple food of rural Maharashtra. Grown in Solapur, Osmanabad, Latur, Aurangabad, Nashik. Kharif and Rabi (sweet sorghum for fodder) seasons. Drought tolerant and rainfed crop.',unistr('Maharashtra is India''s largest Jowar-producing state. Jowar (bhakri) is the staple food of rural Maharashtra. Grown in Solapur, Osmanabad, Latur, Aurangabad, Nashik. Kharif and Rabi (sweet sorghum for fodder) seasons. Drought tolerant and rainfed crop.\u000a\u000aScientific name: Sorghum bicolor\u000a\u000aCategory: Millet / Cereal\u000a\u000aSeason: Kharif\u000a\u000aMarathi name: Jwarī\u000a\u000aHindi name: Jowar\u000a\u000aEnglish name: Sorghum'),'active',NULL);
INSERT INTO produce VALUES(19,'grain','Bajra','Pennisetum glaucum','Millet / Cereal','Kharif','Bajrī','Bajra','Pearl Millet','Bajra is a major Kharif crop of dry districts of Maharashtra — Nashik, Jalgaon, Dhule, Aurangabad. Very drought tolerant; important for poor rainfall areas. Bhakri (flatbread) is traditional use.',unistr('Bajra is a major Kharif crop of dry districts of Maharashtra — Nashik, Jalgaon, Dhule, Aurangabad. Very drought tolerant; important for poor rainfall areas. Bhakri (flatbread) is traditional use.\u000a\u000aScientific name: Pennisetum glaucum\u000a\u000aCategory: Millet / Cereal\u000a\u000aSeason: Kharif\u000a\u000aMarathi name: Bajrī\u000a\u000aHindi name: Bajra\u000a\u000aEnglish name: Pearl Millet'),'active',NULL);
INSERT INTO produce VALUES(20,'grain','Maize','Zea mays','Cereal','Kharif','Makka','Makka','Maize / Corn','Maize is an important Kharif crop in Nashik, Pune, Aurangabad, Ahmednagar and Nanded districts. Used for food (corn), poultry feed, starch and ethanol. Maharashtra contributes ~5% of national maize production.',unistr('Maize is an important Kharif crop in Nashik, Pune, Aurangabad, Ahmednagar and Nanded districts. Used for food (corn), poultry feed, starch and ethanol. Maharashtra contributes ~5% of national maize production.\u000a\u000aScientific name: Zea mays\u000a\u000aCategory: Cereal\u000a\u000aSeason: Kharif\u000a\u000aMarathi name: Makka\u000a\u000aHindi name: Makka\u000a\u000aEnglish name: Maize / Corn'),'active',NULL);
INSERT INTO produce VALUES(21,'grain','Ragi','Eleusine coracana','Millet','Kharif','Nachni','Ragi / Mandua','Finger Millet','Ragi (Nachni) is a nutritionally dense millet; grown in hilly and tribal areas of Nashik, Pune (Junnar), Nandurbar and Konkan. Richest grain source of calcium (344 mg/100g). Nachni bhakri and nachni satva (porridge) are traditional foods.',unistr('Ragi (Nachni) is a nutritionally dense millet; grown in hilly and tribal areas of Nashik, Pune (Junnar), Nandurbar and Konkan. Richest grain source of calcium (344 mg/100g). Nachni bhakri and nachni satva (porridge) are traditional foods.\u000a\u000aScientific name: Eleusine coracana\u000a\u000aCategory: Millet\u000a\u000aSeason: Kharif\u000a\u000aMarathi name: Nachni\u000a\u000aHindi name: Ragi / Mandua\u000a\u000aEnglish name: Finger Millet'),'active',NULL);
INSERT INTO produce VALUES(22,'grain','Kodo Millet','Paspalum scrobiculatum','Millet','Kharif','Kodra','Kodra','Kodo Millet','Kodo Millet (Kodra) is a traditional millet grown in tribal/hilly areas of Nashik, Nandurbar, Amravati and Gadchiroli. Drought-tolerant; low input; nutritious; part of the Nutri-Cereal revival initiative in Maharashtra.',unistr('Kodo Millet (Kodra) is a traditional millet grown in tribal/hilly areas of Nashik, Nandurbar, Amravati and Gadchiroli. Drought-tolerant; low input; nutritious; part of the Nutri-Cereal revival initiative in Maharashtra.\u000a\u000aScientific name: Paspalum scrobiculatum\u000a\u000aCategory: Millet\u000a\u000aSeason: Kharif\u000a\u000aMarathi name: Kodra\u000a\u000aHindi name: Kodra\u000a\u000aEnglish name: Kodo Millet'),'active',NULL);
INSERT INTO produce VALUES(23,'grain','Little Millet','Panicum sumatrense','Millet','Kharif','Vari / Kutki','Kutki','Little Millet','Little Millet (Vari) is used during religious fasting in Maharashtra (Ekadashi, Navratri). Grown in tribal belts of Nashik, Nandurbar and Gadchiroli. Reviving due to health consciousness and fasting food markets.',unistr('Little Millet (Vari) is used during religious fasting in Maharashtra (Ekadashi, Navratri). Grown in tribal belts of Nashik, Nandurbar and Gadchiroli. Reviving due to health consciousness and fasting food markets.\u000a\u000aScientific name: Panicum sumatrense\u000a\u000aCategory: Millet\u000a\u000aSeason: Kharif\u000a\u000aMarathi name: Vari / Kutki\u000a\u000aHindi name: Kutki\u000a\u000aEnglish name: Little Millet'),'active',NULL);
INSERT INTO produce VALUES(24,'grain','Barnyard Millet','Echinochloa frumentacea','Millet','Kharif','Bhagar / Sanwa','Sanwa','Barnyard Millet','Barnyard Millet (Bhagar) is extremely popular in Maharashtra for religious fasting (Upvasachi bhakri, Bhagar rice). Widely consumed during Ekadashi, Navratri. Grown in Nashik, Aurangabad, Nandurbar. High fibre, low GI.',unistr('Barnyard Millet (Bhagar) is extremely popular in Maharashtra for religious fasting (Upvasachi bhakri, Bhagar rice). Widely consumed during Ekadashi, Navratri. Grown in Nashik, Aurangabad, Nandurbar. High fibre, low GI.\u000a\u000aScientific name: Echinochloa frumentacea\u000a\u000aCategory: Millet\u000a\u000aSeason: Kharif\u000a\u000aMarathi name: Bhagar / Sanwa\u000a\u000aHindi name: Sanwa\u000a\u000aEnglish name: Barnyard Millet'),'active',NULL);
INSERT INTO produce VALUES(25,'grain','Proso Millet','Panicum miliaceum','Millet','Kharif','Cheena','Cheena','Proso Millet / Common Millet','Proso Millet is an ancient grain with fastest growth cycle (60–75 days) among millets. Grown in dry areas of Maharashtra as an emergency/catch crop. Low water requirement; high nutritional value. Reviving under health and organic food movements.',unistr('Proso Millet is an ancient grain with fastest growth cycle (60–75 days) among millets. Grown in dry areas of Maharashtra as an emergency/catch crop. Low water requirement; high nutritional value. Reviving under health and organic food movements.\u000a\u000aScientific name: Panicum miliaceum\u000a\u000aCategory: Millet\u000a\u000aSeason: Kharif\u000a\u000aMarathi name: Cheena\u000a\u000aHindi name: Cheena\u000a\u000aEnglish name: Proso Millet / Common Millet'),'active',NULL);
INSERT INTO produce VALUES(26,'grain','Tur (Pigeon Pea)','Cajanus cajan','Pulse','Kharif','Tur','Arhar / Tur','Pigeon Pea / Red Gram','Maharashtra is the largest Tur (pigeon pea) producing state in India. Grown extensively in Latur, Osmanabad, Nanded, Solapur and Marathwada. Staple dal of Maharashtra — tur dal (amti) is fundamental to Maharashtrian thali. Kharif season: sown June–July, harvested January–February.',unistr('Maharashtra is the largest Tur (pigeon pea) producing state in India. Grown extensively in Latur, Osmanabad, Nanded, Solapur and Marathwada. Staple dal of Maharashtra — tur dal (amti) is fundamental to Maharashtrian thali. Kharif season: sown June–July, harvested January–February.\u000a\u000aScientific name: Cajanus cajan\u000a\u000aCategory: Pulse\u000a\u000aSeason: Kharif\u000a\u000aMarathi name: Tur\u000a\u000aHindi name: Arhar / Tur\u000a\u000aEnglish name: Pigeon Pea / Red Gram'),'active',NULL);
INSERT INTO produce VALUES(27,'grain','Chickpea','Cicer arietinum','Pulse','Rabi','Harbhara / Chana','Chana','Chickpea / Bengal Gram','Maharashtra is a leading chickpea-growing state; Marathwada (Latur, Osmanabad, Aurangabad) and Vidarbha are key regions. Both desi (brown) and kabuli (white/large) types grown. Rabi season: sown October–November, harvested January–February.',unistr('Maharashtra is a leading chickpea-growing state; Marathwada (Latur, Osmanabad, Aurangabad) and Vidarbha are key regions. Both desi (brown) and kabuli (white/large) types grown. Rabi season: sown October–November, harvested January–February.\u000a\u000aScientific name: Cicer arietinum\u000a\u000aCategory: Pulse\u000a\u000aSeason: Rabi\u000a\u000aMarathi name: Harbhara / Chana\u000a\u000aHindi name: Chana\u000a\u000aEnglish name: Chickpea / Bengal Gram'),'active',NULL);
INSERT INTO produce VALUES(28,'grain','Urad (Black Gram)','Vigna mungo','Pulse','Kharif','Udid','Urad','Black Gram / Urad','Urad (Udid) is a Kharif pulse grown in Nanded, Latur, Osmanabad, Aurangabad and parts of Vidarbha. Essential for Maharashtrian vada, idli (batter), and dal. Short-duration; good in mixed cropping with Tur.',unistr('Urad (Udid) is a Kharif pulse grown in Nanded, Latur, Osmanabad, Aurangabad and parts of Vidarbha. Essential for Maharashtrian vada, idli (batter), and dal. Short-duration; good in mixed cropping with Tur.\u000a\u000aScientific name: Vigna mungo\u000a\u000aCategory: Pulse\u000a\u000aSeason: Kharif\u000a\u000aMarathi name: Udid\u000a\u000aHindi name: Urad\u000a\u000aEnglish name: Black Gram / Urad'),'active',NULL);
INSERT INTO produce VALUES(29,'grain','Masoor (Lentil)','Lens culinaris','Pulse','Rabi','Masur','Masoor','Lentil / Masoor','Masoor (Red Lentil) is a Rabi pulse grown in Marathwada and Vidarbha — Latur, Osmanabad, Yavatmal. Less common than Tur and Chana but nutritionally important; pink/red split dal used widely in Maharashtrian cuisine.',unistr('Masoor (Red Lentil) is a Rabi pulse grown in Marathwada and Vidarbha — Latur, Osmanabad, Yavatmal. Less common than Tur and Chana but nutritionally important; pink/red split dal used widely in Maharashtrian cuisine.\u000a\u000aScientific name: Lens culinaris\u000a\u000aCategory: Pulse\u000a\u000aSeason: Rabi\u000a\u000aMarathi name: Masur\u000a\u000aHindi name: Masoor\u000a\u000aEnglish name: Lentil / Masoor'),'active',NULL);
INSERT INTO produce VALUES(30,'grain','Soybean','Glycine max','Oilseed','Kharif','Soya','Soya','Soybean','Maharashtra is the largest soybean-growing state in India, with ~40% of national acreage. Grown in Vidarbha (Nagpur, Amravati), Marathwada (Latur, Osmanabad) and Nashik. Major oilseed and protein crop. Sown June–July; harvested September–October.',unistr('Maharashtra is the largest soybean-growing state in India, with ~40% of national acreage. Grown in Vidarbha (Nagpur, Amravati), Marathwada (Latur, Osmanabad) and Nashik. Major oilseed and protein crop. Sown June–July; harvested September–October.\u000a\u000aScientific name: Glycine max\u000a\u000aCategory: Oilseed\u000a\u000aSeason: Kharif\u000a\u000aMarathi name: Soya\u000a\u000aHindi name: Soya\u000a\u000aEnglish name: Soybean'),'active',NULL);
INSERT INTO produce VALUES(31,'grain','Groundnut','Arachis hypogaea','Oilseed','Kharif','Shengdana','Moongphali','Groundnut / Peanut','Groundnut is a major Kharif oilseed and cash crop in Maharashtra — Akola, Amravati, Wardha (Vidarbha) and Nashik, Jalgaon (North Maharashtra). Maharashtra is 4th nationally. Also a Rabi irrigated crop in Solapur. Famous for "Vidarbha shengdana".',unistr('Groundnut is a major Kharif oilseed and cash crop in Maharashtra — Akola, Amravati, Wardha (Vidarbha) and Nashik, Jalgaon (North Maharashtra). Maharashtra is 4th nationally. Also a Rabi irrigated crop in Solapur. Famous for "Vidarbha shengdana".\u000a\u000aScientific name: Arachis hypogaea\u000a\u000aCategory: Oilseed\u000a\u000aSeason: Kharif\u000a\u000aMarathi name: Shengdana\u000a\u000aHindi name: Moongphali\u000a\u000aEnglish name: Groundnut / Peanut'),'active',NULL);
INSERT INTO produce VALUES(32,'grain','Sesame','Sesamum indicum','Oilseed','Kharif','Til','Til','Sesame','Sesame (Til) is a traditional oilseed crop of Maharashtra grown in Aurangabad, Jalgaon, Nashik and Osmanabad. Essential in Maharashtrian sweets — tilgul (sesame-jaggery balls) for Makar Sankranti. High-value crop for domestic and export market.',unistr('Sesame (Til) is a traditional oilseed crop of Maharashtra grown in Aurangabad, Jalgaon, Nashik and Osmanabad. Essential in Maharashtrian sweets — tilgul (sesame-jaggery balls) for Makar Sankranti. High-value crop for domestic and export market.\u000a\u000aScientific name: Sesamum indicum\u000a\u000aCategory: Oilseed\u000a\u000aSeason: Kharif\u000a\u000aMarathi name: Til\u000a\u000aHindi name: Til\u000a\u000aEnglish name: Sesame'),'active',NULL);
INSERT INTO produce VALUES(33,'grain','Sunflower','Helianthus annuus','Oilseed','Rabi','Suryafool','Surajmukhi','Sunflower','Sunflower is grown as a Rabi crop in Maharashtra — Solapur, Osmanabad, Latur, Aurangabad, Nashik. Good oil crop for light black soils; used as edible oil. Also a Kharif crop in some areas.',unistr('Sunflower is grown as a Rabi crop in Maharashtra — Solapur, Osmanabad, Latur, Aurangabad, Nashik. Good oil crop for light black soils; used as edible oil. Also a Kharif crop in some areas.\u000a\u000aScientific name: Helianthus annuus\u000a\u000aCategory: Oilseed\u000a\u000aSeason: Rabi\u000a\u000aMarathi name: Suryafool\u000a\u000aHindi name: Surajmukhi\u000a\u000aEnglish name: Sunflower'),'active',NULL);
INSERT INTO produce VALUES(34,'grain','Sugarcane','Saccharum officinarum','Cash Crop / Industrial','Year-round','Oos / Verdi','Ganna','Sugarcane','Maharashtra is India''s second-largest sugarcane and sugar-producing state. The Deccan plateau districts of Pune, Satara, Sangli, Kolhapur, Solapur, Nashik and Ahmednagar form the "Sugar Belt". Over 200 cooperative sugar factories operate. Maharashtra also leads in ethanol production from sugarcane. Crushed October–March after 10–14 months of growth. By-products: bagasse (energy), molasses (ethanol/alcohol), press mud (compost).',unistr('Maharashtra is India''s second-largest sugarcane and sugar-producing state. The Deccan plateau districts of Pune, Satara, Sangli, Kolhapur, Solapur, Nashik and Ahmednagar form the "Sugar Belt". Over 200 cooperative sugar factories operate. Maharashtra also leads in ethanol production from sugarcane. Crushed October–March after 10–14 months of growth. By-products: bagasse (energy), molasses (ethanol/alcohol), press mud (compost).\u000a\u000aScientific name: Saccharum officinarum\u000a\u000aCategory: Cash Crop / Industrial\u000a\u000aSeason: Year-round\u000a\u000aMarathi name: Oos / Verdi\u000a\u000aHindi name: Ganna\u000a\u000aEnglish name: Sugarcane'),'active',NULL);
INSERT INTO produce VALUES(35,'vegetable','Onion','Allium cepa','Vegetable / Spice','Rabi','Kanda','Pyaaz','Onion','Maharashtra is India''s largest onion-producing state (~40% national share). Nashik, Pune, Ahmednagar, Solapur and Satara are prime growing districts. Nashik''s Lasalgaon APMC is Asia''s largest onion market. Three crops a year possible: Kharif (June–October), Late Kharif (September–January), and Rabi (January–May). Major export crop to Europe, South-East Asia and Middle East.',unistr('Maharashtra is India''s largest onion-producing state (~40% national share). Nashik, Pune, Ahmednagar, Solapur and Satara are prime growing districts. Nashik''s Lasalgaon APMC is Asia''s largest onion market. Three crops a year possible: Kharif (June–October), Late Kharif (September–January), and Rabi (January–May). Major export crop to Europe, South-East Asia and Middle East.\u000a\u000aScientific name: Allium cepa\u000a\u000aCategory: Vegetable / Spice\u000a\u000aSeason: Rabi\u000a\u000aMarathi name: Kanda\u000a\u000aHindi name: Pyaaz\u000a\u000aEnglish name: Onion'),'active',NULL);
INSERT INTO produce VALUES(36,'vegetable','Tomato','Solanum lycopersicum','Vegetable','Year-round','Tomato','Tamatar','Tomato','Maharashtra is a top-3 tomato-producing state. Nashik, Pune, Satara, Ahmednagar and Solapur are major districts. Tomatoes are grown year-round under irrigated conditions; also a major processing crop for puree, paste and ketchup. Narayangaon (Pune) is an important tomato trading hub.',unistr('Maharashtra is a top-3 tomato-producing state. Nashik, Pune, Satara, Ahmednagar and Solapur are major districts. Tomatoes are grown year-round under irrigated conditions; also a major processing crop for puree, paste and ketchup. Narayangaon (Pune) is an important tomato trading hub.\u000a\u000aScientific name: Solanum lycopersicum\u000a\u000aCategory: Vegetable\u000a\u000aSeason: Year-round\u000a\u000aMarathi name: Tomato\u000a\u000aHindi name: Tamatar\u000a\u000aEnglish name: Tomato'),'active',NULL);
INSERT INTO produce VALUES(37,'fruit','Sweet Lime','Citrus limetta','Citrus','Year-round','Mosambi','Mosambi','Sweet Lime / Mosambi','Sweet Lime (Mosambi) is one of Maharashtra''s most commercially important citrus fruits, distinct from orange. Solapur, Osmanabad, Aurangabad, Pune and Nashik are major growing centres. Extremely popular for fresh juice; sold across India year-round. Maharashtra accounts for ~35% of India''s Mosambi production.',unistr('Sweet Lime (Mosambi) is one of Maharashtra''s most commercially important citrus fruits, distinct from orange. Solapur, Osmanabad, Aurangabad, Pune and Nashik are major growing centres. Extremely popular for fresh juice; sold across India year-round. Maharashtra accounts for ~35% of India''s Mosambi production.\u000a\u000aScientific name: Citrus limetta\u000a\u000aCategory: Citrus\u000a\u000aSeason: Year-round\u000a\u000aMarathi name: Mosambi\u000a\u000aHindi name: Mosambi\u000a\u000aEnglish name: Sweet Lime / Mosambi'),'active',NULL);
INSERT INTO produce VALUES(38,'vegetable','Garlic','Allium sativum','Vegetable / Spice','Rabi','Lasun','Lahsun','Garlic','Garlic is an important Rabi spice crop in Maharashtra — Nashik, Satara, Solapur, Pune, Aurangabad. Maharashtra is among top-5 garlic-producing states. Sown October–November; harvested February–March. Maharashtra garlic is known for its pungency and high allicin content. Major export crop and ingredient in Indian cuisine and Ayurvedic medicine.',unistr('Garlic is an important Rabi spice crop in Maharashtra — Nashik, Satara, Solapur, Pune, Aurangabad. Maharashtra is among top-5 garlic-producing states. Sown October–November; harvested February–March. Maharashtra garlic is known for its pungency and high allicin content. Major export crop and ingredient in Indian cuisine and Ayurvedic medicine.\u000a\u000aScientific name: Allium sativum\u000a\u000aCategory: Vegetable / Spice\u000a\u000aSeason: Rabi\u000a\u000aMarathi name: Lasun\u000a\u000aHindi name: Lahsun\u000a\u000aEnglish name: Garlic'),'active',NULL);
INSERT INTO produce VALUES(39,'vegetable','Turmeric','Curcuma longa','Spice / Medicinal','Kharif','Halad','Haldi','Turmeric','Maharashtra is one of India''s top turmeric-producing states. Sangli, Kolhapur, Satara and Pune are major growing districts. Sangli''s Erande (Yelur) turmeric is GI-tagged and renowned for its high curcumin content (>4.5%). Harvested January–March after 8–9 months. Essential in Maharashtrian cooking, medicine (Ayurveda) and cosmetics. Major export to USA, Japan, EU.',unistr('Maharashtra is one of India''s top turmeric-producing states. Sangli, Kolhapur, Satara and Pune are major growing districts. Sangli''s Erande (Yelur) turmeric is GI-tagged and renowned for its high curcumin content (>4.5%). Harvested January–March after 8–9 months. Essential in Maharashtrian cooking, medicine (Ayurveda) and cosmetics. Major export to USA, Japan, EU.\u000a\u000aScientific name: Curcuma longa\u000a\u000aCategory: Spice / Medicinal\u000a\u000aSeason: Kharif\u000a\u000aMarathi name: Halad\u000a\u000aHindi name: Haldi\u000a\u000aEnglish name: Turmeric'),'active',NULL);
INSERT INTO produce VALUES(40,'vegetable','Chilli','Capsicum annuum','Spice / Vegetable','Kharif','Mirchi','Mirch','Chilli / Hot Pepper','Maharashtra is a major chilli-producing state. Aurangabad, Nashik, Pune, Latur, Osmanabad and Amravati are key districts for dry chilli production. Kolhapur Red Chilli is GI-tagged and one of the hottest and most flavourful in India. Chilli grown for fresh, dry, and powder markets. Key ingredient in Kolhapuri cuisine and Maharashtra masalas.',unistr('Maharashtra is a major chilli-producing state. Aurangabad, Nashik, Pune, Latur, Osmanabad and Amravati are key districts for dry chilli production. Kolhapur Red Chilli is GI-tagged and one of the hottest and most flavourful in India. Chilli grown for fresh, dry, and powder markets. Key ingredient in Kolhapuri cuisine and Maharashtra masalas.\u000a\u000aScientific name: Capsicum annuum\u000a\u000aCategory: Spice / Vegetable\u000a\u000aSeason: Kharif\u000a\u000aMarathi name: Mirchi\u000a\u000aHindi name: Mirch\u000a\u000aEnglish name: Chilli / Hot Pepper'),'active',NULL);
INSERT INTO produce VALUES(41,'vegetable','Ginger','Zingiber officinale','Spice / Medicinal','Kharif','Aale','Adrak','Ginger','Ginger is grown in the high-rainfall Western Ghats districts of Maharashtra — Satara, Kolhapur, Sindhudurg, Pune (Maval). A Kharif crop, sown April–May and harvested November–December. Fresh green ginger and dried soonth (dried ginger powder) both produced. Maharashtra contributes ~8% of India''s ginger output. High value for domestic cooking and pharma/ayurvedic industry.',unistr('Ginger is grown in the high-rainfall Western Ghats districts of Maharashtra — Satara, Kolhapur, Sindhudurg, Pune (Maval). A Kharif crop, sown April–May and harvested November–December. Fresh green ginger and dried soonth (dried ginger powder) both produced. Maharashtra contributes ~8% of India''s ginger output. High value for domestic cooking and pharma/ayurvedic industry.\u000a\u000aScientific name: Zingiber officinale\u000a\u000aCategory: Spice / Medicinal\u000a\u000aSeason: Kharif\u000a\u000aMarathi name: Aale\u000a\u000aHindi name: Adrak\u000a\u000aEnglish name: Ginger'),'active',NULL);
INSERT INTO produce VALUES(42,'fruit','Tamarind','Tamarindus indica','Fruit / Spice','Rabi','Chincha','Imli','Tamarind','Tamarind is a perennial tree crop widely found across Maharashtra, especially in Marathwada (Aurangabad, Osmanabad, Latur) and Vidarbha (Amravati, Nagpur). It is a rainfed, low-maintenance crop harvested January–April. Tamarind pulp, seed and shell all have commercial value. Key ingredient in Maharashtra''s chutneys, rasam-style dishes, and the famous Panha drink. Also used in pharmaceuticals, confectionery and food processing.',unistr('Tamarind is a perennial tree crop widely found across Maharashtra, especially in Marathwada (Aurangabad, Osmanabad, Latur) and Vidarbha (Amravati, Nagpur). It is a rainfed, low-maintenance crop harvested January–April. Tamarind pulp, seed and shell all have commercial value. Key ingredient in Maharashtra''s chutneys, rasam-style dishes, and the famous Panha drink. Also used in pharmaceuticals, confectionery and food processing.\u000a\u000aScientific name: Tamarindus indica\u000a\u000aCategory: Fruit / Spice\u000a\u000aSeason: Rabi\u000a\u000aMarathi name: Chincha\u000a\u000aHindi name: Imli\u000a\u000aEnglish name: Tamarind'),'active',NULL);
INSERT INTO produce VALUES(43,'vegetable','Fenugreek','Trigonella foenum-graecum','Spice / Vegetable / Medicinal','Rabi','Methi','Methi','Fenugreek / Methi','Fenugreek (Methi) is grown across Maharashtra as a Rabi crop for its leaves (fresh vegetable) and seeds (spice). Nashik, Pune, Aurangabad and Solapur are major growing areas. The seeds are essential in Maharashtra''s goda masala, pickles and parathas. Rich in fenuside, fibre and iron. Also used medicinally for diabetes and lactation support.',unistr('Fenugreek (Methi) is grown across Maharashtra as a Rabi crop for its leaves (fresh vegetable) and seeds (spice). Nashik, Pune, Aurangabad and Solapur are major growing areas. The seeds are essential in Maharashtra''s goda masala, pickles and parathas. Rich in fenuside, fibre and iron. Also used medicinally for diabetes and lactation support.\u000a\u000aScientific name: Trigonella foenum-graecum\u000a\u000aCategory: Spice / Vegetable / Medicinal\u000a\u000aSeason: Rabi\u000a\u000aMarathi name: Methi\u000a\u000aHindi name: Methi\u000a\u000aEnglish name: Fenugreek / Methi'),'active',NULL);
INSERT INTO produce VALUES(44,'vegetable','Coriander','Coriandrum sativum','Spice / Herb','Rabi','Kothimbir','Dhaniya','Coriander / Dhania','Coriander is one of Maharashtra''s most important spice crops, grown in Nashik, Pune, Satara, Aurangabad. Used both fresh (green coriander leaves) and dry (dhania seeds). Kothimbir Vadi (coriander fritters) is a signature Maharashtrian snack. Maharashtra is among India''s top-5 coriander-producing states. Season: October–January for leaves; February–March for seeds.',unistr('Coriander is one of Maharashtra''s most important spice crops, grown in Nashik, Pune, Satara, Aurangabad. Used both fresh (green coriander leaves) and dry (dhania seeds). Kothimbir Vadi (coriander fritters) is a signature Maharashtrian snack. Maharashtra is among India''s top-5 coriander-producing states. Season: October–January for leaves; February–March for seeds.\u000a\u000aScientific name: Coriandrum sativum\u000a\u000aCategory: Spice / Herb\u000a\u000aSeason: Rabi\u000a\u000aMarathi name: Kothimbir\u000a\u000aHindi name: Dhaniya\u000a\u000aEnglish name: Coriander / Dhania'),'active',NULL);
INSERT INTO produce VALUES(45,'fruit','Watermelon','Citrullus lanatus','Cucurbit Fruit','Zaid','Kalingad','Tarbooz','Watermelon','Watermelon is a major summer (Zaid) crop in Maharashtra — Nashik, Aurangabad, Solapur, Latur, Pune. Grown on sandy riverbed soils; sown February–March, harvested April–June. Maharashtra is a leading watermelon-producing state for domestic market. Large fruits preferred in Indian market; seedless hybrids gaining popularity.',unistr('Watermelon is a major summer (Zaid) crop in Maharashtra — Nashik, Aurangabad, Solapur, Latur, Pune. Grown on sandy riverbed soils; sown February–March, harvested April–June. Maharashtra is a leading watermelon-producing state for domestic market. Large fruits preferred in Indian market; seedless hybrids gaining popularity.\u000a\u000aScientific name: Citrullus lanatus\u000a\u000aCategory: Cucurbit Fruit\u000a\u000aSeason: Zaid\u000a\u000aMarathi name: Kalingad\u000a\u000aHindi name: Tarbooz\u000a\u000aEnglish name: Watermelon'),'active',NULL);
INSERT INTO produce VALUES(46,'fruit','Muskmelon','Cucumis melo','Cucurbit Fruit','Zaid','Kharbuja','Kharbuja','Muskmelon / Cantaloupe','Muskmelon (Kharbuj) is an important summer fruit crop in Maharashtra — Nashik, Pune, Solapur, Jalgaon. Grown on sandy loam soils; excellent in Godavari and Bhima river basin. Season March–June. High demand for fresh consumption and cooling drinks.',unistr('Muskmelon (Kharbuj) is an important summer fruit crop in Maharashtra — Nashik, Pune, Solapur, Jalgaon. Grown on sandy loam soils; excellent in Godavari and Bhima river basin. Season March–June. High demand for fresh consumption and cooling drinks.\u000a\u000aScientific name: Cucumis melo\u000a\u000aCategory: Cucurbit Fruit\u000a\u000aSeason: Zaid\u000a\u000aMarathi name: Kharbuja\u000a\u000aHindi name: Kharbuja\u000a\u000aEnglish name: Muskmelon / Cantaloupe'),'active',NULL);
INSERT INTO produce VALUES(47,'fruit','Lemon','Citrus limon / Citrus aurantiifolia','Citrus','Year-round','Limbu','Nimbu','Lemon / Lime','Lemon and acid lime are widely grown across Maharashtra — Nashik, Pune, Aurangabad, Vidarbha. A perennial crop with year-round fruiting under irrigation. Widely used in Maharashtrian cuisine (limbu sherbet, chutneys, achaar), street food, and increasing export to the Gulf. Drought-tolerant once established.',unistr('Lemon and acid lime are widely grown across Maharashtra — Nashik, Pune, Aurangabad, Vidarbha. A perennial crop with year-round fruiting under irrigation. Widely used in Maharashtrian cuisine (limbu sherbet, chutneys, achaar), street food, and increasing export to the Gulf. Drought-tolerant once established.\u000a\u000aScientific name: Citrus limon / Citrus aurantiifolia\u000a\u000aCategory: Citrus\u000a\u000aSeason: Year-round\u000a\u000aMarathi name: Limbu\u000a\u000aHindi name: Nimbu\u000a\u000aEnglish name: Lemon / Lime'),'active',NULL);
INSERT INTO produce_translations VALUES(1,'hi','आम','फल','Tropical','Zaid','आम GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('आम GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Mangifera indica\u000a\u000aश्रेणी: Tropical\u000a\u000aमौसम: Zaid\u000a\u000aमराठी नाम: Amba\u000a\u000aहिंदी नाम: Aam\u000a\u000aअंग्रेजी नाम: Mango\u000a\u000aमूल डेटासेट विवरण: Maharashtra is one of India''s leading mango-producing states. The Konkan coast is especially famous for Alphonso (Hapus), prized worldwide for its aroma, sweetness, and saffron-orange flesh. Grown across Ratnagiri, Sindhudurg, and Raigad districts. Season: March–June.'));
INSERT INTO produce_translations VALUES(1,'mr','आंबा','फळ','Tropical','Zaid','आंबा हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('आंबा हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Mangifera indica\u000a\u000aश्रेणी: Tropical\u000a\u000aहंगाम: Zaid\u000a\u000aमराठी नाव: Amba\u000a\u000aहिंदी नाव: Aam\u000a\u000aइंग्रजी नाव: Mango\u000a\u000aमूळ डेटासेट तपशील: Maharashtra is one of India''s leading mango-producing states. The Konkan coast is especially famous for Alphonso (Hapus), prized worldwide for its aroma, sweetness, and saffron-orange flesh. Grown across Ratnagiri, Sindhudurg, and Raigad districts. Season: March–June.'));
INSERT INTO produce_translations VALUES(2,'hi','अंगूर','फल','Tropical','Rabi','अंगूर GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('अंगूर GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Vitis vinifera\u000a\u000aश्रेणी: Tropical\u000a\u000aमौसम: Rabi\u000a\u000aमराठी नाम: Draksha\u000a\u000aहिंदी नाम: Angoor\u000a\u000aअंग्रेजी नाम: Grapes\u000a\u000aमूल डेटासेट विवरण: Maharashtra, particularly Nashik district, is India''s largest grape-producing region, accounting for ~70% of national output. Nashik is called the "Wine Capital of India". Grapes are grown from October–November (pruning) with harvest January–March. Major export crop.'));
INSERT INTO produce_translations VALUES(2,'mr','द्राक्ष','फळ','Tropical','Rabi','द्राक्ष हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('द्राक्ष हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Vitis vinifera\u000a\u000aश्रेणी: Tropical\u000a\u000aहंगाम: Rabi\u000a\u000aमराठी नाव: Draksha\u000a\u000aहिंदी नाव: Angoor\u000a\u000aइंग्रजी नाव: Grapes\u000a\u000aमूळ डेटासेट तपशील: Maharashtra, particularly Nashik district, is India''s largest grape-producing region, accounting for ~70% of national output. Nashik is called the "Wine Capital of India". Grapes are grown from October–November (pruning) with harvest January–March. Major export crop.'));
INSERT INTO produce_translations VALUES(3,'hi','संतरा','फल','Citrus','Rabi','संतरा GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('संतरा GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrus sinensis / Citrus reticulata\u000a\u000aश्रेणी: Citrus\u000a\u000aमौसम: Rabi\u000a\u000aमराठी नाम: Santra\u000a\u000aहिंदी नाम: Santra\u000a\u000aअंग्रेजी नाम: Orange\u000a\u000aमूल डेटासेट विवरण: Nagpur is the "Orange City" — Maharashtra''s Vidarbha region produces the famous GI-tagged Nagpur Mandarin, India''s most well-known orange variety, harvested November–January.'));
INSERT INTO produce_translations VALUES(3,'mr','संत्रा','फळ','Citrus','Rabi','संत्रा हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('संत्रा हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrus sinensis / Citrus reticulata\u000a\u000aश्रेणी: Citrus\u000a\u000aहंगाम: Rabi\u000a\u000aमराठी नाव: Santra\u000a\u000aहिंदी नाव: Santra\u000a\u000aइंग्रजी नाव: Orange\u000a\u000aमूळ डेटासेट तपशील: Nagpur is the "Orange City" — Maharashtra''s Vidarbha region produces the famous GI-tagged Nagpur Mandarin, India''s most well-known orange variety, harvested November–January.'));
INSERT INTO produce_translations VALUES(4,'hi','केला','फल','Tropical','Year-round','केला GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('केला GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Musa acuminata / Musa balbisiana\u000a\u000aश्रेणी: Tropical\u000a\u000aमौसम: Year-round\u000a\u000aमराठी नाम: Kela\u000a\u000aहिंदी नाम: Kela\u000a\u000aअंग्रेजी नाम: Banana\u000a\u000aमूल डेटासेट विवरण: Jalgaon district is India''s banana capital — Maharashtra ranks first nationally in banana production. Jalgaon bananas have a GI tag. Bananas are cultivated year-round under drip irrigation.'));
INSERT INTO produce_translations VALUES(4,'mr','केळी','फळ','Tropical','Year-round','केळी हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('केळी हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Musa acuminata / Musa balbisiana\u000a\u000aश्रेणी: Tropical\u000a\u000aहंगाम: Year-round\u000a\u000aमराठी नाव: Kela\u000a\u000aहिंदी नाव: Kela\u000a\u000aइंग्रजी नाव: Banana\u000a\u000aमूळ डेटासेट तपशील: Jalgaon district is India''s banana capital — Maharashtra ranks first nationally in banana production. Jalgaon bananas have a GI tag. Bananas are cultivated year-round under drip irrigation.'));
INSERT INTO produce_translations VALUES(5,'hi','अमरूद','फल','Tropical','Year-round','अमरूद GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('अमरूद GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Psidium guajava\u000a\u000aश्रेणी: Tropical\u000a\u000aमौसम: Year-round\u000a\u000aमराठी नाम: Peru\u000a\u000aहिंदी नाम: Amrood\u000a\u000aअंग्रेजी नाम: Guava\u000a\u000aमूल डेटासेट विवरण: Guava is widely grown across Nashik, Pune, Solapur and Marathwada districts of Maharashtra. Rich in Vitamin C and lycopene; two crops per year possible.'));
INSERT INTO produce_translations VALUES(5,'mr','पेरू','फळ','Tropical','Year-round','पेरू हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('पेरू हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Psidium guajava\u000a\u000aश्रेणी: Tropical\u000a\u000aहंगाम: Year-round\u000a\u000aमराठी नाव: Peru\u000a\u000aहिंदी नाव: Amrood\u000a\u000aइंग्रजी नाव: Guava\u000a\u000aमूळ डेटासेट तपशील: Guava is widely grown across Nashik, Pune, Solapur and Marathwada districts of Maharashtra. Rich in Vitamin C and lycopene; two crops per year possible.'));
INSERT INTO produce_translations VALUES(6,'hi','अनार','फल','Sub-tropical','Year-round','अनार GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('अनार GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Punica granatum\u000a\u000aश्रेणी: Sub-tropical\u000a\u000aमौसम: Year-round\u000a\u000aमराठी नाम: Dalimb\u000a\u000aहिंदी नाम: Anar\u000a\u000aअंग्रेजी नाम: Pomegranate\u000a\u000aमूल डेटासेट विवरण: Maharashtra is the largest pomegranate producer in India, contributing ~80% of national output. Solapur, Sangli, Pune, Nashik, Ahmednagar and Osmanabad are major growing districts. Bhagwa variety has a GI tag and is a prized export fruit.'));
INSERT INTO produce_translations VALUES(6,'mr','डाळिंब','फळ','Sub-tropical','Year-round','डाळिंब हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('डाळिंब हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Punica granatum\u000a\u000aश्रेणी: Sub-tropical\u000a\u000aहंगाम: Year-round\u000a\u000aमराठी नाव: Dalimb\u000a\u000aहिंदी नाव: Anar\u000a\u000aइंग्रजी नाव: Pomegranate\u000a\u000aमूळ डेटासेट तपशील: Maharashtra is the largest pomegranate producer in India, contributing ~80% of national output. Solapur, Sangli, Pune, Nashik, Ahmednagar and Osmanabad are major growing districts. Bhagwa variety has a GI tag and is a prized export fruit.'));
INSERT INTO produce_translations VALUES(7,'hi','सीताफल','फल','Tropical','Kharif','सीताफल GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('सीताफल GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Annona squamosa / Annona reticulata\u000a\u000aश्रेणी: Tropical\u000a\u000aमौसम: Kharif\u000a\u000aमराठी नाम: Sitafal\u000a\u000aहिंदी नाम: Sitafal\u000a\u000aअंग्रेजी नाम: Custard Apple\u000a\u000aमूल डेटासेट विवरण: Custard apple is an important commercial fruit in Maharashtra, grown in dry regions of Nashik, Aurangabad, Osmanabad, Solapur and Pune. Season is September–November.'));
INSERT INTO produce_translations VALUES(7,'mr','सीताफळ','फळ','Tropical','Kharif','सीताफळ हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('सीताफळ हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Annona squamosa / Annona reticulata\u000a\u000aश्रेणी: Tropical\u000a\u000aहंगाम: Kharif\u000a\u000aमराठी नाव: Sitafal\u000a\u000aहिंदी नाव: Sitafal\u000a\u000aइंग्रजी नाव: Custard Apple\u000a\u000aमूळ डेटासेट तपशील: Custard apple is an important commercial fruit in Maharashtra, grown in dry regions of Nashik, Aurangabad, Osmanabad, Solapur and Pune. Season is September–November.'));
INSERT INTO produce_translations VALUES(8,'hi','पपीता','फल','Tropical','Year-round','पपीता GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('पपीता GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Carica papaya\u000a\u000aश्रेणी: Tropical\u000a\u000aमौसम: Year-round\u000a\u000aमराठी नाम: Papai\u000a\u000aहिंदी नाम: Papita\u000a\u000aअंग्रेजी नाम: Papaya\u000a\u000aमूल डेटासेट विवरण: Papaya is grown extensively across Maharashtra for fresh fruit and raw papaya processing. Pune, Nashik, Jalgaon and Aurangabad are major producing districts.'));
INSERT INTO produce_translations VALUES(8,'mr','पपई','फळ','Tropical','Year-round','पपई हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('पपई हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Carica papaya\u000a\u000aश्रेणी: Tropical\u000a\u000aहंगाम: Year-round\u000a\u000aमराठी नाव: Papai\u000a\u000aहिंदी नाव: Papita\u000a\u000aइंग्रजी नाव: Papaya\u000a\u000aमूळ डेटासेट तपशील: Papaya is grown extensively across Maharashtra for fresh fruit and raw papaya processing. Pune, Nashik, Jalgaon and Aurangabad are major producing districts.'));
INSERT INTO produce_translations VALUES(9,'hi','चीकू','फल','Tropical','Year-round','चीकू GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('चीकू GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Manilkara zapota\u000a\u000aश्रेणी: Tropical\u000a\u000aमौसम: Year-round\u000a\u000aमराठी नाम: Chiku\u000a\u000aहिंदी नाम: Chiku\u000a\u000aअंग्रेजी नाम: Sapota / Chikoo\u000a\u000aमूल डेटासेट विवरण: Maharashtra is a major Sapota producer; Palghar, Nashik, Pune and Thane districts are major growing areas. Fruit is available year-round with peak seasons February–May and August–November.'));
INSERT INTO produce_translations VALUES(9,'mr','चीकू','फळ','Tropical','Year-round','चीकू हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('चीकू हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Manilkara zapota\u000a\u000aश्रेणी: Tropical\u000a\u000aहंगाम: Year-round\u000a\u000aमराठी नाव: Chiku\u000a\u000aहिंदी नाव: Chiku\u000a\u000aइंग्रजी नाव: Sapota / Chikoo\u000a\u000aमूळ डेटासेट तपशील: Maharashtra is a major Sapota producer; Palghar, Nashik, Pune and Thane districts are major growing areas. Fruit is available year-round with peak seasons February–May and August–November.'));
INSERT INTO produce_translations VALUES(10,'hi','नारियल','फल','Tropical','Year-round','नारियल GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('नारियल GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Cocos nucifera\u000a\u000aश्रेणी: Tropical\u000a\u000aमौसम: Year-round\u000a\u000aमराठी नाम: Naral\u000a\u000aहिंदी नाम: Nariyal\u000a\u000aअंग्रेजी नाम: Coconut\u000a\u000aमूल डेटासेट विवरण: Coconut is a major crop of the Konkan coast — Ratnagiri, Sindhudurg, Raigad, Palghar and Thane. Used for copra, oil, tender coconut water, and in Maharashtrian cuisine.'));
INSERT INTO produce_translations VALUES(10,'mr','नारळ','फळ','Tropical','Year-round','नारळ हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('नारळ हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Cocos nucifera\u000a\u000aश्रेणी: Tropical\u000a\u000aहंगाम: Year-round\u000a\u000aमराठी नाव: Naral\u000a\u000aहिंदी नाव: Nariyal\u000a\u000aइंग्रजी नाव: Coconut\u000a\u000aमूळ डेटासेट तपशील: Coconut is a major crop of the Konkan coast — Ratnagiri, Sindhudurg, Raigad, Palghar and Thane. Used for copra, oil, tender coconut water, and in Maharashtrian cuisine.'));
INSERT INTO produce_translations VALUES(11,'hi','कटहल','फल','Tropical','Zaid','कटहल GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('कटहल GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Artocarpus heterophyllus\u000a\u000aश्रेणी: Tropical\u000a\u000aमौसम: Zaid\u000a\u000aमराठी नाम: Phanas\u000a\u000aहिंदी नाम: Kathal\u000a\u000aअंग्रेजी नाम: Jackfruit\u000a\u000aमूल डेटासेट विवरण: Jackfruit grows in the humid Konkan belt; both unripe (vegetable use) and ripe fruit are consumed. Ratnagiri, Sindhudurg, Raigad and Thane are major areas. Season May–August.'));
INSERT INTO produce_translations VALUES(11,'mr','फणस','फळ','Tropical','Zaid','फणस हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('फणस हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Artocarpus heterophyllus\u000a\u000aश्रेणी: Tropical\u000a\u000aहंगाम: Zaid\u000a\u000aमराठी नाव: Phanas\u000a\u000aहिंदी नाव: Kathal\u000a\u000aइंग्रजी नाव: Jackfruit\u000a\u000aमूळ डेटासेट तपशील: Jackfruit grows in the humid Konkan belt; both unripe (vegetable use) and ripe fruit are consumed. Ratnagiri, Sindhudurg, Raigad and Thane are major areas. Season May–August.'));
INSERT INTO produce_translations VALUES(12,'hi','आंवला','फल','Sub-tropical','Rabi','आंवला GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('आंवला GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Phyllanthus emblica\u000a\u000aश्रेणी: Sub-tropical\u000a\u000aमौसम: Rabi\u000a\u000aमराठी नाम: Avala\u000a\u000aहिंदी नाम: Amla\u000a\u000aअंग्रेजी नाम: Indian Gooseberry\u000a\u000aमूल डेटासेट विवरण: Amla (Indian Gooseberry) is grown in Nashik, Aurangabad, Pune and Marathwada. Richest natural source of Vitamin C; harvested November–February. Important in Ayurveda and food processing (pickles, candy, juice).'));
INSERT INTO produce_translations VALUES(12,'mr','आवळा','फळ','Sub-tropical','Rabi','आवळा हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('आवळा हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Phyllanthus emblica\u000a\u000aश्रेणी: Sub-tropical\u000a\u000aहंगाम: Rabi\u000a\u000aमराठी नाव: Avala\u000a\u000aहिंदी नाव: Amla\u000a\u000aइंग्रजी नाव: Indian Gooseberry\u000a\u000aमूळ डेटासेट तपशील: Amla (Indian Gooseberry) is grown in Nashik, Aurangabad, Pune and Marathwada. Richest natural source of Vitamin C; harvested November–February. Important in Ayurveda and food processing (pickles, candy, juice).'));
INSERT INTO produce_translations VALUES(13,'hi','स्ट्रॉबेरी','फल','Subtropical Highland','Rabi','स्ट्रॉबेरी GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('स्ट्रॉबेरी GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Fragaria × ananassa\u000a\u000aश्रेणी: Subtropical Highland\u000a\u000aमौसम: Rabi\u000a\u000aमराठी नाम: Strawberry\u000a\u000aहिंदी नाम: Strawberry\u000a\u000aअंग्रेजी नाम: Strawberry\u000a\u000aमूल डेटासेट विवरण: Mahabaleshwar (Satara district) and Panchgani produce 85% of India''s strawberries. Cool highland climate (1,400m elevation) ideal; season November–March. GI tag pending; major tourist attraction.'));
INSERT INTO produce_translations VALUES(13,'mr','स्ट्रॉबेरी','फळ','Subtropical Highland','Rabi','स्ट्रॉबेरी हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('स्ट्रॉबेरी हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Fragaria × ananassa\u000a\u000aश्रेणी: Subtropical Highland\u000a\u000aहंगाम: Rabi\u000a\u000aमराठी नाव: Strawberry\u000a\u000aहिंदी नाव: Strawberry\u000a\u000aइंग्रजी नाव: Strawberry\u000a\u000aमूळ डेटासेट तपशील: Mahabaleshwar (Satara district) and Panchgani produce 85% of India''s strawberries. Cool highland climate (1,400m elevation) ideal; season November–March. GI tag pending; major tourist attraction.'));
INSERT INTO produce_translations VALUES(14,'hi','अंजीर','फल','Sub-tropical','Zaid','अंजीर GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('अंजीर GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Ficus carica\u000a\u000aश्रेणी: Sub-tropical\u000a\u000aमौसम: Zaid\u000a\u000aमराठी नाम: Anjeer\u000a\u000aहिंदी नाम: Anjeer\u000a\u000aअंग्रेजी नाम: Fig\u000a\u000aमूल डेटासेट विवरण: Pune, particularly Purandar taluka, is the "Fig Capital" of India. Maharashtra has a GI tag for Purandar Fig. Season: January–March (main) and June–August (secondary).'));
INSERT INTO produce_translations VALUES(14,'mr','अंजीर','फळ','Sub-tropical','Zaid','अंजीर हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('अंजीर हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Ficus carica\u000a\u000aश्रेणी: Sub-tropical\u000a\u000aहंगाम: Zaid\u000a\u000aमराठी नाव: Anjeer\u000a\u000aहिंदी नाव: Anjeer\u000a\u000aइंग्रजी नाव: Fig\u000a\u000aमूळ डेटासेट तपशील: Pune, particularly Purandar taluka, is the "Fig Capital" of India. Maharashtra has a GI tag for Purandar Fig. Season: January–March (main) and June–August (secondary).'));
INSERT INTO produce_translations VALUES(15,'hi','बेर','फल','Sub-tropical','Rabi','बेर GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('बेर GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Ziziphus mauritiana\u000a\u000aश्रेणी: Sub-tropical\u000a\u000aमौसम: Rabi\u000a\u000aमराठी नाम: Bor\u000a\u000aहिंदी नाम: Ber\u000a\u000aअंग्रेजी नाम: Indian Jujube / Ber\u000a\u000aमूल डेटासेट विवरण: Ber is a drought-tolerant fruit grown in dry zones of Maharashtra — Solapur, Osmanabad, Latur, Aurangabad. Season November–February. Rich in Vitamin C and minerals; good for dry regions.'));
INSERT INTO produce_translations VALUES(15,'mr','बोर','फळ','Sub-tropical','Rabi','बोर हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('बोर हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Ziziphus mauritiana\u000a\u000aश्रेणी: Sub-tropical\u000a\u000aहंगाम: Rabi\u000a\u000aमराठी नाव: Bor\u000a\u000aहिंदी नाव: Ber\u000a\u000aइंग्रजी नाव: Indian Jujube / Ber\u000a\u000aमूळ डेटासेट तपशील: Ber is a drought-tolerant fruit grown in dry zones of Maharashtra — Solapur, Osmanabad, Latur, Aurangabad. Season November–February. Rich in Vitamin C and minerals; good for dry regions.'));
INSERT INTO produce_translations VALUES(16,'hi','चावल','अनाज','Cereal','Kharif','चावल GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('चावल GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Oryza sativa\u000a\u000aश्रेणी: Cereal\u000a\u000aमौसम: Kharif\u000a\u000aमराठी नाम: Bhat / Tandul\u000a\u000aहिंदी नाम: Chawal\u000a\u000aअंग्रेजी नाम: Rice\u000a\u000aमूल डेटासेट विवरण: Rice is the primary Kharif food grain of Maharashtra, grown mainly in Konkan (Ratnagiri, Sindhudurg, Raigad), Western Ghats foothills, and Vidarbha. Maharashtra grows aromatic traditional varieties alongside high-yielding types. Total area ~1.5 million hectares.'));
INSERT INTO produce_translations VALUES(16,'mr','तांदूळ','धान्य','Cereal','Kharif','तांदूळ हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('तांदूळ हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Oryza sativa\u000a\u000aश्रेणी: Cereal\u000a\u000aहंगाम: Kharif\u000a\u000aमराठी नाव: Bhat / Tandul\u000a\u000aहिंदी नाव: Chawal\u000a\u000aइंग्रजी नाव: Rice\u000a\u000aमूळ डेटासेट तपशील: Rice is the primary Kharif food grain of Maharashtra, grown mainly in Konkan (Ratnagiri, Sindhudurg, Raigad), Western Ghats foothills, and Vidarbha. Maharashtra grows aromatic traditional varieties alongside high-yielding types. Total area ~1.5 million hectares.'));
INSERT INTO produce_translations VALUES(17,'hi','गेहूं','अनाज','Cereal','Rabi','गेहूं GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('गेहूं GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Triticum aestivum / Triticum durum\u000a\u000aश्रेणी: Cereal\u000a\u000aमौसम: Rabi\u000a\u000aमराठी नाम: Gahu\u000a\u000aहिंदी नाम: Gehun\u000a\u000aअंग्रेजी नाम: Wheat\u000a\u000aमूल डेटासेट विवरण: Wheat is Maharashtra''s principal Rabi crop; grown in Nashik, Pune, Ahmednagar, Aurangabad, Solapur and Vidarbha under irrigated conditions. Sown October–November, harvested February–March. Maharashtra grows both bread wheat and durum (for semolina/pasta).'));
INSERT INTO produce_translations VALUES(17,'mr','गहू','धान्य','Cereal','Rabi','गहू हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('गहू हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Triticum aestivum / Triticum durum\u000a\u000aश्रेणी: Cereal\u000a\u000aहंगाम: Rabi\u000a\u000aमराठी नाव: Gahu\u000a\u000aहिंदी नाव: Gehun\u000a\u000aइंग्रजी नाव: Wheat\u000a\u000aमूळ डेटासेट तपशील: Wheat is Maharashtra''s principal Rabi crop; grown in Nashik, Pune, Ahmednagar, Aurangabad, Solapur and Vidarbha under irrigated conditions. Sown October–November, harvested February–March. Maharashtra grows both bread wheat and durum (for semolina/pasta).'));
INSERT INTO produce_translations VALUES(18,'hi','ज्वार','अनाज','Millet / Cereal','Kharif','ज्वार GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('ज्वार GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Sorghum bicolor\u000a\u000aश्रेणी: Millet / Cereal\u000a\u000aमौसम: Kharif\u000a\u000aमराठी नाम: Jwarī\u000a\u000aहिंदी नाम: Jowar\u000a\u000aअंग्रेजी नाम: Sorghum\u000a\u000aमूल डेटासेट विवरण: Maharashtra is India''s largest Jowar-producing state. Jowar (bhakri) is the staple food of rural Maharashtra. Grown in Solapur, Osmanabad, Latur, Aurangabad, Nashik. Kharif and Rabi (sweet sorghum for fodder) seasons. Drought tolerant and rainfed crop.'));
INSERT INTO produce_translations VALUES(18,'mr','ज्वारी','धान्य','Millet / Cereal','Kharif','ज्वारी हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('ज्वारी हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Sorghum bicolor\u000a\u000aश्रेणी: Millet / Cereal\u000a\u000aहंगाम: Kharif\u000a\u000aमराठी नाव: Jwarī\u000a\u000aहिंदी नाव: Jowar\u000a\u000aइंग्रजी नाव: Sorghum\u000a\u000aमूळ डेटासेट तपशील: Maharashtra is India''s largest Jowar-producing state. Jowar (bhakri) is the staple food of rural Maharashtra. Grown in Solapur, Osmanabad, Latur, Aurangabad, Nashik. Kharif and Rabi (sweet sorghum for fodder) seasons. Drought tolerant and rainfed crop.'));
INSERT INTO produce_translations VALUES(19,'hi','बाजरा','अनाज','Millet / Cereal','Kharif','बाजरा GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('बाजरा GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Pennisetum glaucum\u000a\u000aश्रेणी: Millet / Cereal\u000a\u000aमौसम: Kharif\u000a\u000aमराठी नाम: Bajrī\u000a\u000aहिंदी नाम: Bajra\u000a\u000aअंग्रेजी नाम: Pearl Millet\u000a\u000aमूल डेटासेट विवरण: Bajra is a major Kharif crop of dry districts of Maharashtra — Nashik, Jalgaon, Dhule, Aurangabad. Very drought tolerant; important for poor rainfall areas. Bhakri (flatbread) is traditional use.'));
INSERT INTO produce_translations VALUES(19,'mr','बाजरी','धान्य','Millet / Cereal','Kharif','बाजरी हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('बाजरी हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Pennisetum glaucum\u000a\u000aश्रेणी: Millet / Cereal\u000a\u000aहंगाम: Kharif\u000a\u000aमराठी नाव: Bajrī\u000a\u000aहिंदी नाव: Bajra\u000a\u000aइंग्रजी नाव: Pearl Millet\u000a\u000aमूळ डेटासेट तपशील: Bajra is a major Kharif crop of dry districts of Maharashtra — Nashik, Jalgaon, Dhule, Aurangabad. Very drought tolerant; important for poor rainfall areas. Bhakri (flatbread) is traditional use.'));
INSERT INTO produce_translations VALUES(20,'hi','मक्का','अनाज','Cereal','Kharif','मक्का GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('मक्का GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Zea mays\u000a\u000aश्रेणी: Cereal\u000a\u000aमौसम: Kharif\u000a\u000aमराठी नाम: Makka\u000a\u000aहिंदी नाम: Makka\u000a\u000aअंग्रेजी नाम: Maize / Corn\u000a\u000aमूल डेटासेट विवरण: Maize is an important Kharif crop in Nashik, Pune, Aurangabad, Ahmednagar and Nanded districts. Used for food (corn), poultry feed, starch and ethanol. Maharashtra contributes ~5% of national maize production.'));
INSERT INTO produce_translations VALUES(20,'mr','मका','धान्य','Cereal','Kharif','मका हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('मका हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Zea mays\u000a\u000aश्रेणी: Cereal\u000a\u000aहंगाम: Kharif\u000a\u000aमराठी नाव: Makka\u000a\u000aहिंदी नाव: Makka\u000a\u000aइंग्रजी नाव: Maize / Corn\u000a\u000aमूळ डेटासेट तपशील: Maize is an important Kharif crop in Nashik, Pune, Aurangabad, Ahmednagar and Nanded districts. Used for food (corn), poultry feed, starch and ethanol. Maharashtra contributes ~5% of national maize production.'));
INSERT INTO produce_translations VALUES(21,'hi','रागी','अनाज','Millet','Kharif','रागी GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('रागी GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Eleusine coracana\u000a\u000aश्रेणी: Millet\u000a\u000aमौसम: Kharif\u000a\u000aमराठी नाम: Nachni\u000a\u000aहिंदी नाम: Ragi / Mandua\u000a\u000aअंग्रेजी नाम: Finger Millet\u000a\u000aमूल डेटासेट विवरण: Ragi (Nachni) is a nutritionally dense millet; grown in hilly and tribal areas of Nashik, Pune (Junnar), Nandurbar and Konkan. Richest grain source of calcium (344 mg/100g). Nachni bhakri and nachni satva (porridge) are traditional foods.'));
INSERT INTO produce_translations VALUES(21,'mr','नाचणी','धान्य','Millet','Kharif','नाचणी हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('नाचणी हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Eleusine coracana\u000a\u000aश्रेणी: Millet\u000a\u000aहंगाम: Kharif\u000a\u000aमराठी नाव: Nachni\u000a\u000aहिंदी नाव: Ragi / Mandua\u000a\u000aइंग्रजी नाव: Finger Millet\u000a\u000aमूळ डेटासेट तपशील: Ragi (Nachni) is a nutritionally dense millet; grown in hilly and tribal areas of Nashik, Pune (Junnar), Nandurbar and Konkan. Richest grain source of calcium (344 mg/100g). Nachni bhakri and nachni satva (porridge) are traditional foods.'));
INSERT INTO produce_translations VALUES(22,'hi','कोदो','अनाज','Millet','Kharif','कोदो GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('कोदो GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Paspalum scrobiculatum\u000a\u000aश्रेणी: Millet\u000a\u000aमौसम: Kharif\u000a\u000aमराठी नाम: Kodra\u000a\u000aहिंदी नाम: Kodra\u000a\u000aअंग्रेजी नाम: Kodo Millet\u000a\u000aमूल डेटासेट विवरण: Kodo Millet (Kodra) is a traditional millet grown in tribal/hilly areas of Nashik, Nandurbar, Amravati and Gadchiroli. Drought-tolerant; low input; nutritious; part of the Nutri-Cereal revival initiative in Maharashtra.'));
INSERT INTO produce_translations VALUES(22,'mr','कोद्रा','धान्य','Millet','Kharif','कोद्रा हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('कोद्रा हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Paspalum scrobiculatum\u000a\u000aश्रेणी: Millet\u000a\u000aहंगाम: Kharif\u000a\u000aमराठी नाव: Kodra\u000a\u000aहिंदी नाव: Kodra\u000a\u000aइंग्रजी नाव: Kodo Millet\u000a\u000aमूळ डेटासेट तपशील: Kodo Millet (Kodra) is a traditional millet grown in tribal/hilly areas of Nashik, Nandurbar, Amravati and Gadchiroli. Drought-tolerant; low input; nutritious; part of the Nutri-Cereal revival initiative in Maharashtra.'));
INSERT INTO produce_translations VALUES(23,'hi','कुटकी','अनाज','Millet','Kharif','कुटकी GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('कुटकी GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Panicum sumatrense\u000a\u000aश्रेणी: Millet\u000a\u000aमौसम: Kharif\u000a\u000aमराठी नाम: Vari / Kutki\u000a\u000aहिंदी नाम: Kutki\u000a\u000aअंग्रेजी नाम: Little Millet\u000a\u000aमूल डेटासेट विवरण: Little Millet (Vari) is used during religious fasting in Maharashtra (Ekadashi, Navratri). Grown in tribal belts of Nashik, Nandurbar and Gadchiroli. Reviving due to health consciousness and fasting food markets.'));
INSERT INTO produce_translations VALUES(23,'mr','वरी / कुटकी','धान्य','Millet','Kharif','वरी / कुटकी हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('वरी / कुटकी हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Panicum sumatrense\u000a\u000aश्रेणी: Millet\u000a\u000aहंगाम: Kharif\u000a\u000aमराठी नाव: Vari / Kutki\u000a\u000aहिंदी नाव: Kutki\u000a\u000aइंग्रजी नाव: Little Millet\u000a\u000aमूळ डेटासेट तपशील: Little Millet (Vari) is used during religious fasting in Maharashtra (Ekadashi, Navratri). Grown in tribal belts of Nashik, Nandurbar and Gadchiroli. Reviving due to health consciousness and fasting food markets.'));
INSERT INTO produce_translations VALUES(24,'hi','सांवा','अनाज','Millet','Kharif','सांवा GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('सांवा GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Echinochloa frumentacea\u000a\u000aश्रेणी: Millet\u000a\u000aमौसम: Kharif\u000a\u000aमराठी नाम: Bhagar / Sanwa\u000a\u000aहिंदी नाम: Sanwa\u000a\u000aअंग्रेजी नाम: Barnyard Millet\u000a\u000aमूल डेटासेट विवरण: Barnyard Millet (Bhagar) is extremely popular in Maharashtra for religious fasting (Upvasachi bhakri, Bhagar rice). Widely consumed during Ekadashi, Navratri. Grown in Nashik, Aurangabad, Nandurbar. High fibre, low GI.'));
INSERT INTO produce_translations VALUES(24,'mr','भगर / सांवा','धान्य','Millet','Kharif','भगर / सांवा हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('भगर / सांवा हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Echinochloa frumentacea\u000a\u000aश्रेणी: Millet\u000a\u000aहंगाम: Kharif\u000a\u000aमराठी नाव: Bhagar / Sanwa\u000a\u000aहिंदी नाव: Sanwa\u000a\u000aइंग्रजी नाव: Barnyard Millet\u000a\u000aमूळ डेटासेट तपशील: Barnyard Millet (Bhagar) is extremely popular in Maharashtra for religious fasting (Upvasachi bhakri, Bhagar rice). Widely consumed during Ekadashi, Navratri. Grown in Nashik, Aurangabad, Nandurbar. High fibre, low GI.'));
INSERT INTO produce_translations VALUES(25,'hi','चीना','अनाज','Millet','Kharif','चीना GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('चीना GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Panicum miliaceum\u000a\u000aश्रेणी: Millet\u000a\u000aमौसम: Kharif\u000a\u000aमराठी नाम: Cheena\u000a\u000aहिंदी नाम: Cheena\u000a\u000aअंग्रेजी नाम: Proso Millet / Common Millet\u000a\u000aमूल डेटासेट विवरण: Proso Millet is an ancient grain with fastest growth cycle (60–75 days) among millets. Grown in dry areas of Maharashtra as an emergency/catch crop. Low water requirement; high nutritional value. Reviving under health and organic food movements.'));
INSERT INTO produce_translations VALUES(25,'mr','चीना','धान्य','Millet','Kharif','चीना हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('चीना हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Panicum miliaceum\u000a\u000aश्रेणी: Millet\u000a\u000aहंगाम: Kharif\u000a\u000aमराठी नाव: Cheena\u000a\u000aहिंदी नाव: Cheena\u000a\u000aइंग्रजी नाव: Proso Millet / Common Millet\u000a\u000aमूळ डेटासेट तपशील: Proso Millet is an ancient grain with fastest growth cycle (60–75 days) among millets. Grown in dry areas of Maharashtra as an emergency/catch crop. Low water requirement; high nutritional value. Reviving under health and organic food movements.'));
INSERT INTO produce_translations VALUES(26,'hi','तूर / अरहर','अनाज','Pulse','Kharif','तूर / अरहर GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('तूर / अरहर GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Cajanus cajan\u000a\u000aश्रेणी: Pulse\u000a\u000aमौसम: Kharif\u000a\u000aमराठी नाम: Tur\u000a\u000aहिंदी नाम: Arhar / Tur\u000a\u000aअंग्रेजी नाम: Pigeon Pea / Red Gram\u000a\u000aमूल डेटासेट विवरण: Maharashtra is the largest Tur (pigeon pea) producing state in India. Grown extensively in Latur, Osmanabad, Nanded, Solapur and Marathwada. Staple dal of Maharashtra — tur dal (amti) is fundamental to Maharashtrian thali. Kharif season: sown June–July, harvested January–February.'));
INSERT INTO produce_translations VALUES(26,'mr','तूर','धान्य','Pulse','Kharif','तूर हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('तूर हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Cajanus cajan\u000a\u000aश्रेणी: Pulse\u000a\u000aहंगाम: Kharif\u000a\u000aमराठी नाव: Tur\u000a\u000aहिंदी नाव: Arhar / Tur\u000a\u000aइंग्रजी नाव: Pigeon Pea / Red Gram\u000a\u000aमूळ डेटासेट तपशील: Maharashtra is the largest Tur (pigeon pea) producing state in India. Grown extensively in Latur, Osmanabad, Nanded, Solapur and Marathwada. Staple dal of Maharashtra — tur dal (amti) is fundamental to Maharashtrian thali. Kharif season: sown June–July, harvested January–February.'));
INSERT INTO produce_translations VALUES(27,'hi','चना','अनाज','Pulse','Rabi','चना GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('चना GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Cicer arietinum\u000a\u000aश्रेणी: Pulse\u000a\u000aमौसम: Rabi\u000a\u000aमराठी नाम: Harbhara / Chana\u000a\u000aहिंदी नाम: Chana\u000a\u000aअंग्रेजी नाम: Chickpea / Bengal Gram\u000a\u000aमूल डेटासेट विवरण: Maharashtra is a leading chickpea-growing state; Marathwada (Latur, Osmanabad, Aurangabad) and Vidarbha are key regions. Both desi (brown) and kabuli (white/large) types grown. Rabi season: sown October–November, harvested January–February.'));
INSERT INTO produce_translations VALUES(27,'mr','हरभरा','धान्य','Pulse','Rabi','हरभरा हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('हरभरा हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Cicer arietinum\u000a\u000aश्रेणी: Pulse\u000a\u000aहंगाम: Rabi\u000a\u000aमराठी नाव: Harbhara / Chana\u000a\u000aहिंदी नाव: Chana\u000a\u000aइंग्रजी नाव: Chickpea / Bengal Gram\u000a\u000aमूळ डेटासेट तपशील: Maharashtra is a leading chickpea-growing state; Marathwada (Latur, Osmanabad, Aurangabad) and Vidarbha are key regions. Both desi (brown) and kabuli (white/large) types grown. Rabi season: sown October–November, harvested January–February.'));
INSERT INTO produce_translations VALUES(28,'hi','उड़द','अनाज','Pulse','Kharif','उड़द GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('उड़द GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Vigna mungo\u000a\u000aश्रेणी: Pulse\u000a\u000aमौसम: Kharif\u000a\u000aमराठी नाम: Udid\u000a\u000aहिंदी नाम: Urad\u000a\u000aअंग्रेजी नाम: Black Gram / Urad\u000a\u000aमूल डेटासेट विवरण: Urad (Udid) is a Kharif pulse grown in Nanded, Latur, Osmanabad, Aurangabad and parts of Vidarbha. Essential for Maharashtrian vada, idli (batter), and dal. Short-duration; good in mixed cropping with Tur.'));
INSERT INTO produce_translations VALUES(28,'mr','उडीद','धान्य','Pulse','Kharif','उडीद हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('उडीद हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Vigna mungo\u000a\u000aश्रेणी: Pulse\u000a\u000aहंगाम: Kharif\u000a\u000aमराठी नाव: Udid\u000a\u000aहिंदी नाव: Urad\u000a\u000aइंग्रजी नाव: Black Gram / Urad\u000a\u000aमूळ डेटासेट तपशील: Urad (Udid) is a Kharif pulse grown in Nanded, Latur, Osmanabad, Aurangabad and parts of Vidarbha. Essential for Maharashtrian vada, idli (batter), and dal. Short-duration; good in mixed cropping with Tur.'));
INSERT INTO produce_translations VALUES(29,'hi','मसूर','अनाज','Pulse','Rabi','मसूर GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('मसूर GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Lens culinaris\u000a\u000aश्रेणी: Pulse\u000a\u000aमौसम: Rabi\u000a\u000aमराठी नाम: Masur\u000a\u000aहिंदी नाम: Masoor\u000a\u000aअंग्रेजी नाम: Lentil / Masoor\u000a\u000aमूल डेटासेट विवरण: Masoor (Red Lentil) is a Rabi pulse grown in Marathwada and Vidarbha — Latur, Osmanabad, Yavatmal. Less common than Tur and Chana but nutritionally important; pink/red split dal used widely in Maharashtrian cuisine.'));
INSERT INTO produce_translations VALUES(29,'mr','मसूर','धान्य','Pulse','Rabi','मसूर हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('मसूर हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Lens culinaris\u000a\u000aश्रेणी: Pulse\u000a\u000aहंगाम: Rabi\u000a\u000aमराठी नाव: Masur\u000a\u000aहिंदी नाव: Masoor\u000a\u000aइंग्रजी नाव: Lentil / Masoor\u000a\u000aमूळ डेटासेट तपशील: Masoor (Red Lentil) is a Rabi pulse grown in Marathwada and Vidarbha — Latur, Osmanabad, Yavatmal. Less common than Tur and Chana but nutritionally important; pink/red split dal used widely in Maharashtrian cuisine.'));
INSERT INTO produce_translations VALUES(30,'hi','सोयाबीन','अनाज','Oilseed','Kharif','सोयाबीन GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('सोयाबीन GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Glycine max\u000a\u000aश्रेणी: Oilseed\u000a\u000aमौसम: Kharif\u000a\u000aमराठी नाम: Soya\u000a\u000aहिंदी नाम: Soya\u000a\u000aअंग्रेजी नाम: Soybean\u000a\u000aमूल डेटासेट विवरण: Maharashtra is the largest soybean-growing state in India, with ~40% of national acreage. Grown in Vidarbha (Nagpur, Amravati), Marathwada (Latur, Osmanabad) and Nashik. Major oilseed and protein crop. Sown June–July; harvested September–October.'));
INSERT INTO produce_translations VALUES(30,'mr','सोयाबीन','धान्य','Oilseed','Kharif','सोयाबीन हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('सोयाबीन हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Glycine max\u000a\u000aश्रेणी: Oilseed\u000a\u000aहंगाम: Kharif\u000a\u000aमराठी नाव: Soya\u000a\u000aहिंदी नाव: Soya\u000a\u000aइंग्रजी नाव: Soybean\u000a\u000aमूळ डेटासेट तपशील: Maharashtra is the largest soybean-growing state in India, with ~40% of national acreage. Grown in Vidarbha (Nagpur, Amravati), Marathwada (Latur, Osmanabad) and Nashik. Major oilseed and protein crop. Sown June–July; harvested September–October.'));
INSERT INTO produce_translations VALUES(31,'hi','मूंगफली','अनाज','Oilseed','Kharif','मूंगफली GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('मूंगफली GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Arachis hypogaea\u000a\u000aश्रेणी: Oilseed\u000a\u000aमौसम: Kharif\u000a\u000aमराठी नाम: Shengdana\u000a\u000aहिंदी नाम: Moongphali\u000a\u000aअंग्रेजी नाम: Groundnut / Peanut\u000a\u000aमूल डेटासेट विवरण: Groundnut is a major Kharif oilseed and cash crop in Maharashtra — Akola, Amravati, Wardha (Vidarbha) and Nashik, Jalgaon (North Maharashtra). Maharashtra is 4th nationally. Also a Rabi irrigated crop in Solapur. Famous for "Vidarbha shengdana".'));
INSERT INTO produce_translations VALUES(31,'mr','शेंगदाणा','धान्य','Oilseed','Kharif','शेंगदाणा हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('शेंगदाणा हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Arachis hypogaea\u000a\u000aश्रेणी: Oilseed\u000a\u000aहंगाम: Kharif\u000a\u000aमराठी नाव: Shengdana\u000a\u000aहिंदी नाव: Moongphali\u000a\u000aइंग्रजी नाव: Groundnut / Peanut\u000a\u000aमूळ डेटासेट तपशील: Groundnut is a major Kharif oilseed and cash crop in Maharashtra — Akola, Amravati, Wardha (Vidarbha) and Nashik, Jalgaon (North Maharashtra). Maharashtra is 4th nationally. Also a Rabi irrigated crop in Solapur. Famous for "Vidarbha shengdana".'));
INSERT INTO produce_translations VALUES(32,'hi','तिल','अनाज','Oilseed','Kharif','तिल GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('तिल GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Sesamum indicum\u000a\u000aश्रेणी: Oilseed\u000a\u000aमौसम: Kharif\u000a\u000aमराठी नाम: Til\u000a\u000aहिंदी नाम: Til\u000a\u000aअंग्रेजी नाम: Sesame\u000a\u000aमूल डेटासेट विवरण: Sesame (Til) is a traditional oilseed crop of Maharashtra grown in Aurangabad, Jalgaon, Nashik and Osmanabad. Essential in Maharashtrian sweets — tilgul (sesame-jaggery balls) for Makar Sankranti. High-value crop for domestic and export market.'));
INSERT INTO produce_translations VALUES(32,'mr','तीळ','धान्य','Oilseed','Kharif','तीळ हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('तीळ हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Sesamum indicum\u000a\u000aश्रेणी: Oilseed\u000a\u000aहंगाम: Kharif\u000a\u000aमराठी नाव: Til\u000a\u000aहिंदी नाव: Til\u000a\u000aइंग्रजी नाव: Sesame\u000a\u000aमूळ डेटासेट तपशील: Sesame (Til) is a traditional oilseed crop of Maharashtra grown in Aurangabad, Jalgaon, Nashik and Osmanabad. Essential in Maharashtrian sweets — tilgul (sesame-jaggery balls) for Makar Sankranti. High-value crop for domestic and export market.'));
INSERT INTO produce_translations VALUES(33,'hi','सूरजमुखी','अनाज','Oilseed','Rabi','सूरजमुखी GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('सूरजमुखी GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Helianthus annuus\u000a\u000aश्रेणी: Oilseed\u000a\u000aमौसम: Rabi\u000a\u000aमराठी नाम: Suryafool\u000a\u000aहिंदी नाम: Surajmukhi\u000a\u000aअंग्रेजी नाम: Sunflower\u000a\u000aमूल डेटासेट विवरण: Sunflower is grown as a Rabi crop in Maharashtra — Solapur, Osmanabad, Latur, Aurangabad, Nashik. Good oil crop for light black soils; used as edible oil. Also a Kharif crop in some areas.'));
INSERT INTO produce_translations VALUES(33,'mr','सूर्यफूल','धान्य','Oilseed','Rabi','सूर्यफूल हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('सूर्यफूल हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Helianthus annuus\u000a\u000aश्रेणी: Oilseed\u000a\u000aहंगाम: Rabi\u000a\u000aमराठी नाव: Suryafool\u000a\u000aहिंदी नाव: Surajmukhi\u000a\u000aइंग्रजी नाव: Sunflower\u000a\u000aमूळ डेटासेट तपशील: Sunflower is grown as a Rabi crop in Maharashtra — Solapur, Osmanabad, Latur, Aurangabad, Nashik. Good oil crop for light black soils; used as edible oil. Also a Kharif crop in some areas.'));
INSERT INTO produce_translations VALUES(34,'hi','गन्ना','अनाज','Cash Crop / Industrial','Year-round','गन्ना GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('गन्ना GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Saccharum officinarum\u000a\u000aश्रेणी: Cash Crop / Industrial\u000a\u000aमौसम: Year-round\u000a\u000aमराठी नाम: Oos / Verdi\u000a\u000aहिंदी नाम: Ganna\u000a\u000aअंग्रेजी नाम: Sugarcane\u000a\u000aमूल डेटासेट विवरण: Maharashtra is India''s second-largest sugarcane and sugar-producing state. The Deccan plateau districts of Pune, Satara, Sangli, Kolhapur, Solapur, Nashik and Ahmednagar form the "Sugar Belt". Over 200 cooperative sugar factories operate. Maharashtra also leads in ethanol production from sugarcane. Crushed October–March after 10–14 months of growth. By-products: bagasse (energy), molasses (ethanol/alcohol), press mud (compost).'));
INSERT INTO produce_translations VALUES(34,'mr','ऊस','धान्य','Cash Crop / Industrial','Year-round','ऊस हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('ऊस हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Saccharum officinarum\u000a\u000aश्रेणी: Cash Crop / Industrial\u000a\u000aहंगाम: Year-round\u000a\u000aमराठी नाव: Oos / Verdi\u000a\u000aहिंदी नाव: Ganna\u000a\u000aइंग्रजी नाव: Sugarcane\u000a\u000aमूळ डेटासेट तपशील: Maharashtra is India''s second-largest sugarcane and sugar-producing state. The Deccan plateau districts of Pune, Satara, Sangli, Kolhapur, Solapur, Nashik and Ahmednagar form the "Sugar Belt". Over 200 cooperative sugar factories operate. Maharashtra also leads in ethanol production from sugarcane. Crushed October–March after 10–14 months of growth. By-products: bagasse (energy), molasses (ethanol/alcohol), press mud (compost).'));
INSERT INTO produce_translations VALUES(35,'hi','प्याज','vegetable','Vegetable / Spice','Rabi','प्याज GreenWings कैटलॉग का एक महत्वपूर्ण vegetable उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('प्याज GreenWings कैटलॉग का एक महत्वपूर्ण vegetable उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Allium cepa\u000a\u000aश्रेणी: Vegetable / Spice\u000a\u000aमौसम: Rabi\u000a\u000aमराठी नाम: Kanda\u000a\u000aहिंदी नाम: Pyaaz\u000a\u000aअंग्रेजी नाम: Onion\u000a\u000aमूल डेटासेट विवरण: Maharashtra is India''s largest onion-producing state (~40% national share). Nashik, Pune, Ahmednagar, Solapur and Satara are prime growing districts. Nashik''s Lasalgaon APMC is Asia''s largest onion market. Three crops a year possible: Kharif (June–October), Late Kharif (September–January), and Rabi (January–May). Major export crop to Europe, South-East Asia and Middle East.'));
INSERT INTO produce_translations VALUES(35,'mr','कांदा','vegetable','Vegetable / Spice','Rabi','कांदा हे GreenWings कॅटलॉगमधील महत्त्वाचे vegetable उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('कांदा हे GreenWings कॅटलॉगमधील महत्त्वाचे vegetable उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Allium cepa\u000a\u000aश्रेणी: Vegetable / Spice\u000a\u000aहंगाम: Rabi\u000a\u000aमराठी नाव: Kanda\u000a\u000aहिंदी नाव: Pyaaz\u000a\u000aइंग्रजी नाव: Onion\u000a\u000aमूळ डेटासेट तपशील: Maharashtra is India''s largest onion-producing state (~40% national share). Nashik, Pune, Ahmednagar, Solapur and Satara are prime growing districts. Nashik''s Lasalgaon APMC is Asia''s largest onion market. Three crops a year possible: Kharif (June–October), Late Kharif (September–January), and Rabi (January–May). Major export crop to Europe, South-East Asia and Middle East.'));
INSERT INTO produce_translations VALUES(36,'hi','टमाटर','vegetable','Vegetable','Year-round','टमाटर GreenWings कैटलॉग का एक महत्वपूर्ण vegetable उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('टमाटर GreenWings कैटलॉग का एक महत्वपूर्ण vegetable उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Solanum lycopersicum\u000a\u000aश्रेणी: Vegetable\u000a\u000aमौसम: Year-round\u000a\u000aमराठी नाम: Tomato\u000a\u000aहिंदी नाम: Tamatar\u000a\u000aअंग्रेजी नाम: Tomato\u000a\u000aमूल डेटासेट विवरण: Maharashtra is a top-3 tomato-producing state. Nashik, Pune, Satara, Ahmednagar and Solapur are major districts. Tomatoes are grown year-round under irrigated conditions; also a major processing crop for puree, paste and ketchup. Narayangaon (Pune) is an important tomato trading hub.'));
INSERT INTO produce_translations VALUES(36,'mr','टोमॅटो','vegetable','Vegetable','Year-round','टोमॅटो हे GreenWings कॅटलॉगमधील महत्त्वाचे vegetable उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('टोमॅटो हे GreenWings कॅटलॉगमधील महत्त्वाचे vegetable उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Solanum lycopersicum\u000a\u000aश्रेणी: Vegetable\u000a\u000aहंगाम: Year-round\u000a\u000aमराठी नाव: Tomato\u000a\u000aहिंदी नाव: Tamatar\u000a\u000aइंग्रजी नाव: Tomato\u000a\u000aमूळ डेटासेट तपशील: Maharashtra is a top-3 tomato-producing state. Nashik, Pune, Satara, Ahmednagar and Solapur are major districts. Tomatoes are grown year-round under irrigated conditions; also a major processing crop for puree, paste and ketchup. Narayangaon (Pune) is an important tomato trading hub.'));
INSERT INTO produce_translations VALUES(37,'hi','मोसंबी','फल','Citrus','Year-round','मोसंबी GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('मोसंबी GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrus limetta\u000a\u000aश्रेणी: Citrus\u000a\u000aमौसम: Year-round\u000a\u000aमराठी नाम: Mosambi\u000a\u000aहिंदी नाम: Mosambi\u000a\u000aअंग्रेजी नाम: Sweet Lime / Mosambi\u000a\u000aमूल डेटासेट विवरण: Sweet Lime (Mosambi) is one of Maharashtra''s most commercially important citrus fruits, distinct from orange. Solapur, Osmanabad, Aurangabad, Pune and Nashik are major growing centres. Extremely popular for fresh juice; sold across India year-round. Maharashtra accounts for ~35% of India''s Mosambi production.'));
INSERT INTO produce_translations VALUES(37,'mr','मोसंबी','फळ','Citrus','Year-round','मोसंबी हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('मोसंबी हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrus limetta\u000a\u000aश्रेणी: Citrus\u000a\u000aहंगाम: Year-round\u000a\u000aमराठी नाव: Mosambi\u000a\u000aहिंदी नाव: Mosambi\u000a\u000aइंग्रजी नाव: Sweet Lime / Mosambi\u000a\u000aमूळ डेटासेट तपशील: Sweet Lime (Mosambi) is one of Maharashtra''s most commercially important citrus fruits, distinct from orange. Solapur, Osmanabad, Aurangabad, Pune and Nashik are major growing centres. Extremely popular for fresh juice; sold across India year-round. Maharashtra accounts for ~35% of India''s Mosambi production.'));
INSERT INTO produce_translations VALUES(38,'hi','लहसुन','vegetable','Vegetable / Spice','Rabi','लहसुन GreenWings कैटलॉग का एक महत्वपूर्ण vegetable उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('लहसुन GreenWings कैटलॉग का एक महत्वपूर्ण vegetable उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Allium sativum\u000a\u000aश्रेणी: Vegetable / Spice\u000a\u000aमौसम: Rabi\u000a\u000aमराठी नाम: Lasun\u000a\u000aहिंदी नाम: Lahsun\u000a\u000aअंग्रेजी नाम: Garlic\u000a\u000aमूल डेटासेट विवरण: Garlic is an important Rabi spice crop in Maharashtra — Nashik, Satara, Solapur, Pune, Aurangabad. Maharashtra is among top-5 garlic-producing states. Sown October–November; harvested February–March. Maharashtra garlic is known for its pungency and high allicin content. Major export crop and ingredient in Indian cuisine and Ayurvedic medicine.'));
INSERT INTO produce_translations VALUES(38,'mr','लसूण','vegetable','Vegetable / Spice','Rabi','लसूण हे GreenWings कॅटलॉगमधील महत्त्वाचे vegetable उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('लसूण हे GreenWings कॅटलॉगमधील महत्त्वाचे vegetable उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Allium sativum\u000a\u000aश्रेणी: Vegetable / Spice\u000a\u000aहंगाम: Rabi\u000a\u000aमराठी नाव: Lasun\u000a\u000aहिंदी नाव: Lahsun\u000a\u000aइंग्रजी नाव: Garlic\u000a\u000aमूळ डेटासेट तपशील: Garlic is an important Rabi spice crop in Maharashtra — Nashik, Satara, Solapur, Pune, Aurangabad. Maharashtra is among top-5 garlic-producing states. Sown October–November; harvested February–March. Maharashtra garlic is known for its pungency and high allicin content. Major export crop and ingredient in Indian cuisine and Ayurvedic medicine.'));
INSERT INTO produce_translations VALUES(39,'hi','हल्दी','vegetable','Spice / Medicinal','Kharif','हल्दी GreenWings कैटलॉग का एक महत्वपूर्ण vegetable उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('हल्दी GreenWings कैटलॉग का एक महत्वपूर्ण vegetable उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Curcuma longa\u000a\u000aश्रेणी: Spice / Medicinal\u000a\u000aमौसम: Kharif\u000a\u000aमराठी नाम: Halad\u000a\u000aहिंदी नाम: Haldi\u000a\u000aअंग्रेजी नाम: Turmeric\u000a\u000aमूल डेटासेट विवरण: Maharashtra is one of India''s top turmeric-producing states. Sangli, Kolhapur, Satara and Pune are major growing districts. Sangli''s Erande (Yelur) turmeric is GI-tagged and renowned for its high curcumin content (>4.5%). Harvested January–March after 8–9 months. Essential in Maharashtrian cooking, medicine (Ayurveda) and cosmetics. Major export to USA, Japan, EU.'));
INSERT INTO produce_translations VALUES(39,'mr','हळद','vegetable','Spice / Medicinal','Kharif','हळद हे GreenWings कॅटलॉगमधील महत्त्वाचे vegetable उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('हळद हे GreenWings कॅटलॉगमधील महत्त्वाचे vegetable उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Curcuma longa\u000a\u000aश्रेणी: Spice / Medicinal\u000a\u000aहंगाम: Kharif\u000a\u000aमराठी नाव: Halad\u000a\u000aहिंदी नाव: Haldi\u000a\u000aइंग्रजी नाव: Turmeric\u000a\u000aमूळ डेटासेट तपशील: Maharashtra is one of India''s top turmeric-producing states. Sangli, Kolhapur, Satara and Pune are major growing districts. Sangli''s Erande (Yelur) turmeric is GI-tagged and renowned for its high curcumin content (>4.5%). Harvested January–March after 8–9 months. Essential in Maharashtrian cooking, medicine (Ayurveda) and cosmetics. Major export to USA, Japan, EU.'));
INSERT INTO produce_translations VALUES(40,'hi','मिर्च','vegetable','Spice / Vegetable','Kharif','मिर्च GreenWings कैटलॉग का एक महत्वपूर्ण vegetable उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('मिर्च GreenWings कैटलॉग का एक महत्वपूर्ण vegetable उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Capsicum annuum\u000a\u000aश्रेणी: Spice / Vegetable\u000a\u000aमौसम: Kharif\u000a\u000aमराठी नाम: Mirchi\u000a\u000aहिंदी नाम: Mirch\u000a\u000aअंग्रेजी नाम: Chilli / Hot Pepper\u000a\u000aमूल डेटासेट विवरण: Maharashtra is a major chilli-producing state. Aurangabad, Nashik, Pune, Latur, Osmanabad and Amravati are key districts for dry chilli production. Kolhapur Red Chilli is GI-tagged and one of the hottest and most flavourful in India. Chilli grown for fresh, dry, and powder markets. Key ingredient in Kolhapuri cuisine and Maharashtra masalas.'));
INSERT INTO produce_translations VALUES(40,'mr','मिरची','vegetable','Spice / Vegetable','Kharif','मिरची हे GreenWings कॅटलॉगमधील महत्त्वाचे vegetable उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('मिरची हे GreenWings कॅटलॉगमधील महत्त्वाचे vegetable उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Capsicum annuum\u000a\u000aश्रेणी: Spice / Vegetable\u000a\u000aहंगाम: Kharif\u000a\u000aमराठी नाव: Mirchi\u000a\u000aहिंदी नाव: Mirch\u000a\u000aइंग्रजी नाव: Chilli / Hot Pepper\u000a\u000aमूळ डेटासेट तपशील: Maharashtra is a major chilli-producing state. Aurangabad, Nashik, Pune, Latur, Osmanabad and Amravati are key districts for dry chilli production. Kolhapur Red Chilli is GI-tagged and one of the hottest and most flavourful in India. Chilli grown for fresh, dry, and powder markets. Key ingredient in Kolhapuri cuisine and Maharashtra masalas.'));
INSERT INTO produce_translations VALUES(41,'hi','अदरक','vegetable','Spice / Medicinal','Kharif','अदरक GreenWings कैटलॉग का एक महत्वपूर्ण vegetable उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('अदरक GreenWings कैटलॉग का एक महत्वपूर्ण vegetable उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Zingiber officinale\u000a\u000aश्रेणी: Spice / Medicinal\u000a\u000aमौसम: Kharif\u000a\u000aमराठी नाम: Aale\u000a\u000aहिंदी नाम: Adrak\u000a\u000aअंग्रेजी नाम: Ginger\u000a\u000aमूल डेटासेट विवरण: Ginger is grown in the high-rainfall Western Ghats districts of Maharashtra — Satara, Kolhapur, Sindhudurg, Pune (Maval). A Kharif crop, sown April–May and harvested November–December. Fresh green ginger and dried soonth (dried ginger powder) both produced. Maharashtra contributes ~8% of India''s ginger output. High value for domestic cooking and pharma/ayurvedic industry.'));
INSERT INTO produce_translations VALUES(41,'mr','आले','vegetable','Spice / Medicinal','Kharif','आले हे GreenWings कॅटलॉगमधील महत्त्वाचे vegetable उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('आले हे GreenWings कॅटलॉगमधील महत्त्वाचे vegetable उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Zingiber officinale\u000a\u000aश्रेणी: Spice / Medicinal\u000a\u000aहंगाम: Kharif\u000a\u000aमराठी नाव: Aale\u000a\u000aहिंदी नाव: Adrak\u000a\u000aइंग्रजी नाव: Ginger\u000a\u000aमूळ डेटासेट तपशील: Ginger is grown in the high-rainfall Western Ghats districts of Maharashtra — Satara, Kolhapur, Sindhudurg, Pune (Maval). A Kharif crop, sown April–May and harvested November–December. Fresh green ginger and dried soonth (dried ginger powder) both produced. Maharashtra contributes ~8% of India''s ginger output. High value for domestic cooking and pharma/ayurvedic industry.'));
INSERT INTO produce_translations VALUES(42,'hi','इमली','फल','Fruit / Spice','Rabi','इमली GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('इमली GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Tamarindus indica\u000a\u000aश्रेणी: Fruit / Spice\u000a\u000aमौसम: Rabi\u000a\u000aमराठी नाम: Chincha\u000a\u000aहिंदी नाम: Imli\u000a\u000aअंग्रेजी नाम: Tamarind\u000a\u000aमूल डेटासेट विवरण: Tamarind is a perennial tree crop widely found across Maharashtra, especially in Marathwada (Aurangabad, Osmanabad, Latur) and Vidarbha (Amravati, Nagpur). It is a rainfed, low-maintenance crop harvested January–April. Tamarind pulp, seed and shell all have commercial value. Key ingredient in Maharashtra''s chutneys, rasam-style dishes, and the famous Panha drink. Also used in pharmaceuticals, confectionery and food processing.'));
INSERT INTO produce_translations VALUES(42,'mr','चिंच','फळ','Fruit / Spice','Rabi','चिंच हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('चिंच हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Tamarindus indica\u000a\u000aश्रेणी: Fruit / Spice\u000a\u000aहंगाम: Rabi\u000a\u000aमराठी नाव: Chincha\u000a\u000aहिंदी नाव: Imli\u000a\u000aइंग्रजी नाव: Tamarind\u000a\u000aमूळ डेटासेट तपशील: Tamarind is a perennial tree crop widely found across Maharashtra, especially in Marathwada (Aurangabad, Osmanabad, Latur) and Vidarbha (Amravati, Nagpur). It is a rainfed, low-maintenance crop harvested January–April. Tamarind pulp, seed and shell all have commercial value. Key ingredient in Maharashtra''s chutneys, rasam-style dishes, and the famous Panha drink. Also used in pharmaceuticals, confectionery and food processing.'));
INSERT INTO produce_translations VALUES(43,'hi','मेथी','vegetable','Spice / Vegetable / Medicinal','Rabi','मेथी GreenWings कैटलॉग का एक महत्वपूर्ण vegetable उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('मेथी GreenWings कैटलॉग का एक महत्वपूर्ण vegetable उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Trigonella foenum-graecum\u000a\u000aश्रेणी: Spice / Vegetable / Medicinal\u000a\u000aमौसम: Rabi\u000a\u000aमराठी नाम: Methi\u000a\u000aहिंदी नाम: Methi\u000a\u000aअंग्रेजी नाम: Fenugreek / Methi\u000a\u000aमूल डेटासेट विवरण: Fenugreek (Methi) is grown across Maharashtra as a Rabi crop for its leaves (fresh vegetable) and seeds (spice). Nashik, Pune, Aurangabad and Solapur are major growing areas. The seeds are essential in Maharashtra''s goda masala, pickles and parathas. Rich in fenuside, fibre and iron. Also used medicinally for diabetes and lactation support.'));
INSERT INTO produce_translations VALUES(43,'mr','मेथी','vegetable','Spice / Vegetable / Medicinal','Rabi','मेथी हे GreenWings कॅटलॉगमधील महत्त्वाचे vegetable उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('मेथी हे GreenWings कॅटलॉगमधील महत्त्वाचे vegetable उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Trigonella foenum-graecum\u000a\u000aश्रेणी: Spice / Vegetable / Medicinal\u000a\u000aहंगाम: Rabi\u000a\u000aमराठी नाव: Methi\u000a\u000aहिंदी नाव: Methi\u000a\u000aइंग्रजी नाव: Fenugreek / Methi\u000a\u000aमूळ डेटासेट तपशील: Fenugreek (Methi) is grown across Maharashtra as a Rabi crop for its leaves (fresh vegetable) and seeds (spice). Nashik, Pune, Aurangabad and Solapur are major growing areas. The seeds are essential in Maharashtra''s goda masala, pickles and parathas. Rich in fenuside, fibre and iron. Also used medicinally for diabetes and lactation support.'));
INSERT INTO produce_translations VALUES(44,'hi','धनिया','vegetable','Spice / Herb','Rabi','धनिया GreenWings कैटलॉग का एक महत्वपूर्ण vegetable उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('धनिया GreenWings कैटलॉग का एक महत्वपूर्ण vegetable उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Coriandrum sativum\u000a\u000aश्रेणी: Spice / Herb\u000a\u000aमौसम: Rabi\u000a\u000aमराठी नाम: Kothimbir\u000a\u000aहिंदी नाम: Dhaniya\u000a\u000aअंग्रेजी नाम: Coriander / Dhania\u000a\u000aमूल डेटासेट विवरण: Coriander is one of Maharashtra''s most important spice crops, grown in Nashik, Pune, Satara, Aurangabad. Used both fresh (green coriander leaves) and dry (dhania seeds). Kothimbir Vadi (coriander fritters) is a signature Maharashtrian snack. Maharashtra is among India''s top-5 coriander-producing states. Season: October–January for leaves; February–March for seeds.'));
INSERT INTO produce_translations VALUES(44,'mr','कोथिंबीर','vegetable','Spice / Herb','Rabi','कोथिंबीर हे GreenWings कॅटलॉगमधील महत्त्वाचे vegetable उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('कोथिंबीर हे GreenWings कॅटलॉगमधील महत्त्वाचे vegetable उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Coriandrum sativum\u000a\u000aश्रेणी: Spice / Herb\u000a\u000aहंगाम: Rabi\u000a\u000aमराठी नाव: Kothimbir\u000a\u000aहिंदी नाव: Dhaniya\u000a\u000aइंग्रजी नाव: Coriander / Dhania\u000a\u000aमूळ डेटासेट तपशील: Coriander is one of Maharashtra''s most important spice crops, grown in Nashik, Pune, Satara, Aurangabad. Used both fresh (green coriander leaves) and dry (dhania seeds). Kothimbir Vadi (coriander fritters) is a signature Maharashtrian snack. Maharashtra is among India''s top-5 coriander-producing states. Season: October–January for leaves; February–March for seeds.'));
INSERT INTO produce_translations VALUES(45,'hi','तरबूज','फल','Cucurbit Fruit','Zaid','तरबूज GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('तरबूज GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrullus lanatus\u000a\u000aश्रेणी: Cucurbit Fruit\u000a\u000aमौसम: Zaid\u000a\u000aमराठी नाम: Kalingad\u000a\u000aहिंदी नाम: Tarbooz\u000a\u000aअंग्रेजी नाम: Watermelon\u000a\u000aमूल डेटासेट विवरण: Watermelon is a major summer (Zaid) crop in Maharashtra — Nashik, Aurangabad, Solapur, Latur, Pune. Grown on sandy riverbed soils; sown February–March, harvested April–June. Maharashtra is a leading watermelon-producing state for domestic market. Large fruits preferred in Indian market; seedless hybrids gaining popularity.'));
INSERT INTO produce_translations VALUES(45,'mr','कलिंगड','फळ','Cucurbit Fruit','Zaid','कलिंगड हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('कलिंगड हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrullus lanatus\u000a\u000aश्रेणी: Cucurbit Fruit\u000a\u000aहंगाम: Zaid\u000a\u000aमराठी नाव: Kalingad\u000a\u000aहिंदी नाव: Tarbooz\u000a\u000aइंग्रजी नाव: Watermelon\u000a\u000aमूळ डेटासेट तपशील: Watermelon is a major summer (Zaid) crop in Maharashtra — Nashik, Aurangabad, Solapur, Latur, Pune. Grown on sandy riverbed soils; sown February–March, harvested April–June. Maharashtra is a leading watermelon-producing state for domestic market. Large fruits preferred in Indian market; seedless hybrids gaining popularity.'));
INSERT INTO produce_translations VALUES(46,'hi','खरबूजा','फल','Cucurbit Fruit','Zaid','खरबूजा GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('खरबूजा GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Cucumis melo\u000a\u000aश्रेणी: Cucurbit Fruit\u000a\u000aमौसम: Zaid\u000a\u000aमराठी नाम: Kharbuja\u000a\u000aहिंदी नाम: Kharbuja\u000a\u000aअंग्रेजी नाम: Muskmelon / Cantaloupe\u000a\u000aमूल डेटासेट विवरण: Muskmelon (Kharbuj) is an important summer fruit crop in Maharashtra — Nashik, Pune, Solapur, Jalgaon. Grown on sandy loam soils; excellent in Godavari and Bhima river basin. Season March–June. High demand for fresh consumption and cooling drinks.'));
INSERT INTO produce_translations VALUES(46,'mr','खरबूज','फळ','Cucurbit Fruit','Zaid','खरबूज हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('खरबूज हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Cucumis melo\u000a\u000aश्रेणी: Cucurbit Fruit\u000a\u000aहंगाम: Zaid\u000a\u000aमराठी नाव: Kharbuja\u000a\u000aहिंदी नाव: Kharbuja\u000a\u000aइंग्रजी नाव: Muskmelon / Cantaloupe\u000a\u000aमूळ डेटासेट तपशील: Muskmelon (Kharbuj) is an important summer fruit crop in Maharashtra — Nashik, Pune, Solapur, Jalgaon. Grown on sandy loam soils; excellent in Godavari and Bhima river basin. Season March–June. High demand for fresh consumption and cooling drinks.'));
INSERT INTO produce_translations VALUES(47,'hi','नींबू','फल','Citrus','Year-round','नींबू GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('नींबू GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrus limon / Citrus aurantiifolia\u000a\u000aश्रेणी: Citrus\u000a\u000aमौसम: Year-round\u000a\u000aमराठी नाम: Limbu\u000a\u000aहिंदी नाम: Nimbu\u000a\u000aअंग्रेजी नाम: Lemon / Lime\u000a\u000aमूल डेटासेट विवरण: Lemon and acid lime are widely grown across Maharashtra — Nashik, Pune, Aurangabad, Vidarbha. A perennial crop with year-round fruiting under irrigation. Widely used in Maharashtrian cuisine (limbu sherbet, chutneys, achaar), street food, and increasing export to the Gulf. Drought-tolerant once established.'));
INSERT INTO produce_translations VALUES(47,'mr','लिंबू','फळ','Citrus','Year-round','लिंबू हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('लिंबू हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrus limon / Citrus aurantiifolia\u000a\u000aश्रेणी: Citrus\u000a\u000aहंगाम: Year-round\u000a\u000aमराठी नाव: Limbu\u000a\u000aहिंदी नाव: Nimbu\u000a\u000aइंग्रजी नाव: Lemon / Lime\u000a\u000aमूळ डेटासेट तपशील: Lemon and acid lime are widely grown across Maharashtra — Nashik, Pune, Aurangabad, Vidarbha. A perennial crop with year-round fruiting under irrigation. Widely used in Maharashtrian cuisine (limbu sherbet, chutneys, achaar), street food, and increasing export to the Gulf. Drought-tolerant once established.'));
INSERT INTO subtypes VALUES(1,1,'Alphonso (Hapus)','Maharashtra','Sweet, aromatic, rich saffron flavour, low fibre','Mangifera indica cv. Alphonso','Hapus','GI-tagged variety from Ratnagiri & Sindhudurg; considered the king of mangoes; peak season April–May; ideal for pulp and fresh consumption.',unistr('GI-tagged variety from Ratnagiri & Sindhudurg; considered the king of mangoes; peak season April–May; ideal for pulp and fresh consumption.\u000a\u000aScientific name: Mangifera indica cv. Alphonso\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: Sweet, aromatic, rich saffron flavour, low fibre\u000a\u000aMarathi name: Hapus'),NULL);
INSERT INTO subtypes VALUES(2,1,'Kesar','Gujarat/Maharashtra','Sweet, less fibrous, deep orange pulp','Mangifera indica cv. Kesar','Kesar','Grown in Aurangabad and Marathwada; second most exported variety; saffron-coloured pulp; season May–June.',unistr('Grown in Aurangabad and Marathwada; second most exported variety; saffron-coloured pulp; season May–June.\u000a\u000aScientific name: Mangifera indica cv. Kesar\u000a\u000aOrigin: Gujarat/Maharashtra\u000a\u000aTaste profile: Sweet, less fibrous, deep orange pulp\u000a\u000aMarathi name: Kesar'),NULL);
INSERT INTO subtypes VALUES(3,1,'Langra','Uttar Pradesh/Maharashtra','Sweet-sour, green skin, rich flavour','Mangifera indica cv. Langra','Langra','Grown in Nashik and Pune regions; medium-large fruit; greenish skin even when ripe.',unistr('Grown in Nashik and Pune regions; medium-large fruit; greenish skin even when ripe.\u000a\u000aScientific name: Mangifera indica cv. Langra\u000a\u000aOrigin: Uttar Pradesh/Maharashtra\u000a\u000aTaste profile: Sweet-sour, green skin, rich flavour\u000a\u000aMarathi name: Langra'),NULL);
INSERT INTO subtypes VALUES(4,1,'Dasheri','Uttar Pradesh/Maharashtra','Sweet, fibrous, aromatic','Mangifera indica cv. Dasheri','Dasheri','Long fruit with thin skin; grown in Vidarbha; season June–July.',unistr('Long fruit with thin skin; grown in Vidarbha; season June–July.\u000a\u000aScientific name: Mangifera indica cv. Dasheri\u000a\u000aOrigin: Uttar Pradesh/Maharashtra\u000a\u000aTaste profile: Sweet, fibrous, aromatic\u000a\u000aMarathi name: Dasheri'),NULL);
INSERT INTO subtypes VALUES(5,1,'Totapuri','South India/Maharashtra','Mildly sweet, tangy, firm, low fibre','Mangifera indica cv. Totapuri','Totapuri','Large, elongated beak-shaped fruit; widely processed into mango pulp and pickle; grown in Solapur and Osmanabad.',unistr('Large, elongated beak-shaped fruit; widely processed into mango pulp and pickle; grown in Solapur and Osmanabad.\u000a\u000aScientific name: Mangifera indica cv. Totapuri\u000a\u000aOrigin: South India/Maharashtra\u000a\u000aTaste profile: Mildly sweet, tangy, firm, low fibre\u000a\u000aMarathi name: Totapuri'),NULL);
INSERT INTO subtypes VALUES(6,1,'Pairi','Maharashtra','Sweet, juicy, mild sour notes','Mangifera indica cv. Pairi','Pairi','Early season variety from Konkan; oval fruit; eaten fresh; also called Pyari.',unistr('Early season variety from Konkan; oval fruit; eaten fresh; also called Pyari.\u000a\u000aScientific name: Mangifera indica cv. Pairi\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: Sweet, juicy, mild sour notes\u000a\u000aMarathi name: Pairi'),NULL);
INSERT INTO subtypes VALUES(7,1,'Ratna','Maharashtra','Very sweet, aromatic, less fibrous','Mangifera indica cv. Ratna','Ratna','Hybrid developed at Dr BSKKV Dapoli; Alphonso × Neelum cross; regular bearer; popular in Konkan.',unistr('Hybrid developed at Dr BSKKV Dapoli; Alphonso × Neelum cross; regular bearer; popular in Konkan.\u000a\u000aScientific name: Mangifera indica cv. Ratna\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: Very sweet, aromatic, less fibrous\u000a\u000aMarathi name: Ratna'),NULL);
INSERT INTO subtypes VALUES(8,1,'Sindhu','Maharashtra','Sweet, aromatic, low fibre, long shelf life','Mangifera indica cv. Sindhu','Sindhu','Hybrid (Ratna × Alphonso) developed at Vengurle; excellent export quality; shelf life 10–12 days.',unistr('Hybrid (Ratna × Alphonso) developed at Vengurle; excellent export quality; shelf life 10–12 days.\u000a\u000aScientific name: Mangifera indica cv. Sindhu\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: Sweet, aromatic, low fibre, long shelf life\u000a\u000aMarathi name: Sindhu'),NULL);
INSERT INTO subtypes VALUES(9,1,'Neelum','Tamil Nadu/Maharashtra','Sweet, mild, fibrous','Mangifera indica cv. Neelum','Nilam','Late season variety (June–August); grown in Marathwada and Vidarbha; small-medium fruit, yellow skin.',unistr('Late season variety (June–August); grown in Marathwada and Vidarbha; small-medium fruit, yellow skin.\u000a\u000aScientific name: Mangifera indica cv. Neelum\u000a\u000aOrigin: Tamil Nadu/Maharashtra\u000a\u000aTaste profile: Sweet, mild, fibrous\u000a\u000aMarathi name: Nilam'),NULL);
INSERT INTO subtypes VALUES(10,1,'Amrapali','Maharashtra','Very sweet, deep red-orange flesh','Mangifera indica cv. Amrapali','Amrapali','Dwarf hybrid; suitable for high-density planting; grown in Nashik and Jalgaon.',unistr('Dwarf hybrid; suitable for high-density planting; grown in Nashik and Jalgaon.\u000a\u000aScientific name: Mangifera indica cv. Amrapali\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: Very sweet, deep red-orange flesh\u000a\u000aMarathi name: Amrapali'),NULL);
INSERT INTO subtypes VALUES(11,1,'Mallika','Maharashtra','Sweet, juicy, long shelf life','Mangifera indica cv. Mallika','Mallika','Neelum × Dasheri hybrid; regular bearer; wide adaptability; popular in export markets.',unistr('Neelum × Dasheri hybrid; regular bearer; wide adaptability; popular in export markets.\u000a\u000aScientific name: Mangifera indica cv. Mallika\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: Sweet, juicy, long shelf life\u000a\u000aMarathi name: Mallika'),NULL);
INSERT INTO subtypes VALUES(12,1,'Vanraj','Gujarat/Maharashtra','Sweet, mild, fibrous','Mangifera indica cv. Vanraj','Vanraj','Developed at NAU Gujarat; grown in Nashik, Dhule; tolerant to adverse conditions.',unistr('Developed at NAU Gujarat; grown in Nashik, Dhule; tolerant to adverse conditions.\u000a\u000aScientific name: Mangifera indica cv. Vanraj\u000a\u000aOrigin: Gujarat/Maharashtra\u000a\u000aTaste profile: Sweet, mild, fibrous\u000a\u000aMarathi name: Vanraj'),NULL);
INSERT INTO subtypes VALUES(13,2,'Thompson Seedless','Maharashtra','Sweet, mild, crisp, seedless','Vitis vinifera cv. Thompson Seedless','Thompson Seedless','Most widely grown table and raisin grape in Nashik, Sangli, Pune; green-gold colour; dominant export variety; also base for wine.',unistr('Most widely grown table and raisin grape in Nashik, Sangli, Pune; green-gold colour; dominant export variety; also base for wine.\u000a\u000aScientific name: Vitis vinifera cv. Thompson Seedless\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: Sweet, mild, crisp, seedless\u000a\u000aMarathi name: Thompson Seedless'),NULL);
INSERT INTO subtypes VALUES(14,2,'Tas-A-Ganesh','Maharashtra','Sweet, firm, large berries, seedless','Vitis vinifera cv. Tas-A-Ganesh','Tas-A-Ganesh','Early maturing mutation of Thompson; large elongated berries; popular in domestic and export market; Nashik and Sangli.',unistr('Early maturing mutation of Thompson; large elongated berries; popular in domestic and export market; Nashik and Sangli.\u000a\u000aScientific name: Vitis vinifera cv. Tas-A-Ganesh\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: Sweet, firm, large berries, seedless\u000a\u000aMarathi name: Tas-A-Ganesh'),NULL);
INSERT INTO subtypes VALUES(15,2,'Sonaka','Maharashtra','Sweet, firm, elongated, seedless','Vitis vinifera cv. Sonaka','Sonaka','Developed in Maharashtra; excellent export quality; long shelf life; grown in Nashik, Pune; superior post-harvest quality.',unistr('Developed in Maharashtra; excellent export quality; long shelf life; grown in Nashik, Pune; superior post-harvest quality.\u000a\u000aScientific name: Vitis vinifera cv. Sonaka\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: Sweet, firm, elongated, seedless\u000a\u000aMarathi name: Sonaka'),NULL);
INSERT INTO subtypes VALUES(16,2,'Sharad Seedless','Maharashtra','Sweet, crisp, medium size, seedless','Vitis vinifera cv. Sharad Seedless','Sharad Seedless','Late-maturing variety; Nashik; green-white berries; popular raisin grape.',unistr('Late-maturing variety; Nashik; green-white berries; popular raisin grape.\u000a\u000aScientific name: Vitis vinifera cv. Sharad Seedless\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: Sweet, crisp, medium size, seedless\u000a\u000aMarathi name: Sharad Seedless'),NULL);
INSERT INTO subtypes VALUES(17,2,'Flame Seedless','USA/Maharashtra','Sweet, slightly tart, red, seedless','Vitis vinifera cv. Flame Seedless','Flame Seedless','Red-berry seedless variety; grown in Nashik; attractive colour; export variety.',unistr('Red-berry seedless variety; grown in Nashik; attractive colour; export variety.\u000a\u000aScientific name: Vitis vinifera cv. Flame Seedless\u000a\u000aOrigin: USA/Maharashtra\u000a\u000aTaste profile: Sweet, slightly tart, red, seedless\u000a\u000aMarathi name: Flame Seedless'),NULL);
INSERT INTO subtypes VALUES(18,2,'Crimson Seedless','USA/Maharashtra','Sweet, firm, dark red, seedless','Vitis vinifera cv. Crimson Seedless','Crimson Seedless','Large red berries; late season; high sugar content; export quality; Nashik.',unistr('Large red berries; late season; high sugar content; export quality; Nashik.\u000a\u000aScientific name: Vitis vinifera cv. Crimson Seedless\u000a\u000aOrigin: USA/Maharashtra\u000a\u000aTaste profile: Sweet, firm, dark red, seedless\u000a\u000aMarathi name: Crimson Seedless'),NULL);
INSERT INTO subtypes VALUES(19,2,'Manik Chaman','Maharashtra','Sweet, large berries, red-black, seeded','Vitis vinifera cv. Manik Chaman','Manik Chaman','Also called Beauty Seedless; grown in Nashik, Sangli; large berries; domestic market.',unistr('Also called Beauty Seedless; grown in Nashik, Sangli; large berries; domestic market.\u000a\u000aScientific name: Vitis vinifera cv. Manik Chaman\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: Sweet, large berries, red-black, seeded\u000a\u000aMarathi name: Manik Chaman'),NULL);
INSERT INTO subtypes VALUES(20,3,'Nagpur Orange','Maharashtra','Sweet-tangy, juicy, aromatic, thin skin','Citrus reticulata cv. Nagpur Mandarin','Nagpur Santra','GI-tagged; grown in Nagpur, Amravati, Wardha; season Nov–Jan; star export variety; deep orange colour.',unistr('GI-tagged; grown in Nagpur, Amravati, Wardha; season Nov–Jan; star export variety; deep orange colour.\u000a\u000aScientific name: Citrus reticulata cv. Nagpur Mandarin\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: Sweet-tangy, juicy, aromatic, thin skin\u000a\u000aMarathi name: Nagpur Santra'),NULL);
INSERT INTO subtypes VALUES(21,3,'Valencia Orange','Maharashtra','Sweet, juicy, low seeds','Citrus sinensis cv. Valencia','Valencia Santra','Sweet orange type; grown in Marathwada; used for juice.',unistr('Sweet orange type; grown in Marathwada; used for juice.\u000a\u000aScientific name: Citrus sinensis cv. Valencia\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: Sweet, juicy, low seeds\u000a\u000aMarathi name: Valencia Santra'),NULL);
INSERT INTO subtypes VALUES(22,3,'Mosambi (Sweet Lime)','Maharashtra','Mildly sweet, low acid','Citrus limetta','Mosambi','Sweet lime; highly popular for juice; grown in Pune, Solapur, Aurangabad; year-round availability.',unistr('Sweet lime; highly popular for juice; grown in Pune, Solapur, Aurangabad; year-round availability.\u000a\u000aScientific name: Citrus limetta\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: Mildly sweet, low acid\u000a\u000aMarathi name: Mosambi'),NULL);
INSERT INTO subtypes VALUES(23,3,'Hamlin Orange','Maharashtra','Sweet, juicy, early season','Citrus sinensis cv. Hamlin','Hamlin Santra','Early-bearing sweet orange; Marathwada and Vidarbha.',unistr('Early-bearing sweet orange; Marathwada and Vidarbha.\u000a\u000aScientific name: Citrus sinensis cv. Hamlin\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: Sweet, juicy, early season\u000a\u000aMarathi name: Hamlin Santra'),NULL);
INSERT INTO subtypes VALUES(24,4,'Grand Naine','Maharashtra','Sweet, firm, long shelf life','Musa acuminata cv. Grand Naine','Grand Naine','Most commercially grown; Jalgaon, Nandurbar; GI-tagged Jalgaon banana; export quality; tall plant, medium bunch.',unistr('Most commercially grown; Jalgaon, Nandurbar; GI-tagged Jalgaon banana; export quality; tall plant, medium bunch.\u000a\u000aScientific name: Musa acuminata cv. Grand Naine\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: Sweet, firm, long shelf life\u000a\u000aMarathi name: Grand Naine'),NULL);
INSERT INTO subtypes VALUES(25,4,'Dwarf Cavendish','Maharashtra','Sweet, creamy, slightly tangy','Musa acuminata cv. Dwarf Cavendish','Dwarf Kela','Short statured; wind resistant; Jalgaon, Pune; widely used commercially and domestically.',unistr('Short statured; wind resistant; Jalgaon, Pune; widely used commercially and domestically.\u000a\u000aScientific name: Musa acuminata cv. Dwarf Cavendish\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: Sweet, creamy, slightly tangy\u000a\u000aMarathi name: Dwarf Kela'),NULL);
INSERT INTO subtypes VALUES(26,4,'Robusta','Maharashtra','Sweet, aromatic, medium-large fruit','Musa acuminata cv. Robusta','Robusta Kela','Taller than Dwarf Cavendish; widely grown in Maharashtra; good disease resistance.',unistr('Taller than Dwarf Cavendish; widely grown in Maharashtra; good disease resistance.\u000a\u000aScientific name: Musa acuminata cv. Robusta\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: Sweet, aromatic, medium-large fruit\u000a\u000aMarathi name: Robusta Kela'),NULL);
INSERT INTO subtypes VALUES(27,4,'Shrimanthi','Maharashtra','Very sweet, soft, small fruit','Musa acuminata cv. Shrimanthi','Shrimanthi','Local traditional variety from Konkan and Kolhapur; festival use; aromatic.',unistr('Local traditional variety from Konkan and Kolhapur; festival use; aromatic.\u000a\u000aScientific name: Musa acuminata cv. Shrimanthi\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: Very sweet, soft, small fruit\u000a\u000aMarathi name: Shrimanthi'),NULL);
INSERT INTO subtypes VALUES(28,4,'Basrai','Maharashtra','Sweet, aromatic, plump','Musa acuminata cv. Basrai','Basrai Kela','Traditional Jalgaon variety; basis of Jalgaon''s banana fame; good yield and flavour.',unistr('Traditional Jalgaon variety; basis of Jalgaon''s banana fame; good yield and flavour.\u000a\u000aScientific name: Musa acuminata cv. Basrai\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: Sweet, aromatic, plump\u000a\u000aMarathi name: Basrai Kela'),NULL);
INSERT INTO subtypes VALUES(29,5,'Allahabad Safeda','Uttar Pradesh/Maharashtra','Sweet, white pulp, mild flavour','Psidium guajava cv. Allahabad Safeda','Safeda Peru','Most popular commercial variety; grown across Maharashtra; white flesh; high yield; good shelf life.',unistr('Most popular commercial variety; grown across Maharashtra; white flesh; high yield; good shelf life.\u000a\u000aScientific name: Psidium guajava cv. Allahabad Safeda\u000a\u000aOrigin: Uttar Pradesh/Maharashtra\u000a\u000aTaste profile: Sweet, white pulp, mild flavour\u000a\u000aMarathi name: Safeda Peru'),NULL);
INSERT INTO subtypes VALUES(30,5,'Lalit','Maharashtra','Sweet, pink pulp, aromatic','Psidium guajava cv. Lalit','Lalit Peru','Developed at IARI; pink-fleshed; high Vitamin C; grown in Nashik, Pune.',unistr('Developed at IARI; pink-fleshed; high Vitamin C; grown in Nashik, Pune.\u000a\u000aScientific name: Psidium guajava cv. Lalit\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: Sweet, pink pulp, aromatic\u000a\u000aMarathi name: Lalit Peru'),NULL);
INSERT INTO subtypes VALUES(31,5,'Shweta','Maharashtra','Sweet, soft, white pulp','Psidium guajava cv. Shweta','Shweta Peru','High-yielding variety; good post-harvest quality; Nashik.',unistr('High-yielding variety; good post-harvest quality; Nashik.\u000a\u000aScientific name: Psidium guajava cv. Shweta\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: Sweet, soft, white pulp\u000a\u000aMarathi name: Shweta Peru'),NULL);
INSERT INTO subtypes VALUES(32,5,'Lucknow-49 (Sardar)','Uttar Pradesh/Maharashtra','Sweet, juicy, white-yellow pulp','Psidium guajava cv. L-49','Lucknow Peru','Very popular; round fruit; widely adapted; grown across Maharashtra.',unistr('Very popular; round fruit; widely adapted; grown across Maharashtra.\u000a\u000aScientific name: Psidium guajava cv. L-49\u000a\u000aOrigin: Uttar Pradesh/Maharashtra\u000a\u000aTaste profile: Sweet, juicy, white-yellow pulp\u000a\u000aMarathi name: Lucknow Peru'),NULL);
INSERT INTO subtypes VALUES(33,6,'Bhagwa','Maharashtra','Sweet, deep red arils, low seed hardness, juicy','Punica granatum cv. Bhagwa','Bhagwa Dalimb','GI-tagged; grown in Solapur, Sangli, Nashik, Pune; saffron-red thick skin; 65–70% aril weight; top export variety to Middle East, Europe.',unistr('GI-tagged; grown in Solapur, Sangli, Nashik, Pune; saffron-red thick skin; 65–70% aril weight; top export variety to Middle East, Europe.\u000a\u000aScientific name: Punica granatum cv. Bhagwa\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: Sweet, deep red arils, low seed hardness, juicy\u000a\u000aMarathi name: Bhagwa Dalimb'),NULL);
INSERT INTO subtypes VALUES(34,6,'Ganesh','Maharashtra','Sweet, mild, pink arils','Punica granatum cv. Ganesh','Ganesh Dalimb','Traditional variety; Pune and Nashik; large soft-seeded fruit; good for fresh market.',unistr('Traditional variety; Pune and Nashik; large soft-seeded fruit; good for fresh market.\u000a\u000aScientific name: Punica granatum cv. Ganesh\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: Sweet, mild, pink arils\u000a\u000aMarathi name: Ganesh Dalimb'),NULL);
INSERT INTO subtypes VALUES(35,6,'Mridula','Karnataka/Maharashtra','Very sweet, deep red, soft seeds','Punica granatum cv. Mridula','Mridula Dalimb','Deep red attractive arils; grown in Solapur and Osmanabad; early-bearing.',unistr('Deep red attractive arils; grown in Solapur and Osmanabad; early-bearing.\u000a\u000aScientific name: Punica granatum cv. Mridula\u000a\u000aOrigin: Karnataka/Maharashtra\u000a\u000aTaste profile: Very sweet, deep red, soft seeds\u000a\u000aMarathi name: Mridula Dalimb'),NULL);
INSERT INTO subtypes VALUES(36,6,'Arakta','Karnataka/Maharashtra','Sweet, deep red, attractive appearance','Punica granatum cv. Arakta','Arakta Dalimb','Large fruit; bright red skin; grown in Marathwada and Nashik; good export potential.',unistr('Large fruit; bright red skin; grown in Marathwada and Nashik; good export potential.\u000a\u000aScientific name: Punica granatum cv. Arakta\u000a\u000aOrigin: Karnataka/Maharashtra\u000a\u000aTaste profile: Sweet, deep red, attractive appearance\u000a\u000aMarathi name: Arakta Dalimb'),NULL);
INSERT INTO subtypes VALUES(37,7,'Balanagar','Telangana/Maharashtra','Sweet, creamy, white flesh, low seeds','Annona squamosa cv. Balanagar','Balanagar Sitafal','Most popular commercial variety in Maharashtra; Nashik, Aurangabad; large fruit; high pulp recovery.',unistr('Most popular commercial variety in Maharashtra; Nashik, Aurangabad; large fruit; high pulp recovery.\u000a\u000aScientific name: Annona squamosa cv. Balanagar\u000a\u000aOrigin: Telangana/Maharashtra\u000a\u000aTaste profile: Sweet, creamy, white flesh, low seeds\u000a\u000aMarathi name: Balanagar Sitafal'),NULL);
INSERT INTO subtypes VALUES(38,7,'Red Sitafal','Maharashtra','Very sweet, soft, aromatic, reddish skin','Annona reticulata','Lal Sitafal','Bullock''s heart variety; red skin; higher sweetness; Nashik and Marathwada.',unistr('Bullock''s heart variety; red skin; higher sweetness; Nashik and Marathwada.\u000a\u000aScientific name: Annona reticulata\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: Very sweet, soft, aromatic, reddish skin\u000a\u000aMarathi name: Lal Sitafal'),NULL);
INSERT INTO subtypes VALUES(39,8,'Red Lady','Taiwan/Maharashtra','Very sweet, red-orange flesh, firm','Carica papaya cv. Red Lady','Red Lady Papai','F1 hybrid; most popular commercial variety; Pune, Nashik; gynoecious; high yield; disease resistant.',unistr('F1 hybrid; most popular commercial variety; Pune, Nashik; gynoecious; high yield; disease resistant.\u000a\u000aScientific name: Carica papaya cv. Red Lady\u000a\u000aOrigin: Taiwan/Maharashtra\u000a\u000aTaste profile: Very sweet, red-orange flesh, firm\u000a\u000aMarathi name: Red Lady Papai'),NULL);
INSERT INTO subtypes VALUES(40,8,'Taiwan','Taiwan/Maharashtra','Sweet, orange flesh, medium size','Carica papaya cv. Taiwan 786','Taiwan Papai','Widely grown hybrid; dual purpose (fruit + raw); Jalgaon and Nashik; year-round production.',unistr('Widely grown hybrid; dual purpose (fruit + raw); Jalgaon and Nashik; year-round production.\u000a\u000aScientific name: Carica papaya cv. Taiwan 786\u000a\u000aOrigin: Taiwan/Maharashtra\u000a\u000aTaste profile: Sweet, orange flesh, medium size\u000a\u000aMarathi name: Taiwan Papai'),NULL);
