INSERT INTO subtypes VALUES(171,43,'Kasuri Methi (IARI-PEB)','India','Strongly aromatic, small leaf, dried use','Trigonella foenum-graecum cv. Kasuri','Kasuri Methi','Small-leafed aromatic variety; dried for culinary use; grown in Nashik and Pune; premium quality.',unistr('Small-leafed aromatic variety; dried for culinary use; grown in Nashik and Pune; premium quality.\u000a\u000aScientific name: Trigonella foenum-graecum cv. Kasuri\u000a\u000aOrigin: India\u000a\u000aTaste profile: Strongly aromatic, small leaf, dried use\u000a\u000aMarathi name: Kasuri Methi'),NULL);
INSERT INTO subtypes VALUES(172,43,'RMt-1 (Rajasthan)','Rajasthan/Maharashtra','Bitter seeds, good leaf yield','Trigonella foenum-graecum cv. RMt-1','RMt-1 Methi','Good seed yield; adapted to Maharashtra Rabi; Nashik, Aurangabad; used for seed and fresh leaf both.',unistr('Good seed yield; adapted to Maharashtra Rabi; Nashik, Aurangabad; used for seed and fresh leaf both.\u000a\u000aScientific name: Trigonella foenum-graecum cv. RMt-1\u000a\u000aOrigin: Rajasthan/Maharashtra\u000a\u000aTaste profile: Bitter seeds, good leaf yield\u000a\u000aMarathi name: RMt-1 Methi'),NULL);
INSERT INTO subtypes VALUES(173,44,'CO-1','Maharashtra','Aromatic, high leaf yield, fresh market','Coriandrum sativum cv. CO-1','CO-1 Kothimbir','Tall plant; high green leaf yield; Nashik, Pune, Satara; widely grown for leaf market; successive harvests.',unistr('Tall plant; high green leaf yield; Nashik, Pune, Satara; widely grown for leaf market; successive harvests.\u000a\u000aScientific name: Coriandrum sativum cv. CO-1\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: Aromatic, high leaf yield, fresh market\u000a\u000aMarathi name: CO-1 Kothimbir'),NULL);
INSERT INTO subtypes VALUES(174,44,'Phule Suvarna','Maharashtra','Good seed yield, aromatic, dual purpose','Coriandrum sativum cv. Phule Suvarna','Phule Suvarna Kothimbir','MPKV Rahuri; dual-purpose (leaf + seed); Nashik; Rabi; popular with cooperative farms.',unistr('MPKV Rahuri; dual-purpose (leaf + seed); Nashik; Rabi; popular with cooperative farms.\u000a\u000aScientific name: Coriandrum sativum cv. Phule Suvarna\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: Good seed yield, aromatic, dual purpose\u000a\u000aMarathi name: Phule Suvarna Kothimbir'),NULL);
INSERT INTO subtypes VALUES(175,44,'Rajendra Swati','Maharashtra','High seed yield, aromatic, good oil','Coriandrum sativum cv. Rajendra Swati','Rajendra Swati Kothimbir','RAU Bihar; adapted to Maharashtra; high dhania (seed) yield; Nashik, Aurangabad.',unistr('RAU Bihar; adapted to Maharashtra; high dhania (seed) yield; Nashik, Aurangabad.\u000a\u000aScientific name: Coriandrum sativum cv. Rajendra Swati\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: High seed yield, aromatic, good oil\u000a\u000aMarathi name: Rajendra Swati Kothimbir'),NULL);
INSERT INTO subtypes VALUES(176,45,'Sugar Baby','USA/Maharashtra','Very sweet (Brix 10–12), dark green, small round','Citrullus lanatus cv. Sugar Baby','Sugar Baby Kalingad','Most popular variety in Maharashtra; compact fruit; deep red flesh; sold widely in Nashik, Nashik, Solapur.',unistr('Most popular variety in Maharashtra; compact fruit; deep red flesh; sold widely in Nashik, Nashik, Solapur.\u000a\u000aScientific name: Citrullus lanatus cv. Sugar Baby\u000a\u000aOrigin: USA/Maharashtra\u000a\u000aTaste profile: Very sweet (Brix 10–12), dark green, small round\u000a\u000aMarathi name: Sugar Baby Kalingad'),NULL);
INSERT INTO subtypes VALUES(177,45,'Arka Manik','India (IIHR)','Sweet, firm red flesh, high yield','Citrullus lanatus cv. Arka Manik','Arka Manik Kalingad','IIHR Bengaluru; striped green fruit; high sugar; 5–8 kg fruit; Nashik, Aurangabad.',unistr('IIHR Bengaluru; striped green fruit; high sugar; 5–8 kg fruit; Nashik, Aurangabad.\u000a\u000aScientific name: Citrullus lanatus cv. Arka Manik\u000a\u000aOrigin: India (IIHR)\u000a\u000aTaste profile: Sweet, firm red flesh, high yield\u000a\u000aMarathi name: Arka Manik Kalingad'),NULL);
INSERT INTO subtypes VALUES(178,45,'Phule Indrayani (Seedless)','Maharashtra','Sweet, seedless, crisp','Citrullus lanatus cv. Phule Indrayani','Bijrahit Kalingad','MPKV Rahuri seedless hybrid; premium market; Nashik valley; polliniser plants required.',unistr('MPKV Rahuri seedless hybrid; premium market; Nashik valley; polliniser plants required.\u000a\u000aScientific name: Citrullus lanatus cv. Phule Indrayani\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: Sweet, seedless, crisp\u000a\u000aMarathi name: Bijrahit Kalingad'),NULL);
INSERT INTO subtypes VALUES(179,45,'NS-295 (Namdhari)','Maharashtra','Very sweet, oblong, striped, red flesh','Citrullus lanatus cv. NS-295','NS-295 Kalingad','Namdhari Seeds F1; very high yield; Nashik, Solapur; excellent transport quality; large 8–10 kg fruit.',unistr('Namdhari Seeds F1; very high yield; Nashik, Solapur; excellent transport quality; large 8–10 kg fruit.\u000a\u000aScientific name: Citrullus lanatus cv. NS-295\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: Very sweet, oblong, striped, red flesh\u000a\u000aMarathi name: NS-295 Kalingad'),NULL);
INSERT INTO subtypes VALUES(180,46,'Arka Rajhans','India (IIHR)','Very sweet, orange flesh, aromatic, netted skin','Cucumis melo cv. Arka Rajhans','Arka Rajhans Kharbuja','IIHR Bengaluru; popular in Maharashtra; cantaloupe type; netted rind; high Brix 12–14.',unistr('IIHR Bengaluru; popular in Maharashtra; cantaloupe type; netted rind; high Brix 12–14.\u000a\u000aScientific name: Cucumis melo cv. Arka Rajhans\u000a\u000aOrigin: India (IIHR)\u000a\u000aTaste profile: Very sweet, orange flesh, aromatic, netted skin\u000a\u000aMarathi name: Arka Rajhans Kharbuja'),NULL);
INSERT INTO subtypes VALUES(181,46,'Hara Madhu','India','Sweet, green flesh, smooth skin','Cucumis melo cv. Hara Madhu','Hara Madhu Kharbuja','Pale green smooth skin; classic Indian muskmelon; grown across Maharashtra; affordable and popular.',unistr('Pale green smooth skin; classic Indian muskmelon; grown across Maharashtra; affordable and popular.\u000a\u000aScientific name: Cucumis melo cv. Hara Madhu\u000a\u000aOrigin: India\u000a\u000aTaste profile: Sweet, green flesh, smooth skin\u000a\u000aMarathi name: Hara Madhu Kharbuja'),NULL);
INSERT INTO subtypes VALUES(182,46,'Phule Shreshtha','Maharashtra','Sweet, high yield, good keeping quality','Cucumis melo cv. Phule Shreshtha','Phule Shreshtha Kharbuja','MPKV Rahuri; recommended for Maharashtra summer; Nashik, Pune; medium-large fruit.',unistr('MPKV Rahuri; recommended for Maharashtra summer; Nashik, Pune; medium-large fruit.\u000a\u000aScientific name: Cucumis melo cv. Phule Shreshtha\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: Sweet, high yield, good keeping quality\u000a\u000aMarathi name: Phule Shreshtha Kharbuja'),NULL);
INSERT INTO subtypes VALUES(183,47,'Sai Sharbati','Maharashtra','Acidic, juicy, thin-skinned, aromatic','Citrus limon cv. Sai Sharbati','Sai Sharbati Limbu','Popular commercial variety in Maharashtra; Nashik, Pune; high juice content; year-round fruiting.',unistr('Popular commercial variety in Maharashtra; Nashik, Pune; high juice content; year-round fruiting.\u000a\u000aScientific name: Citrus limon cv. Sai Sharbati\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: Acidic, juicy, thin-skinned, aromatic\u000a\u000aMarathi name: Sai Sharbati Limbu'),NULL);
INSERT INTO subtypes VALUES(184,47,'Phule Saurabh','Maharashtra','Acidic, aromatic, high juice, soft rind','Citrus limon cv. Phule Saurabh','Phule Saurabh Limbu','MPKV Rahuri; improved lemon variety; suitable for drip-irrigated orchards; Nashik, Aurangabad.',unistr('MPKV Rahuri; improved lemon variety; suitable for drip-irrigated orchards; Nashik, Aurangabad.\u000a\u000aScientific name: Citrus limon cv. Phule Saurabh\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: Acidic, aromatic, high juice, soft rind\u000a\u000aMarathi name: Phule Saurabh Limbu'),NULL);
INSERT INTO subtypes VALUES(185,47,'Seedless Lime','Maharashtra','Acidic, thin-skinned, nearly seedless','Citrus aurantiifolia (seedless type)','Bijrahit Limbu','Acid lime type; Konkan and Pune; very popular for household use and street food vendors.',unistr('Acid lime type; Konkan and Pune; very popular for household use and street food vendors.\u000a\u000aScientific name: Citrus aurantiifolia (seedless type)\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: Acidic, thin-skinned, nearly seedless\u000a\u000aMarathi name: Bijrahit Limbu'),NULL);
INSERT INTO subtypes VALUES(186,47,'Eureka Lemon','USA/Maharashtra','Strongly acidic, aromatic, thick-skinned','Citrus limon cv. Eureka','Eureka Limbu','Introduced variety; grown in Nashik and Pune; export-quality large lemon; increasing adoption.',unistr('Introduced variety; grown in Nashik and Pune; export-quality large lemon; increasing adoption.\u000a\u000aScientific name: Citrus limon cv. Eureka\u000a\u000aOrigin: USA/Maharashtra\u000a\u000aTaste profile: Strongly acidic, aromatic, thick-skinned\u000a\u000aMarathi name: Eureka Limbu'),NULL);
INSERT INTO subtype_translations VALUES(1,'hi','Alphonso (Hapus)','Maharashtra','Sweet, aromatic, rich saffron flavour, low fibre','Alphonso (Hapus) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Alphonso (Hapus) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Mangifera indica cv. Alphonso\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, aromatic, rich saffron flavour, low fibre\u000a\u000aमराठी नाम: Hapus\u000a\u000aमूल डेटासेट विवरण: GI-tagged variety from Ratnagiri & Sindhudurg; considered the king of mangoes; peak season April–May; ideal for pulp and fresh consumption.'));
INSERT INTO subtype_translations VALUES(1,'mr','Hapus','Maharashtra','Sweet, aromatic, rich saffron flavour, low fibre','Hapus ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Hapus ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Mangifera indica cv. Alphonso\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, aromatic, rich saffron flavour, low fibre\u000a\u000aमराठी नाव: Hapus\u000a\u000aमूळ डेटासेट तपशील: GI-tagged variety from Ratnagiri & Sindhudurg; considered the king of mangoes; peak season April–May; ideal for pulp and fresh consumption.'));
INSERT INTO subtype_translations VALUES(2,'hi','Kesar','Gujarat/Maharashtra','Sweet, less fibrous, deep orange pulp','Kesar इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Kesar इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Mangifera indica cv. Kesar\u000a\u000aउत्पत्ति क्षेत्र: Gujarat/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, less fibrous, deep orange pulp\u000a\u000aमराठी नाम: Kesar\u000a\u000aमूल डेटासेट विवरण: Grown in Aurangabad and Marathwada; second most exported variety; saffron-coloured pulp; season May–June.'));
INSERT INTO subtype_translations VALUES(2,'mr','Kesar','Gujarat/Maharashtra','Sweet, less fibrous, deep orange pulp','Kesar ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Kesar ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Mangifera indica cv. Kesar\u000a\u000aउत्पत्ती क्षेत्र: Gujarat/Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, less fibrous, deep orange pulp\u000a\u000aमराठी नाव: Kesar\u000a\u000aमूळ डेटासेट तपशील: Grown in Aurangabad and Marathwada; second most exported variety; saffron-coloured pulp; season May–June.'));
INSERT INTO subtype_translations VALUES(3,'hi','Langra','Uttar Pradesh/Maharashtra','Sweet-sour, green skin, rich flavour','Langra इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Langra इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Mangifera indica cv. Langra\u000a\u000aउत्पत्ति क्षेत्र: Uttar Pradesh/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet-sour, green skin, rich flavour\u000a\u000aमराठी नाम: Langra\u000a\u000aमूल डेटासेट विवरण: Grown in Nashik and Pune regions; medium-large fruit; greenish skin even when ripe.'));
INSERT INTO subtype_translations VALUES(3,'mr','Langra','Uttar Pradesh/Maharashtra','Sweet-sour, green skin, rich flavour','Langra ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Langra ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Mangifera indica cv. Langra\u000a\u000aउत्पत्ती क्षेत्र: Uttar Pradesh/Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet-sour, green skin, rich flavour\u000a\u000aमराठी नाव: Langra\u000a\u000aमूळ डेटासेट तपशील: Grown in Nashik and Pune regions; medium-large fruit; greenish skin even when ripe.'));
INSERT INTO subtype_translations VALUES(4,'hi','Dasheri','Uttar Pradesh/Maharashtra','Sweet, fibrous, aromatic','Dasheri इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Dasheri इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Mangifera indica cv. Dasheri\u000a\u000aउत्पत्ति क्षेत्र: Uttar Pradesh/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, fibrous, aromatic\u000a\u000aमराठी नाम: Dasheri\u000a\u000aमूल डेटासेट विवरण: Long fruit with thin skin; grown in Vidarbha; season June–July.'));
INSERT INTO subtype_translations VALUES(4,'mr','Dasheri','Uttar Pradesh/Maharashtra','Sweet, fibrous, aromatic','Dasheri ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Dasheri ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Mangifera indica cv. Dasheri\u000a\u000aउत्पत्ती क्षेत्र: Uttar Pradesh/Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, fibrous, aromatic\u000a\u000aमराठी नाव: Dasheri\u000a\u000aमूळ डेटासेट तपशील: Long fruit with thin skin; grown in Vidarbha; season June–July.'));
INSERT INTO subtype_translations VALUES(5,'hi','Totapuri','South India/Maharashtra','Mildly sweet, tangy, firm, low fibre','Totapuri इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Totapuri इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Mangifera indica cv. Totapuri\u000a\u000aउत्पत्ति क्षेत्र: South India/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Mildly sweet, tangy, firm, low fibre\u000a\u000aमराठी नाम: Totapuri\u000a\u000aमूल डेटासेट विवरण: Large, elongated beak-shaped fruit; widely processed into mango pulp and pickle; grown in Solapur and Osmanabad.'));
INSERT INTO subtype_translations VALUES(5,'mr','Totapuri','South India/Maharashtra','Mildly sweet, tangy, firm, low fibre','Totapuri ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Totapuri ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Mangifera indica cv. Totapuri\u000a\u000aउत्पत्ती क्षेत्र: South India/Maharashtra\u000a\u000aचव वैशिष्ट्य: Mildly sweet, tangy, firm, low fibre\u000a\u000aमराठी नाव: Totapuri\u000a\u000aमूळ डेटासेट तपशील: Large, elongated beak-shaped fruit; widely processed into mango pulp and pickle; grown in Solapur and Osmanabad.'));
INSERT INTO subtype_translations VALUES(6,'hi','Pairi','Maharashtra','Sweet, juicy, mild sour notes','Pairi इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Pairi इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Mangifera indica cv. Pairi\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, juicy, mild sour notes\u000a\u000aमराठी नाम: Pairi\u000a\u000aमूल डेटासेट विवरण: Early season variety from Konkan; oval fruit; eaten fresh; also called Pyari.'));
INSERT INTO subtype_translations VALUES(6,'mr','Pairi','Maharashtra','Sweet, juicy, mild sour notes','Pairi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Pairi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Mangifera indica cv. Pairi\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, juicy, mild sour notes\u000a\u000aमराठी नाव: Pairi\u000a\u000aमूळ डेटासेट तपशील: Early season variety from Konkan; oval fruit; eaten fresh; also called Pyari.'));
INSERT INTO subtype_translations VALUES(7,'hi','Ratna','Maharashtra','Very sweet, aromatic, less fibrous','Ratna इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Ratna इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Mangifera indica cv. Ratna\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very sweet, aromatic, less fibrous\u000a\u000aमराठी नाम: Ratna\u000a\u000aमूल डेटासेट विवरण: Hybrid developed at Dr BSKKV Dapoli; Alphonso × Neelum cross; regular bearer; popular in Konkan.'));
INSERT INTO subtype_translations VALUES(7,'mr','Ratna','Maharashtra','Very sweet, aromatic, less fibrous','Ratna ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Ratna ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Mangifera indica cv. Ratna\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Very sweet, aromatic, less fibrous\u000a\u000aमराठी नाव: Ratna\u000a\u000aमूळ डेटासेट तपशील: Hybrid developed at Dr BSKKV Dapoli; Alphonso × Neelum cross; regular bearer; popular in Konkan.'));
INSERT INTO subtype_translations VALUES(8,'hi','Sindhu','Maharashtra','Sweet, aromatic, low fibre, long shelf life','Sindhu इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Sindhu इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Mangifera indica cv. Sindhu\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, aromatic, low fibre, long shelf life\u000a\u000aमराठी नाम: Sindhu\u000a\u000aमूल डेटासेट विवरण: Hybrid (Ratna × Alphonso) developed at Vengurle; excellent export quality; shelf life 10–12 days.'));
INSERT INTO subtype_translations VALUES(8,'mr','Sindhu','Maharashtra','Sweet, aromatic, low fibre, long shelf life','Sindhu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Sindhu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Mangifera indica cv. Sindhu\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, aromatic, low fibre, long shelf life\u000a\u000aमराठी नाव: Sindhu\u000a\u000aमूळ डेटासेट तपशील: Hybrid (Ratna × Alphonso) developed at Vengurle; excellent export quality; shelf life 10–12 days.'));
INSERT INTO subtype_translations VALUES(9,'hi','Neelum','Tamil Nadu/Maharashtra','Sweet, mild, fibrous','Neelum इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Neelum इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Mangifera indica cv. Neelum\u000a\u000aउत्पत्ति क्षेत्र: Tamil Nadu/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, mild, fibrous\u000a\u000aमराठी नाम: Nilam\u000a\u000aमूल डेटासेट विवरण: Late season variety (June–August); grown in Marathwada and Vidarbha; small-medium fruit, yellow skin.'));
INSERT INTO subtype_translations VALUES(9,'mr','Nilam','Tamil Nadu/Maharashtra','Sweet, mild, fibrous','Nilam ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Nilam ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Mangifera indica cv. Neelum\u000a\u000aउत्पत्ती क्षेत्र: Tamil Nadu/Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, mild, fibrous\u000a\u000aमराठी नाव: Nilam\u000a\u000aमूळ डेटासेट तपशील: Late season variety (June–August); grown in Marathwada and Vidarbha; small-medium fruit, yellow skin.'));
INSERT INTO subtype_translations VALUES(10,'hi','Amrapali','Maharashtra','Very sweet, deep red-orange flesh','Amrapali इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Amrapali इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Mangifera indica cv. Amrapali\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very sweet, deep red-orange flesh\u000a\u000aमराठी नाम: Amrapali\u000a\u000aमूल डेटासेट विवरण: Dwarf hybrid; suitable for high-density planting; grown in Nashik and Jalgaon.'));
INSERT INTO subtype_translations VALUES(10,'mr','Amrapali','Maharashtra','Very sweet, deep red-orange flesh','Amrapali ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Amrapali ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Mangifera indica cv. Amrapali\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Very sweet, deep red-orange flesh\u000a\u000aमराठी नाव: Amrapali\u000a\u000aमूळ डेटासेट तपशील: Dwarf hybrid; suitable for high-density planting; grown in Nashik and Jalgaon.'));
INSERT INTO subtype_translations VALUES(11,'hi','Mallika','Maharashtra','Sweet, juicy, long shelf life','Mallika इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Mallika इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Mangifera indica cv. Mallika\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, juicy, long shelf life\u000a\u000aमराठी नाम: Mallika\u000a\u000aमूल डेटासेट विवरण: Neelum × Dasheri hybrid; regular bearer; wide adaptability; popular in export markets.'));
INSERT INTO subtype_translations VALUES(11,'mr','Mallika','Maharashtra','Sweet, juicy, long shelf life','Mallika ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Mallika ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Mangifera indica cv. Mallika\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, juicy, long shelf life\u000a\u000aमराठी नाव: Mallika\u000a\u000aमूळ डेटासेट तपशील: Neelum × Dasheri hybrid; regular bearer; wide adaptability; popular in export markets.'));
INSERT INTO subtype_translations VALUES(12,'hi','Vanraj','Gujarat/Maharashtra','Sweet, mild, fibrous','Vanraj इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Vanraj इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Mangifera indica cv. Vanraj\u000a\u000aउत्पत्ति क्षेत्र: Gujarat/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, mild, fibrous\u000a\u000aमराठी नाम: Vanraj\u000a\u000aमूल डेटासेट विवरण: Developed at NAU Gujarat; grown in Nashik, Dhule; tolerant to adverse conditions.'));
INSERT INTO subtype_translations VALUES(12,'mr','Vanraj','Gujarat/Maharashtra','Sweet, mild, fibrous','Vanraj ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Vanraj ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Mangifera indica cv. Vanraj\u000a\u000aउत्पत्ती क्षेत्र: Gujarat/Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, mild, fibrous\u000a\u000aमराठी नाव: Vanraj\u000a\u000aमूळ डेटासेट तपशील: Developed at NAU Gujarat; grown in Nashik, Dhule; tolerant to adverse conditions.'));
INSERT INTO subtype_translations VALUES(13,'hi','Thompson Seedless','Maharashtra','Sweet, mild, crisp, seedless','Thompson Seedless इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Thompson Seedless इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Vitis vinifera cv. Thompson Seedless\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, mild, crisp, seedless\u000a\u000aमराठी नाम: Thompson Seedless\u000a\u000aमूल डेटासेट विवरण: Most widely grown table and raisin grape in Nashik, Sangli, Pune; green-gold colour; dominant export variety; also base for wine.'));
INSERT INTO subtype_translations VALUES(13,'mr','Thompson Seedless','Maharashtra','Sweet, mild, crisp, seedless','Thompson Seedless ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Thompson Seedless ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Vitis vinifera cv. Thompson Seedless\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, mild, crisp, seedless\u000a\u000aमराठी नाव: Thompson Seedless\u000a\u000aमूळ डेटासेट तपशील: Most widely grown table and raisin grape in Nashik, Sangli, Pune; green-gold colour; dominant export variety; also base for wine.'));
INSERT INTO subtype_translations VALUES(14,'hi','Tas-A-Ganesh','Maharashtra','Sweet, firm, large berries, seedless','Tas-A-Ganesh इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Tas-A-Ganesh इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Vitis vinifera cv. Tas-A-Ganesh\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, firm, large berries, seedless\u000a\u000aमराठी नाम: Tas-A-Ganesh\u000a\u000aमूल डेटासेट विवरण: Early maturing mutation of Thompson; large elongated berries; popular in domestic and export market; Nashik and Sangli.'));
INSERT INTO subtype_translations VALUES(14,'mr','Tas-A-Ganesh','Maharashtra','Sweet, firm, large berries, seedless','Tas-A-Ganesh ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Tas-A-Ganesh ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Vitis vinifera cv. Tas-A-Ganesh\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, firm, large berries, seedless\u000a\u000aमराठी नाव: Tas-A-Ganesh\u000a\u000aमूळ डेटासेट तपशील: Early maturing mutation of Thompson; large elongated berries; popular in domestic and export market; Nashik and Sangli.'));
INSERT INTO subtype_translations VALUES(15,'hi','Sonaka','Maharashtra','Sweet, firm, elongated, seedless','Sonaka इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Sonaka इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Vitis vinifera cv. Sonaka\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, firm, elongated, seedless\u000a\u000aमराठी नाम: Sonaka\u000a\u000aमूल डेटासेट विवरण: Developed in Maharashtra; excellent export quality; long shelf life; grown in Nashik, Pune; superior post-harvest quality.'));
INSERT INTO subtype_translations VALUES(15,'mr','Sonaka','Maharashtra','Sweet, firm, elongated, seedless','Sonaka ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Sonaka ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Vitis vinifera cv. Sonaka\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, firm, elongated, seedless\u000a\u000aमराठी नाव: Sonaka\u000a\u000aमूळ डेटासेट तपशील: Developed in Maharashtra; excellent export quality; long shelf life; grown in Nashik, Pune; superior post-harvest quality.'));
INSERT INTO subtype_translations VALUES(16,'hi','Sharad Seedless','Maharashtra','Sweet, crisp, medium size, seedless','Sharad Seedless इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Sharad Seedless इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Vitis vinifera cv. Sharad Seedless\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, crisp, medium size, seedless\u000a\u000aमराठी नाम: Sharad Seedless\u000a\u000aमूल डेटासेट विवरण: Late-maturing variety; Nashik; green-white berries; popular raisin grape.'));
INSERT INTO subtype_translations VALUES(16,'mr','Sharad Seedless','Maharashtra','Sweet, crisp, medium size, seedless','Sharad Seedless ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Sharad Seedless ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Vitis vinifera cv. Sharad Seedless\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, crisp, medium size, seedless\u000a\u000aमराठी नाव: Sharad Seedless\u000a\u000aमूळ डेटासेट तपशील: Late-maturing variety; Nashik; green-white berries; popular raisin grape.'));
INSERT INTO subtype_translations VALUES(17,'hi','Flame Seedless','USA/Maharashtra','Sweet, slightly tart, red, seedless','Flame Seedless इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Flame Seedless इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Vitis vinifera cv. Flame Seedless\u000a\u000aउत्पत्ति क्षेत्र: USA/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, slightly tart, red, seedless\u000a\u000aमराठी नाम: Flame Seedless\u000a\u000aमूल डेटासेट विवरण: Red-berry seedless variety; grown in Nashik; attractive colour; export variety.'));
