INSERT INTO subtype_translations VALUES(18,'mr','Crimson Seedless','USA/Maharashtra','Sweet, firm, dark red, seedless','Crimson Seedless ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Crimson Seedless ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Vitis vinifera cv. Crimson Seedless\u000a\u000aउत्पत्ती क्षेत्र: USA/Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, firm, dark red, seedless\u000a\u000aमराठी नाव: Crimson Seedless\u000a\u000aमूळ डेटासेट तपशील: Large red berries; late season; high sugar content; export quality; Nashik.'));
INSERT INTO subtype_translations VALUES(19,'hi','Manik Chaman','Maharashtra','Sweet, large berries, red-black, seeded','Manik Chaman इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Manik Chaman इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Vitis vinifera cv. Manik Chaman\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, large berries, red-black, seeded\u000a\u000aमराठी नाम: Manik Chaman\u000a\u000aमूल डेटासेट विवरण: Also called Beauty Seedless; grown in Nashik, Sangli; large berries; domestic market.'));
INSERT INTO subtype_translations VALUES(19,'mr','Manik Chaman','Maharashtra','Sweet, large berries, red-black, seeded','Manik Chaman ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Manik Chaman ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Vitis vinifera cv. Manik Chaman\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, large berries, red-black, seeded\u000a\u000aमराठी नाव: Manik Chaman\u000a\u000aमूळ डेटासेट तपशील: Also called Beauty Seedless; grown in Nashik, Sangli; large berries; domestic market.'));
INSERT INTO subtype_translations VALUES(20,'hi','Nagpur Orange','Maharashtra','Sweet-tangy, juicy, aromatic, thin skin','Nagpur Orange इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Nagpur Orange इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrus reticulata cv. Nagpur Mandarin\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet-tangy, juicy, aromatic, thin skin\u000a\u000aमराठी नाम: Nagpur Santra\u000a\u000aमूल डेटासेट विवरण: GI-tagged; grown in Nagpur, Amravati, Wardha; season Nov–Jan; star export variety; deep orange colour.'));
INSERT INTO subtype_translations VALUES(20,'mr','Nagpur Santra','Maharashtra','Sweet-tangy, juicy, aromatic, thin skin','Nagpur Santra ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Nagpur Santra ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrus reticulata cv. Nagpur Mandarin\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet-tangy, juicy, aromatic, thin skin\u000a\u000aमराठी नाव: Nagpur Santra\u000a\u000aमूळ डेटासेट तपशील: GI-tagged; grown in Nagpur, Amravati, Wardha; season Nov–Jan; star export variety; deep orange colour.'));
INSERT INTO subtype_translations VALUES(21,'hi','Valencia Orange','Maharashtra','Sweet, juicy, low seeds','Valencia Orange इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Valencia Orange इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrus sinensis cv. Valencia\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, juicy, low seeds\u000a\u000aमराठी नाम: Valencia Santra\u000a\u000aमूल डेटासेट विवरण: Sweet orange type; grown in Marathwada; used for juice.'));
INSERT INTO subtype_translations VALUES(21,'mr','Valencia Santra','Maharashtra','Sweet, juicy, low seeds','Valencia Santra ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Valencia Santra ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrus sinensis cv. Valencia\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, juicy, low seeds\u000a\u000aमराठी नाव: Valencia Santra\u000a\u000aमूळ डेटासेट तपशील: Sweet orange type; grown in Marathwada; used for juice.'));
INSERT INTO subtype_translations VALUES(22,'hi','Mosambi (Sweet Lime)','Maharashtra','Mildly sweet, low acid','Mosambi (Sweet Lime) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Mosambi (Sweet Lime) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrus limetta\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Mildly sweet, low acid\u000a\u000aमराठी नाम: Mosambi\u000a\u000aमूल डेटासेट विवरण: Sweet lime; highly popular for juice; grown in Pune, Solapur, Aurangabad; year-round availability.'));
INSERT INTO subtype_translations VALUES(22,'mr','Mosambi','Maharashtra','Mildly sweet, low acid','Mosambi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Mosambi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrus limetta\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Mildly sweet, low acid\u000a\u000aमराठी नाव: Mosambi\u000a\u000aमूळ डेटासेट तपशील: Sweet lime; highly popular for juice; grown in Pune, Solapur, Aurangabad; year-round availability.'));
INSERT INTO subtype_translations VALUES(23,'hi','Hamlin Orange','Maharashtra','Sweet, juicy, early season','Hamlin Orange इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Hamlin Orange इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrus sinensis cv. Hamlin\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, juicy, early season\u000a\u000aमराठी नाम: Hamlin Santra\u000a\u000aमूल डेटासेट विवरण: Early-bearing sweet orange; Marathwada and Vidarbha.'));
INSERT INTO subtype_translations VALUES(23,'mr','Hamlin Santra','Maharashtra','Sweet, juicy, early season','Hamlin Santra ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Hamlin Santra ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrus sinensis cv. Hamlin\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, juicy, early season\u000a\u000aमराठी नाव: Hamlin Santra\u000a\u000aमूळ डेटासेट तपशील: Early-bearing sweet orange; Marathwada and Vidarbha.'));
INSERT INTO subtype_translations VALUES(24,'hi','Grand Naine','Maharashtra','Sweet, firm, long shelf life','Grand Naine इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Grand Naine इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Musa acuminata cv. Grand Naine\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, firm, long shelf life\u000a\u000aमराठी नाम: Grand Naine\u000a\u000aमूल डेटासेट विवरण: Most commercially grown; Jalgaon, Nandurbar; GI-tagged Jalgaon banana; export quality; tall plant, medium bunch.'));
INSERT INTO subtype_translations VALUES(24,'mr','Grand Naine','Maharashtra','Sweet, firm, long shelf life','Grand Naine ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Grand Naine ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Musa acuminata cv. Grand Naine\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, firm, long shelf life\u000a\u000aमराठी नाव: Grand Naine\u000a\u000aमूळ डेटासेट तपशील: Most commercially grown; Jalgaon, Nandurbar; GI-tagged Jalgaon banana; export quality; tall plant, medium bunch.'));
INSERT INTO subtype_translations VALUES(25,'hi','Dwarf Cavendish','Maharashtra','Sweet, creamy, slightly tangy','Dwarf Cavendish इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Dwarf Cavendish इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Musa acuminata cv. Dwarf Cavendish\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, creamy, slightly tangy\u000a\u000aमराठी नाम: Dwarf Kela\u000a\u000aमूल डेटासेट विवरण: Short statured; wind resistant; Jalgaon, Pune; widely used commercially and domestically.'));
INSERT INTO subtype_translations VALUES(25,'mr','Dwarf Kela','Maharashtra','Sweet, creamy, slightly tangy','Dwarf Kela ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Dwarf Kela ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Musa acuminata cv. Dwarf Cavendish\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, creamy, slightly tangy\u000a\u000aमराठी नाव: Dwarf Kela\u000a\u000aमूळ डेटासेट तपशील: Short statured; wind resistant; Jalgaon, Pune; widely used commercially and domestically.'));
INSERT INTO subtype_translations VALUES(26,'hi','Robusta','Maharashtra','Sweet, aromatic, medium-large fruit','Robusta इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Robusta इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Musa acuminata cv. Robusta\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, aromatic, medium-large fruit\u000a\u000aमराठी नाम: Robusta Kela\u000a\u000aमूल डेटासेट विवरण: Taller than Dwarf Cavendish; widely grown in Maharashtra; good disease resistance.'));
INSERT INTO subtype_translations VALUES(26,'mr','Robusta Kela','Maharashtra','Sweet, aromatic, medium-large fruit','Robusta Kela ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Robusta Kela ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Musa acuminata cv. Robusta\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, aromatic, medium-large fruit\u000a\u000aमराठी नाव: Robusta Kela\u000a\u000aमूळ डेटासेट तपशील: Taller than Dwarf Cavendish; widely grown in Maharashtra; good disease resistance.'));
INSERT INTO subtype_translations VALUES(27,'hi','Shrimanthi','Maharashtra','Very sweet, soft, small fruit','Shrimanthi इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Shrimanthi इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Musa acuminata cv. Shrimanthi\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very sweet, soft, small fruit\u000a\u000aमराठी नाम: Shrimanthi\u000a\u000aमूल डेटासेट विवरण: Local traditional variety from Konkan and Kolhapur; festival use; aromatic.'));
INSERT INTO subtype_translations VALUES(27,'mr','Shrimanthi','Maharashtra','Very sweet, soft, small fruit','Shrimanthi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Shrimanthi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Musa acuminata cv. Shrimanthi\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Very sweet, soft, small fruit\u000a\u000aमराठी नाव: Shrimanthi\u000a\u000aमूळ डेटासेट तपशील: Local traditional variety from Konkan and Kolhapur; festival use; aromatic.'));
INSERT INTO subtype_translations VALUES(28,'hi','Basrai','Maharashtra','Sweet, aromatic, plump','Basrai इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Basrai इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Musa acuminata cv. Basrai\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, aromatic, plump\u000a\u000aमराठी नाम: Basrai Kela\u000a\u000aमूल डेटासेट विवरण: Traditional Jalgaon variety; basis of Jalgaon''s banana fame; good yield and flavour.'));
INSERT INTO subtype_translations VALUES(28,'mr','Basrai Kela','Maharashtra','Sweet, aromatic, plump','Basrai Kela ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Basrai Kela ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Musa acuminata cv. Basrai\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, aromatic, plump\u000a\u000aमराठी नाव: Basrai Kela\u000a\u000aमूळ डेटासेट तपशील: Traditional Jalgaon variety; basis of Jalgaon''s banana fame; good yield and flavour.'));
INSERT INTO subtype_translations VALUES(29,'hi','Allahabad Safeda','Uttar Pradesh/Maharashtra','Sweet, white pulp, mild flavour','Allahabad Safeda इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Allahabad Safeda इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Psidium guajava cv. Allahabad Safeda\u000a\u000aउत्पत्ति क्षेत्र: Uttar Pradesh/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, white pulp, mild flavour\u000a\u000aमराठी नाम: Safeda Peru\u000a\u000aमूल डेटासेट विवरण: Most popular commercial variety; grown across Maharashtra; white flesh; high yield; good shelf life.'));
INSERT INTO subtype_translations VALUES(29,'mr','Safeda Peru','Uttar Pradesh/Maharashtra','Sweet, white pulp, mild flavour','Safeda Peru ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Safeda Peru ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Psidium guajava cv. Allahabad Safeda\u000a\u000aउत्पत्ती क्षेत्र: Uttar Pradesh/Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, white pulp, mild flavour\u000a\u000aमराठी नाव: Safeda Peru\u000a\u000aमूळ डेटासेट तपशील: Most popular commercial variety; grown across Maharashtra; white flesh; high yield; good shelf life.'));
INSERT INTO subtype_translations VALUES(30,'hi','Lalit','Maharashtra','Sweet, pink pulp, aromatic','Lalit इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Lalit इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Psidium guajava cv. Lalit\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, pink pulp, aromatic\u000a\u000aमराठी नाम: Lalit Peru\u000a\u000aमूल डेटासेट विवरण: Developed at IARI; pink-fleshed; high Vitamin C; grown in Nashik, Pune.'));
