INSERT INTO subtype_translations VALUES(31,'hi','Shweta','Maharashtra','Sweet, soft, white pulp','Shweta इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Shweta इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Psidium guajava cv. Shweta\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, soft, white pulp\u000a\u000aमराठी नाम: Shweta Peru\u000a\u000aमूल डेटासेट विवरण: High-yielding variety; good post-harvest quality; Nashik.'));
INSERT INTO subtype_translations VALUES(31,'mr','Shweta Peru','Maharashtra','Sweet, soft, white pulp','Shweta Peru ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Shweta Peru ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Psidium guajava cv. Shweta\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, soft, white pulp\u000a\u000aमराठी नाव: Shweta Peru\u000a\u000aमूळ डेटासेट तपशील: High-yielding variety; good post-harvest quality; Nashik.'));
INSERT INTO subtype_translations VALUES(32,'hi','Lucknow-49 (Sardar)','Uttar Pradesh/Maharashtra','Sweet, juicy, white-yellow pulp','Lucknow-49 (Sardar) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Lucknow-49 (Sardar) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Psidium guajava cv. L-49\u000a\u000aउत्पत्ति क्षेत्र: Uttar Pradesh/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, juicy, white-yellow pulp\u000a\u000aमराठी नाम: Lucknow Peru\u000a\u000aमूल डेटासेट विवरण: Very popular; round fruit; widely adapted; grown across Maharashtra.'));
INSERT INTO subtype_translations VALUES(32,'mr','Lucknow Peru','Uttar Pradesh/Maharashtra','Sweet, juicy, white-yellow pulp','Lucknow Peru ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Lucknow Peru ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Psidium guajava cv. L-49\u000a\u000aउत्पत्ती क्षेत्र: Uttar Pradesh/Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, juicy, white-yellow pulp\u000a\u000aमराठी नाव: Lucknow Peru\u000a\u000aमूळ डेटासेट तपशील: Very popular; round fruit; widely adapted; grown across Maharashtra.'));
INSERT INTO subtype_translations VALUES(33,'hi','Bhagwa','Maharashtra','Sweet, deep red arils, low seed hardness, juicy','Bhagwa इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Bhagwa इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Punica granatum cv. Bhagwa\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, deep red arils, low seed hardness, juicy\u000a\u000aमराठी नाम: Bhagwa Dalimb\u000a\u000aमूल डेटासेट विवरण: GI-tagged; grown in Solapur, Sangli, Nashik, Pune; saffron-red thick skin; 65–70% aril weight; top export variety to Middle East, Europe.'));
INSERT INTO subtype_translations VALUES(33,'mr','Bhagwa Dalimb','Maharashtra','Sweet, deep red arils, low seed hardness, juicy','Bhagwa Dalimb ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Bhagwa Dalimb ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Punica granatum cv. Bhagwa\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, deep red arils, low seed hardness, juicy\u000a\u000aमराठी नाव: Bhagwa Dalimb\u000a\u000aमूळ डेटासेट तपशील: GI-tagged; grown in Solapur, Sangli, Nashik, Pune; saffron-red thick skin; 65–70% aril weight; top export variety to Middle East, Europe.'));
INSERT INTO subtype_translations VALUES(34,'hi','Ganesh','Maharashtra','Sweet, mild, pink arils','Ganesh इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Ganesh इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Punica granatum cv. Ganesh\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, mild, pink arils\u000a\u000aमराठी नाम: Ganesh Dalimb\u000a\u000aमूल डेटासेट विवरण: Traditional variety; Pune and Nashik; large soft-seeded fruit; good for fresh market.'));
INSERT INTO subtype_translations VALUES(34,'mr','Ganesh Dalimb','Maharashtra','Sweet, mild, pink arils','Ganesh Dalimb ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Ganesh Dalimb ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Punica granatum cv. Ganesh\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, mild, pink arils\u000a\u000aमराठी नाव: Ganesh Dalimb\u000a\u000aमूळ डेटासेट तपशील: Traditional variety; Pune and Nashik; large soft-seeded fruit; good for fresh market.'));
INSERT INTO subtype_translations VALUES(35,'hi','Mridula','Karnataka/Maharashtra','Very sweet, deep red, soft seeds','Mridula इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Mridula इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Punica granatum cv. Mridula\u000a\u000aउत्पत्ति क्षेत्र: Karnataka/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very sweet, deep red, soft seeds\u000a\u000aमराठी नाम: Mridula Dalimb\u000a\u000aमूल डेटासेट विवरण: Deep red attractive arils; grown in Solapur and Osmanabad; early-bearing.'));
INSERT INTO subtype_translations VALUES(35,'mr','Mridula Dalimb','Karnataka/Maharashtra','Very sweet, deep red, soft seeds','Mridula Dalimb ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Mridula Dalimb ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Punica granatum cv. Mridula\u000a\u000aउत्पत्ती क्षेत्र: Karnataka/Maharashtra\u000a\u000aचव वैशिष्ट्य: Very sweet, deep red, soft seeds\u000a\u000aमराठी नाव: Mridula Dalimb\u000a\u000aमूळ डेटासेट तपशील: Deep red attractive arils; grown in Solapur and Osmanabad; early-bearing.'));
INSERT INTO subtype_translations VALUES(36,'hi','Arakta','Karnataka/Maharashtra','Sweet, deep red, attractive appearance','Arakta इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Arakta इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Punica granatum cv. Arakta\u000a\u000aउत्पत्ति क्षेत्र: Karnataka/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, deep red, attractive appearance\u000a\u000aमराठी नाम: Arakta Dalimb\u000a\u000aमूल डेटासेट विवरण: Large fruit; bright red skin; grown in Marathwada and Nashik; good export potential.'));
INSERT INTO subtype_translations VALUES(36,'mr','Arakta Dalimb','Karnataka/Maharashtra','Sweet, deep red, attractive appearance','Arakta Dalimb ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Arakta Dalimb ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Punica granatum cv. Arakta\u000a\u000aउत्पत्ती क्षेत्र: Karnataka/Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, deep red, attractive appearance\u000a\u000aमराठी नाव: Arakta Dalimb\u000a\u000aमूळ डेटासेट तपशील: Large fruit; bright red skin; grown in Marathwada and Nashik; good export potential.'));
INSERT INTO subtype_translations VALUES(37,'hi','Balanagar','Telangana/Maharashtra','Sweet, creamy, white flesh, low seeds','Balanagar इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Balanagar इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Annona squamosa cv. Balanagar\u000a\u000aउत्पत्ति क्षेत्र: Telangana/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, creamy, white flesh, low seeds\u000a\u000aमराठी नाम: Balanagar Sitafal\u000a\u000aमूल डेटासेट विवरण: Most popular commercial variety in Maharashtra; Nashik, Aurangabad; large fruit; high pulp recovery.'));
INSERT INTO subtype_translations VALUES(37,'mr','Balanagar Sitafal','Telangana/Maharashtra','Sweet, creamy, white flesh, low seeds','Balanagar Sitafal ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Balanagar Sitafal ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Annona squamosa cv. Balanagar\u000a\u000aउत्पत्ती क्षेत्र: Telangana/Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, creamy, white flesh, low seeds\u000a\u000aमराठी नाव: Balanagar Sitafal\u000a\u000aमूळ डेटासेट तपशील: Most popular commercial variety in Maharashtra; Nashik, Aurangabad; large fruit; high pulp recovery.'));
INSERT INTO subtype_translations VALUES(38,'hi','Red Sitafal','Maharashtra','Very sweet, soft, aromatic, reddish skin','Red Sitafal इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Red Sitafal इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Annona reticulata\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very sweet, soft, aromatic, reddish skin\u000a\u000aमराठी नाम: Lal Sitafal\u000a\u000aमूल डेटासेट विवरण: Bullock''s heart variety; red skin; higher sweetness; Nashik and Marathwada.'));
INSERT INTO subtype_translations VALUES(38,'mr','Lal Sitafal','Maharashtra','Very sweet, soft, aromatic, reddish skin','Lal Sitafal ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Lal Sitafal ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Annona reticulata\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Very sweet, soft, aromatic, reddish skin\u000a\u000aमराठी नाव: Lal Sitafal\u000a\u000aमूळ डेटासेट तपशील: Bullock''s heart variety; red skin; higher sweetness; Nashik and Marathwada.'));
INSERT INTO subtype_translations VALUES(39,'hi','Red Lady','Taiwan/Maharashtra','Very sweet, red-orange flesh, firm','Red Lady इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Red Lady इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Carica papaya cv. Red Lady\u000a\u000aउत्पत्ति क्षेत्र: Taiwan/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very sweet, red-orange flesh, firm\u000a\u000aमराठी नाम: Red Lady Papai\u000a\u000aमूल डेटासेट विवरण: F1 hybrid; most popular commercial variety; Pune, Nashik; gynoecious; high yield; disease resistant.'));
INSERT INTO subtype_translations VALUES(39,'mr','Red Lady Papai','Taiwan/Maharashtra','Very sweet, red-orange flesh, firm','Red Lady Papai ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Red Lady Papai ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Carica papaya cv. Red Lady\u000a\u000aउत्पत्ती क्षेत्र: Taiwan/Maharashtra\u000a\u000aचव वैशिष्ट्य: Very sweet, red-orange flesh, firm\u000a\u000aमराठी नाव: Red Lady Papai\u000a\u000aमूळ डेटासेट तपशील: F1 hybrid; most popular commercial variety; Pune, Nashik; gynoecious; high yield; disease resistant.'));
INSERT INTO subtype_translations VALUES(40,'hi','Taiwan','Taiwan/Maharashtra','Sweet, orange flesh, medium size','Taiwan इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Taiwan इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Carica papaya cv. Taiwan 786\u000a\u000aउत्पत्ति क्षेत्र: Taiwan/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, orange flesh, medium size\u000a\u000aमराठी नाम: Taiwan Papai\u000a\u000aमूल डेटासेट विवरण: Widely grown hybrid; dual purpose (fruit + raw); Jalgaon and Nashik; year-round production.'));
INSERT INTO subtype_translations VALUES(40,'mr','Taiwan Papai','Taiwan/Maharashtra','Sweet, orange flesh, medium size','Taiwan Papai ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Taiwan Papai ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Carica papaya cv. Taiwan 786\u000a\u000aउत्पत्ती क्षेत्र: Taiwan/Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, orange flesh, medium size\u000a\u000aमराठी नाव: Taiwan Papai\u000a\u000aमूळ डेटासेट तपशील: Widely grown hybrid; dual purpose (fruit + raw); Jalgaon and Nashik; year-round production.'));
INSERT INTO subtype_translations VALUES(41,'hi','Kalipatti','Maharashtra','Very sweet, granular, brown flesh','Kalipatti इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Kalipatti इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Manilkara zapota cv. Kalipatti\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very sweet, granular, brown flesh\u000a\u000aमराठी नाम: Kalipatti Chiku\u000a\u000aमूल डेटासेट विवरण: Most popular commercial variety; Palghar, Nashik; oval shape; high yield; good shelf life.'));
INSERT INTO subtype_translations VALUES(41,'mr','Kalipatti Chiku','Maharashtra','Very sweet, granular, brown flesh','Kalipatti Chiku ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Kalipatti Chiku ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Manilkara zapota cv. Kalipatti\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Very sweet, granular, brown flesh\u000a\u000aमराठी नाव: Kalipatti Chiku\u000a\u000aमूळ डेटासेट तपशील: Most popular commercial variety; Palghar, Nashik; oval shape; high yield; good shelf life.'));
INSERT INTO subtype_translations VALUES(42,'hi','Cricket Ball','Maharashtra','Sweet, large, round, high sugar','Cricket Ball इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Cricket Ball इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Manilkara zapota cv. Cricket Ball\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, large, round, high sugar\u000a\u000aमराठी नाम: Cricket Ball Chiku\u000a\u000aमूल डेटासेट विवरण: Round large fruit; high market value; Pune and Nashik.'));
INSERT INTO subtype_translations VALUES(42,'mr','Cricket Ball Chiku','Maharashtra','Sweet, large, round, high sugar','Cricket Ball Chiku ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Cricket Ball Chiku ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Manilkara zapota cv. Cricket Ball\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, large, round, high sugar\u000a\u000aमराठी नाव: Cricket Ball Chiku\u000a\u000aमूळ डेटासेट तपशील: Round large fruit; high market value; Pune and Nashik.'));
INSERT INTO subtype_translations VALUES(43,'hi','West Coast Tall','Maharashtra','Rich coconut water, thick white copra','West Coast Tall इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('West Coast Tall इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Cocos nucifera cv. West Coast Tall\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Rich coconut water, thick white copra\u000a\u000aमराठी नाम: Konkan Naral\u000a\u000aमूल डेटासेट विवरण: Tall variety; most widely grown in Konkan; high copra yield; drought tolerant once established.'));
INSERT INTO subtype_translations VALUES(43,'mr','Konkan Naral','Maharashtra','Rich coconut water, thick white copra','Konkan Naral ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Konkan Naral ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Cocos nucifera cv. West Coast Tall\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Rich coconut water, thick white copra\u000a\u000aमराठी नाव: Konkan Naral\u000a\u000aमूळ डेटासेट तपशील: Tall variety; most widely grown in Konkan; high copra yield; drought tolerant once established.'));
INSERT INTO subtype_translations VALUES(44,'hi','Dwarf','Maharashtra','Sweet tender water, thin husk','Dwarf इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Dwarf इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Cocos nucifera var. nana\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet tender water, thin husk\u000a\u000aमराठी नाम: Bodka Naral\u000a\u000aमूल डेटासेट विवरण: Early bearing; tender coconut market; Ratnagiri and Sindhudurg; shorter lifespan than tall.'));
INSERT INTO subtype_translations VALUES(44,'mr','Bodka Naral','Maharashtra','Sweet tender water, thin husk','Bodka Naral ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Bodka Naral ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Cocos nucifera var. nana\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet tender water, thin husk\u000a\u000aमराठी नाव: Bodka Naral\u000a\u000aमूळ डेटासेट तपशील: Early bearing; tender coconut market; Ratnagiri and Sindhudurg; shorter lifespan than tall.'));
INSERT INTO subtype_translations VALUES(45,'hi','Local Konkan','Maharashtra','Sweet, aromatic, orange-yellow flesh','Local Konkan इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Local Konkan इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Artocarpus heterophyllus (local)\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, aromatic, orange-yellow flesh\u000a\u000aमराठी नाम: Konkan Phanas\u000a\u000aमूल डेटासेट विवरण: Traditional variety from Konkan; high-quality sweet bulbs; used raw as vegetable and ripe as fruit.'));
INSERT INTO subtype_translations VALUES(45,'mr','Konkan Phanas','Maharashtra','Sweet, aromatic, orange-yellow flesh','Konkan Phanas ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Konkan Phanas ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Artocarpus heterophyllus (local)\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, aromatic, orange-yellow flesh\u000a\u000aमराठी नाव: Konkan Phanas\u000a\u000aमूळ डेटासेट तपशील: Traditional variety from Konkan; high-quality sweet bulbs; used raw as vegetable and ripe as fruit.'));
INSERT INTO subtype_translations VALUES(46,'hi','Singapore','Malaysia/Maharashtra','Sweet, firm, less sticky','Singapore इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Singapore इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Artocarpus heterophyllus cv. Singapore\u000a\u000aउत्पत्ति क्षेत्र: Malaysia/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, firm, less sticky\u000a\u000aमराठी नाम: Singapore Phanas\u000a\u000aमूल डेटासेट विवरण: Less latex; firmer bulbs; good for processing; grown in Konkan.'));
INSERT INTO subtype_translations VALUES(46,'mr','Singapore Phanas','Malaysia/Maharashtra','Sweet, firm, less sticky','Singapore Phanas ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Singapore Phanas ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Artocarpus heterophyllus cv. Singapore\u000a\u000aउत्पत्ती क्षेत्र: Malaysia/Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, firm, less sticky\u000a\u000aमराठी नाव: Singapore Phanas\u000a\u000aमूळ डेटासेट तपशील: Less latex; firmer bulbs; good for processing; grown in Konkan.'));
INSERT INTO subtype_translations VALUES(47,'hi','NA-7','Maharashtra','Sour, astringent, large fruit','NA-7 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('NA-7 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Phyllanthus emblica cv. NA-7\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sour, astringent, large fruit\u000a\u000aमराठी नाम: NA-7 Avala\u000a\u000aमूल डेटासेट विवरण: Most popular commercial variety in Maharashtra; large fruit; Nashik and Aurangabad; high Vitamin C.'));
