INSERT INTO subtype_translations VALUES(48,'hi','Krishna','Maharashtra','Sour, medium size, firm','Krishna इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Krishna इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Phyllanthus emblica cv. Krishna\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sour, medium size, firm\u000a\u000aमराठी नाम: Krishna Avala\u000a\u000aमूल डेटासेट विवरण: High yielding; grown in Marathwada; good for processing.'));
