INSERT INTO subtype_translations VALUES(49,'hi','Kanchan','Maharashtra','Mildly sour, attractive appearance','Kanchan इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Kanchan इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Phyllanthus emblica cv. Kanchan\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Mildly sour, attractive appearance\u000a\u000aमराठी नाम: Kanchan Avala\u000a\u000aमूल डेटासेट विवरण: Regular bearer; Nashik; good for candy and pickle industry.'));
INSERT INTO subtype_translations VALUES(49,'mr','Kanchan Avala','Maharashtra','Mildly sour, attractive appearance','Kanchan Avala ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Kanchan Avala ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Phyllanthus emblica cv. Kanchan\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Mildly sour, attractive appearance\u000a\u000aमराठी नाव: Kanchan Avala\u000a\u000aमूळ डेटासेट तपशील: Regular bearer; Nashik; good for candy and pickle industry.'));
INSERT INTO subtype_translations VALUES(50,'hi','Camarosa','USA/Maharashtra','Sweet-tart, firm, bright red','Camarosa इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Camarosa इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Fragaria × ananassa cv. Camarosa\u000a\u000aउत्पत्ति क्षेत्र: USA/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet-tart, firm, bright red\u000a\u000aमराठी नाम: Camarosa Strawberry\u000a\u000aमूल डेटासेट विवरण: Most popular variety in Mahabaleshwar; large berry; good shelf life; high yield; fresh market and processing.'));
