INSERT INTO subtype_translations VALUES(51,'hi','Festival','USA/Maharashtra','Very sweet, aromatic, deep red','Festival इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Festival इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Fragaria × ananassa cv. Festival\u000a\u000aउत्पत्ति क्षेत्र: USA/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very sweet, aromatic, deep red\u000a\u000aमराठी नाम: Festival Strawberry\u000a\u000aमूल डेटासेट विवरण: Sweet flavour; Mahabaleshwar and Panchgani; popular with tourists.'));
INSERT INTO subtype_translations VALUES(51,'mr','Festival Strawberry','USA/Maharashtra','Very sweet, aromatic, deep red','Festival Strawberry ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Festival Strawberry ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Fragaria × ananassa cv. Festival\u000a\u000aउत्पत्ती क्षेत्र: USA/Maharashtra\u000a\u000aचव वैशिष्ट्य: Very sweet, aromatic, deep red\u000a\u000aमराठी नाव: Festival Strawberry\u000a\u000aमूळ डेटासेट तपशील: Sweet flavour; Mahabaleshwar and Panchgani; popular with tourists.'));
INSERT INTO subtype_translations VALUES(52,'hi','Sweet Charlie','USA/Maharashtra','Very sweet, aromatic, early season','Sweet Charlie इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Sweet Charlie इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Fragaria × ananassa cv. Sweet Charlie\u000a\u000aउत्पत्ति क्षेत्र: USA/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very sweet, aromatic, early season\u000a\u000aमराठी नाम: Sweet Charlie Strawberry\u000a\u000aमूल डेटासेट विवरण: Early bearing; soft fruit; excellent flavour; Mahabaleshwar.'));
INSERT INTO subtype_translations VALUES(52,'mr','Sweet Charlie Strawberry','USA/Maharashtra','Very sweet, aromatic, early season','Sweet Charlie Strawberry ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Sweet Charlie Strawberry ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Fragaria × ananassa cv. Sweet Charlie\u000a\u000aउत्पत्ती क्षेत्र: USA/Maharashtra\u000a\u000aचव वैशिष्ट्य: Very sweet, aromatic, early season\u000a\u000aमराठी नाव: Sweet Charlie Strawberry\u000a\u000aमूळ डेटासेट तपशील: Early bearing; soft fruit; excellent flavour; Mahabaleshwar.'));
INSERT INTO subtype_translations VALUES(53,'hi','Poona Fig (Dinkar)','Maharashtra','Very sweet, golden-green skin, soft, aromatic','Poona Fig (Dinkar) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Poona Fig (Dinkar) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Ficus carica cv. Poona\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very sweet, golden-green skin, soft, aromatic\u000a\u000aमराठी नाम: Poona Anjeer\u000a\u000aमूल डेटासेट विवरण: GI-tagged Purandar fig; unique sweetness; grown exclusively in Purandar, Pune; best eaten fresh; limited production, premium price.'));
INSERT INTO subtype_translations VALUES(53,'mr','Poona Anjeer','Maharashtra','Very sweet, golden-green skin, soft, aromatic','Poona Anjeer ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Poona Anjeer ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Ficus carica cv. Poona\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Very sweet, golden-green skin, soft, aromatic\u000a\u000aमराठी नाव: Poona Anjeer\u000a\u000aमूळ डेटासेट तपशील: GI-tagged Purandar fig; unique sweetness; grown exclusively in Purandar, Pune; best eaten fresh; limited production, premium price.'));
INSERT INTO subtype_translations VALUES(54,'hi','Umran','Rajasthan/Maharashtra','Sweet, large, firm, low acidity','Umran इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Umran इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Ziziphus mauritiana cv. Umran\u000a\u000aउत्पत्ति क्षेत्र: Rajasthan/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, large, firm, low acidity\u000a\u000aमराठी नाम: Umran Bor\u000a\u000aमूल डेटासेट विवरण: Most popular commercial variety; large oval fruit; good shelf life; Solapur, Aurangabad.'));
INSERT INTO subtype_translations VALUES(54,'mr','Umran Bor','Rajasthan/Maharashtra','Sweet, large, firm, low acidity','Umran Bor ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Umran Bor ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Ziziphus mauritiana cv. Umran\u000a\u000aउत्पत्ती क्षेत्र: Rajasthan/Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, large, firm, low acidity\u000a\u000aमराठी नाव: Umran Bor\u000a\u000aमूळ डेटासेट तपशील: Most popular commercial variety; large oval fruit; good shelf life; Solapur, Aurangabad.'));
INSERT INTO subtype_translations VALUES(55,'hi','Gola','Maharashtra','Sweet-sour, round, medium size','Gola इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Gola इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Ziziphus mauritiana cv. Gola\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet-sour, round, medium size\u000a\u000aमराठी नाम: Gola Bor\u000a\u000aमूल डेटासेट विवरण: Traditional variety; good domestic market; Marathwada and Vidarbha.'));
INSERT INTO subtype_translations VALUES(55,'mr','Gola Bor','Maharashtra','Sweet-sour, round, medium size','Gola Bor ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Gola Bor ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Ziziphus mauritiana cv. Gola\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet-sour, round, medium size\u000a\u000aमराठी नाव: Gola Bor\u000a\u000aमूळ डेटासेट तपशील: Traditional variety; good domestic market; Marathwada and Vidarbha.'));
INSERT INTO subtype_translations VALUES(56,'hi','Indrayani','Maharashtra','Aromatic, soft, sticky when cooked','Indrayani इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Indrayani इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Oryza sativa cv. Indrayani\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Aromatic, soft, sticky when cooked\u000a\u000aमराठी नाम: Indrayani Tandul\u000a\u000aमूल डेटासेट विवरण: GI-tagged; developed at Dr BSKKV, Dapoli; grown in Pune, Nashik and Konkan; premium price; very popular in Pune city market.'));
INSERT INTO subtype_translations VALUES(56,'mr','Indrayani Tandul','Maharashtra','Aromatic, soft, sticky when cooked','Indrayani Tandul ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Indrayani Tandul ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Oryza sativa cv. Indrayani\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Aromatic, soft, sticky when cooked\u000a\u000aमराठी नाव: Indrayani Tandul\u000a\u000aमूळ डेटासेट तपशील: GI-tagged; developed at Dr BSKKV, Dapoli; grown in Pune, Nashik and Konkan; premium price; very popular in Pune city market.'));
INSERT INTO subtype_translations VALUES(57,'hi','Ambemohar','Maharashtra','Highly aromatic (mango blossom scent), soft, short grain','Ambemohar इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Ambemohar इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Oryza sativa cv. Ambemohar\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Highly aromatic (mango blossom scent), soft, short grain\u000a\u000aमराठी नाम: Ambemohar Tandul\u000a\u000aमूल डेटासेट विवरण: Heritage aromatic variety; Pune and Konkan hills; named for its mango-blossom aroma; slow cooking; festival and high-value rice.'));
INSERT INTO subtype_translations VALUES(57,'mr','Ambemohar Tandul','Maharashtra','Highly aromatic (mango blossom scent), soft, short grain','Ambemohar Tandul ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Ambemohar Tandul ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Oryza sativa cv. Ambemohar\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Highly aromatic (mango blossom scent), soft, short grain\u000a\u000aमराठी नाव: Ambemohar Tandul\u000a\u000aमूळ डेटासेट तपशील: Heritage aromatic variety; Pune and Konkan hills; named for its mango-blossom aroma; slow cooking; festival and high-value rice.'));
INSERT INTO subtype_translations VALUES(58,'hi','Kolam','Maharashtra','Slightly aromatic, slender, fluffy on cooking','Kolam इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Kolam इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Oryza sativa cv. Kolam\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Slightly aromatic, slender, fluffy on cooking\u000a\u000aमराठी नाम: Kolam Tandul\u000a\u000aमूल डेटासेट विवरण: Very popular in Mumbai-Pune; medium-slender grain; widely used for daily cooking; Nashik, Konkan.'));
INSERT INTO subtype_translations VALUES(58,'mr','Kolam Tandul','Maharashtra','Slightly aromatic, slender, fluffy on cooking','Kolam Tandul ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Kolam Tandul ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Oryza sativa cv. Kolam\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Slightly aromatic, slender, fluffy on cooking\u000a\u000aमराठी नाव: Kolam Tandul\u000a\u000aमूळ डेटासेट तपशील: Very popular in Mumbai-Pune; medium-slender grain; widely used for daily cooking; Nashik, Konkan.'));
INSERT INTO subtype_translations VALUES(59,'hi','HMT','India','Mild aroma, long grain, non-sticky','HMT इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('HMT इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Oryza sativa cv. HMT\u000a\u000aउत्पत्ति क्षेत्र: India\u000a\u000aस्वाद प्रोफाइल: Mild aroma, long grain, non-sticky\u000a\u000aमराठी नाम: HMT Tandul\u000a\u000aमूल डेटासेट विवरण: Named for its resemblance to HMT watches (long slim grain); popular across Maharashtra; biryani rice.'));
INSERT INTO subtype_translations VALUES(59,'mr','HMT Tandul','India','Mild aroma, long grain, non-sticky','HMT Tandul ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('HMT Tandul ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Oryza sativa cv. HMT\u000a\u000aउत्पत्ती क्षेत्र: India\u000a\u000aचव वैशिष्ट्य: Mild aroma, long grain, non-sticky\u000a\u000aमराठी नाव: HMT Tandul\u000a\u000aमूळ डेटासेट तपशील: Named for its resemblance to HMT watches (long slim grain); popular across Maharashtra; biryani rice.'));
INSERT INTO subtype_translations VALUES(60,'hi','Jaya','India (IRRI origin)','Plain, non-aromatic, high-yield','Jaya इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Jaya इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Oryza sativa cv. Jaya\u000a\u000aउत्पत्ति क्षेत्र: India (IRRI origin)\u000a\u000aस्वाद प्रोफाइल: Plain, non-aromatic, high-yield\u000a\u000aमराठी नाम: Jaya Tandul\u000a\u000aमूल डेटासेट विवरण: High-yielding semi-dwarf; widely grown in irrigated areas of Vidarbha and Marathwada.'));
INSERT INTO subtype_translations VALUES(60,'mr','Jaya Tandul','India (IRRI origin)','Plain, non-aromatic, high-yield','Jaya Tandul ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Jaya Tandul ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Oryza sativa cv. Jaya\u000a\u000aउत्पत्ती क्षेत्र: India (IRRI origin)\u000a\u000aचव वैशिष्ट्य: Plain, non-aromatic, high-yield\u000a\u000aमराठी नाव: Jaya Tandul\u000a\u000aमूळ डेटासेट तपशील: High-yielding semi-dwarf; widely grown in irrigated areas of Vidarbha and Marathwada.'));
INSERT INTO subtype_translations VALUES(61,'hi','Swarna','India','Non-aromatic, medium-bold, high yield','Swarna इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Swarna इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Oryza sativa cv. Swarna (MTU 7029)\u000a\u000aउत्पत्ति क्षेत्र: India\u000a\u000aस्वाद प्रोफाइल: Non-aromatic, medium-bold, high yield\u000a\u000aमराठी नाम: Swarna Tandul\u000a\u000aमूल डेटासेट विवरण: Most widely grown HYV rice in Maharashtra; Vidarbha; flood tolerant; rainfed and irrigated.'));
INSERT INTO subtype_translations VALUES(61,'mr','Swarna Tandul','India','Non-aromatic, medium-bold, high yield','Swarna Tandul ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Swarna Tandul ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Oryza sativa cv. Swarna (MTU 7029)\u000a\u000aउत्पत्ती क्षेत्र: India\u000a\u000aचव वैशिष्ट्य: Non-aromatic, medium-bold, high yield\u000a\u000aमराठी नाव: Swarna Tandul\u000a\u000aमूळ डेटासेट तपशील: Most widely grown HYV rice in Maharashtra; Vidarbha; flood tolerant; rainfed and irrigated.'));
INSERT INTO subtype_translations VALUES(62,'hi','Basmati','India','Very aromatic, extra long slender grain, fluffy','Basmati इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Basmati इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Oryza sativa cv. Basmati\u000a\u000aउत्पत्ति क्षेत्र: India\u000a\u000aस्वाद प्रोफाइल: Very aromatic, extra long slender grain, fluffy\u000a\u000aमराठी नाम: Basmati Tandul\u000a\u000aमूल डेटासेट विवरण: Grown in Nashik and parts of Marathwada; mostly for export and premium market.'));
INSERT INTO subtype_translations VALUES(62,'mr','Basmati Tandul','India','Very aromatic, extra long slender grain, fluffy','Basmati Tandul ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Basmati Tandul ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Oryza sativa cv. Basmati\u000a\u000aउत्पत्ती क्षेत्र: India\u000a\u000aचव वैशिष्ट्य: Very aromatic, extra long slender grain, fluffy\u000a\u000aमराठी नाव: Basmati Tandul\u000a\u000aमूळ डेटासेट तपशील: Grown in Nashik and parts of Marathwada; mostly for export and premium market.'));
INSERT INTO subtype_translations VALUES(63,'hi','Karjat-4','Maharashtra','Aromatic, short-bold, good palatability','Karjat-4 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Karjat-4 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Oryza sativa cv. Karjat-4\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Aromatic, short-bold, good palatability\u000a\u000aमराठी नाम: Karjat Tandul\u000a\u000aमूल डेटासेट विवरण: Developed at Regional Agricultural Research Station, Karjat; adapted to Konkan; medium duration.'));
INSERT INTO subtype_translations VALUES(63,'mr','Karjat Tandul','Maharashtra','Aromatic, short-bold, good palatability','Karjat Tandul ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Karjat Tandul ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Oryza sativa cv. Karjat-4\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Aromatic, short-bold, good palatability\u000a\u000aमराठी नाव: Karjat Tandul\u000a\u000aमूळ डेटासेट तपशील: Developed at Regional Agricultural Research Station, Karjat; adapted to Konkan; medium duration.'));
INSERT INTO subtype_translations VALUES(64,'hi','Phule Samruddhi','Maharashtra','High yield, medium grain, good cooking quality','Phule Samruddhi इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Phule Samruddhi इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Oryza sativa cv. Phule Samruddhi\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: High yield, medium grain, good cooking quality\u000a\u000aमराठी नाम: Phule Samruddhi Tandul\u000a\u000aमूल डेटासेट विवरण: Developed by MPKV Rahuri; high-yielding; suitable for Konkan and Western Maharashtra.'));
INSERT INTO subtype_translations VALUES(64,'mr','Phule Samruddhi Tandul','Maharashtra','High yield, medium grain, good cooking quality','Phule Samruddhi Tandul ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Phule Samruddhi Tandul ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Oryza sativa cv. Phule Samruddhi\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: High yield, medium grain, good cooking quality\u000a\u000aमराठी नाव: Phule Samruddhi Tandul\u000a\u000aमूळ डेटासेट तपशील: Developed by MPKV Rahuri; high-yielding; suitable for Konkan and Western Maharashtra.'));
INSERT INTO subtype_translations VALUES(65,'hi','Lokwan','Maharashtra','Nutty, slightly sweet, good chapati quality','Lokwan इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Lokwan इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Triticum aestivum cv. Lokwan\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Nutty, slightly sweet, good chapati quality\u000a\u000aमराठी नाम: Lokwan Gahu\u000a\u000aमूल डेटासेट विवरण: Heritage wheat of Maharashtra; famous for chapati quality; medium yield; lower gluten than modern varieties; Nashik, Pune, Aurangabad.'));
INSERT INTO subtype_translations VALUES(65,'mr','Lokwan Gahu','Maharashtra','Nutty, slightly sweet, good chapati quality','Lokwan Gahu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Lokwan Gahu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Triticum aestivum cv. Lokwan\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Nutty, slightly sweet, good chapati quality\u000a\u000aमराठी नाव: Lokwan Gahu\u000a\u000aमूळ डेटासेट तपशील: Heritage wheat of Maharashtra; famous for chapati quality; medium yield; lower gluten than modern varieties; Nashik, Pune, Aurangabad.'));
INSERT INTO subtype_translations VALUES(66,'hi','HD-2189','India','Plain, high gluten, good milling quality','HD-2189 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('HD-2189 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Triticum aestivum cv. HD-2189\u000a\u000aउत्पत्ति क्षेत्र: India\u000a\u000aस्वाद प्रोफाइल: Plain, high gluten, good milling quality\u000a\u000aमराठी नाम: HD-2189 Gahu\u000a\u000aमूल डेटासेट विवरण: Widely grown HYV; adaptable; Nashik and Aurangabad irrigated zones.'));
INSERT INTO subtype_translations VALUES(66,'mr','HD-2189 Gahu','India','Plain, high gluten, good milling quality','HD-2189 Gahu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('HD-2189 Gahu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Triticum aestivum cv. HD-2189\u000a\u000aउत्पत्ती क्षेत्र: India\u000a\u000aचव वैशिष्ट्य: Plain, high gluten, good milling quality\u000a\u000aमराठी नाव: HD-2189 Gahu\u000a\u000aमूळ डेटासेट तपशील: Widely grown HYV; adaptable; Nashik and Aurangabad irrigated zones.'));
INSERT INTO subtype_translations VALUES(67,'hi','HD-2967','India','Mild, high yield, good chapati quality','HD-2967 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('HD-2967 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Triticum aestivum cv. HD-2967\u000a\u000aउत्पत्ति क्षेत्र: India\u000a\u000aस्वाद प्रोफाइल: Mild, high yield, good chapati quality\u000a\u000aमराठी नाम: HD-2967 Gahu\u000a\u000aमूल डेटासेट विवरण: One of most popular wheats in Maharashtra; rust-resistant; Nashik, Pune, Vidarbha.'));
INSERT INTO subtype_translations VALUES(67,'mr','HD-2967 Gahu','India','Mild, high yield, good chapati quality','HD-2967 Gahu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('HD-2967 Gahu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Triticum aestivum cv. HD-2967\u000a\u000aउत्पत्ती क्षेत्र: India\u000a\u000aचव वैशिष्ट्य: Mild, high yield, good chapati quality\u000a\u000aमराठी नाव: HD-2967 Gahu\u000a\u000aमूळ डेटासेट तपशील: One of most popular wheats in Maharashtra; rust-resistant; Nashik, Pune, Vidarbha.'));
INSERT INTO subtype_translations VALUES(68,'hi','NIAW-34','Maharashtra','Mild flavour, high yield, semi-dwarf','NIAW-34 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('NIAW-34 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Triticum aestivum cv. NIAW-34\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Mild flavour, high yield, semi-dwarf\u000a\u000aमराठी नाम: NIAW-34 Gahu\u000a\u000aमूल डेटासेट विवरण: Developed at NIPHAD, Nashik; well adapted to Maharashtra; good tillering.'));
INSERT INTO subtype_translations VALUES(68,'mr','NIAW-34 Gahu','Maharashtra','Mild flavour, high yield, semi-dwarf','NIAW-34 Gahu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('NIAW-34 Gahu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Triticum aestivum cv. NIAW-34\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Mild flavour, high yield, semi-dwarf\u000a\u000aमराठी नाव: NIAW-34 Gahu\u000a\u000aमूळ डेटासेट तपशील: Developed at NIPHAD, Nashik; well adapted to Maharashtra; good tillering.'));
INSERT INTO subtype_translations VALUES(69,'hi','NIAW-917','Maharashtra','Good chapati quality, heat tolerant','NIAW-917 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('NIAW-917 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Triticum aestivum cv. NIAW-917\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Good chapati quality, heat tolerant\u000a\u000aमराठी नाम: NIAW-917 Gahu\u000a\u000aमूल डेटासेट विवरण: Heat-tolerant variety for Maharashtra; late sowing conditions; Marathwada.'));
