INSERT INTO subtype_translations VALUES(70,'hi','MACS-6222','Maharashtra','High protein, good chapati quality','MACS-6222 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('MACS-6222 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Triticum aestivum cv. MACS-6222\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: High protein, good chapati quality\u000a\u000aमराठी नाम: MACS-6222 Gahu\u000a\u000aमूल डेटासेट विवरण: Developed at ARI, Pune; high-yielding; Nashik, Pune, Solapur.'));
INSERT INTO subtype_translations VALUES(70,'mr','MACS-6222 Gahu','Maharashtra','High protein, good chapati quality','MACS-6222 Gahu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('MACS-6222 Gahu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Triticum aestivum cv. MACS-6222\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: High protein, good chapati quality\u000a\u000aमराठी नाव: MACS-6222 Gahu\u000a\u000aमूळ डेटासेट तपशील: Developed at ARI, Pune; high-yielding; Nashik, Pune, Solapur.'));
INSERT INTO subtype_translations VALUES(71,'hi','AKAW-4627','Maharashtra','Durum type, high protein, golden semolina','AKAW-4627 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('AKAW-4627 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Triticum durum cv. AKAW-4627\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Durum type, high protein, golden semolina\u000a\u000aमराठी नाम: AKAW Gahu\u000a\u000aमूल डेटासेट विवरण: Durum wheat; Akola series; Vidarbha and Marathwada; used for semolina (rawa/suji).'));
INSERT INTO subtype_translations VALUES(71,'mr','AKAW Gahu','Maharashtra','Durum type, high protein, golden semolina','AKAW Gahu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('AKAW Gahu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Triticum durum cv. AKAW-4627\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Durum type, high protein, golden semolina\u000a\u000aमराठी नाव: AKAW Gahu\u000a\u000aमूळ डेटासेट तपशील: Durum wheat; Akola series; Vidarbha and Marathwada; used for semolina (rawa/suji).'));
INSERT INTO subtype_translations VALUES(72,'hi','Maldandi','Maharashtra','Bold, white grain, excellent bhakri quality','Maldandi इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Maldandi इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Sorghum bicolor cv. Maldandi 35-1\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Bold, white grain, excellent bhakri quality\u000a\u000aमराठी नाम: Maldandi Jwarī\u000a\u000aमूल डेटासेट विवरण: Heritage rabi sorghum; Solapur is the heartland; world-famous grain quality; GI tag sought; premium price; iconic Maharashtrian grain.'));
INSERT INTO subtype_translations VALUES(72,'mr','Maldandi Jwarī','Maharashtra','Bold, white grain, excellent bhakri quality','Maldandi Jwarī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Maldandi Jwarī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Sorghum bicolor cv. Maldandi 35-1\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Bold, white grain, excellent bhakri quality\u000a\u000aमराठी नाव: Maldandi Jwarī\u000a\u000aमूळ डेटासेट तपशील: Heritage rabi sorghum; Solapur is the heartland; world-famous grain quality; GI tag sought; premium price; iconic Maharashtrian grain.'));
INSERT INTO subtype_translations VALUES(73,'hi','Dagadi Jowar','Maharashtra','Nutty, hard grain, very drought tolerant','Dagadi Jowar इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Dagadi Jowar इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Sorghum bicolor (local landrace)\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Nutty, hard grain, very drought tolerant\u000a\u000aमराठी नाम: Dagadi Jwarī\u000a\u000aमूल डेटासेट विवरण: Traditional hard-grain Kharif variety; Marathwada and Vidarbha; grown without irrigation.'));
INSERT INTO subtype_translations VALUES(73,'mr','Dagadi Jwarī','Maharashtra','Nutty, hard grain, very drought tolerant','Dagadi Jwarī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Dagadi Jwarī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Sorghum bicolor (local landrace)\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Nutty, hard grain, very drought tolerant\u000a\u000aमराठी नाव: Dagadi Jwarī\u000a\u000aमूळ डेटासेट तपशील: Traditional hard-grain Kharif variety; Marathwada and Vidarbha; grown without irrigation.'));
INSERT INTO subtype_translations VALUES(74,'hi','Phule Vasudha','Maharashtra','High yield, white grain, good quality','Phule Vasudha इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Phule Vasudha इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Sorghum bicolor cv. Phule Vasudha\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: High yield, white grain, good quality\u000a\u000aमराठी नाम: Phule Vasudha Jwarī\u000a\u000aमूल डेटासेट विवरण: Developed by MPKV; Rabi season; Nashik, Pune, Aurangabad; dual purpose (grain + fodder).'));
INSERT INTO subtype_translations VALUES(74,'mr','Phule Vasudha Jwarī','Maharashtra','High yield, white grain, good quality','Phule Vasudha Jwarī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Phule Vasudha Jwarī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Sorghum bicolor cv. Phule Vasudha\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: High yield, white grain, good quality\u000a\u000aमराठी नाव: Phule Vasudha Jwarī\u000a\u000aमूळ डेटासेट तपशील: Developed by MPKV; Rabi season; Nashik, Pune, Aurangabad; dual purpose (grain + fodder).'));
INSERT INTO subtype_translations VALUES(75,'hi','CSV-15','India (ICRISAT)','Bold white grain, high yield','CSV-15 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('CSV-15 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Sorghum bicolor cv. CSV-15\u000a\u000aउत्पत्ति क्षेत्र: India (ICRISAT)\u000a\u000aस्वाद प्रोफाइल: Bold white grain, high yield\u000a\u000aमराठी नाम: CSV-15 Jwarī\u000a\u000aमूल डेटासेट विवरण: ICRISAT-developed; widely adapted; Maharashtra, Karnataka; Kharif.'));
INSERT INTO subtype_translations VALUES(75,'mr','CSV-15 Jwarī','India (ICRISAT)','Bold white grain, high yield','CSV-15 Jwarī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('CSV-15 Jwarī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Sorghum bicolor cv. CSV-15\u000a\u000aउत्पत्ती क्षेत्र: India (ICRISAT)\u000a\u000aचव वैशिष्ट्य: Bold white grain, high yield\u000a\u000aमराठी नाव: CSV-15 Jwarī\u000a\u000aमूळ डेटासेट तपशील: ICRISAT-developed; widely adapted; Maharashtra, Karnataka; Kharif.'));
