INSERT INTO subtype_translations VALUES(79,'hi','CSH-16','India','Very high yield, white grain, hybrid','CSH-16 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('CSH-16 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Sorghum bicolor cv. CSH-16\u000a\u000aउत्पत्ति क्षेत्र: India\u000a\u000aस्वाद प्रोफाइल: Very high yield, white grain, hybrid\u000a\u000aमराठी नाम: CSH-16 Jwarī\u000a\u000aमूल डेटासेट विवरण: Widely grown hybrid; Kharif and Rabi; Maharashtra and Andhra Pradesh.'));
INSERT INTO subtype_translations VALUES(79,'mr','CSH-16 Jwarī','India','Very high yield, white grain, hybrid','CSH-16 Jwarī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('CSH-16 Jwarī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Sorghum bicolor cv. CSH-16\u000a\u000aउत्पत्ती क्षेत्र: India\u000a\u000aचव वैशिष्ट्य: Very high yield, white grain, hybrid\u000a\u000aमराठी नाव: CSH-16 Jwarī\u000a\u000aमूळ डेटासेट तपशील: Widely grown hybrid; Kharif and Rabi; Maharashtra and Andhra Pradesh.'));
INSERT INTO subtype_translations VALUES(80,'hi','ICTP-8203','India (ICRISAT)','Grey-white grain, good taste, nutritious','ICTP-8203 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('ICTP-8203 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Pennisetum glaucum cv. ICTP-8203\u000a\u000aउत्पत्ति क्षेत्र: India (ICRISAT)\u000a\u000aस्वाद प्रोफाइल: Grey-white grain, good taste, nutritious\u000a\u000aमराठी नाम: ICTP Bajrī\u000a\u000aमूल डेटासेट विवरण: Open-pollinated variety; widely adopted in Maharashtra; drought-tolerant; ICRISAT developed.'));
