INSERT INTO subtype_translations VALUES(81,'mr','Shanti Bajrī','Maharashtra','White grain, mild flavour, high yield','Shanti Bajrī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Shanti Bajrī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Pennisetum glaucum cv. Shanti\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: White grain, mild flavour, high yield\u000a\u000aमराठी नाव: Shanti Bajrī\u000a\u000aमूळ डेटासेट तपशील: MPKV Rahuri; well adapted to dry zones of Nashik, Aurangabad; Kharif.'));
INSERT INTO subtype_translations VALUES(82,'hi','Saburi','Maharashtra','Good grain quality, medium yield','Saburi इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Saburi इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Pennisetum glaucum cv. Saburi\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Good grain quality, medium yield\u000a\u000aमराठी नाम: Saburi Bajrī\u000a\u000aमूल डेटासेट विवरण: MPKV variety; Maharashtra; dual purpose.'));
INSERT INTO subtype_translations VALUES(82,'mr','Saburi Bajrī','Maharashtra','Good grain quality, medium yield','Saburi Bajrī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Saburi Bajrī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Pennisetum glaucum cv. Saburi\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Good grain quality, medium yield\u000a\u000aमराठी नाव: Saburi Bajrī\u000a\u000aमूळ डेटासेट तपशील: MPKV variety; Maharashtra; dual purpose.'));
INSERT INTO subtype_translations VALUES(83,'hi','Phule Mahashakti','Maharashtra','High protein, bold grain, high yield','Phule Mahashakti इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Phule Mahashakti इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Pennisetum glaucum cv. Phule Mahashakti\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: High protein, bold grain, high yield\u000a\u000aमराठी नाम: Phule Mahashakti Bajrī\u000a\u000aमूल डेटासेट विवरण: Biofortified; high iron and zinc; MPKV; Nashik, Dhule, Jalgaon.'));
