INSERT INTO subtype_translations VALUES(84,'hi','HHB-67','India','Bold grey grain, very high yield, hybrid','HHB-67 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('HHB-67 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Pennisetum glaucum cv. HHB-67\u000a\u000aउत्पत्ति क्षेत्र: India\u000a\u000aस्वाद प्रोफाइल: Bold grey grain, very high yield, hybrid\u000a\u000aमराठी नाम: HHB-67 Bajrī\u000a\u000aमूल डेटासेट विवरण: Most popular hybrid in Maharashtra; CCSHAU Hisar; Nashik, Jalgaon, Dhule.'));
