INSERT INTO subtype_translations VALUES(85,'hi','African Tall','Maharashtra','Plain, starchy, large cob, open-pollinated','African Tall इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('African Tall इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Zea mays cv. African Tall\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Plain, starchy, large cob, open-pollinated\u000a\u000aमराठी नाम: African Tall Makka\u000a\u000aमूल डेटासेट विवरण: Traditional OPV; tall plant; widely grown in Nashik and Pune; good for food and fodder.'));
