INSERT INTO subtype_translations VALUES(86,'hi','Vijay Composite','India','Good flavour, medium yield','Vijay Composite इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Vijay Composite इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Zea mays cv. Vijay\u000a\u000aउत्पत्ति क्षेत्र: India\u000a\u000aस्वाद प्रोफाइल: Good flavour, medium yield\u000a\u000aमराठी नाम: Vijay Makka\u000a\u000aमूल डेटासेट विवरण: Open-pollinated; IARI developed; adaptable to Maharashtra; Kharif.'));
