INSERT INTO subtype_translations VALUES(88,'mr','HQPM-1 Makka','India','High protein (QPM), sweet-nutty flavour','HQPM-1 Makka ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('HQPM-1 Makka ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Zea mays cv. HQPM-1\u000a\u000aउत्पत्ती क्षेत्र: India\u000a\u000aचव वैशिष्ट्य: High protein (QPM), sweet-nutty flavour\u000a\u000aमराठी नाव: HQPM-1 Makka\u000a\u000aमूळ डेटासेट तपशील: Quality Protein Maize; IARI; high lysine and tryptophan; nutritionally superior; poultry and food.'));
INSERT INTO subtype_translations VALUES(89,'hi','Bioseed 9681','Maharashtra','Very high yield, bold grain, hybrid','Bioseed 9681 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Bioseed 9681 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Zea mays cv. Bioseed 9681\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very high yield, bold grain, hybrid\u000a\u000aमराठी नाम: Bioseed Makka\u000a\u000aमूल डेटासेट विवरण: Commercial hybrid; Nashik, Pune; widely used by contract farmers.'));
INSERT INTO subtype_translations VALUES(89,'mr','Bioseed Makka','Maharashtra','Very high yield, bold grain, hybrid','Bioseed Makka ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Bioseed Makka ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Zea mays cv. Bioseed 9681\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Very high yield, bold grain, hybrid\u000a\u000aमराठी नाव: Bioseed Makka\u000a\u000aमूळ डेटासेट तपशील: Commercial hybrid; Nashik, Pune; widely used by contract farmers.'));
INSERT INTO subtype_translations VALUES(90,'hi','Dapoli-1','Maharashtra','Brown grain, earthy, nutritious','Dapoli-1 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Dapoli-1 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Eleusine coracana cv. Dapoli-1\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Brown grain, earthy, nutritious\u000a\u000aमराठी नाम: Dapoli Nachni\u000a\u000aमूल डेटासेट विवरण: Developed at BSKKV Dapoli; adapted to Konkan; Kharif; good yield.'));
