INSERT INTO subtype_translations VALUES(91,'hi','GPU-28','Karnataka/Maharashtra','Brown-black grain, high yield','GPU-28 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('GPU-28 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Eleusine coracana cv. GPU-28\u000a\u000aउत्पत्ति क्षेत्र: Karnataka/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Brown-black grain, high yield\u000a\u000aमराठी नाम: GPU-28 Nachni\u000a\u000aमूल डेटासेट विवरण: One of most popular varieties; GKVK Bengaluru; widely adapted to Maharashtra.'));
INSERT INTO subtype_translations VALUES(91,'mr','GPU-28 Nachni','Karnataka/Maharashtra','Brown-black grain, high yield','GPU-28 Nachni ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('GPU-28 Nachni ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Eleusine coracana cv. GPU-28\u000a\u000aउत्पत्ती क्षेत्र: Karnataka/Maharashtra\u000a\u000aचव वैशिष्ट्य: Brown-black grain, high yield\u000a\u000aमराठी नाव: GPU-28 Nachni\u000a\u000aमूळ डेटासेट तपशील: One of most popular varieties; GKVK Bengaluru; widely adapted to Maharashtra.'));
INSERT INTO subtype_translations VALUES(92,'hi','GPU-67','Karnataka/Maharashtra','Brown grain, blast-resistant, high yield','GPU-67 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('GPU-67 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Eleusine coracana cv. GPU-67\u000a\u000aउत्पत्ति क्षेत्र: Karnataka/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Brown grain, blast-resistant, high yield\u000a\u000aमराठी नाम: GPU-67 Nachni\u000a\u000aमूल डेटासेट विवरण: Disease resistant; good yield; Nashik hills and Nandurbar.'));
INSERT INTO subtype_translations VALUES(92,'mr','GPU-67 Nachni','Karnataka/Maharashtra','Brown grain, blast-resistant, high yield','GPU-67 Nachni ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('GPU-67 Nachni ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Eleusine coracana cv. GPU-67\u000a\u000aउत्पत्ती क्षेत्र: Karnataka/Maharashtra\u000a\u000aचव वैशिष्ट्य: Brown grain, blast-resistant, high yield\u000a\u000aमराठी नाव: GPU-67 Nachni\u000a\u000aमूळ डेटासेट तपशील: Disease resistant; good yield; Nashik hills and Nandurbar.'));
INSERT INTO subtype_translations VALUES(93,'hi','Indaf-5','India','Dark brown, higher protein content','Indaf-5 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Indaf-5 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Eleusine coracana cv. Indaf-5\u000a\u000aउत्पत्ति क्षेत्र: India\u000a\u000aस्वाद प्रोफाइल: Dark brown, higher protein content\u000a\u000aमराठी नाम: Indaf Nachni\u000a\u000aमूल डेटासेट विवरण: ICAR developed; high yielding; used widely in Maharashtra tribal districts.'));
INSERT INTO subtype_translations VALUES(93,'mr','Indaf Nachni','India','Dark brown, higher protein content','Indaf Nachni ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Indaf Nachni ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Eleusine coracana cv. Indaf-5\u000a\u000aउत्पत्ती क्षेत्र: India\u000a\u000aचव वैशिष्ट्य: Dark brown, higher protein content\u000a\u000aमराठी नाव: Indaf Nachni\u000a\u000aमूळ डेटासेट तपशील: ICAR developed; high yielding; used widely in Maharashtra tribal districts.'));
INSERT INTO subtype_translations VALUES(94,'hi','Local Kodra','Maharashtra','Earthy, nutty, slightly bitter if unhulled','Local Kodra इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Local Kodra इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Paspalum scrobiculatum (local landrace)\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Earthy, nutty, slightly bitter if unhulled\u000a\u000aमराठी नाम: Sthanik Kodra\u000a\u000aमूल डेटासेट विवरण: Indigenous landraces grown in Nashik and Nandurbar tribal belts; integral to tribal food culture.'));
INSERT INTO subtype_translations VALUES(94,'mr','Sthanik Kodra','Maharashtra','Earthy, nutty, slightly bitter if unhulled','Sthanik Kodra ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Sthanik Kodra ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Paspalum scrobiculatum (local landrace)\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Earthy, nutty, slightly bitter if unhulled\u000a\u000aमराठी नाव: Sthanik Kodra\u000a\u000aमूळ डेटासेट तपशील: Indigenous landraces grown in Nashik and Nandurbar tribal belts; integral to tribal food culture.'));
INSERT INTO subtype_translations VALUES(95,'hi','Kutki (Local)','Maharashtra','Mild, slightly nutty, soft when cooked','Kutki (Local) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Kutki (Local) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Panicum sumatrense (local)\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Mild, slightly nutty, soft when cooked\u000a\u000aमराठी नाम: Sthanik Vari\u000a\u000aमूल डेटासेट विवरण: Traditional landrace; Nashik and Nandurbar; used for vari chi bhakri and khichdi during fasting.'));
INSERT INTO subtype_translations VALUES(95,'mr','Sthanik Vari','Maharashtra','Mild, slightly nutty, soft when cooked','Sthanik Vari ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Sthanik Vari ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Panicum sumatrense (local)\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Mild, slightly nutty, soft when cooked\u000a\u000aमराठी नाव: Sthanik Vari\u000a\u000aमूळ डेटासेट तपशील: Traditional landrace; Nashik and Nandurbar; used for vari chi bhakri and khichdi during fasting.'));
INSERT INTO subtype_translations VALUES(96,'hi','Bhagar (Local)','Maharashtra','Mild, fluffy, slightly chewy','Bhagar (Local) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Bhagar (Local) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Echinochloa frumentacea (local)\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Mild, fluffy, slightly chewy\u000a\u000aमराठी नाम: Sthanik Bhagar\u000a\u000aमूल डेटासेट विवरण: Traditional local variety; grown across Maharashtra; essential fasting food; khichdi and bhakri.'));
INSERT INTO subtype_translations VALUES(96,'mr','Sthanik Bhagar','Maharashtra','Mild, fluffy, slightly chewy','Sthanik Bhagar ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Sthanik Bhagar ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Echinochloa frumentacea (local)\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Mild, fluffy, slightly chewy\u000a\u000aमराठी नाव: Sthanik Bhagar\u000a\u000aमूळ डेटासेट तपशील: Traditional local variety; grown across Maharashtra; essential fasting food; khichdi and bhakri.'));
INSERT INTO subtype_translations VALUES(97,'hi','PRJ-1','Maharashtra','Good grain quality, high yield','PRJ-1 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('PRJ-1 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Echinochloa frumentacea cv. PRJ-1\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Good grain quality, high yield\u000a\u000aमराठी नाम: PRJ-1 Bhagar\u000a\u000aमूल डेटासेट विवरण: Improved variety; BSKKV Dapoli; Konkan and Nashik.'));
INSERT INTO subtype_translations VALUES(97,'mr','PRJ-1 Bhagar','Maharashtra','Good grain quality, high yield','PRJ-1 Bhagar ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('PRJ-1 Bhagar ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Echinochloa frumentacea cv. PRJ-1\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Good grain quality, high yield\u000a\u000aमराठी नाव: PRJ-1 Bhagar\u000a\u000aमूळ डेटासेट तपशील: Improved variety; BSKKV Dapoli; Konkan and Nashik.'));
INSERT INTO subtype_translations VALUES(98,'hi','Cheena (Local)','Maharashtra','Mild, bland, soft when cooked','Cheena (Local) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Cheena (Local) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Panicum miliaceum (local landrace)\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Mild, bland, soft when cooked\u000a\u000aमराठी नाम: Sthanik Cheena\u000a\u000aमूल डेटासेट विवरण: Local varieties; Marathwada and Vidarbha; very short duration; used for khichdi and upma.'));
INSERT INTO subtype_translations VALUES(98,'mr','Sthanik Cheena','Maharashtra','Mild, bland, soft when cooked','Sthanik Cheena ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Sthanik Cheena ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Panicum miliaceum (local landrace)\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Mild, bland, soft when cooked\u000a\u000aमराठी नाव: Sthanik Cheena\u000a\u000aमूळ डेटासेट तपशील: Local varieties; Marathwada and Vidarbha; very short duration; used for khichdi and upma.'));
INSERT INTO subtype_translations VALUES(99,'hi','BSMR-736 (Vipula)','Maharashtra','Good cooking quality, earthy flavour','BSMR-736 (Vipula) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('BSMR-736 (Vipula) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Cajanus cajan cv. BSMR-736\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Good cooking quality, earthy flavour\u000a\u000aमराठी नाम: Vipula Tur\u000a\u000aमूल डेटासेट विवरण: Wilt and sterility mosaic resistant; MPKV Rahuri; Marathwada and Vidarbha; medium duration.'));
INSERT INTO subtype_translations VALUES(99,'mr','Vipula Tur','Maharashtra','Good cooking quality, earthy flavour','Vipula Tur ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Vipula Tur ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Cajanus cajan cv. BSMR-736\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Good cooking quality, earthy flavour\u000a\u000aमराठी नाव: Vipula Tur\u000a\u000aमूळ डेटासेट तपशील: Wilt and sterility mosaic resistant; MPKV Rahuri; Marathwada and Vidarbha; medium duration.'));
INSERT INTO subtype_translations VALUES(100,'hi','Asha (ICPL-87119)','India (ICRISAT)','Good flavour, medium-bold grain','Asha (ICPL-87119) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Asha (ICPL-87119) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Cajanus cajan cv. Asha\u000a\u000aउत्पत्ति क्षेत्र: India (ICRISAT)\u000a\u000aस्वाद प्रोफाइल: Good flavour, medium-bold grain\u000a\u000aमराठी नाम: Asha Tur\u000a\u000aमूल डेटासेट विवरण: Wilt-resistant; widely adapted; popular in Latur, Osmanabad; medium duration.'));
INSERT INTO subtype_translations VALUES(100,'mr','Asha Tur','India (ICRISAT)','Good flavour, medium-bold grain','Asha Tur ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Asha Tur ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Cajanus cajan cv. Asha\u000a\u000aउत्पत्ती क्षेत्र: India (ICRISAT)\u000a\u000aचव वैशिष्ट्य: Good flavour, medium-bold grain\u000a\u000aमराठी नाव: Asha Tur\u000a\u000aमूळ डेटासेट तपशील: Wilt-resistant; widely adapted; popular in Latur, Osmanabad; medium duration.'));
INSERT INTO subtype_translations VALUES(101,'hi','Maruti','Maharashtra','Large seed, good dal recovery, bold grain','Maruti इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Maruti इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Cajanus cajan cv. Maruti\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Large seed, good dal recovery, bold grain\u000a\u000aमराठी नाम: Maruti Tur\u000a\u000aमूल डेटासेट विवरण: Bold-seeded variety; Marathwada; high market value; good for commercial dal production.'));
INSERT INTO subtype_translations VALUES(101,'mr','Maruti Tur','Maharashtra','Large seed, good dal recovery, bold grain','Maruti Tur ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Maruti Tur ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Cajanus cajan cv. Maruti\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Large seed, good dal recovery, bold grain\u000a\u000aमराठी नाव: Maruti Tur\u000a\u000aमूळ डेटासेट तपशील: Bold-seeded variety; Marathwada; high market value; good for commercial dal production.'));
INSERT INTO subtype_translations VALUES(102,'hi','ICPL-87119','India (ICRISAT)','Medium grain, disease resistant','ICPL-87119 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('ICPL-87119 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Cajanus cajan cv. ICPL-87119\u000a\u000aउत्पत्ति क्षेत्र: India (ICRISAT)\u000a\u000aस्वाद प्रोफाइल: Medium grain, disease resistant\u000a\u000aमराठी नाम: Prabhat Tur\u000a\u000aमूल डेटासेट विवरण: Extra-early variety; ICRISAT; Marathwada; good for areas with short seasons.'));
INSERT INTO subtype_translations VALUES(102,'mr','Prabhat Tur','India (ICRISAT)','Medium grain, disease resistant','Prabhat Tur ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Prabhat Tur ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Cajanus cajan cv. ICPL-87119\u000a\u000aउत्पत्ती क्षेत्र: India (ICRISAT)\u000a\u000aचव वैशिष्ट्य: Medium grain, disease resistant\u000a\u000aमराठी नाव: Prabhat Tur\u000a\u000aमूळ डेटासेट तपशील: Extra-early variety; ICRISAT; Marathwada; good for areas with short seasons.'));
INSERT INTO subtype_translations VALUES(103,'hi','Vijay','Maharashtra','Earthy, creamy, desi type, medium seed','Vijay इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Vijay इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Cicer arietinum cv. Vijay\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Earthy, creamy, desi type, medium seed\u000a\u000aमराठी नाम: Vijay Harbhara\u000a\u000aमूल डेटासेट विवरण: Wilt-resistant desi variety; MPKV Rahuri; widely grown in Marathwada.'));
INSERT INTO subtype_translations VALUES(103,'mr','Vijay Harbhara','Maharashtra','Earthy, creamy, desi type, medium seed','Vijay Harbhara ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Vijay Harbhara ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Cicer arietinum cv. Vijay\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Earthy, creamy, desi type, medium seed\u000a\u000aमराठी नाव: Vijay Harbhara\u000a\u000aमूळ डेटासेट तपशील: Wilt-resistant desi variety; MPKV Rahuri; widely grown in Marathwada.'));
INSERT INTO subtype_translations VALUES(104,'hi','Digvijay','Maharashtra','Good cooking quality, desi type','Digvijay इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Digvijay इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Cicer arietinum cv. Digvijay\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Good cooking quality, desi type\u000a\u000aमराठी नाम: Digvijay Harbhara\u000a\u000aमूल डेटासेट विवरण: High yielding; Marathwada; rust and wilt tolerant.'));
