INSERT INTO subtype_translations VALUES(105,'hi','JAKI-9218','Maharashtra','Bold kabuli type, white, premium','JAKI-9218 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('JAKI-9218 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Cicer arietinum cv. JAKI-9218\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Bold kabuli type, white, premium\u000a\u000aमराठी नाम: JAKI Kabuli Harbhara\u000a\u000aमूल डेटासेट विवरण: Kabuli chickpea; large white seeds; premium export market; Latur, Osmanabad.'));
