INSERT INTO subtype_translations VALUES(106,'hi','Vishal','Maharashtra','Bold kabuli, creamy white, export quality','Vishal इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Vishal इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Cicer arietinum cv. Vishal\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Bold kabuli, creamy white, export quality\u000a\u000aमराठी नाम: Vishal Kabuli Harbhara\u000a\u000aमूल डेटासेट विवरण: Large-seeded kabuli; Marathwada; grown for export to Middle East and Europe.'));
INSERT INTO subtype_translations VALUES(106,'mr','Vishal Kabuli Harbhara','Maharashtra','Bold kabuli, creamy white, export quality','Vishal Kabuli Harbhara ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Vishal Kabuli Harbhara ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Cicer arietinum cv. Vishal\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Bold kabuli, creamy white, export quality\u000a\u000aमराठी नाव: Vishal Kabuli Harbhara\u000a\u000aमूळ डेटासेट तपशील: Large-seeded kabuli; Marathwada; grown for export to Middle East and Europe.'));
INSERT INTO subtype_translations VALUES(107,'hi','TAU-1','Maharashtra','Black seed, bold, good dal quality','TAU-1 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('TAU-1 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Vigna mungo cv. TAU-1\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Black seed, bold, good dal quality\u000a\u000aमराठी नाम: TAU-1 Udid\u000a\u000aमूल डेटासेट विवरण: MPKV Parbhani; widely grown in Marathwada; Kharif; wilt tolerant.'));
INSERT INTO subtype_translations VALUES(107,'mr','TAU-1 Udid','Maharashtra','Black seed, bold, good dal quality','TAU-1 Udid ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('TAU-1 Udid ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Vigna mungo cv. TAU-1\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Black seed, bold, good dal quality\u000a\u000aमराठी नाव: TAU-1 Udid\u000a\u000aमूळ डेटासेट तपशील: MPKV Parbhani; widely grown in Marathwada; Kharif; wilt tolerant.'));
INSERT INTO subtype_translations VALUES(108,'hi','TPU-4','Maharashtra','Medium black seed, good yield','TPU-4 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('TPU-4 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Vigna mungo cv. TPU-4\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Medium black seed, good yield\u000a\u000aमराठी नाम: TPU-4 Udid\u000a\u000aमूल डेटासेट विवरण: MPKV variety; adapted to Marathwada and Vidarbha.'));
