INSERT INTO subtype_translations VALUES(109,'hi','AKU-15','Maharashtra','Bold black seed, high protein','AKU-15 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('AKU-15 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Vigna mungo cv. AKU-15\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Bold black seed, high protein\u000a\u000aमराठी नाम: AKU Udid\u000a\u000aमूल डेटासेट विवरण: Akola series; Vidarbha; disease-resistant; Kharif.'));
INSERT INTO subtype_translations VALUES(109,'mr','AKU Udid','Maharashtra','Bold black seed, high protein','AKU Udid ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('AKU Udid ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Vigna mungo cv. AKU-15\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Bold black seed, high protein\u000a\u000aमराठी नाव: AKU Udid\u000a\u000aमूळ डेटासेट तपशील: Akola series; Vidarbha; disease-resistant; Kharif.'));
INSERT INTO subtype_translations VALUES(110,'hi','JL-3','Maharashtra','Orange-red split, mild earthy flavour','JL-3 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('JL-3 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Lens culinaris cv. JL-3\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Orange-red split, mild earthy flavour\u000a\u000aमराठी नाम: JL-3 Masur\u000a\u000aमूल डेटासेट विवरण: MPKV Parbhani; adapted to Marathwada; Rabi; medium yield.'));
