INSERT INTO subtype_translations VALUES(113,'hi','JS-335','Madhya Pradesh/Maharashtra','Neutral, beany, high protein and oil','JS-335 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('JS-335 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Glycine max cv. JS-335\u000a\u000aउत्पत्ति क्षेत्र: Madhya Pradesh/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Neutral, beany, high protein and oil\u000a\u000aमराठी नाम: JS-335 Soya\u000a\u000aमूल डेटासेट विवरण: Most widely grown variety in Maharashtra for decades; Vidarbha and Marathwada; good yield and oil content.'));
