INSERT INTO subtype_translations VALUES(116,'mr','MAUS-158 Soya','Maharashtra','High yield, lodging resistant','MAUS-158 Soya ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('MAUS-158 Soya ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Glycine max cv. MAUS-158\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: High yield, lodging resistant\u000a\u000aमराठी नाव: MAUS-158 Soya\u000a\u000aमूळ डेटासेट तपशील: Latest MPKV variety; improved pod-shatter resistance; Maharashtra.'));
INSERT INTO subtype_translations VALUES(117,'hi','JL-24','Maharashtra','Rich nutty flavour, high oil, Spanish type','JL-24 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('JL-24 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Arachis hypogaea cv. JL-24\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Rich nutty flavour, high oil, Spanish type\u000a\u000aमराठी नाम: JL-24 Shengdana\u000a\u000aमूल डेटासेट विवरण: Most popular in Maharashtra; MPKV Junnar; Spanish bunch; widely grown in Vidarbha, Nashik; short duration.'));
INSERT INTO subtype_translations VALUES(117,'mr','JL-24 Shengdana','Maharashtra','Rich nutty flavour, high oil, Spanish type','JL-24 Shengdana ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('JL-24 Shengdana ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Arachis hypogaea cv. JL-24\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Rich nutty flavour, high oil, Spanish type\u000a\u000aमराठी नाव: JL-24 Shengdana\u000a\u000aमूळ डेटासेट तपशील: Most popular in Maharashtra; MPKV Junnar; Spanish bunch; widely grown in Vidarbha, Nashik; short duration.'));
INSERT INTO subtype_translations VALUES(118,'hi','TAG-24','India','Good oil content, bold kernel, Spanish','TAG-24 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('TAG-24 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Arachis hypogaea cv. TAG-24\u000a\u000aउत्पत्ति क्षेत्र: India\u000a\u000aस्वाद प्रोफाइल: Good oil content, bold kernel, Spanish\u000a\u000aमराठी नाम: TAG-24 Shengdana\u000a\u000aमूल डेटासेट विवरण: Tilakar Agri; drought-tolerant; Marathwada, Vidarbha; Kharif.'));
