INSERT INTO subtype_translations VALUES(120,'hi','Phule Pragati','Maharashtra','Bold kernel, high oil, good yield','Phule Pragati इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Phule Pragati इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Arachis hypogaea cv. Phule Pragati\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Bold kernel, high oil, good yield\u000a\u000aमराठी नाम: Phule Pragati Shengdana\u000a\u000aमूल डेटासेट विवरण: MPKV Rahuri; improved variety; dual purpose (oil + fresh nut); Maharashtra.'));
