INSERT INTO subtype_translations VALUES(121,'hi','AKT-64','Maharashtra','White seed, nutty, high oil (50–54%)','AKT-64 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('AKT-64 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Sesamum indicum cv. AKT-64\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: White seed, nutty, high oil (50–54%)\u000a\u000aमराठी नाम: AKT-64 Til\u000a\u000aमूल डेटासेट विवरण: Akola series; Vidarbha and Marathwada; white-seeded; high oil; good export quality.'));
