INSERT INTO subtype_translations VALUES(122,'hi','JLT-7','Maharashtra','White seed, good oil content','JLT-7 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('JLT-7 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Sesamum indicum cv. JLT-7\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: White seed, good oil content\u000a\u000aमराठी नाम: JLT-7 Til\u000a\u000aमूल डेटासेट विवरण: MPKV Jalgaon variety; North Maharashtra; Kharif; medium yield.'));
