INSERT INTO subtype_translations VALUES(123,'mr','Phule Til','Maharashtra','White seed, high oil, improved variety','Phule Til ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Phule Til ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Sesamum indicum cv. Phule Til-1\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: White seed, high oil, improved variety\u000a\u000aमराठी नाव: Phule Til\u000a\u000aमूळ डेटासेट तपशील: MPKV Rahuri; widely recommended for Maharashtra; good yield under rainfed conditions.'));
INSERT INTO subtype_translations VALUES(124,'hi','Morden','Canada/Maharashtra','High oil content, open-pollinated','Morden इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Morden इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Helianthus annuus cv. Morden\u000a\u000aउत्पत्ति क्षेत्र: Canada/Maharashtra\u000a\u000aस्वाद प्रोफाइल: High oil content, open-pollinated\u000a\u000aमराठी नाम: Morden Suryafool\u000a\u000aमूल डेटासेट विवरण: OPV; adapted to dry conditions in Marathwada; medium height; good oil (40–45%).'));
INSERT INTO subtype_translations VALUES(124,'mr','Morden Suryafool','Canada/Maharashtra','High oil content, open-pollinated','Morden Suryafool ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Morden Suryafool ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Helianthus annuus cv. Morden\u000a\u000aउत्पत्ती क्षेत्र: Canada/Maharashtra\u000a\u000aचव वैशिष्ट्य: High oil content, open-pollinated\u000a\u000aमराठी नाव: Morden Suryafool\u000a\u000aमूळ डेटासेट तपशील: OPV; adapted to dry conditions in Marathwada; medium height; good oil (40–45%).'));
INSERT INTO subtype_translations VALUES(125,'hi','KBSH-1','Karnataka/Maharashtra','High oil (42–45%), hybrid, high yield','KBSH-1 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('KBSH-1 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Helianthus annuus cv. KBSH-1\u000a\u000aउत्पत्ति क्षेत्र: Karnataka/Maharashtra\u000a\u000aस्वाद प्रोफाइल: High oil (42–45%), hybrid, high yield\u000a\u000aमराठी नाम: KBSH-1 Suryafool\u000a\u000aमूल डेटासेट विवरण: Hybrid; UASD Dharwad; most popular sunflower hybrid in Maharashtra; Solapur, Latur.'));
INSERT INTO subtype_translations VALUES(125,'mr','KBSH-1 Suryafool','Karnataka/Maharashtra','High oil (42–45%), hybrid, high yield','KBSH-1 Suryafool ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('KBSH-1 Suryafool ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Helianthus annuus cv. KBSH-1\u000a\u000aउत्पत्ती क्षेत्र: Karnataka/Maharashtra\u000a\u000aचव वैशिष्ट्य: High oil (42–45%), hybrid, high yield\u000a\u000aमराठी नाव: KBSH-1 Suryafool\u000a\u000aमूळ डेटासेट तपशील: Hybrid; UASD Dharwad; most popular sunflower hybrid in Maharashtra; Solapur, Latur.'));
INSERT INTO subtype_translations VALUES(126,'hi','KBSH-44','Karnataka/Maharashtra','Very high oil, large head, hybrid','KBSH-44 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('KBSH-44 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Helianthus annuus cv. KBSH-44\u000a\u000aउत्पत्ति क्षेत्र: Karnataka/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very high oil, large head, hybrid\u000a\u000aमराठी नाम: KBSH-44 Suryafool\u000a\u000aमूल डेटासेट विवरण: Improved hybrid; UASD; downy mildew resistant; Maharashtra dry zones.'));
INSERT INTO subtype_translations VALUES(126,'mr','KBSH-44 Suryafool','Karnataka/Maharashtra','Very high oil, large head, hybrid','KBSH-44 Suryafool ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('KBSH-44 Suryafool ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Helianthus annuus cv. KBSH-44\u000a\u000aउत्पत्ती क्षेत्र: Karnataka/Maharashtra\u000a\u000aचव वैशिष्ट्य: Very high oil, large head, hybrid\u000a\u000aमराठी नाव: KBSH-44 Suryafool\u000a\u000aमूळ डेटासेट तपशील: Improved hybrid; UASD; downy mildew resistant; Maharashtra dry zones.'));
INSERT INTO subtype_translations VALUES(127,'hi','Co-86032','Maharashtra','High sugar (CCS 12–13%), medium-thick cane','Co-86032 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Co-86032 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Saccharum officinarum cv. Co-86032\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: High sugar (CCS 12–13%), medium-thick cane\u000a\u000aमराठी नाम: Co-86032 Oos\u000a\u000aमूल डेटासेट विवरण: Most widely grown variety in Maharashtra sugar belt; high sucrose; Pune, Satara, Sangli, Kolhapur.'));
INSERT INTO subtype_translations VALUES(127,'mr','Co-86032 Oos','Maharashtra','High sugar (CCS 12–13%), medium-thick cane','Co-86032 Oos ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Co-86032 Oos ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Saccharum officinarum cv. Co-86032\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: High sugar (CCS 12–13%), medium-thick cane\u000a\u000aमराठी नाव: Co-86032 Oos\u000a\u000aमूळ डेटासेट तपशील: Most widely grown variety in Maharashtra sugar belt; high sucrose; Pune, Satara, Sangli, Kolhapur.'));
INSERT INTO subtype_translations VALUES(128,'hi','CoC-671 (Karuppan)','Tamil Nadu/Maharashtra','Very high sugar, thick cane','CoC-671 (Karuppan) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('CoC-671 (Karuppan) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Saccharum officinarum cv. CoC-671\u000a\u000aउत्पत्ति क्षेत्र: Tamil Nadu/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very high sugar, thick cane\u000a\u000aमराठी नाम: CoC-671 Oos\u000a\u000aमूल डेटासेट विवरण: Red cane; high CCS; drought-tolerant; Marathwada and Solapur belt.'));
