INSERT INTO subtype_translations VALUES(129,'hi','Co-94012','Maharashtra','High yield, high sugar, thin-medium cane','Co-94012 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Co-94012 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Saccharum officinarum cv. Co-94012\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: High yield, high sugar, thin-medium cane\u000a\u000aमराठी नाम: Co-94012 Oos\u000a\u000aमूल डेटासेट विवरण: Developed for Maharashtra; resistant to red rot; Nashik, Ahmednagar, Pune.'));
INSERT INTO subtype_translations VALUES(129,'mr','Co-94012 Oos','Maharashtra','High yield, high sugar, thin-medium cane','Co-94012 Oos ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Co-94012 Oos ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Saccharum officinarum cv. Co-94012\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: High yield, high sugar, thin-medium cane\u000a\u000aमराठी नाव: Co-94012 Oos\u000a\u000aमूळ डेटासेट तपशील: Developed for Maharashtra; resistant to red rot; Nashik, Ahmednagar, Pune.'));
INSERT INTO subtype_translations VALUES(130,'hi','Phule-265 (VSI-434)','Maharashtra','High sugar, high yield, mid-late variety','Phule-265 (VSI-434) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Phule-265 (VSI-434) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Saccharum officinarum cv. Phule-265\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: High sugar, high yield, mid-late variety\u000a\u000aमराठी नाम: Phule Oos\u000a\u000aमूल डेटासेट विवरण: Developed at Vasantdada Sugar Institute, Pune; ideal for cooperative factories; Pune, Satara.'));
INSERT INTO subtype_translations VALUES(130,'mr','Phule Oos','Maharashtra','High sugar, high yield, mid-late variety','Phule Oos ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Phule Oos ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Saccharum officinarum cv. Phule-265\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: High sugar, high yield, mid-late variety\u000a\u000aमराठी नाव: Phule Oos\u000a\u000aमूळ डेटासेट तपशील: Developed at Vasantdada Sugar Institute, Pune; ideal for cooperative factories; Pune, Satara.'));
INSERT INTO subtype_translations VALUES(131,'hi','Co-740','Maharashtra','Early maturity, good sugar recovery','Co-740 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Co-740 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Saccharum officinarum cv. Co-740\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Early maturity, good sugar recovery\u000a\u000aमराठी नाम: Co-740 Oos\u000a\u000aमूल डेटासेट विवरण: Early variety; once the most grown in Maharashtra; being replaced by newer hybrids.'));
INSERT INTO subtype_translations VALUES(131,'mr','Co-740 Oos','Maharashtra','Early maturity, good sugar recovery','Co-740 Oos ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Co-740 Oos ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Saccharum officinarum cv. Co-740\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Early maturity, good sugar recovery\u000a\u000aमराठी नाव: Co-740 Oos\u000a\u000aमूळ डेटासेट तपशील: Early variety; once the most grown in Maharashtra; being replaced by newer hybrids.'));
INSERT INTO subtype_translations VALUES(132,'hi','MS-10001 (Phule Mahadhan)','Maharashtra','Very high yield, high CCS','MS-10001 (Phule Mahadhan) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('MS-10001 (Phule Mahadhan) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Saccharum officinarum cv. MS-10001\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very high yield, high CCS\u000a\u000aमराठी नाम: Phule Mahadhan Oos\u000a\u000aमूल डेटासेट विवरण: Latest high-yield release by MPKV and VSI; Pune, Satara, Sangli; water-efficient under drip.'));
