INSERT INTO subtype_translations VALUES(133,'hi','Bhima Raj','Maharashtra','Mild-pungent, red-purple, firm, long shelf life','Bhima Raj इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Bhima Raj इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Allium cepa cv. Bhima Raj\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Mild-pungent, red-purple, firm, long shelf life\u000a\u000aमराठी नाम: Bhima Raj Kanda\u000a\u000aमूल डेटासेट विवरण: ICAR-DOGR Pune; most popular commercial variety; excellent storage and export quality; Nashik, Pune, Ahmednagar; Rabi.'));
