INSERT INTO subtype_translations VALUES(135,'hi','Bhima Kiran','Maharashtra','Pungent, reddish, high yield, Kharif','Bhima Kiran इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Bhima Kiran इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Allium cepa cv. Bhima Kiran\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Pungent, reddish, high yield, Kharif\u000a\u000aमराठी नाम: Bhima Kiran Kanda\u000a\u000aमूल डेटासेट विवरण: Kharif/Late Kharif specialist; ICAR-DOGR; resistant to purple blotch; Pune, Nashik.'));
