INSERT INTO subtype_translations VALUES(136,'hi','N-2-4-1 (NHRDF)','Maharashtra','Mild pungent, red, medium bulb, Rabi','N-2-4-1 (NHRDF) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('N-2-4-1 (NHRDF) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Allium cepa cv. N-2-4-1\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Mild pungent, red, medium bulb, Rabi\u000a\u000aमराठी नाम: N-2-4-1 Kanda\u000a\u000aमूल डेटासेट विवरण: NHRDF variety; popular for Rabi; Maharashtra and Karnataka; export quality; Nashik.'));
