INSERT INTO subtype_translations VALUES(137,'mr','Phikka Lal Kanda','Maharashtra','Mild pungent, light red, good export','Phikka Lal Kanda ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Phikka Lal Kanda ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Allium cepa cv. Agrifound Light Red\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Mild pungent, light red, good export\u000a\u000aमराठी नाव: Phikka Lal Kanda\u000a\u000aमूळ डेटासेट तपशील: NHRDF; light-red colour preferred in Europe; export-grade; Nashik, Pune.'));
INSERT INTO subtype_translations VALUES(138,'hi','Phule Samarth','Maharashtra','Pungent, deep red, high yield, hybrid','Phule Samarth इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Phule Samarth इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Allium cepa cv. Phule Samarth\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Pungent, deep red, high yield, hybrid\u000a\u000aमराठी नाम: Phule Samarth Kanda\u000a\u000aमूल डेटासेट विवरण: MPKV Rahuri F1 hybrid; very high yield; Rabi; excellent storage; recommended for export belt.'));
