INSERT INTO subtype_translations VALUES(139,'hi','Nasik Red (Local)','Maharashtra','Very pungent, classic red, traditional variety','Nasik Red (Local) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Nasik Red (Local) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Allium cepa (local landrace)\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very pungent, classic red, traditional variety\u000a\u000aमराठी नाम: Nashik Lal Kanda\u000a\u000aमूल डेटासेट विवरण: Traditional Nashik landrace; smaller bulb; intense flavour; preferred in domestic market and for export dehydration.'));
