INSERT INTO subtype_translations VALUES(144,'mr','Arka Vikas Tomato','Maharashtra','Large, red, firm, good yield, OPV','Arka Vikas Tomato ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Arka Vikas Tomato ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Solanum lycopersicum cv. Arka Vikas\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Large, red, firm, good yield, OPV\u000a\u000aमराठी नाव: Arka Vikas Tomato\u000a\u000aमूळ डेटासेट तपशील: IIHR Bengaluru; adapted to Maharashtra; suitable for rainy season; wilt-tolerant.'));
INSERT INTO subtype_translations VALUES(145,'hi','Sathgudi','Andhra Pradesh/Maharashtra','Mildly sweet, very juicy, thin skin','Sathgudi इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Sathgudi इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrus limetta cv. Sathgudi\u000a\u000aउत्पत्ति क्षेत्र: Andhra Pradesh/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Mildly sweet, very juicy, thin skin\u000a\u000aमराठी नाम: Sathgudi Mosambi\u000a\u000aमूल डेटासेट विवरण: Most widely grown Mosambi variety in Maharashtra; Solapur, Osmanabad; high juice content; year-round availability.'));
INSERT INTO subtype_translations VALUES(145,'mr','Sathgudi Mosambi','Andhra Pradesh/Maharashtra','Mildly sweet, very juicy, thin skin','Sathgudi Mosambi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Sathgudi Mosambi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrus limetta cv. Sathgudi\u000a\u000aउत्पत्ती क्षेत्र: Andhra Pradesh/Maharashtra\u000a\u000aचव वैशिष्ट्य: Mildly sweet, very juicy, thin skin\u000a\u000aमराठी नाव: Sathgudi Mosambi\u000a\u000aमूळ डेटासेट तपशील: Most widely grown Mosambi variety in Maharashtra; Solapur, Osmanabad; high juice content; year-round availability.'));
INSERT INTO subtype_translations VALUES(146,'hi','Phule Mosambi-1','Maharashtra','Sweet, juicy, good rind colour','Phule Mosambi-1 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Phule Mosambi-1 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrus limetta cv. Phule Mosambi-1\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, juicy, good rind colour\u000a\u000aमराठी नाम: Phule Mosambi\u000a\u000aमूल डेटासेट विवरण: MPKV Rahuri developed; suitable for Maharashtra''s dry zones; good adaptation.'));
INSERT INTO subtype_translations VALUES(146,'mr','Phule Mosambi','Maharashtra','Sweet, juicy, good rind colour','Phule Mosambi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Phule Mosambi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrus limetta cv. Phule Mosambi-1\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, juicy, good rind colour\u000a\u000aमराठी नाव: Phule Mosambi\u000a\u000aमूळ डेटासेट तपशील: MPKV Rahuri developed; suitable for Maharashtra''s dry zones; good adaptation.'));
INSERT INTO subtype_translations VALUES(147,'hi','Seedless Mosambi (Local)','Maharashtra','Sweet, nearly seedless, smooth skin','Seedless Mosambi (Local) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Seedless Mosambi (Local) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrus limetta (seedless type)\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, nearly seedless, smooth skin\u000a\u000aमराठी नाम: Bijrahit Mosambi\u000a\u000aमूल डेटासेट विवरण: Seedless selections grown in Pune and Solapur; premium market; limited production.'));
INSERT INTO subtype_translations VALUES(147,'mr','Bijrahit Mosambi','Maharashtra','Sweet, nearly seedless, smooth skin','Bijrahit Mosambi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Bijrahit Mosambi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrus limetta (seedless type)\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, nearly seedless, smooth skin\u000a\u000aमराठी नाव: Bijrahit Mosambi\u000a\u000aमूळ डेटासेट तपशील: Seedless selections grown in Pune and Solapur; premium market; limited production.'));
INSERT INTO subtype_translations VALUES(148,'hi','Yamuna Safed (G-1)','India','Strongly pungent, white, large cloves','Yamuna Safed (G-1) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Yamuna Safed (G-1) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Allium sativum cv. Yamuna Safed\u000a\u000aउत्पत्ति क्षेत्र: India\u000a\u000aस्वाद प्रोफाइल: Strongly pungent, white, large cloves\u000a\u000aमराठी नाम: Yamuna Safed Lasun\u000a\u000aमूल डेटासेट विवरण: NHRDF variety; most popular in Maharashtra; large white bulb; good storage; Nashik, Pune.'));
INSERT INTO subtype_translations VALUES(148,'mr','Yamuna Safed Lasun','India','Strongly pungent, white, large cloves','Yamuna Safed Lasun ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Yamuna Safed Lasun ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Allium sativum cv. Yamuna Safed\u000a\u000aउत्पत्ती क्षेत्र: India\u000a\u000aचव वैशिष्ट्य: Strongly pungent, white, large cloves\u000a\u000aमराठी नाव: Yamuna Safed Lasun\u000a\u000aमूळ डेटासेट तपशील: NHRDF variety; most popular in Maharashtra; large white bulb; good storage; Nashik, Pune.'));
INSERT INTO subtype_translations VALUES(149,'hi','Phule Bahugunak','Maharashtra','Very pungent, big bulb, long shelf life','Phule Bahugunak इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Phule Bahugunak इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Allium sativum cv. Phule Bahugunak\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very pungent, big bulb, long shelf life\u000a\u000aमराठी नाम: Phule Bahugunak Lasun\u000a\u000aमूल डेटासेट विवरण: MPKV Rahuri; specifically bred for Maharashtra conditions; high yield; Nashik, Satara.'));
INSERT INTO subtype_translations VALUES(149,'mr','Phule Bahugunak Lasun','Maharashtra','Very pungent, big bulb, long shelf life','Phule Bahugunak Lasun ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Phule Bahugunak Lasun ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Allium sativum cv. Phule Bahugunak\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Very pungent, big bulb, long shelf life\u000a\u000aमराठी नाव: Phule Bahugunak Lasun\u000a\u000aमूळ डेटासेट तपशील: MPKV Rahuri; specifically bred for Maharashtra conditions; high yield; Nashik, Satara.'));
INSERT INTO subtype_translations VALUES(150,'hi','Agrifound White (G-41)','Maharashtra','Pungent, white, medium bulb, export quality','Agrifound White (G-41) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Agrifound White (G-41) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Allium sativum cv. G-41\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Pungent, white, medium bulb, export quality\u000a\u000aमराठी नाम: Safed Lasun\u000a\u000aमूल डेटासेट विवरण: NHRDF; export-grade white garlic; Maharashtra and Rajasthan; Nashik, Solapur.'));
INSERT INTO subtype_translations VALUES(150,'mr','Safed Lasun','Maharashtra','Pungent, white, medium bulb, export quality','Safed Lasun ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Safed Lasun ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Allium sativum cv. G-41\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Pungent, white, medium bulb, export quality\u000a\u000aमराठी नाव: Safed Lasun\u000a\u000aमूळ डेटासेट तपशील: NHRDF; export-grade white garlic; Maharashtra and Rajasthan; Nashik, Solapur.'));
INSERT INTO subtype_translations VALUES(151,'hi','Desi Kali (Local Black Garlic)','Maharashtra','Strongly pungent, purple-tinged cloves','Desi Kali (Local Black Garlic) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Desi Kali (Local Black Garlic) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Allium sativum (local landrace)\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Strongly pungent, purple-tinged cloves\u000a\u000aमराठी नाम: Desi Kali Lasun\u000a\u000aमूल डेटासेट विवरण: Indigenous variety; smaller bulb; intense flavour; drought tolerant; grown without irrigation in Marathwada.'));
INSERT INTO subtype_translations VALUES(151,'mr','Desi Kali Lasun','Maharashtra','Strongly pungent, purple-tinged cloves','Desi Kali Lasun ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Desi Kali Lasun ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Allium sativum (local landrace)\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Strongly pungent, purple-tinged cloves\u000a\u000aमराठी नाव: Desi Kali Lasun\u000a\u000aमूळ डेटासेट तपशील: Indigenous variety; smaller bulb; intense flavour; drought tolerant; grown without irrigation in Marathwada.'));
INSERT INTO subtype_translations VALUES(152,'hi','Sangli Turmeric (Erande/Rajapuri)','Maharashtra','High curcumin (>4.5%), intense golden, earthy-bitter','Sangli Turmeric (Erande/Rajapuri) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Sangli Turmeric (Erande/Rajapuri) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Curcuma longa cv. Rajapuri\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: High curcumin (>4.5%), intense golden, earthy-bitter\u000a\u000aमराठी नाम: Sangli Halad\u000a\u000aमूल डेटासेट विवरण: GI-tagged; grown in Sangli, Kolhapur, Satara; premium price; thick rhizome; dry and polished for export. Best curcumin content in world.'));
INSERT INTO subtype_translations VALUES(152,'mr','Sangli Halad','Maharashtra','High curcumin (>4.5%), intense golden, earthy-bitter','Sangli Halad ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Sangli Halad ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Curcuma longa cv. Rajapuri\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: High curcumin (>4.5%), intense golden, earthy-bitter\u000a\u000aमराठी नाव: Sangli Halad\u000a\u000aमूळ डेटासेट तपशील: GI-tagged; grown in Sangli, Kolhapur, Satara; premium price; thick rhizome; dry and polished for export. Best curcumin content in world.'));
INSERT INTO subtype_translations VALUES(153,'hi','Phule Swarnim','Maharashtra','High curcumin, good yield, improved variety','Phule Swarnim इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Phule Swarnim इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Curcuma longa cv. Phule Swarnim\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: High curcumin, good yield, improved variety\u000a\u000aमराठी नाम: Phule Swarnim Halad\u000a\u000aमूल डेटासेट विवरण: MPKV Rahuri; specifically bred for Maharashtra; high curcumin and yield; Sangli, Satara.'));
INSERT INTO subtype_translations VALUES(153,'mr','Phule Swarnim Halad','Maharashtra','High curcumin, good yield, improved variety','Phule Swarnim Halad ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Phule Swarnim Halad ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Curcuma longa cv. Phule Swarnim\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: High curcumin, good yield, improved variety\u000a\u000aमराठी नाव: Phule Swarnim Halad\u000a\u000aमूळ डेटासेट तपशील: MPKV Rahuri; specifically bred for Maharashtra; high curcumin and yield; Sangli, Satara.'));
INSERT INTO subtype_translations VALUES(154,'hi','Selam','Tamil Nadu/Maharashtra','Medium curcumin, round finger, good yield','Selam इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Selam इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Curcuma longa cv. Salem\u000a\u000aउत्पत्ति क्षेत्र: Tamil Nadu/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Medium curcumin, round finger, good yield\u000a\u000aमराठी नाम: Salem Halad\u000a\u000aमूल डेटासेट विवरण: Salem type; popular in Pune, Nashik; early maturing; bright yellow colour.'));
