INSERT INTO subtype_translations VALUES(155,'hi','Sugandham','Maharashtra','Aromatic, high oil, good curcumin','Sugandham इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Sugandham इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Curcuma longa cv. Sugandham\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Aromatic, high oil, good curcumin\u000a\u000aमराठी नाम: Sugandhi Halad\u000a\u000aमूल डेटासेट विवरण: Aromatic variety; IISR Kozhikode; adapted to Maharashtra; good for value-added products.'));
INSERT INTO subtype_translations VALUES(155,'mr','Sugandhi Halad','Maharashtra','Aromatic, high oil, good curcumin','Sugandhi Halad ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Sugandhi Halad ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Curcuma longa cv. Sugandham\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Aromatic, high oil, good curcumin\u000a\u000aमराठी नाव: Sugandhi Halad\u000a\u000aमूळ डेटासेट तपशील: Aromatic variety; IISR Kozhikode; adapted to Maharashtra; good for value-added products.'));
INSERT INTO subtype_translations VALUES(156,'hi','Pratibha','Maharashtra','High curcumin (4–5%), bold rhizome','Pratibha इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Pratibha इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Curcuma longa cv. Pratibha\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: High curcumin (4–5%), bold rhizome\u000a\u000aमराठी नाम: Pratibha Halad\u000a\u000aमूल डेटासेट विवरण: MPKV variety; Sangli and Kolhapur; high export value; disease-tolerant.'));
INSERT INTO subtype_translations VALUES(156,'mr','Pratibha Halad','Maharashtra','High curcumin (4–5%), bold rhizome','Pratibha Halad ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Pratibha Halad ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Curcuma longa cv. Pratibha\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: High curcumin (4–5%), bold rhizome\u000a\u000aमराठी नाव: Pratibha Halad\u000a\u000aमूळ डेटासेट तपशील: MPKV variety; Sangli and Kolhapur; high export value; disease-tolerant.'));
INSERT INTO subtype_translations VALUES(157,'hi','Kolhapuri Chilli (Lavangi)','Maharashtra','Extremely hot, deep red, smoky-earthy','Kolhapuri Chilli (Lavangi) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Kolhapuri Chilli (Lavangi) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Capsicum annuum cv. Lavangi\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Extremely hot, deep red, smoky-earthy\u000a\u000aमराठी नाम: Lavangi Mirchi\u000a\u000aमूल डेटासेट विवरण: GI-tagged; Kolhapur and Sangli; small, thin chilli; very high Scoville (>100,000 SHU); essential for Kolhapuri masala and dry red chilli powder; prized export variety.'));
INSERT INTO subtype_translations VALUES(157,'mr','Lavangi Mirchi','Maharashtra','Extremely hot, deep red, smoky-earthy','Lavangi Mirchi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Lavangi Mirchi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Capsicum annuum cv. Lavangi\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Extremely hot, deep red, smoky-earthy\u000a\u000aमराठी नाव: Lavangi Mirchi\u000a\u000aमूळ डेटासेट तपशील: GI-tagged; Kolhapur and Sangli; small, thin chilli; very high Scoville (>100,000 SHU); essential for Kolhapuri masala and dry red chilli powder; prized export variety.'));
INSERT INTO subtype_translations VALUES(158,'hi','Phule Jyoti','Maharashtra','Medium hot, bright red, high yield','Phule Jyoti इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Phule Jyoti इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Capsicum annuum cv. Phule Jyoti\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Medium hot, bright red, high yield\u000a\u000aमराठी नाम: Phule Jyoti Mirchi\u000a\u000aमूल डेटासेट विवरण: MPKV Rahuri; popular commercial variety; Maharashtra Kharif; good for fresh and dry use.'));
INSERT INTO subtype_translations VALUES(158,'mr','Phule Jyoti Mirchi','Maharashtra','Medium hot, bright red, high yield','Phule Jyoti Mirchi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Phule Jyoti Mirchi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Capsicum annuum cv. Phule Jyoti\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Medium hot, bright red, high yield\u000a\u000aमराठी नाव: Phule Jyoti Mirchi\u000a\u000aमूळ डेटासेट तपशील: MPKV Rahuri; popular commercial variety; Maharashtra Kharif; good for fresh and dry use.'));
INSERT INTO subtype_translations VALUES(159,'hi','Byadgi Chilli','Karnataka/Maharashtra','Mildly hot, deep red, high colour (ASTA)','Byadgi Chilli इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Byadgi Chilli इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Capsicum annuum cv. Byadgi\u000a\u000aउत्पत्ति क्षेत्र: Karnataka/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Mildly hot, deep red, high colour (ASTA)\u000a\u000aमराठी नाम: Byadgi Mirchi\u000a\u000aमूल डेटासेट विवरण: Grown in Aurangabad and Osmanabad; bright colour without high pungency; ideal for colour-extraction and masala powders; high export demand.'));
INSERT INTO subtype_translations VALUES(159,'mr','Byadgi Mirchi','Karnataka/Maharashtra','Mildly hot, deep red, high colour (ASTA)','Byadgi Mirchi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Byadgi Mirchi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Capsicum annuum cv. Byadgi\u000a\u000aउत्पत्ती क्षेत्र: Karnataka/Maharashtra\u000a\u000aचव वैशिष्ट्य: Mildly hot, deep red, high colour (ASTA)\u000a\u000aमराठी नाव: Byadgi Mirchi\u000a\u000aमूळ डेटासेट तपशील: Grown in Aurangabad and Osmanabad; bright colour without high pungency; ideal for colour-extraction and masala powders; high export demand.'));
INSERT INTO subtype_translations VALUES(160,'hi','Kashmiri Chilli (Maharashtra Grown)','Maharashtra','Very mild, deep red, high colour','Kashmiri Chilli (Maharashtra Grown) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Kashmiri Chilli (Maharashtra Grown) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Capsicum annuum cv. K-2\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very mild, deep red, high colour\u000a\u000aमराठी नाम: Kashmiri Mirchi\u000a\u000aमूल डेटासेट विवरण: Low-pungency variety grown in Maharashtra for colour; used in tandoori, butter chicken; Nashik and Aurangabad.'));
INSERT INTO subtype_translations VALUES(160,'mr','Kashmiri Mirchi','Maharashtra','Very mild, deep red, high colour','Kashmiri Mirchi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Kashmiri Mirchi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Capsicum annuum cv. K-2\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Very mild, deep red, high colour\u000a\u000aमराठी नाव: Kashmiri Mirchi\u000a\u000aमूळ डेटासेट तपशील: Low-pungency variety grown in Maharashtra for colour; used in tandoori, butter chicken; Nashik and Aurangabad.'));
INSERT INTO subtype_translations VALUES(161,'hi','Arka Meghana','Maharashtra','Hot, bold red fruit, high yield, hybrid','Arka Meghana इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Arka Meghana इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Capsicum annuum cv. Arka Meghana\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Hot, bold red fruit, high yield, hybrid\u000a\u000aमराठी नाम: Arka Meghana Mirchi\u000a\u000aमूल डेटासेट विवरण: IIHR Bengaluru F1 hybrid; adapted to Maharashtra; wilt and virus resistant; Nashik, Pune.'));
INSERT INTO subtype_translations VALUES(161,'mr','Arka Meghana Mirchi','Maharashtra','Hot, bold red fruit, high yield, hybrid','Arka Meghana Mirchi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Arka Meghana Mirchi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Capsicum annuum cv. Arka Meghana\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Hot, bold red fruit, high yield, hybrid\u000a\u000aमराठी नाव: Arka Meghana Mirchi\u000a\u000aमूळ डेटासेट तपशील: IIHR Bengaluru F1 hybrid; adapted to Maharashtra; wilt and virus resistant; Nashik, Pune.'));
INSERT INTO subtype_translations VALUES(162,'hi','Pusa Jwala','India','Very hot, green to red, thin-walled, aromatic','Pusa Jwala इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Pusa Jwala इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Capsicum annuum cv. Pusa Jwala\u000a\u000aउत्पत्ति क्षेत्र: India\u000a\u000aस्वाद प्रोफाइल: Very hot, green to red, thin-walled, aromatic\u000a\u000aमराठी नाम: Pusa Jwala Mirchi\u000a\u000aमूल डेटासेट विवरण: IARI variety; widely grown across Maharashtra; popular for fresh green and dry red market; Nashik, Aurangabad.'));
INSERT INTO subtype_translations VALUES(162,'mr','Pusa Jwala Mirchi','India','Very hot, green to red, thin-walled, aromatic','Pusa Jwala Mirchi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Pusa Jwala Mirchi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Capsicum annuum cv. Pusa Jwala\u000a\u000aउत्पत्ती क्षेत्र: India\u000a\u000aचव वैशिष्ट्य: Very hot, green to red, thin-walled, aromatic\u000a\u000aमराठी नाव: Pusa Jwala Mirchi\u000a\u000aमूळ डेटासेट तपशील: IARI variety; widely grown across Maharashtra; popular for fresh green and dry red market; Nashik, Aurangabad.'));
INSERT INTO subtype_translations VALUES(163,'hi','Mahadeo (Local Konkan)','Maharashtra','Very pungent, aromatic, high oil, spicy','Mahadeo (Local Konkan) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Mahadeo (Local Konkan) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Zingiber officinale (local landrace)\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very pungent, aromatic, high oil, spicy\u000a\u000aमराठी नाम: Konkan Aale\u000a\u000aमूल डेटासेट विवरण: Traditional high-oil landrace from Western Ghats; Satara, Kolhapur, Sindhudurg; premium dried ginger (Soonth); high gingerol content.'));
INSERT INTO subtype_translations VALUES(163,'mr','Konkan Aale','Maharashtra','Very pungent, aromatic, high oil, spicy','Konkan Aale ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Konkan Aale ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Zingiber officinale (local landrace)\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Very pungent, aromatic, high oil, spicy\u000a\u000aमराठी नाव: Konkan Aale\u000a\u000aमूळ डेटासेट तपशील: Traditional high-oil landrace from Western Ghats; Satara, Kolhapur, Sindhudurg; premium dried ginger (Soonth); high gingerol content.'));
INSERT INTO subtype_translations VALUES(164,'hi','Suprabha','India (IISR)','Pungent, high yield, good oleoresin','Suprabha इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Suprabha इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Zingiber officinale cv. Suprabha\u000a\u000aउत्पत्ति क्षेत्र: India (IISR)\u000a\u000aस्वाद प्रोफाइल: Pungent, high yield, good oleoresin\u000a\u000aमराठी नाम: Suprabha Aale\u000a\u000aमूल डेटासेट विवरण: ICAR-IISR Kozhikode; adapted to Maharashtra; high yield; good for fresh and processing market.'));
INSERT INTO subtype_translations VALUES(164,'mr','Suprabha Aale','India (IISR)','Pungent, high yield, good oleoresin','Suprabha Aale ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Suprabha Aale ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Zingiber officinale cv. Suprabha\u000a\u000aउत्पत्ती क्षेत्र: India (IISR)\u000a\u000aचव वैशिष्ट्य: Pungent, high yield, good oleoresin\u000a\u000aमराठी नाव: Suprabha Aale\u000a\u000aमूळ डेटासेट तपशील: ICAR-IISR Kozhikode; adapted to Maharashtra; high yield; good for fresh and processing market.'));
INSERT INTO subtype_translations VALUES(165,'hi','Himgiri','Himachal Pradesh/Maharashtra','Medium pungent, high yield, large rhizome','Himgiri इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Himgiri इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Zingiber officinale cv. Himgiri\u000a\u000aउत्पत्ति क्षेत्र: Himachal Pradesh/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Medium pungent, high yield, large rhizome\u000a\u000aमराठी नाम: Himgiri Aale\u000a\u000aमूल डेटासेट विवरण: Adapted to highlands; Satara and Pune hills; good fresh ginger yield.'));
INSERT INTO subtype_translations VALUES(165,'mr','Himgiri Aale','Himachal Pradesh/Maharashtra','Medium pungent, high yield, large rhizome','Himgiri Aale ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Himgiri Aale ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Zingiber officinale cv. Himgiri\u000a\u000aउत्पत्ती क्षेत्र: Himachal Pradesh/Maharashtra\u000a\u000aचव वैशिष्ट्य: Medium pungent, high yield, large rhizome\u000a\u000aमराठी नाव: Himgiri Aale\u000a\u000aमूळ डेटासेट तपशील: Adapted to highlands; Satara and Pune hills; good fresh ginger yield.'));
INSERT INTO subtype_translations VALUES(166,'hi','Rio-de-Janeiro','Brazil/Maharashtra','Mild pungent, plump rhizome, high fresh weight','Rio-de-Janeiro इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Rio-de-Janeiro इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Zingiber officinale cv. Rio-de-Janeiro\u000a\u000aउत्पत्ति क्षेत्र: Brazil/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Mild pungent, plump rhizome, high fresh weight\u000a\u000aमराठी नाम: Rio Aale\u000a\u000aमूल डेटासेट विवरण: Low fibre; preferred for fresh vegetable use; grown in Pune and Nashik irrigated areas.'));
INSERT INTO subtype_translations VALUES(166,'mr','Rio Aale','Brazil/Maharashtra','Mild pungent, plump rhizome, high fresh weight','Rio Aale ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Rio Aale ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Zingiber officinale cv. Rio-de-Janeiro\u000a\u000aउत्पत्ती क्षेत्र: Brazil/Maharashtra\u000a\u000aचव वैशिष्ट्य: Mild pungent, plump rhizome, high fresh weight\u000a\u000aमराठी नाव: Rio Aale\u000a\u000aमूळ डेटासेट तपशील: Low fibre; preferred for fresh vegetable use; grown in Pune and Nashik irrigated areas.'));
INSERT INTO subtype_translations VALUES(167,'hi','Pragati','Maharashtra','Sweet-sour, thick pulp, low seed, high yield','Pragati इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Pragati इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Tamarindus indica cv. Pragati\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet-sour, thick pulp, low seed, high yield\u000a\u000aमराठी नाम: Pragati Chincha\u000a\u000aमूल डेटासेट विवरण: Improved selection; high pulp-to-seed ratio; Maharashtra''s Marathwada belt; grafted plants available from MPKV.'));
INSERT INTO subtype_translations VALUES(167,'mr','Pragati Chincha','Maharashtra','Sweet-sour, thick pulp, low seed, high yield','Pragati Chincha ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Pragati Chincha ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Tamarindus indica cv. Pragati\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet-sour, thick pulp, low seed, high yield\u000a\u000aमराठी नाव: Pragati Chincha\u000a\u000aमूळ डेटासेट तपशील: Improved selection; high pulp-to-seed ratio; Maharashtra''s Marathwada belt; grafted plants available from MPKV.'));
INSERT INTO subtype_translations VALUES(168,'hi','PKM-1','Tamil Nadu/Maharashtra','Sour-sweet, fleshy, low fibre, high pulp','PKM-1 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('PKM-1 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Tamarindus indica cv. PKM-1\u000a\u000aउत्पत्ति क्षेत्र: Tamil Nadu/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sour-sweet, fleshy, low fibre, high pulp\u000a\u000aमराठी नाम: PKM-1 Chincha\u000a\u000aमूल डेटासेट विवरण: Tamil Nadu variety adopted in Maharashtra; high yield; early bearing grafted plants; Nashik, Aurangabad.'));
INSERT INTO subtype_translations VALUES(168,'mr','PKM-1 Chincha','Tamil Nadu/Maharashtra','Sour-sweet, fleshy, low fibre, high pulp','PKM-1 Chincha ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('PKM-1 Chincha ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Tamarindus indica cv. PKM-1\u000a\u000aउत्पत्ती क्षेत्र: Tamil Nadu/Maharashtra\u000a\u000aचव वैशिष्ट्य: Sour-sweet, fleshy, low fibre, high pulp\u000a\u000aमराठी नाव: PKM-1 Chincha\u000a\u000aमूळ डेटासेट तपशील: Tamil Nadu variety adopted in Maharashtra; high yield; early bearing grafted plants; Nashik, Aurangabad.'));
INSERT INTO subtype_translations VALUES(169,'hi','Urigam (Local)','Maharashtra','Sour, traditional, deep brown pulp','Urigam (Local) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Urigam (Local) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Tamarindus indica (local landrace)\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sour, traditional, deep brown pulp\u000a\u000aमराठी नाम: Sthanik Chincha\u000a\u000aमूल डेटासेट विवरण: Wild-type landraces grown along roads and forest margins; Marathwada; fruiting December–March; traditional harvest.'));
INSERT INTO subtype_translations VALUES(169,'mr','Sthanik Chincha','Maharashtra','Sour, traditional, deep brown pulp','Sthanik Chincha ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Sthanik Chincha ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Tamarindus indica (local landrace)\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sour, traditional, deep brown pulp\u000a\u000aमराठी नाव: Sthanik Chincha\u000a\u000aमूळ डेटासेट तपशील: Wild-type landraces grown along roads and forest margins; Marathwada; fruiting December–March; traditional harvest.'));
INSERT INTO subtype_translations VALUES(170,'hi','Pusa Early Bunching','India','Mildly bitter, leafy, quick to bolt','Pusa Early Bunching इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Pusa Early Bunching इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Trigonella foenum-graecum cv. Pusa Early Bunching\u000a\u000aउत्पत्ति क्षेत्र: India\u000a\u000aस्वाद प्रोफाइल: Mildly bitter, leafy, quick to bolt\u000a\u000aमराठी नाम: Lavkar Methi\u000a\u000aमूल डेटासेट विवरण: IARI; popular for fresh leaf market; short duration; Maharashtra Rabi; continuous harvest possible.'));
INSERT INTO subtype_translations VALUES(170,'mr','Lavkar Methi','India','Mildly bitter, leafy, quick to bolt','Lavkar Methi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Lavkar Methi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Trigonella foenum-graecum cv. Pusa Early Bunching\u000a\u000aउत्पत्ती क्षेत्र: India\u000a\u000aचव वैशिष्ट्य: Mildly bitter, leafy, quick to bolt\u000a\u000aमराठी नाव: Lavkar Methi\u000a\u000aमूळ डेटासेट तपशील: IARI; popular for fresh leaf market; short duration; Maharashtra Rabi; continuous harvest possible.'));
INSERT INTO subtype_translations VALUES(171,'hi','Kasuri Methi (IARI-PEB)','India','Strongly aromatic, small leaf, dried use','Kasuri Methi (IARI-PEB) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Kasuri Methi (IARI-PEB) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Trigonella foenum-graecum cv. Kasuri\u000a\u000aउत्पत्ति क्षेत्र: India\u000a\u000aस्वाद प्रोफाइल: Strongly aromatic, small leaf, dried use\u000a\u000aमराठी नाम: Kasuri Methi\u000a\u000aमूल डेटासेट विवरण: Small-leafed aromatic variety; dried for culinary use; grown in Nashik and Pune; premium quality.'));
INSERT INTO subtype_translations VALUES(171,'mr','Kasuri Methi','India','Strongly aromatic, small leaf, dried use','Kasuri Methi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Kasuri Methi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Trigonella foenum-graecum cv. Kasuri\u000a\u000aउत्पत्ती क्षेत्र: India\u000a\u000aचव वैशिष्ट्य: Strongly aromatic, small leaf, dried use\u000a\u000aमराठी नाव: Kasuri Methi\u000a\u000aमूळ डेटासेट तपशील: Small-leafed aromatic variety; dried for culinary use; grown in Nashik and Pune; premium quality.'));
INSERT INTO subtype_translations VALUES(172,'hi','RMt-1 (Rajasthan)','Rajasthan/Maharashtra','Bitter seeds, good leaf yield','RMt-1 (Rajasthan) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('RMt-1 (Rajasthan) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Trigonella foenum-graecum cv. RMt-1\u000a\u000aउत्पत्ति क्षेत्र: Rajasthan/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Bitter seeds, good leaf yield\u000a\u000aमराठी नाम: RMt-1 Methi\u000a\u000aमूल डेटासेट विवरण: Good seed yield; adapted to Maharashtra Rabi; Nashik, Aurangabad; used for seed and fresh leaf both.'));
INSERT INTO subtype_translations VALUES(172,'mr','RMt-1 Methi','Rajasthan/Maharashtra','Bitter seeds, good leaf yield','RMt-1 Methi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('RMt-1 Methi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Trigonella foenum-graecum cv. RMt-1\u000a\u000aउत्पत्ती क्षेत्र: Rajasthan/Maharashtra\u000a\u000aचव वैशिष्ट्य: Bitter seeds, good leaf yield\u000a\u000aमराठी नाव: RMt-1 Methi\u000a\u000aमूळ डेटासेट तपशील: Good seed yield; adapted to Maharashtra Rabi; Nashik, Aurangabad; used for seed and fresh leaf both.'));
INSERT INTO subtype_translations VALUES(173,'hi','CO-1','Maharashtra','Aromatic, high leaf yield, fresh market','CO-1 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('CO-1 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Coriandrum sativum cv. CO-1\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Aromatic, high leaf yield, fresh market\u000a\u000aमराठी नाम: CO-1 Kothimbir\u000a\u000aमूल डेटासेट विवरण: Tall plant; high green leaf yield; Nashik, Pune, Satara; widely grown for leaf market; successive harvests.'));
INSERT INTO subtype_translations VALUES(173,'mr','CO-1 Kothimbir','Maharashtra','Aromatic, high leaf yield, fresh market','CO-1 Kothimbir ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('CO-1 Kothimbir ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Coriandrum sativum cv. CO-1\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Aromatic, high leaf yield, fresh market\u000a\u000aमराठी नाव: CO-1 Kothimbir\u000a\u000aमूळ डेटासेट तपशील: Tall plant; high green leaf yield; Nashik, Pune, Satara; widely grown for leaf market; successive harvests.'));
INSERT INTO subtype_translations VALUES(174,'hi','Phule Suvarna','Maharashtra','Good seed yield, aromatic, dual purpose','Phule Suvarna इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Phule Suvarna इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Coriandrum sativum cv. Phule Suvarna\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Good seed yield, aromatic, dual purpose\u000a\u000aमराठी नाम: Phule Suvarna Kothimbir\u000a\u000aमूल डेटासेट विवरण: MPKV Rahuri; dual-purpose (leaf + seed); Nashik; Rabi; popular with cooperative farms.'));
INSERT INTO subtype_translations VALUES(174,'mr','Phule Suvarna Kothimbir','Maharashtra','Good seed yield, aromatic, dual purpose','Phule Suvarna Kothimbir ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Phule Suvarna Kothimbir ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Coriandrum sativum cv. Phule Suvarna\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Good seed yield, aromatic, dual purpose\u000a\u000aमराठी नाव: Phule Suvarna Kothimbir\u000a\u000aमूळ डेटासेट तपशील: MPKV Rahuri; dual-purpose (leaf + seed); Nashik; Rabi; popular with cooperative farms.'));
INSERT INTO subtype_translations VALUES(175,'hi','Rajendra Swati','Maharashtra','High seed yield, aromatic, good oil','Rajendra Swati इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Rajendra Swati इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Coriandrum sativum cv. Rajendra Swati\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: High seed yield, aromatic, good oil\u000a\u000aमराठी नाम: Rajendra Swati Kothimbir\u000a\u000aमूल डेटासेट विवरण: RAU Bihar; adapted to Maharashtra; high dhania (seed) yield; Nashik, Aurangabad.'));
INSERT INTO subtype_translations VALUES(175,'mr','Rajendra Swati Kothimbir','Maharashtra','High seed yield, aromatic, good oil','Rajendra Swati Kothimbir ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Rajendra Swati Kothimbir ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Coriandrum sativum cv. Rajendra Swati\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: High seed yield, aromatic, good oil\u000a\u000aमराठी नाव: Rajendra Swati Kothimbir\u000a\u000aमूळ डेटासेट तपशील: RAU Bihar; adapted to Maharashtra; high dhania (seed) yield; Nashik, Aurangabad.'));
INSERT INTO subtype_translations VALUES(176,'hi','Sugar Baby','USA/Maharashtra','Very sweet (Brix 10–12), dark green, small round','Sugar Baby इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Sugar Baby इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrullus lanatus cv. Sugar Baby\u000a\u000aउत्पत्ति क्षेत्र: USA/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very sweet (Brix 10–12), dark green, small round\u000a\u000aमराठी नाम: Sugar Baby Kalingad\u000a\u000aमूल डेटासेट विवरण: Most popular variety in Maharashtra; compact fruit; deep red flesh; sold widely in Nashik, Nashik, Solapur.'));
INSERT INTO subtype_translations VALUES(176,'mr','Sugar Baby Kalingad','USA/Maharashtra','Very sweet (Brix 10–12), dark green, small round','Sugar Baby Kalingad ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Sugar Baby Kalingad ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrullus lanatus cv. Sugar Baby\u000a\u000aउत्पत्ती क्षेत्र: USA/Maharashtra\u000a\u000aचव वैशिष्ट्य: Very sweet (Brix 10–12), dark green, small round\u000a\u000aमराठी नाव: Sugar Baby Kalingad\u000a\u000aमूळ डेटासेट तपशील: Most popular variety in Maharashtra; compact fruit; deep red flesh; sold widely in Nashik, Nashik, Solapur.'));
INSERT INTO subtype_translations VALUES(177,'hi','Arka Manik','India (IIHR)','Sweet, firm red flesh, high yield','Arka Manik इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Arka Manik इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrullus lanatus cv. Arka Manik\u000a\u000aउत्पत्ति क्षेत्र: India (IIHR)\u000a\u000aस्वाद प्रोफाइल: Sweet, firm red flesh, high yield\u000a\u000aमराठी नाम: Arka Manik Kalingad\u000a\u000aमूल डेटासेट विवरण: IIHR Bengaluru; striped green fruit; high sugar; 5–8 kg fruit; Nashik, Aurangabad.'));
INSERT INTO subtype_translations VALUES(177,'mr','Arka Manik Kalingad','India (IIHR)','Sweet, firm red flesh, high yield','Arka Manik Kalingad ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Arka Manik Kalingad ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrullus lanatus cv. Arka Manik\u000a\u000aउत्पत्ती क्षेत्र: India (IIHR)\u000a\u000aचव वैशिष्ट्य: Sweet, firm red flesh, high yield\u000a\u000aमराठी नाव: Arka Manik Kalingad\u000a\u000aमूळ डेटासेट तपशील: IIHR Bengaluru; striped green fruit; high sugar; 5–8 kg fruit; Nashik, Aurangabad.'));
INSERT INTO subtype_translations VALUES(178,'hi','Phule Indrayani (Seedless)','Maharashtra','Sweet, seedless, crisp','Phule Indrayani (Seedless) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Phule Indrayani (Seedless) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrullus lanatus cv. Phule Indrayani\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, seedless, crisp\u000a\u000aमराठी नाम: Bijrahit Kalingad\u000a\u000aमूल डेटासेट विवरण: MPKV Rahuri seedless hybrid; premium market; Nashik valley; polliniser plants required.'));
INSERT INTO subtype_translations VALUES(178,'mr','Bijrahit Kalingad','Maharashtra','Sweet, seedless, crisp','Bijrahit Kalingad ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Bijrahit Kalingad ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrullus lanatus cv. Phule Indrayani\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, seedless, crisp\u000a\u000aमराठी नाव: Bijrahit Kalingad\u000a\u000aमूळ डेटासेट तपशील: MPKV Rahuri seedless hybrid; premium market; Nashik valley; polliniser plants required.'));
INSERT INTO subtype_translations VALUES(179,'hi','NS-295 (Namdhari)','Maharashtra','Very sweet, oblong, striped, red flesh','NS-295 (Namdhari) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('NS-295 (Namdhari) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrullus lanatus cv. NS-295\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very sweet, oblong, striped, red flesh\u000a\u000aमराठी नाम: NS-295 Kalingad\u000a\u000aमूल डेटासेट विवरण: Namdhari Seeds F1; very high yield; Nashik, Solapur; excellent transport quality; large 8–10 kg fruit.'));
INSERT INTO subtype_translations VALUES(179,'mr','NS-295 Kalingad','Maharashtra','Very sweet, oblong, striped, red flesh','NS-295 Kalingad ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('NS-295 Kalingad ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrullus lanatus cv. NS-295\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Very sweet, oblong, striped, red flesh\u000a\u000aमराठी नाव: NS-295 Kalingad\u000a\u000aमूळ डेटासेट तपशील: Namdhari Seeds F1; very high yield; Nashik, Solapur; excellent transport quality; large 8–10 kg fruit.'));
INSERT INTO subtype_translations VALUES(180,'hi','Arka Rajhans','India (IIHR)','Very sweet, orange flesh, aromatic, netted skin','Arka Rajhans इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Arka Rajhans इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Cucumis melo cv. Arka Rajhans\u000a\u000aउत्पत्ति क्षेत्र: India (IIHR)\u000a\u000aस्वाद प्रोफाइल: Very sweet, orange flesh, aromatic, netted skin\u000a\u000aमराठी नाम: Arka Rajhans Kharbuja\u000a\u000aमूल डेटासेट विवरण: IIHR Bengaluru; popular in Maharashtra; cantaloupe type; netted rind; high Brix 12–14.'));
INSERT INTO subtype_translations VALUES(180,'mr','Arka Rajhans Kharbuja','India (IIHR)','Very sweet, orange flesh, aromatic, netted skin','Arka Rajhans Kharbuja ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Arka Rajhans Kharbuja ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Cucumis melo cv. Arka Rajhans\u000a\u000aउत्पत्ती क्षेत्र: India (IIHR)\u000a\u000aचव वैशिष्ट्य: Very sweet, orange flesh, aromatic, netted skin\u000a\u000aमराठी नाव: Arka Rajhans Kharbuja\u000a\u000aमूळ डेटासेट तपशील: IIHR Bengaluru; popular in Maharashtra; cantaloupe type; netted rind; high Brix 12–14.'));
INSERT INTO subtype_translations VALUES(181,'hi','Hara Madhu','India','Sweet, green flesh, smooth skin','Hara Madhu इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Hara Madhu इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Cucumis melo cv. Hara Madhu\u000a\u000aउत्पत्ति क्षेत्र: India\u000a\u000aस्वाद प्रोफाइल: Sweet, green flesh, smooth skin\u000a\u000aमराठी नाम: Hara Madhu Kharbuja\u000a\u000aमूल डेटासेट विवरण: Pale green smooth skin; classic Indian muskmelon; grown across Maharashtra; affordable and popular.'));
INSERT INTO subtype_translations VALUES(181,'mr','Hara Madhu Kharbuja','India','Sweet, green flesh, smooth skin','Hara Madhu Kharbuja ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Hara Madhu Kharbuja ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Cucumis melo cv. Hara Madhu\u000a\u000aउत्पत्ती क्षेत्र: India\u000a\u000aचव वैशिष्ट्य: Sweet, green flesh, smooth skin\u000a\u000aमराठी नाव: Hara Madhu Kharbuja\u000a\u000aमूळ डेटासेट तपशील: Pale green smooth skin; classic Indian muskmelon; grown across Maharashtra; affordable and popular.'));
INSERT INTO subtype_translations VALUES(182,'hi','Phule Shreshtha','Maharashtra','Sweet, high yield, good keeping quality','Phule Shreshtha इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Phule Shreshtha इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Cucumis melo cv. Phule Shreshtha\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, high yield, good keeping quality\u000a\u000aमराठी नाम: Phule Shreshtha Kharbuja\u000a\u000aमूल डेटासेट विवरण: MPKV Rahuri; recommended for Maharashtra summer; Nashik, Pune; medium-large fruit.'));
INSERT INTO subtype_translations VALUES(182,'mr','Phule Shreshtha Kharbuja','Maharashtra','Sweet, high yield, good keeping quality','Phule Shreshtha Kharbuja ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Phule Shreshtha Kharbuja ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Cucumis melo cv. Phule Shreshtha\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, high yield, good keeping quality\u000a\u000aमराठी नाव: Phule Shreshtha Kharbuja\u000a\u000aमूळ डेटासेट तपशील: MPKV Rahuri; recommended for Maharashtra summer; Nashik, Pune; medium-large fruit.'));
INSERT INTO subtype_translations VALUES(183,'hi','Sai Sharbati','Maharashtra','Acidic, juicy, thin-skinned, aromatic','Sai Sharbati इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Sai Sharbati इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrus limon cv. Sai Sharbati\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Acidic, juicy, thin-skinned, aromatic\u000a\u000aमराठी नाम: Sai Sharbati Limbu\u000a\u000aमूल डेटासेट विवरण: Popular commercial variety in Maharashtra; Nashik, Pune; high juice content; year-round fruiting.'));
INSERT INTO subtype_translations VALUES(183,'mr','Sai Sharbati Limbu','Maharashtra','Acidic, juicy, thin-skinned, aromatic','Sai Sharbati Limbu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Sai Sharbati Limbu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrus limon cv. Sai Sharbati\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Acidic, juicy, thin-skinned, aromatic\u000a\u000aमराठी नाव: Sai Sharbati Limbu\u000a\u000aमूळ डेटासेट तपशील: Popular commercial variety in Maharashtra; Nashik, Pune; high juice content; year-round fruiting.'));
INSERT INTO subtype_translations VALUES(184,'hi','Phule Saurabh','Maharashtra','Acidic, aromatic, high juice, soft rind','Phule Saurabh इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Phule Saurabh इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrus limon cv. Phule Saurabh\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Acidic, aromatic, high juice, soft rind\u000a\u000aमराठी नाम: Phule Saurabh Limbu\u000a\u000aमूल डेटासेट विवरण: MPKV Rahuri; improved lemon variety; suitable for drip-irrigated orchards; Nashik, Aurangabad.'));
INSERT INTO subtype_translations VALUES(184,'mr','Phule Saurabh Limbu','Maharashtra','Acidic, aromatic, high juice, soft rind','Phule Saurabh Limbu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Phule Saurabh Limbu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrus limon cv. Phule Saurabh\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Acidic, aromatic, high juice, soft rind\u000a\u000aमराठी नाव: Phule Saurabh Limbu\u000a\u000aमूळ डेटासेट तपशील: MPKV Rahuri; improved lemon variety; suitable for drip-irrigated orchards; Nashik, Aurangabad.'));
INSERT INTO subtype_translations VALUES(185,'hi','Seedless Lime','Maharashtra','Acidic, thin-skinned, nearly seedless','Seedless Lime इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Seedless Lime इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrus aurantiifolia (seedless type)\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Acidic, thin-skinned, nearly seedless\u000a\u000aमराठी नाम: Bijrahit Limbu\u000a\u000aमूल डेटासेट विवरण: Acid lime type; Konkan and Pune; very popular for household use and street food vendors.'));
INSERT INTO subtype_translations VALUES(185,'mr','Bijrahit Limbu','Maharashtra','Acidic, thin-skinned, nearly seedless','Bijrahit Limbu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Bijrahit Limbu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrus aurantiifolia (seedless type)\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Acidic, thin-skinned, nearly seedless\u000a\u000aमराठी नाव: Bijrahit Limbu\u000a\u000aमूळ डेटासेट तपशील: Acid lime type; Konkan and Pune; very popular for household use and street food vendors.'));
INSERT INTO subtype_translations VALUES(186,'hi','Eureka Lemon','USA/Maharashtra','Strongly acidic, aromatic, thick-skinned','Eureka Lemon इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Eureka Lemon इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrus limon cv. Eureka\u000a\u000aउत्पत्ति क्षेत्र: USA/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Strongly acidic, aromatic, thick-skinned\u000a\u000aमराठी नाम: Eureka Limbu\u000a\u000aमूल डेटासेट विवरण: Introduced variety; grown in Nashik and Pune; export-quality large lemon; increasing adoption.'));
INSERT INTO subtype_translations VALUES(186,'mr','Eureka Limbu','USA/Maharashtra','Strongly acidic, aromatic, thick-skinned','Eureka Limbu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Eureka Limbu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrus limon cv. Eureka\u000a\u000aउत्पत्ती क्षेत्र: USA/Maharashtra\u000a\u000aचव वैशिष्ट्य: Strongly acidic, aromatic, thick-skinned\u000a\u000aमराठी नाव: Eureka Limbu\u000a\u000aमूळ डेटासेट तपशील: Introduced variety; grown in Nashik and Pune; export-quality large lemon; increasing adoption.'));
