INSERT INTO local_fertilizers VALUES(1,'Neem Coated Urea','Nitrogen fertilizer','National Fertilizers Limited','India','Government-approved nitrogen fertilizer designed to release nitrogen gradually and reduce nutrient loss in Indian field conditions.','Nitrogen 46% with neem oil coating for controlled release.','Basal and top dressing nitrogen nutrition for cereals, sugarcane, cotton and vegetables.','Wheat, maize, paddy, sugarcane, cotton, onion and leafy vegetables.','Avoid direct seed contact, waterlogged fields and crops under severe drought stress.','Broadcast evenly and incorporate into moist soil. Split application is recommended for long-duration crops.','Basal dose and active vegetative growth stage.','Kharif and rabi.','18-35 C.','Alluvial, black cotton and medium-textured soils with adequate moisture.','Supports steady vegetative growth, improves nitrogen use efficiency and helps reduce volatilization losses.','Use soil-test based dosage, wear gloves, and do not over-apply near water bodies.','/assets/agri-inputs/local-neem-urea.svg','active','/resources/neem-coated-urea-guide.txt','Government of India fertilizer control approved category','Recommended across Maharashtra for cereals, sugarcane and onion under guided nutrient plans.','2026-06-20T16:26:46+00:00','2026-06-20T16:26:46+00:00');
INSERT INTO local_fertilizers VALUES(2,'City Compost Organic Manure','Organic fertilizer','Maharashtra Agro Industries Development Corporation','India','Organic manure option for soil health improvement, carbon addition and balanced microbial activity in regional farming systems.','Organic carbon, humic matter, secondary nutrients and beneficial microbial activity.','Soil conditioning, organic carbon improvement and pre-planting manure application.','Grapes, pomegranate, banana, vegetables, pulses, cereals and orchard crops.','Avoid fresh application near tender seedlings without proper compost maturity confirmation.','Apply during land preparation and mix well into the root zone.','Before sowing, before transplanting and during orchard basin preparation.','Pre-kharif, pre-rabi and orchard annual nutrition cycle.','15-38 C.','Low-organic-carbon soils, black soils and light soils needing structure improvement.','Improves soil structure, moisture holding, microbial activity and long-term nutrient availability.','Use mature compost only and avoid mixing directly with concentrated chemical fertilizers during storage.','/assets/agri-inputs/local-city-compost.svg','active','/resources/city-compost-guide.txt','Organic input aligned with government soil health improvement programmes','Useful for Nashik and Yeola orchards where organic carbon rebuilding is a priority.','2026-06-20T16:26:46+00:00','2026-06-20T16:26:46+00:00');
INSERT INTO imported_fertilizers VALUES(1,'YaraMila Complex 12-11-18','NPK complex fertilizer','Yara International','Norway','Premium imported NPK formulation for balanced macronutrient supply and quality-focused crop development.','NPK 12-11-18 with sulphur, magnesium and crop-available micronutrient support.','Balanced nutrition for high-value crops requiring uniform granule quality and predictable nutrient release.','Grapes, pomegranate, banana, vegetables, floriculture and protected cultivation crops.','Avoid salt-sensitive nursery crops and direct placement near tender roots without irrigation.','Apply through soil broadcasting, band placement or fertigation-compatible programmes as advised.','Vegetative growth, flowering support and early fruit development.','Year-round for irrigated high-value crops.','16-34 C.','Well-drained loam, black soil and managed orchard soils.','Supports uniform growth, flowering, fruit size and premium quality output.','Follow crop-specific dosage, avoid mixing with incompatible alkaline materials and store in a dry place.','/assets/agri-inputs/imported-yaramila.svg','active','/resources/yaramila-product-specification.txt','YaraMila','Importer quality documentation, batch certificate and compliant product labelling required.','European granulation standards with declared nutrient composition and traceability.','2026-06-20T16:26:46+00:00','2026-06-20T16:26:46+00:00');
INSERT INTO imported_fertilizers VALUES(2,'Haifa Multi-K Potassium Nitrate','Water soluble fertilizer','Haifa Group','Israel','High-purity imported potassium nitrate used for precision fertigation, fruit quality and stress-stage nutrition.','Potassium nitrate with nitrate nitrogen and fully water-soluble potassium.','Fertigation, foliar feeding and precision crop nutrition programmes.','Grapes, pomegranate, banana, tomato, chilli, capsicum, cucumber and export-oriented vegetables.','Avoid use on crops under severe water stress or with incompatible calcium-rich tank mixes.','Apply through drip fertigation or foliar spray as per agronomist dosage guidance.','Flowering, fruit setting, fruit sizing and quality development stages.','Irrigated crop cycles and protected cultivation seasons.','14-32 C.','Drip-irrigated soils with managed EC and pH.','Improves fruit size, colour, sugar accumulation and potassium-driven crop quality.','Check water pH and EC, avoid excessive foliar concentration and follow label directions.','/assets/agri-inputs/imported-haifa-multik.svg','active','/resources/haifa-multik-specification.txt','Multi-K','Product import documentation, certificate of analysis and batch traceability required.','High-purity crystalline water-soluble fertilizer for fertigation systems.','2026-06-20T16:26:46+00:00','2026-06-20T16:26:46+00:00');
INSERT INTO local_fertilizer_translations VALUES(1,1,'hi','नीम लेपित यूरिया','नाइट्रोजन उर्वरक','सरकार द्वारा अनुमोदित नाइट्रोजन उर्वरक, जो भारतीय खेत परिस्थितियों में नाइट्रोजन को धीरे-धीरे उपलब्ध कराने और पोषक तत्वों की हानि कम करने में मदद करता है।','नियंत्रित रिलीज के लिए नीम तेल लेप के साथ 46% नाइट्रोजन।','अनाज, गन्ना, कपास और सब्जियों में बेसल तथा टॉप ड्रेसिंग नाइट्रोजन पोषण।','स्थिर वानस्पतिक वृद्धि, बेहतर नाइट्रोजन उपयोग दक्षता और वाष्पीकरण हानि में कमी।','मिट्टी परीक्षण आधारित मात्रा का उपयोग करें, दस्ताने पहनें और जल स्रोतों के पास अधिक मात्रा न डालें।','2026-06-22T07:56:31+00:00','2026-06-30T11:47:42+00:00','भारत','गेहूं, मक्का, धान, गन्ना, कपास, प्याज और पत्तेदार सब्जियां।','बीज के सीधे संपर्क, जलभराव वाले खेतों और गंभीर सूखे तनाव वाली फसलों में उपयोग से बचें।','नम मिट्टी में समान रूप से छिड़कें और हल्का मिला दें। लंबी अवधि की फसलों में विभाजित मात्रा देना बेहतर है।','बेसल मात्रा और सक्रिय वानस्पतिक वृद्धि अवस्था।','खरीफ और रबी।','18-35 C.','पर्याप्त नमी वाली जलोढ़, काली कपास और मध्यम बनावट की मिट्टी।','भारत सरकार के उर्वरक नियंत्रण अनुमोदित वर्ग के अंतर्गत।','महाराष्ट्र में अनाज, गन्ना और प्याज के लिए मार्गदर्शित पोषण योजना के तहत अनुशंसित।','','','');
INSERT INTO local_fertilizer_translations VALUES(2,1,'mr','नीम लेपित युरिया','नायट्रोजन खत','भारतीय शेती परिस्थितीत नायट्रोजन हळूहळू उपलब्ध करून पोषक घटकांची हानी कमी करण्यासाठी तयार केलेले शासनमान्य नायट्रोजन खत.','नियंत्रित उपलब्धतेसाठी नीम तेलाच्या लेपासह 46% नायट्रोजन.','तृणधान्ये, ऊस, कापूस आणि भाजीपाला पिकांसाठी बेसल व टॉप ड्रेसिंग नायट्रोजन पोषण.','समतोल वाढ, नायट्रोजन वापर कार्यक्षमता आणि उडून जाणारी हानी कमी करण्यास मदत.','माती परीक्षणानुसार मात्रा द्या, हातमोजे वापरा आणि पाणवठ्याजवळ अतिमात्रा टाळा.','2026-06-22T07:56:31+00:00','2026-06-30T11:47:42+00:00','भारत','गहू, मका, भात, ऊस, कापूस, कांदा आणि पालेभाज्या.','बियाण्याशी थेट संपर्क, पाणी साचलेली शेते आणि तीव्र दुष्काळ ताण असलेली पिके टाळा.','ओलसर मातीत समप्रमाणात पसरवून हलके मिसळा. दीर्घ कालावधीच्या पिकांसाठी विभागून मात्रा देणे योग्य.','बेसल मात्रा आणि सक्रिय वाढीची अवस्था.','खरीप आणि रबी.','18-35 C.','पुरेशी ओल असलेली गाळाची, काळी कापूस व मध्यम पोताची माती.','भारत सरकारच्या खत नियंत्रण मान्य श्रेणीअंतर्गत.','महाराष्ट्रात तृणधान्ये, ऊस आणि कांदा पिकांसाठी मार्गदर्शित पोषण योजनेत अनुशंसित.','','','');
INSERT INTO local_fertilizer_translations VALUES(3,2,'hi','सिटी कम्पोस्ट जैविक खाद','जैविक उर्वरक','मिट्टी स्वास्थ्य सुधार, कार्बन वृद्धि और क्षेत्रीय खेती प्रणालियों में संतुलित सूक्ष्मजीव गतिविधि के लिए जैविक खाद विकल्प।','जैविक कार्बन, ह्यूमिक पदार्थ, द्वितीयक पोषक तत्व और लाभकारी सूक्ष्मजीव गतिविधि।','मिट्टी सुधार, जैविक कार्बन बढ़ाने और रोपाई/बुवाई से पहले खाद के रूप में।','मिट्टी की संरचना, नमी धारण क्षमता, सूक्ष्मजीव गतिविधि और दीर्घकालीन पोषक उपलब्धता में सुधार।','केवल परिपक्व कम्पोस्ट का उपयोग करें और भंडारण में इसे सघन रासायनिक उर्वरकों के साथ सीधे न मिलाएं।','2026-06-22T07:56:31+00:00','2026-06-30T11:47:42+00:00','भारत','अंगूर, अनार, केला, सब्जियां, दलहन, अनाज और बागवानी फसलें।','पूरी तरह पकी खाद की पुष्टि के बिना नाजुक पौधों के पास ताजा उपयोग न करें।','भूमि तैयारी के समय डालें और जड़ क्षेत्र में अच्छी तरह मिलाएं।','बुवाई से पहले, रोपाई से पहले और बागों में बेसिन तैयारी के समय।','पूर्व-खरीफ, पूर्व-रबी और बागों का वार्षिक पोषण चक्र।','15-38 C.','कम जैविक कार्बन वाली, काली और संरचना सुधार की जरूरत वाली हल्की मिट्टियां।','सरकारी मिट्टी स्वास्थ्य सुधार कार्यक्रमों से जुड़ा जैविक इनपुट।','नाशिक और येवला के बागों में जैविक कार्बन पुनर्निर्माण के लिए उपयोगी।','','','');
INSERT INTO local_fertilizer_translations VALUES(4,2,'mr','सिटी कम्पोस्ट सेंद्रिय खत','सेंद्रिय खत','मातीचे आरोग्य सुधारणा, कार्बन वाढ आणि प्रादेशिक शेती पद्धतींमध्ये संतुलित सूक्ष्मजीव क्रियेसाठी सेंद्रिय खताचा पर्याय.','सेंद्रिय कार्बन, ह्युमिक घटक, दुय्यम पोषक घटक आणि उपयुक्त सूक्ष्मजीव क्रिया.','माती सुधारणा, सेंद्रिय कार्बन वाढ आणि लागवडीपूर्व खत म्हणून वापर.','मातीची रचना, ओल धारण क्षमता, सूक्ष्मजीव क्रिया आणि दीर्घकालीन पोषक उपलब्धता सुधारते.','परिपक्व कम्पोस्टच वापरा आणि साठवणीत तीव्र रासायनिक खतांसोबत थेट मिसळू नका.','2026-06-22T07:56:31+00:00','2026-06-30T11:47:42+00:00','भारत','द्राक्षे, डाळिंब, केळी, भाजीपाला, कडधान्ये, तृणधान्ये आणि फळबाग पिके.','खत पूर्णपणे परिपक्व असल्याची खात्री नसल्यास कोवळ्या रोपांजवळ ताजा वापर टाळा.','जमीन तयारीच्या वेळी टाका आणि मुळांच्या भागात व्यवस्थित मिसळा.','पेरणीपूर्वी, लागवडीपूर्वी आणि बागेतील बेसिन तयारीच्या वेळी.','पूर्व-खरीप, पूर्व-रबी आणि बागांचा वार्षिक पोषण चक्र.','15-38 C.','कमी सेंद्रिय कार्बन असलेली, काळी आणि रचना सुधारण्याची गरज असलेली हलकी माती.','शासकीय माती आरोग्य सुधार कार्यक्रमांशी सुसंगत सेंद्रिय इनपुट.','नाशिक आणि येवला भागातील बागांसाठी सेंद्रिय कार्बन वाढवण्यास उपयुक्त.','','','');
INSERT INTO imported_fertilizer_translations VALUES(1,1,'hi','YaraMila कॉम्प्लेक्स 12-11-18','एनपीके कॉम्प्लेक्स उर्वरक','संतुलित मुख्य पोषक तत्वों और गुणवत्ता-केंद्रित फसल विकास के लिए प्रीमियम आयातित एनपीके फॉर्मुलेशन।','सल्फर, मैग्नीशियम और उपलब्ध सूक्ष्म पोषक समर्थन के साथ NPK 12-11-18।','समान ग्रेन्यूल गुणवत्ता और अनुमानित पोषक रिलीज चाहने वाली उच्च-मूल्य फसलों के लिए संतुलित पोषण।','समान वृद्धि, फूल, फल आकार और प्रीमियम गुणवत्ता उत्पादन में मदद।','फसल-विशिष्ट मात्रा अपनाएं, असंगत क्षारीय सामग्री से मिश्रण न करें और सूखी जगह पर रखें।','2026-06-22T07:56:31+00:00','2026-06-30T11:47:42+00:00','नॉर्वे','अंगूर, अनार, केला, सब्जियां, फूलों की खेती और संरक्षित खेती की फसलें।','नमक-संवेदनशील नर्सरी फसलों और सिंचाई के बिना कोमल जड़ों के पास सीधे उपयोग से बचें।','सलाह के अनुसार मिट्टी में छिड़काव, बैंड प्लेसमेंट या फर्टिगेशन कार्यक्रम में उपयोग करें।','वानस्पतिक वृद्धि, फूल समर्थन और प्रारंभिक फल विकास।','सिंचित उच्च-मूल्य फसलों के लिए वर्षभर।','16-34 C.','अच्छी जलनिकासी वाली दोमट, काली और प्रबंधित बाग मिट्टी।','','','YaraMila','आयातक गुणवत्ता दस्तावेज, बैच प्रमाणपत्र और अनुरूप उत्पाद लेबलिंग आवश्यक।','घोषित पोषक संरचना और ट्रेसबिलिटी के साथ यूरोपीय ग्रेनुलेशन मानक।');
INSERT INTO imported_fertilizer_translations VALUES(2,1,'mr','YaraMila कॉम्प्लेक्स 12-11-18','एनपीके कॉम्प्लेक्स खत','समतोल मुख्य पोषक पुरवठा आणि गुणवत्तापूर्ण पीक विकासासाठी प्रीमियम आयातित एनपीके फॉर्म्युलेशन.','सल्फर, मॅग्नेशियम आणि उपलब्ध सूक्ष्म पोषक समर्थनासह NPK 12-11-18.','एकसमान दाणेदार गुणवत्ता आणि अंदाजित पोषक उपलब्धता हवी असलेल्या उच्च-मूल्य पिकांसाठी समतोल पोषण.','समतोल वाढ, फुलोरा, फळांचा आकार आणि प्रीमियम दर्जाचे उत्पादन यास मदत.','पीकनिहाय मात्रा पाळा, विसंगत क्षारीय पदार्थांशी मिश्रण टाळा आणि कोरड्या ठिकाणी साठवा.','2026-06-22T07:56:31+00:00','2026-06-30T11:47:42+00:00','नॉर्वे','द्राक्षे, डाळिंब, केळी, भाजीपाला, फुलशेती आणि संरक्षित शेतीतील पिके.','मीठ-संवेदनशील नर्सरी पिके आणि सिंचनाशिवाय कोवळ्या मुळांजवळ थेट वापर टाळा.','सल्ल्यानुसार मातीवर पसरवणे, बँड प्लेसमेंट किंवा फर्टिगेशन कार्यक्रमात वापरा.','वानस्पतिक वाढ, फुलोरा समर्थन आणि प्रारंभिक फलधारणा.','सिंचित उच्च-मूल्य पिकांसाठी वर्षभर.','16-34 C.','चांगला निचरा असलेली दोमट, काळी आणि व्यवस्थापित बाग माती.','','','YaraMila','आयात गुणवत्ता कागदपत्रे, बॅच प्रमाणपत्र आणि अनुरूप उत्पादन लेबलिंग आवश्यक.','घोषित पोषक संरचना आणि ट्रेसेबिलिटीसह युरोपीय दाणेदार मानके.');
INSERT INTO imported_fertilizer_translations VALUES(3,2,'hi','Haifa Multi-K पोटैशियम नाइट्रेट','जल घुलनशील उर्वरक','प्रिसिजन फर्टिगेशन, फल गुणवत्ता और तनाव अवस्था पोषण के लिए उच्च-शुद्धता आयातित पोटैशियम नाइट्रेट।','नाइट्रेट नाइट्रोजन और पूर्णतः जल-घुलनशील पोटैशियम के साथ पोटैशियम नाइट्रेट।','फर्टिगेशन, पर्णीय छिड़काव और प्रिसिजन फसल पोषण कार्यक्रम।','फल आकार, रंग, शर्करा संचय और पोटैशियम-आधारित गुणवत्ता में सुधार।','पानी का pH और EC जांचें, अधिक पर्णीय सांद्रता से बचें और लेबल निर्देशों का पालन करें।','2026-06-22T07:56:31+00:00','2026-06-30T11:47:42+00:00','इजराइल','अंगूर, अनार, केला, टमाटर, मिर्च, शिमला मिर्च, ककड़ी और निर्यात-उन्मुख सब्जियां।','गंभीर जल तनाव वाली फसलों या कैल्शियम-समृद्ध असंगत टैंक मिश्रणों में उपयोग से बचें।','कृषि विशेषज्ञ की मात्रा सलाह के अनुसार ड्रिप फर्टिगेशन या पर्णीय स्प्रे से उपयोग करें।','फूल, फल सेटिंग, फल आकार और गुणवत्ता विकास अवस्था।','सिंचित फसल चक्र और संरक्षित खेती के मौसम।','14-32 C.','प्रबंधित EC और pH वाली ड्रिप-सिंचित मिट्टियां।','','','Multi-K','उत्पाद आयात दस्तावेज, विश्लेषण प्रमाणपत्र और बैच ट्रेसबिलिटी आवश्यक।','फर्टिगेशन प्रणालियों के लिए उच्च-शुद्धता क्रिस्टलीय जल-घुलनशील उर्वरक।');
INSERT INTO imported_fertilizer_translations VALUES(4,2,'mr','Haifa Multi-K पोटॅशियम नायट्रेट','पाण्यात विद्रव्य खत','प्रिसिजन फर्टिगेशन, फळ गुणवत्ता आणि ताण अवस्थेतील पोषणासाठी उच्च-शुद्धतेचे आयातित पोटॅशियम नायट्रेट.','नायट्रेट नायट्रोजन आणि पूर्णपणे पाण्यात विद्रव्य पोटॅशियमसह पोटॅशियम नायट्रेट.','फर्टिगेशन, पानांवर फवारणी आणि अचूक पीक पोषण कार्यक्रम.','फळांचा आकार, रंग, साखर संचय आणि पोटॅशियम-आधारित गुणवत्ता सुधारते.','पाण्याचा pH आणि EC तपासा, जास्त पर्णीय सांद्रता टाळा आणि लेबलवरील सूचना पाळा.','2026-06-22T07:56:31+00:00','2026-06-30T11:47:42+00:00','इस्रायल','द्राक्षे, डाळिंब, केळी, टोमॅटो, मिरची, ढोबळी मिरची, काकडी आणि निर्याताभिमुख भाजीपाला.','तीव्र पाण्याच्या ताणाखालील पिके किंवा कॅल्शियमयुक्त विसंगत टँक मिश्रणात वापर टाळा.','कृषी तज्ज्ञांच्या मात्रेनुसार ड्रिप फर्टिगेशन किंवा पानांवरील फवारणीद्वारे वापरा.','फुलोरा, फलधारणा, फळ वाढ आणि गुणवत्ता विकास अवस्था.','सिंचित पीक चक्र आणि संरक्षित शेती हंगाम.','14-32 C.','नियंत्रित EC आणि pH असलेली ड्रिप-सिंचित माती.','','','Multi-K','उत्पादन आयात कागदपत्रे, विश्लेषण प्रमाणपत्र आणि बॅच ट्रेसेबिलिटी आवश्यक.','फर्टिगेशन प्रणालींसाठी उच्च-शुद्धतेचे स्फटिकीय पाण्यात विद्रव्य खत.');
INSERT INTO company_stories VALUES(1,'From the Farms of Yeola (Nashik) to the World','home-hero','en','GreenWings connects farmer knowledge, natural farming values and market-ready systems so rural prosperity can travel from local fields to global opportunities.','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/serious_discussion_in_farm.png',1,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(2,'येवला (नाशिक) के खेतों से दुनिया तक','home-hero','hi','ग्रीनविंग्स किसान ज्ञान, प्राकृतिक खेती और बाजार-तैयार प्रणालियों को जोड़ता है ताकि ग्रामीण समृद्धि स्थानीय खेतों से वैश्विक अवसरों तक पहुंचे।','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/serious_discussion_in_farm.png',1,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(3,'येवला (नाशिक) च्या शेतातून जगभर','home-hero','mr','ग्रीनविंग्स शेतकरी ज्ञान, नैसर्गिक शेती मूल्ये आणि बाजारपेठेसाठी तयार प्रणाली जोडून ग्रामीण समृद्धी जागतिक संधींपर्यंत पोहोचवते.','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/serious_discussion_in_farm.png',1,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(4,'Farmers Connected: 1,100+','home-stat-farmers','en','A growing community of farmers is connected through GreenWings training, advisory, input support and market-linkage programmes.','',2,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(5,'किसान जुड़े: 1,100+','home-stat-farmers','hi','ग्रीनविंग्स प्रशिक्षण, सलाह, इनपुट सहयोग और बाजार संपर्क के माध्यम से किसानों का बढ़ता समुदाय जोड़ रहा है।','',2,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(6,'जोडलेले शेतकरी: 1,100+','home-stat-farmers','mr','ग्रीनविंग्स प्रशिक्षण, सल्ला, इनपुट सहाय्य आणि बाजार जोडणीद्वारे वाढता शेतकरी समुदाय जोडत आहे.','',2,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(7,'Knowledge Sharing','community-knowledge-sharing','en','GreenWings creates farmer learning circles where practical field experience, scientific guidance and seasonal crop planning are shared openly.','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/Serious_disciussion_in_another_farm.png',10,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(8,'ज्ञान साझा करना','community-knowledge-sharing','hi','ग्रीनविंग्स किसान सीखने के समूह बनाता है जहां खेत का अनुभव, वैज्ञानिक सलाह और मौसमी फसल योजना खुले रूप से साझा की जाती है।','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/Serious_disciussion_in_another_farm.png',10,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(9,'ज्ञानाची देवाणघेवाण','community-knowledge-sharing','mr','ग्रीनविंग्स शेतकरी शिक्षण गट तयार करते जिथे प्रत्यक्ष शेतातील अनुभव, वैज्ञानिक मार्गदर्शन आणि हंगामी पीक नियोजन खुलेपणाने शेअर केले जाते.','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/Serious_disciussion_in_another_farm.png',10,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(10,'Farmer Networking','community-farmer-networking','en','The platform strengthens farmer-to-farmer relationships so members can collaborate on cultivation, aggregation, market access and collective growth.','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/a_few_more_farmers.png',11,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(11,'किसान नेटवर्किंग','community-farmer-networking','hi','यह मंच किसानों के बीच सहयोग को मजबूत करता है ताकि खेती, संग्रह, बाजार पहुंच और सामूहिक विकास में साझेदारी बढ़े।','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/a_few_more_farmers.png',11,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(12,'शेतकरी नेटवर्किंग','community-farmer-networking','mr','हे व्यासपीठ शेतकरी-ते-शेतकरी नाते मजबूत करते, ज्यामुळे लागवड, संकलन, बाजार प्रवेश आणि सामूहिक वाढीत सहकार्य वाढते.','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/a_few_more_farmers.png',11,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(13,'Training Programs','community-training-programs','en','Training programmes help farmers adopt better practices in soil health, crop nutrition, post-harvest handling and digital market readiness.','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/Farmers_with_livestacks.png',12,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(14,'प्रशिक्षण कार्यक्रम','community-training-programs','hi','प्रशिक्षण कार्यक्रम किसानों को मिट्टी स्वास्थ्य, फसल पोषण, कटाई के बाद प्रबंधन और डिजिटल बाजार तैयारी में बेहतर अभ्यास अपनाने में मदद करते हैं।','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/Farmers_with_livestacks.png',12,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(15,'प्रशिक्षण कार्यक्रम','community-training-programs','mr','प्रशिक्षण कार्यक्रम शेतकऱ्यांना माती आरोग्य, पीक पोषण, काढणीनंतरची हाताळणी आणि डिजिटल बाजार तयारीतील चांगल्या पद्धती स्वीकारण्यास मदत करतात.','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/Farmers_with_livestacks.png',12,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(16,'Innovation','community-innovation','en','GreenWings encourages practical innovation through agri-technology, data-led decisions, climate-aware cultivation and value-chain partnerships.','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/Farmer_with_livestacks.png',13,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(17,'नवाचार','community-innovation','hi','ग्रीनविंग्स कृषि तकनीक, डेटा आधारित निर्णय, जलवायु-सजग खेती और मूल्य-श्रृंखला साझेदारी के माध्यम से व्यावहारिक नवाचार को बढ़ावा देता है।','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/Farmer_with_livestacks.png',13,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(18,'नवोन्मेष','community-innovation','mr','ग्रीनविंग्स कृषी तंत्रज्ञान, माहितीआधारित निर्णय, हवामान-जाणिवेची शेती आणि मूल्यसाखळी भागीदारीद्वारे व्यावहारिक नवोन्मेषाला प्रोत्साहन देते.','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/Farmer_with_livestacks.png',13,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(19,'Learning','community-learning','en','Continuous learning keeps farmers prepared for changing weather, market demand, input choices, quality standards and export opportunities.','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/serious_discussion_in_farm.png',14,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(20,'लगातार सीखना','community-learning','hi','लगातार सीखने से किसान बदलते मौसम, बाजार मांग, इनपुट विकल्प, गुणवत्ता मानक और निर्यात अवसरों के लिए तैयार रहते हैं।','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/serious_discussion_in_farm.png',14,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(21,'सतत शिकणे','community-learning','mr','सतत शिकण्यामुळे शेतकरी बदलते हवामान, बाजार मागणी, इनपुट निवड, गुणवत्ता मानके आणि निर्यात संधींसाठी तयार राहतात.','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/serious_discussion_in_farm.png',14,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(22,'Sustainable Agriculture','community-sustainable-agriculture','en','Sustainable agriculture is promoted through natural farming, responsible input use, soil improvement and water-conscious cultivation.','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/Serious_disciussion_in_another_farm.png',15,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(23,'टिकाऊ कृषि','community-sustainable-agriculture','hi','टिकाऊ कृषि को प्राकृतिक खेती, जिम्मेदार इनपुट उपयोग, मिट्टी सुधार और जल-सचेत खेती के माध्यम से बढ़ावा दिया जाता है।','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/Serious_disciussion_in_another_farm.png',15,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(24,'शाश्वत शेती','community-sustainable-agriculture','mr','नैसर्गिक शेती, जबाबदार इनपुट वापर, माती सुधारणा आणि पाणी-जाणिवेच्या लागवडीद्वारे शाश्वत शेतीला प्रोत्साहन दिले जाते.','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/Serious_disciussion_in_another_farm.png',15,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(25,'Company Introduction','company-introduction','en','GREEN WINGS FARMERS PRODUCER COMPANY LIMITED is a farmer-owned organisation founded to connect farmers with inputs, knowledge, technology, processing, value addition and better markets.','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/a_few_more_farmers.png',20,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(26,'कंपनी परिचय','company-introduction','hi','ग्रीन विंग्स फार्मर्स प्रोड्यूसर कंपनी लिमिटेड किसानों को इनपुट, ज्ञान, तकनीक, प्रसंस्करण, मूल्यवर्धन और बेहतर बाजारों से जोड़ने वाला किसान-स्वामित्व संगठन है।','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/a_few_more_farmers.png',20,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(27,'कंपनी परिचय','company-introduction','mr','ग्रीन विंग्स फार्मर्स प्रोड्यूसर कंपनी लिमिटेड ही शेतकऱ्यांना इनपुट, ज्ञान, तंत्रज्ञान, प्रक्रिया, मूल्यवर्धन आणि चांगल्या बाजारपेठांशी जोडणारी शेतकरी-मालकीची संस्था आहे.','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/a_few_more_farmers.png',20,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(28,'Our Journey','our-journey','en','GreenWings began in 2023 with a clear purpose: unite farmers around trust, learning, collaboration and long-term agricultural growth.','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/Farmers_with_livestacks.png',21,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(29,'हमारी यात्रा','our-journey','hi','ग्रीनविंग्स की शुरुआत 2023 में विश्वास, सीख, सहयोग और दीर्घकालीन कृषि विकास के उद्देश्य से हुई।','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/Farmers_with_livestacks.png',21,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(30,'आमचा प्रवास','our-journey','mr','ग्रीनविंग्सची सुरुवात 2023 मध्ये विश्वास, शिक्षण, सहकार्य आणि दीर्घकालीन कृषी विकासाच्या उद्देशाने झाली.','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/Farmers_with_livestacks.png',21,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(31,'Vision','vision','en','To build a trusted farmer-led agricultural ecosystem that carries the strength of Yeola and Nashik farming communities to national and international markets.','',22,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(32,'दृष्टि','vision','hi','येवला और नाशिक के किसानों की शक्ति को राष्ट्रीय और अंतरराष्ट्रीय बाजारों तक पहुंचाने वाला भरोसेमंद किसान-नेतृत्व कृषि तंत्र बनाना।','',22,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(33,'दृष्टी','vision','mr','येवला आणि नाशिकच्या शेतकरी समुदायाची ताकद राष्ट्रीय आणि आंतरराष्ट्रीय बाजारपेठांपर्यंत नेणारी विश्वासार्ह शेतकरी-नेतृत्व कृषि व्यवस्था उभारणे.','',22,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(34,'Mission','mission','en','To empower farmers through training, natural farming support, input guidance, aggregation, processing, value addition and market connectivity.','',23,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(35,'मिशन','mission','hi','प्रशिक्षण, प्राकृतिक खेती सहयोग, इनपुट मार्गदर्शन, aggregation, प्रसंस्करण, मूल्यवर्धन और बाजार संपर्क से किसानों को सशक्त बनाना।','',23,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(36,'मिशन','mission','mr','प्रशिक्षण, नैसर्गिक शेती सहाय्य, इनपुट मार्गदर्शन, aggregation, प्रक्रिया, मूल्यवर्धन आणि बाजार जोडणीद्वारे शेतकऱ्यांना सक्षम करणे.','',23,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(37,'Core Values','core-values','en','Trust, transparency, farmer-first decision making, sustainability, innovation, community ownership and shared prosperity guide GreenWings.','',24,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(38,'मुख्य मूल्य','core-values','hi','विश्वास, पारदर्शिता, किसान-प्रथम निर्णय, स्थिरता, नवाचार, सामुदायिक स्वामित्व और साझा समृद्धि।','',24,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(39,'मूल्ये','core-values','mr','विश्वास, पारदर्शकता, शेतकरी-प्रथम निर्णय, शाश्वतता, नवोन्मेष, समुदाय मालकी आणि सामायिक समृद्धी.','',24,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(40,'Export Vision','export-vision','en','GreenWings aims to prepare farmer produce for premium markets through quality systems, traceability, grading, packaging and buyer readiness.','',25,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(41,'निर्यात दृष्टि','export-vision','hi','गुणवत्ता प्रणाली, traceability, grading, packaging और buyer readiness के माध्यम से किसान उत्पाद को प्रीमियम बाजारों के लिए तैयार करना।','',25,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(42,'निर्यात दृष्टी','export-vision','mr','गुणवत्ता प्रणाली, traceability, grading, packaging आणि buyer readiness द्वारे शेतमाल प्रीमियम बाजारपेठांसाठी तयार करणे.','',25,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(43,'Natural Farming Initiative','natural-farming-initiative','en','The natural farming initiative promotes soil health, reduced chemical dependency, local resources, biodiversity and resilient production systems.','',26,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(44,'प्राकृतिक खेती पहल','natural-farming-initiative','hi','मिट्टी के स्वास्थ्य, कम रासायनिक निर्भरता, स्थानीय संसाधनों, जैव विविधता और लचीली उत्पादन प्रणाली को बढ़ावा देना।','',26,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(45,'नैसर्गिक शेती उपक्रम','natural-farming-initiative','mr','मातीचे आरोग्य, कमी रासायनिक अवलंबित्व, स्थानिक संसाधने, जैवविविधता आणि लवचिक उत्पादन प्रणालींना प्रोत्साहन देणे.','',26,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(46,'Farmer Empowerment Strategy','farmer-empowerment-strategy','en','The farmer empowerment strategy focuses on knowledge access, group strength, digital connectivity, finance readiness and better bargaining power.','',27,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(47,'किसान सशक्तिकरण रणनीति','farmer-empowerment-strategy','hi','ज्ञान, समूह शक्ति, डिजिटल कनेक्टिविटी, वित्तीय तैयारी और बेहतर सौदेबाजी शक्ति पर केंद्रित रणनीति।','',27,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(48,'शेतकरी सक्षमीकरण रणनीती','farmer-empowerment-strategy','mr','ज्ञान, समूह शक्ती, डिजिटल जोडणी, वित्तीय तयारी आणि चांगल्या सौदेबाजी शक्तीवर केंद्रित रणनीती.','',27,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(49,'Processing & Value Addition Strategy','processing-value-addition-strategy','en','GreenWings plans to support grading, primary processing, packaging, storage and value-added products that increase farmer income.','',28,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(50,'प्रसंस्करण और मूल्यवर्धन रणनीति','processing-value-addition-strategy','hi','grading, primary processing, packaging, storage और value-added products से किसानों की आय बढ़ाना।','',28,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_stories VALUES(51,'प्रक्रिया आणि मूल्यवर्धन रणनीती','processing-value-addition-strategy','mr','grading, primary processing, packaging, storage आणि value-added products द्वारे शेतकऱ्यांचे उत्पन्न वाढवणे.','',28,'published','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_milestones VALUES(1,'2023','Company Formation','GreenWings was formally established as a farmer producer company to organise farmers around shared growth.','/assets/greenwings-community.png',1,'2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00',NULL,'en','published');
INSERT INTO company_milestones VALUES(2,'2023','Natural Farming Initiative','The company began promoting soil health, natural farming awareness and responsible input usage.','/assets/greenwings-hero.png',2,'2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00',NULL,'en','published');
INSERT INTO company_milestones VALUES(3,'2024','Farmer Growth Milestones','Farmer participation expanded through village meetings, training programmes and collective planning.','/assets/greenwings-community.png',3,'2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00',NULL,'en','published');
INSERT INTO company_milestones VALUES(4,'2025','Export Expansion Milestones','GreenWings started preparing farmers for export readiness through quality, grading and buyer-oriented practices.','/assets/greenwings-hero.png',4,'2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00',NULL,'en','published');
INSERT INTO company_milestones VALUES(5,'2026','Processing and Value Addition Milestones','The organisation began shaping plans for grading, packaging, primary processing and value-added products.','/assets/greenwings-community.png',5,'2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00',NULL,'en','published');
INSERT INTO company_milestones VALUES(6,'2023','Company Established','Green Wings Farmers Producer Company was established on 4 March 2023 under the Government of India’s Formation and Promotion of 10,000 Farmer Producer Organizations scheme, with financial support from NABARD.',NULL,1,'2026-06-21T08:23:44+00:00','2026-06-21T08:23:44+00:00','Official FPO registration under national FPO promotion initiative','en','published');
INSERT INTO company_milestones VALUES(7,'2023','Government Onion Procurement Started','The company began its work through government onion procurement under NAFED in collaboration with Mahakisan Vriddhi Agro Federation.',NULL,2,'2026-06-21T08:23:44+00:00','2026-06-21T08:23:44+00:00','First major procurement activity launched','en','published');
INSERT INTO company_milestones VALUES(8,'2023','Summer Onion Procurement','In its first year, the company purchased 3,453 quintals of summer onion from farmers and supplied it to NAFED. Farmers received at least ₹2 per kg more than the market committee rate, helping each trolley earn approximately ₹5,000 more.',NULL,3,'2026-06-21T08:23:44+00:00','2026-06-21T08:23:44+00:00','3,453 quintals procured, 150+ farmers directly benefited','en','published');
INSERT INTO company_milestones VALUES(9,'2023','Red Onion Procurement','The company later received another opportunity for red onion procurement. Under this activity, it purchased 5,861 quintals of onion from farmers and helped more than 200 farmers benefit from better pricing. Farmers received an average of ₹4 per kg more, which increased farmer satisfaction and strengthened membership.',NULL,4,'2026-06-21T08:23:44+00:00','2026-06-21T08:23:44+00:00','5,861 quintals procured, 200+ farmers benefited','en','published');
INSERT INTO company_milestones VALUES(10,'2023','Membership Growth','After successful onion procurement activities, farmers joined the company as members, increasing the company’s membership base to 323.',NULL,5,'2026-06-21T08:23:44+00:00','2026-06-21T08:23:44+00:00','323 members','en','published');
INSERT INTO company_milestones VALUES(11,'2023','First-Year Turnover','Due to these procurement activities, the company achieved a turnover of approximately ₹2 crore in its first year. All farmer payments were transferred online directly to their bank accounts.',NULL,6,'2026-06-21T08:23:44+00:00','2026-06-21T08:23:44+00:00','₹2 crore first-year turnover','en','published');
INSERT INTO company_milestones VALUES(12,'2024','Continued Independent Procurement','Due to changes in government and NAFED procurement policies, and payment delays from Mahakisan Vriddhi Federation, the company did not receive further government onion procurement work. However, Green Wings continued its activities independently and carried on onion procurement at the local level.',NULL,7,'2026-06-21T08:23:44+00:00','2026-06-21T08:23:44+00:00','Independent procurement activities continued','en','published');
INSERT INTO company_milestones VALUES(13,'2024','Seeds and Organic Fertilizer Support','The company continued supporting farmers by supplying seeds and organic fertilizers, helping farmers access important agricultural inputs.',NULL,8,'2026-06-21T08:23:44+00:00','2026-06-21T08:23:44+00:00','Farmer input support continued','en','published');
INSERT INTO company_milestones VALUES(14,'2025','Membership Crossed 600+','Through consistent farmer support, procurement activities, and input supply services, Green Wings Farmers Producer Company expanded its membership base to more than 600 farmers.',NULL,9,'2026-06-21T08:23:44+00:00','2026-06-21T08:23:44+00:00','600+ members','en','published');
INSERT INTO company_milestones VALUES(15,'2023','कंपनी की स्थापना','ग्रीन विंग्स फार्मर्स प्रोड्यूसर कंपनी की स्थापना 4 मार्च 2023 को भारत सरकार की 10,000 किसान उत्पादक संगठनों के गठन और संवर्धन योजना के अंतर्गत NABARD की वित्तीय सहायता से हुई।',NULL,1,'2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00','राष्ट्रीय FPO प्रोत्साहन पहल के अंतर्गत आधिकारिक पंजीकरण','hi','published');
INSERT INTO company_milestones VALUES(16,'2023','कंपनीची स्थापना','ग्रीन विंग्स फार्मर्स प्रोड्यूसर कंपनीची स्थापना 4 मार्च 2023 रोजी भारत सरकारच्या 10,000 शेतकरी उत्पादक संघटनांच्या स्थापना आणि प्रोत्साहन योजनेअंतर्गत NABARD च्या आर्थिक सहाय्याने झाली.',NULL,1,'2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00','राष्ट्रीय FPO प्रोत्साहन उपक्रमांतर्गत अधिकृत नोंदणी','mr','published');
INSERT INTO company_milestones VALUES(17,'2023','सरकारी प्याज खरीद शुरू','कंपनी ने NAFED के अंतर्गत महाकिसान वृद्धि एग्रो फेडरेशन के सहयोग से सरकारी प्याज खरीद के माध्यम से अपना कार्य शुरू किया।',NULL,2,'2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00','पहली प्रमुख खरीद गतिविधि शुरू','hi','published');
INSERT INTO company_milestones VALUES(18,'2023','सरकारी कांदा खरेदी सुरू','कंपनीने NAFED अंतर्गत महाकिसान वृद्धी अॅग्रो फेडरेशनच्या सहकार्याने सरकारी कांदा खरेदीद्वारे कामाची सुरुवात केली.',NULL,2,'2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00','पहिली मोठी खरेदी गतिविधी सुरू','mr','published');
INSERT INTO company_milestones VALUES(19,'2023','ग्रीष्मकालीन प्याज खरीद','पहले वर्ष में कंपनी ने किसानों से 3,453 क्विंटल ग्रीष्मकालीन प्याज खरीदकर NAFED को आपूर्ति किया। किसानों को बाजार समिति दर से कम से कम ₹2 प्रति किलो अधिक मिला, जिससे प्रत्येक ट्रॉली पर लगभग ₹5,000 अतिरिक्त आय हुई।',NULL,3,'2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00','3,453 क्विंटल खरीद, 150+ किसानों को प्रत्यक्ष लाभ','hi','published');
INSERT INTO company_milestones VALUES(20,'2023','उन्हाळी कांदा खरेदी','पहिल्या वर्षी कंपनीने शेतकऱ्यांकडून 3,453 क्विंटल उन्हाळी कांदा खरेदी करून NAFED ला पुरवठा केला. शेतकऱ्यांना बाजार समिती दरापेक्षा किमान ₹2 प्रति किलो जास्त दर मिळाला, ज्यामुळे प्रत्येक ट्रॉलीमागे अंदाजे ₹5,000 अधिक उत्पन्न झाले.',NULL,3,'2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00','3,453 क्विंटल खरेदी, 150+ शेतकऱ्यांना थेट लाभ','mr','published');
INSERT INTO company_milestones VALUES(21,'2023','लाल प्याज खरीद','बाद में कंपनी को लाल प्याज खरीद का अवसर मिला। इस गतिविधि में 5,861 क्विंटल प्याज खरीदा गया और 200 से अधिक किसानों को बेहतर मूल्य मिला। किसानों को औसतन ₹4 प्रति किलो अधिक मिला, जिससे संतुष्टि और सदस्यता मजबूत हुई।',NULL,4,'2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00','5,861 क्विंटल खरीद, 200+ किसानों को लाभ','hi','published');
INSERT INTO company_milestones VALUES(22,'2023','लाल कांदा खरेदी','नंतर कंपनीला लाल कांदा खरेदीची संधी मिळाली. या उपक्रमात 5,861 क्विंटल कांदा खरेदी करण्यात आला आणि 200 पेक्षा जास्त शेतकऱ्यांना चांगला दर मिळाला. शेतकऱ्यांना सरासरी ₹4 प्रति किलो अधिक मिळाल्याने समाधान आणि सदस्यता मजबूत झाली.',NULL,4,'2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00','5,861 क्विंटल खरेदी, 200+ शेतकऱ्यांना लाभ','mr','published');
INSERT INTO company_milestones VALUES(23,'2023','सदस्यता वृद्धि','सफल प्याज खरीद गतिविधियों के बाद किसान कंपनी के सदस्य बने और सदस्य संख्या 323 तक पहुंच गई।',NULL,5,'2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00','323 सदस्य','hi','published');
INSERT INTO company_milestones VALUES(24,'2023','सदस्यता वाढ','यशस्वी कांदा खरेदी उपक्रमांनंतर शेतकरी कंपनीचे सदस्य झाले आणि सदस्य संख्या 323 पर्यंत वाढली.',NULL,5,'2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00','323 सदस्य','mr','published');
INSERT INTO company_milestones VALUES(25,'2023','पहले वर्ष का कारोबार','इन खरीद गतिविधियों के कारण कंपनी ने पहले वर्ष में लगभग ₹2 करोड़ का कारोबार किया। सभी किसानों का भुगतान सीधे उनके बैंक खातों में ऑनलाइन किया गया।',NULL,6,'2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00','₹2 करोड़ पहले वर्ष का कारोबार','hi','published');
INSERT INTO company_milestones VALUES(26,'2023','पहिल्या वर्षाचा उलाढाल','या खरेदी उपक्रमांमुळे कंपनीने पहिल्या वर्षात अंदाजे ₹2 कोटींची उलाढाल साध्य केली. सर्व शेतकरी देयके थेट त्यांच्या बँक खात्यात ऑनलाइन जमा करण्यात आली.',NULL,6,'2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00','₹2 कोटी पहिल्या वर्षाची उलाढाल','mr','published');
INSERT INTO company_milestones VALUES(27,'2024','स्वतंत्र खरीद जारी','सरकारी और NAFED खरीद नीतियों में बदलाव तथा महाकिसान वृद्धि फेडरेशन से भुगतान में देरी के कारण कंपनी को आगे सरकारी प्याज खरीद कार्य नहीं मिला। फिर भी ग्रीन विंग्स ने स्थानीय स्तर पर स्वतंत्र खरीद गतिविधियां जारी रखीं।',NULL,7,'2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00','स्वतंत्र खरीद गतिविधियां जारी','hi','published');
INSERT INTO company_milestones VALUES(28,'2024','स्वतंत्र खरेदी सुरूच','सरकारी आणि NAFED खरेदी धोरणांतील बदल तसेच महाकिसान वृद्धी फेडरेशनकडून देयक विलंबामुळे कंपनीला पुढील सरकारी कांदा खरेदीचे काम मिळाले नाही. तरीही ग्रीन विंग्सने स्थानिक पातळीवर स्वतंत्र खरेदी सुरू ठेवली.',NULL,7,'2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00','स्वतंत्र खरेदी गतिविधी सुरू','mr','published');
INSERT INTO company_milestones VALUES(29,'2024','बीज और जैविक खाद सहायता','कंपनी ने किसानों को बीज और जैविक खाद उपलब्ध कराकर महत्वपूर्ण कृषि इनपुट तक पहुंच में सहयोग जारी रखा।',NULL,8,'2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00','किसान इनपुट सहायता जारी','hi','published');
INSERT INTO company_milestones VALUES(30,'2024','बियाणे आणि सेंद्रिय खत सहाय्य','कंपनीने शेतकऱ्यांना बियाणे आणि सेंद्रिय खते पुरवून महत्त्वाच्या कृषी इनपुटपर्यंतची मदत सुरू ठेवली.',NULL,8,'2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00','शेतकरी इनपुट सहाय्य सुरू','mr','published');
INSERT INTO company_milestones VALUES(31,'2025','सदस्यता 600+ पार','लगातार किसान सहायता, खरीद गतिविधियों और इनपुट आपूर्ति सेवाओं के माध्यम से ग्रीन विंग्स फार्मर्स प्रोड्यूसर कंपनी ने अपनी सदस्य संख्या 600 से अधिक कर ली।',NULL,9,'2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00','600+ सदस्य','hi','published');
INSERT INTO company_milestones VALUES(32,'2025','सदस्यता 600+ पार','सातत्यपूर्ण शेतकरी सहाय्य, खरेदी उपक्रम आणि इनपुट पुरवठा सेवांद्वारे ग्रीन विंग्स फार्मर्स प्रोड्यूसर कंपनीची सदस्य संख्या 600 पेक्षा जास्त झाली.',NULL,9,'2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00','600+ सदस्य','mr','published');
INSERT INTO company_milestones VALUES(33,'2023','कंपनी गठन','ग्रीनविंग्स को किसानों को साझा विकास के लिए संगठित करने वाली किसान उत्पादक कंपनी के रूप में औपचारिक रूप से स्थापित किया गया.','/assets/greenwings-community.png',1,'2026-06-27 17:16:23','2026-06-27 17:16:23',NULL,'hi','published');
INSERT INTO company_milestones VALUES(34,'2023','कंपनी स्थापना','शेतकऱ्यांना सामूहिक विकासासाठी संघटित करण्यासाठी ग्रीनविंग्सची किसान उत्पादक कंपनी म्हणून औपचारिक स्थापना झाली.','/assets/greenwings-community.png',1,'2026-06-27 17:16:23','2026-06-27 17:16:23',NULL,'mr','published');
INSERT INTO company_milestones VALUES(35,'2023','प्राकृतिक खेती पहल','कंपनी ने मिट्टी के स्वास्थ्य, प्राकृतिक खेती जागरूकता और जिम्मेदार इनपुट उपयोग को बढ़ावा देना शुरू किया.','/assets/greenwings-hero.png',2,'2026-06-27 17:16:23','2026-06-27 17:16:23',NULL,'hi','published');
INSERT INTO company_milestones VALUES(36,'2023','नैसर्गिक शेती उपक्रम','कंपनीने मातीचे आरोग्य, नैसर्गिक शेती जनजागृती आणि जबाबदार इनपुट वापराला प्रोत्साहन देणे सुरू केले.','/assets/greenwings-hero.png',2,'2026-06-27 17:16:23','2026-06-27 17:16:23',NULL,'mr','published');
INSERT INTO company_milestones VALUES(37,'2024','किसान विकास पड़ाव','गांव बैठकों, प्रशिक्षण कार्यक्रमों और सामूहिक नियोजन के माध्यम से किसानों की भागीदारी बढ़ी.','/assets/greenwings-community.png',3,'2026-06-27 17:16:23','2026-06-27 17:16:23',NULL,'hi','published');
INSERT INTO company_milestones VALUES(38,'2024','शेतकरी वाढीचे टप्पे','गाव बैठका, प्रशिक्षण कार्यक्रम आणि सामूहिक नियोजनाच्या माध्यमातून शेतकऱ्यांचा सहभाग वाढला.','/assets/greenwings-community.png',3,'2026-06-27 17:16:23','2026-06-27 17:16:23',NULL,'mr','published');
INSERT INTO company_milestones VALUES(39,'2025','निर्यात विस्तार पड़ाव','ग्रीनविंग्स ने गुणवत्ता, ग्रेडिंग और buyer-oriented practices के माध्यम से किसानों को export readiness के लिए तैयार करना शुरू किया.','/assets/greenwings-hero.png',4,'2026-06-27 17:16:23','2026-06-27 17:16:23',NULL,'hi','published');
INSERT INTO company_milestones VALUES(40,'2025','निर्यात विस्ताराचे टप्पे','ग्रीनविंग्सने गुणवत्ता, ग्रेडिंग आणि खरेदीदार-केंद्रित पद्धतींद्वारे शेतकऱ्यांना export readiness साठी तयार करणे सुरू केले.','/assets/greenwings-hero.png',4,'2026-06-27 17:16:23','2026-06-27 17:16:23',NULL,'mr','published');
INSERT INTO company_milestones VALUES(41,'2026','प्रोसेसिंग और वैल्यू एडिशन पड़ाव','संस्था ने ग्रेडिंग, पैकेजिंग, प्राथमिक प्रोसेसिंग और value-added products की योजनाओं को आकार देना शुरू किया.','/assets/greenwings-community.png',5,'2026-06-27 17:16:23','2026-06-27 17:16:23',NULL,'hi','published');
INSERT INTO company_milestones VALUES(42,'2026','प्रक्रिया आणि मूल्यवर्धनाचे टप्पे','संस्थेने ग्रेडिंग, पॅकेजिंग, प्राथमिक प्रक्रिया आणि value-added products यांच्या योजनांना आकार देणे सुरू केले.','/assets/greenwings-community.png',5,'2026-06-27 17:16:23','2026-06-27 17:16:23',NULL,'mr','published');
INSERT INTO company_milestone_translations VALUES(1,1,'hi','कंपनी स्थापना','ग्रीनविंग्स को साझा विकास के लिए किसानों को संगठित करने वाली किसान उत्पादक कंपनी के रूप में औपचारिक रूप से स्थापित किया गया।','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00',NULL);
INSERT INTO company_milestone_translations VALUES(2,1,'mr','कंपनी स्थापना','सामायिक वाढीसाठी शेतकऱ्यांना संघटित करणारी शेतकरी उत्पादक कंपनी म्हणून ग्रीनविंग्सची औपचारिक स्थापना झाली.','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00',NULL);
INSERT INTO company_milestone_translations VALUES(3,2,'hi','प्राकृतिक खेती पहल','कंपनी ने मिट्टी स्वास्थ्य, प्राकृतिक खेती जागरूकता और जिम्मेदार इनपुट उपयोग को बढ़ावा देना शुरू किया।','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00',NULL);
INSERT INTO company_milestone_translations VALUES(4,2,'mr','नैसर्गिक शेती उपक्रम','कंपनीने माती आरोग्य, नैसर्गिक शेती जागरूकता आणि जबाबदार इनपुट वापराला प्रोत्साहन देण्यास सुरुवात केली.','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00',NULL);
INSERT INTO company_milestone_translations VALUES(5,3,'hi','किसान विकास मील के पत्थर','गांव बैठकों, प्रशिक्षण कार्यक्रमों और सामूहिक योजना के माध्यम से किसानों की भागीदारी बढ़ी।','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00',NULL);
INSERT INTO company_milestone_translations VALUES(6,3,'mr','शेतकरी वाढीचे टप्पे','गाव बैठका, प्रशिक्षण कार्यक्रम आणि सामूहिक नियोजनाद्वारे शेतकरी सहभाग वाढला.','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00',NULL);
INSERT INTO company_milestone_translations VALUES(7,4,'hi','निर्यात विस्तार मील के पत्थर','ग्रीनविंग्स ने गुणवत्ता, ग्रेडिंग और खरीदार-केंद्रित पद्धतियों के माध्यम से किसानों को निर्यात तैयारी के लिए तैयार करना शुरू किया।','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00',NULL);
INSERT INTO company_milestone_translations VALUES(8,4,'mr','निर्यात विस्ताराचे टप्पे','ग्रीनविंग्सने गुणवत्ता, ग्रेडिंग आणि खरेदीदार-केंद्रित पद्धतींद्वारे शेतकऱ्यांना निर्यात तयारीसाठी तयार करणे सुरू केले.','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00',NULL);
INSERT INTO company_milestone_translations VALUES(9,5,'hi','प्रसंस्करण और मूल्यवर्धन मील के पत्थर','संगठन ने ग्रेडिंग, पैकेजिंग, प्राथमिक प्रसंस्करण और मूल्य-वर्धित उत्पादों की योजनाएं बनाना शुरू किया।','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00',NULL);
INSERT INTO company_milestone_translations VALUES(10,5,'mr','प्रक्रिया आणि मूल्यवर्धनाचे टप्पे','संस्थेने ग्रेडिंग, पॅकेजिंग, प्राथमिक प्रक्रिया आणि मूल्यवर्धित उत्पादनांच्या योजना आकारास आणण्यास सुरुवात केली.','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00',NULL);
INSERT INTO leadership_members VALUES(1,'Mr. Malhari Runjaba Jadhav','Chairman','Provides strategic direction for GreenWings with a focus on farmer trust, governance and collective rural development.','/assets/greenwings-community.png',1,1,'2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00',NULL,'/assets/greenwings-community.png','en');
INSERT INTO leadership_members VALUES(2,'Mr. Manik Ramchandra Rasal','Vice Chairman','Supports organisational planning, member coordination and practical implementation of farmer-first programmes.','/assets/greenwings-hero.png',2,1,'2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00',NULL,'/assets/greenwings-hero.png','en');
INSERT INTO leadership_members VALUES(3,'Mr. Nandkishor Shriram Shinde','Secretary','Oversees documentation, coordination and member communication for transparent company operations.','/assets/greenwings-community.png',3,1,'2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00',NULL,'/assets/greenwings-community.png','en');
INSERT INTO leadership_members VALUES(4,'Mrs. Varsha Vishwambhar Patil','Director','Represents community development priorities and encourages inclusive participation across farmer groups.','/assets/greenwings-hero.png',4,1,'2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00',NULL,'/assets/greenwings-hero.png','en');
INSERT INTO leadership_members VALUES(5,'Mr. Tushar Gorakhanath Shelke','Director and Chief Executive Officer','Leads GreenWings operations, digital strategy, farmer services and market-connectivity initiatives.','/assets/greenwings-community.png',5,1,'2026-06-21T07:28:03+00:00','2026-06-21T08:23:44+00:00','Mr. Tushar Gorakhanath Shelke serves as Director and Chief Executive Officer of Green Wings Farmers Producer Company. He leads the company’s operational management and export-oriented growth vision.','/assets/greenwings-community.png','en');
INSERT INTO leadership_member_translations VALUES(1,1,'hi','अध्यक्ष','किसान विश्वास, सुशासन और सामूहिक ग्रामीण विकास पर ध्यान देते हुए ग्रीनविंग्स को रणनीतिक दिशा प्रदान करते हैं।','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO leadership_member_translations VALUES(2,1,'mr','अध्यक्ष','शेतकरी विश्वास, सुशासन आणि सामूहिक ग्रामीण विकासावर लक्ष केंद्रित करून ग्रीनविंग्सला धोरणात्मक दिशा देतात.','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO leadership_member_translations VALUES(3,2,'hi','उपाध्यक्ष','संगठनात्मक योजना, सदस्य समन्वय और किसान-प्रथम कार्यक्रमों के व्यावहारिक कार्यान्वयन में सहयोग करते हैं।','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO leadership_member_translations VALUES(4,2,'mr','उपाध्यक्ष','संस्थात्मक नियोजन, सदस्य समन्वय आणि शेतकरी-प्रथम कार्यक्रमांच्या प्रत्यक्ष अंमलबजावणीत सहकार्य करतात.','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO leadership_member_translations VALUES(5,3,'hi','सचिव','पारदर्शी कंपनी संचालन के लिए दस्तावेजीकरण, समन्वय और सदस्य संचार की देखरेख करते हैं।','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO leadership_member_translations VALUES(6,3,'mr','सचिव','पारदर्शक कंपनी कामकाजासाठी दस्तऐवजीकरण, समन्वय आणि सदस्य संवादाची देखरेख करतात.','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO leadership_member_translations VALUES(7,4,'hi','निदेशक','सामुदायिक विकास प्राथमिकताओं का प्रतिनिधित्व करती हैं और किसान समूहों में समावेशी भागीदारी को प्रोत्साहित करती हैं।','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO leadership_member_translations VALUES(8,4,'mr','संचालक','समुदाय विकासाच्या प्राधान्यांचे प्रतिनिधित्व करतात आणि शेतकरी गटांमध्ये समावेशक सहभागाला प्रोत्साहन देतात.','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO leadership_member_translations VALUES(9,5,'hi','निदेशक और मुख्य कार्यकारी अधिकारी','ग्रीनविंग्स संचालन, डिजिटल रणनीति, किसान सेवाओं और बाजार-संपर्क पहलों का नेतृत्व करते हैं।','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO leadership_member_translations VALUES(10,5,'mr','संचालक आणि मुख्य कार्यकारी अधिकारी','ग्रीनविंग्सचे कामकाज, डिजिटल धोरण, शेतकरी सेवा आणि बाजार-जोडणी उपक्रमांचे नेतृत्व करतात.','2026-06-21T07:28:03+00:00','2026-06-21T07:28:03+00:00');
INSERT INTO company_contents VALUES(1,'company_introduction','Introduction','Green Wings Farmers Producer Company Limited',unistr('Green Wings Farmers Producer Company was established on 4 March 2023 under the Government of India’s “Formation and Promotion of 10,000 Farmer Producer Organizations (FPOs)” scheme. The company received financial support from NABARD under this initiative.\u000a\u000aGreen Wings Farmers Producer Company was established with the objective of ensuring the progress and prosperity of farmers and securing a brighter future for them. The company was formed to bring farmers together so that they could receive fair and remunerative prices for their agricultural produce. Another key objective was to help farmers reduce their cultivation costs by collectively procuring seeds, fertilizers, and other agricultural inputs at more affordable rates.\u000a\u000aIn addition, the Board of Directors adopted a policy of promoting Natural Farming and Organic Farming, while actively encouraging and creating awareness about these sustainable agricultural practices among farmers.\u000a\u000aThe Chief Executive Officer, Mr. Tushar Gorakhanath Shelke, envisioned that the agricultural produce of the company should reach markets beyond Yeola Taluka and Nashik District. His goal was to ensure that the company’s produce was marketed not only across Maharashtra and India, but also in international markets. With this vision, the company decided to enter the field of exports as well.\u000a\u000aAt the same time, Chairman Mr. Malhari Runjaba Jadhav and Secretary Mr. Nandkishor Shriram Shinde adopted a strategy focused on the processing and value addition of agricultural produce, with the aim of helping farmers obtain better prices and enhanced value for their products.\u000a\u000aThrough these initiatives, Green Wings Farmers Producer Company continues to work towards empowering farmers, promoting sustainable agriculture, increasing farm incomes, and creating access to domestic as well as international markets.'),'en',1,'published','2026-06-21T08:23:44+00:00','2026-06-21T08:23:44+00:00');
INSERT INTO company_contents VALUES(2,'vision','Vision','','To empower farmers by connecting them with fair markets, sustainable farming practices, value-added processing opportunities, and domestic as well as international agricultural trade networks.','en',2,'published','2026-06-21T08:23:44+00:00','2026-06-21T08:23:44+00:00');
INSERT INTO company_contents VALUES(3,'mission','Mission','','To unite farmers under a strong Farmer Producer Organisation, reduce their input costs through collective procurement, promote natural and organic farming, support value addition of agricultural produce, and help farmers receive better returns through market linkage and export-oriented growth.','en',3,'published','2026-06-21T08:23:44+00:00','2026-06-21T08:23:44+00:00');
INSERT INTO company_contents VALUES(13,'company_introduction','परिचय','ग्रीन विंग्स फार्मर्स प्रोड्यूसर कंपनी लिमिटेड',unistr('ग्रीन विंग्स फार्मर्स प्रोड्यूसर कंपनी की स्थापना 4 मार्च 2023 को भारत सरकार की “10,000 किसान उत्पादक संगठनों के गठन और संवर्धन” योजना के अंतर्गत हुई। इस पहल के तहत कंपनी को NABARD से वित्तीय सहायता प्राप्त हुई।\u000a\u000aकंपनी का उद्देश्य किसानों की प्रगति, समृद्धि और उज्ज्वल भविष्य को मजबूत करना है। किसानों को एकजुट कर उनकी कृषि उपज के लिए उचित और लाभकारी मूल्य दिलाना तथा बीज, उर्वरक और अन्य कृषि इनपुट सामूहिक रूप से कम लागत पर उपलब्ध कराना इसका प्रमुख लक्ष्य है।\u000a\u000aबोर्ड ऑफ डायरेक्टर्स ने प्राकृतिक खेती और जैविक खेती को बढ़ावा देने की नीति अपनाई है और किसानों में इन टिकाऊ कृषि पद्धतियों के प्रति जागरूकता निर्माण पर काम कर रहा है।\u000a\u000aमुख्य कार्यकारी अधिकारी श्री तुषार गोरखनाथ शेलके की दृष्टि है कि कंपनी की कृषि उपज येवला तालुका और नाशिक जिले से आगे महाराष्ट्र, भारत और अंतरराष्ट्रीय बाजारों तक पहुंचे। इसी सोच के साथ कंपनी ने निर्यात क्षेत्र में भी प्रवेश करने का निर्णय लिया।\u000a\u000aअध्यक्ष श्री मल्हारी रुणजाबा जाधव और सचिव श्री नंदकिशोर श्रीराम शिंदे ने कृषि उपज के प्रसंस्करण और मूल्यवर्धन पर आधारित रणनीति अपनाई है, ताकि किसानों को अपने उत्पादों का बेहतर मूल्य मिल सके।\u000a\u000aइन पहलों के माध्यम से ग्रीन विंग्स किसानों को सशक्त बनाने, टिकाऊ कृषि को बढ़ावा देने, किसानों की आय बढ़ाने और घरेलू तथा अंतरराष्ट्रीय बाजारों तक पहुंच बनाने के लिए निरंतर कार्य कर रहा है।'),'hi',1,'published','2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00');
INSERT INTO company_contents VALUES(14,'vision','दृष्टि','','किसानों को उचित बाजारों, टिकाऊ खेती पद्धतियों, मूल्यवर्धित प्रसंस्करण अवसरों और घरेलू तथा अंतरराष्ट्रीय कृषि व्यापार नेटवर्क से जोड़कर सशक्त बनाना।','hi',2,'published','2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00');
INSERT INTO company_contents VALUES(15,'mission','मिशन','','किसानों को एक मजबूत किसान उत्पादक संगठन के अंतर्गत संगठित करना, सामूहिक खरीद से इनपुट लागत कम करना, प्राकृतिक और जैविक खेती को बढ़ावा देना, कृषि उपज के मूल्यवर्धन में सहयोग करना और बाजार संपर्क तथा निर्यात-उन्मुख विकास के माध्यम से किसानों को बेहतर रिटर्न दिलाना।','hi',3,'published','2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00');
INSERT INTO company_contents VALUES(16,'company_introduction','परिचय','ग्रीन विंग्स फार्मर्स प्रोड्यूसर कंपनी लिमिटेड',unistr('ग्रीन विंग्स फार्मर्स प्रोड्यूसर कंपनीची स्थापना 4 मार्च 2023 रोजी भारत सरकारच्या “10,000 शेतकरी उत्पादक संघटनांची स्थापना आणि प्रोत्साहन” योजनेअंतर्गत झाली. या उपक्रमांतर्गत कंपनीला NABARD कडून आर्थिक सहाय्य मिळाले.\u000a\u000aकंपनीची स्थापना शेतकऱ्यांची प्रगती, समृद्धी आणि उज्ज्वल भविष्य मजबूत करण्याच्या उद्देशाने झाली. शेतकऱ्यांना एकत्र आणून त्यांच्या शेतमालाला योग्य आणि फायदेशीर दर मिळवून देणे, तसेच बियाणे, खते आणि इतर कृषी इनपुट सामूहिक खरेदीद्वारे कमी खर्चात उपलब्ध करून देणे हा प्रमुख उद्देश आहे.\u000a\u000aसंचालक मंडळाने नैसर्गिक शेती आणि सेंद्रिय शेतीला प्रोत्साहन देण्याचे धोरण स्वीकारले असून या शाश्वत शेती पद्धतींबद्दल शेतकऱ्यांमध्ये जागरूकता निर्माण करण्यावर भर दिला आहे.\u000a\u000aमुख्य कार्यकारी अधिकारी श्री. तुषार गोरखनाथ शेलके यांची दृष्टी अशी आहे की कंपनीचा शेतमाल येवला तालुका आणि नाशिक जिल्ह्याच्या पलीकडे महाराष्ट्र, भारत आणि आंतरराष्ट्रीय बाजारपेठांपर्यंत पोहोचावा. या दृष्टिकोनातून कंपनीने निर्यात क्षेत्रातही प्रवेश करण्याचा निर्णय घेतला.\u000a\u000aत्याचबरोबर अध्यक्ष श्री. मल्हारी रुणजाबा जाधव आणि सचिव श्री. नंदकिशोर श्रीराम शिंदे यांनी शेतमाल प्रक्रिया आणि मूल्यवर्धनावर आधारित रणनीती स्वीकारली आहे, ज्यामुळे शेतकऱ्यांना त्यांच्या उत्पादनांना अधिक चांगला दर मिळू शकेल.\u000a\u000aया उपक्रमांद्वारे ग्रीन विंग्स शेतकऱ्यांचे सक्षमीकरण, शाश्वत शेतीचा प्रसार, शेतकरी उत्पन्नवाढ आणि देशांतर्गत तसेच आंतरराष्ट्रीय बाजारपेठांशी जोडणी यासाठी सातत्याने कार्य करत आहे.'),'mr',1,'published','2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00');
INSERT INTO company_contents VALUES(17,'vision','दृष्टी','','शेतकऱ्यांना योग्य बाजारपेठा, शाश्वत शेती पद्धती, मूल्यवर्धित प्रक्रिया संधी आणि देशांतर्गत तसेच आंतरराष्ट्रीय कृषी व्यापार नेटवर्कशी जोडून सक्षम करणे.','mr',2,'published','2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00');
INSERT INTO company_contents VALUES(18,'mission','मिशन','','शेतकऱ्यांना मजबूत शेतकरी उत्पादक संस्थेखाली एकत्र आणणे, सामूहिक खरेदीद्वारे इनपुट खर्च कमी करणे, नैसर्गिक आणि सेंद्रिय शेतीला प्रोत्साहन देणे, शेतमालाच्या मूल्यवर्धनाला आधार देणे आणि बाजार जोडणी तसेच निर्याताभिमुख वाढीद्वारे शेतकऱ्यांना चांगला परतावा मिळवून देणे.','mr',3,'published','2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00');
INSERT INTO company_timelines VALUES(1,'2023','Company Established','Green Wings Farmers Producer Company was established on 4 March 2023 under the Government of India’s Formation and Promotion of 10,000 Farmer Producer Organizations scheme, with financial support from NABARD.','Official FPO registration under national FPO promotion initiative','en',1,'published','2026-06-21T08:23:44+00:00','2026-06-21T08:23:44+00:00');
INSERT INTO company_timelines VALUES(2,'2023','Government Onion Procurement Started','The company began its work through government onion procurement under NAFED in collaboration with Mahakisan Vriddhi Agro Federation.','First major procurement activity launched','en',2,'published','2026-06-21T08:23:44+00:00','2026-06-21T08:23:44+00:00');
INSERT INTO company_timelines VALUES(3,'2023','Summer Onion Procurement','In its first year, the company purchased 3,453 quintals of summer onion from farmers and supplied it to NAFED. Farmers received at least ₹2 per kg more than the market committee rate, helping each trolley earn approximately ₹5,000 more.','3,453 quintals procured, 150+ farmers directly benefited','en',3,'published','2026-06-21T08:23:44+00:00','2026-06-21T08:23:44+00:00');
INSERT INTO company_timelines VALUES(4,'2023','Red Onion Procurement','The company later received another opportunity for red onion procurement. Under this activity, it purchased 5,861 quintals of onion from farmers and helped more than 200 farmers benefit from better pricing. Farmers received an average of ₹4 per kg more, which increased farmer satisfaction and strengthened membership.','5,861 quintals procured, 200+ farmers benefited','en',4,'published','2026-06-21T08:23:44+00:00','2026-06-21T08:23:44+00:00');
INSERT INTO company_timelines VALUES(5,'2023','Membership Growth','After successful onion procurement activities, farmers joined the company as members, increasing the company’s membership base to 323.','323 members','en',5,'published','2026-06-21T08:23:44+00:00','2026-06-21T08:23:44+00:00');
INSERT INTO company_timelines VALUES(6,'2023','First-Year Turnover','Due to these procurement activities, the company achieved a turnover of approximately ₹2 crore in its first year. All farmer payments were transferred online directly to their bank accounts.','₹2 crore first-year turnover','en',6,'published','2026-06-21T08:23:44+00:00','2026-06-21T08:23:44+00:00');
INSERT INTO company_timelines VALUES(7,'2024','Continued Independent Procurement','Due to changes in government and NAFED procurement policies, and payment delays from Mahakisan Vriddhi Federation, the company did not receive further government onion procurement work. However, Green Wings continued its activities independently and carried on onion procurement at the local level.','Independent procurement activities continued','en',7,'published','2026-06-21T08:23:44+00:00','2026-06-21T08:23:44+00:00');
INSERT INTO company_timelines VALUES(8,'2024','Seeds and Organic Fertilizer Support','The company continued supporting farmers by supplying seeds and organic fertilizers, helping farmers access important agricultural inputs.','Farmer input support continued','en',8,'published','2026-06-21T08:23:44+00:00','2026-06-21T08:23:44+00:00');
INSERT INTO company_timelines VALUES(9,'2025','Membership Crossed 600+','Through consistent farmer support, procurement activities, and input supply services, Green Wings Farmers Producer Company expanded its membership base to more than 600 farmers.','600+ members','en',9,'published','2026-06-21T08:23:44+00:00','2026-06-21T08:23:44+00:00');
INSERT INTO company_timelines VALUES(28,'2023','कंपनी की स्थापना','ग्रीन विंग्स फार्मर्स प्रोड्यूसर कंपनी की स्थापना 4 मार्च 2023 को भारत सरकार की 10,000 किसान उत्पादक संगठनों के गठन और संवर्धन योजना के अंतर्गत NABARD की वित्तीय सहायता से हुई।','राष्ट्रीय FPO प्रोत्साहन पहल के अंतर्गत आधिकारिक पंजीकरण','hi',1,'published','2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00');
INSERT INTO company_timelines VALUES(29,'2023','कंपनीची स्थापना','ग्रीन विंग्स फार्मर्स प्रोड्यूसर कंपनीची स्थापना 4 मार्च 2023 रोजी भारत सरकारच्या 10,000 शेतकरी उत्पादक संघटनांच्या स्थापना आणि प्रोत्साहन योजनेअंतर्गत NABARD च्या आर्थिक सहाय्याने झाली.','राष्ट्रीय FPO प्रोत्साहन उपक्रमांतर्गत अधिकृत नोंदणी','mr',1,'published','2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00');
INSERT INTO company_timelines VALUES(30,'2023','सरकारी प्याज खरीद शुरू','कंपनी ने NAFED के अंतर्गत महाकिसान वृद्धि एग्रो फेडरेशन के सहयोग से सरकारी प्याज खरीद के माध्यम से अपना कार्य शुरू किया।','पहली प्रमुख खरीद गतिविधि शुरू','hi',2,'published','2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00');
INSERT INTO company_timelines VALUES(31,'2023','सरकारी कांदा खरेदी सुरू','कंपनीने NAFED अंतर्गत महाकिसान वृद्धी अॅग्रो फेडरेशनच्या सहकार्याने सरकारी कांदा खरेदीद्वारे कामाची सुरुवात केली.','पहिली मोठी खरेदी गतिविधी सुरू','mr',2,'published','2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00');
INSERT INTO company_timelines VALUES(32,'2023','ग्रीष्मकालीन प्याज खरीद','पहले वर्ष में कंपनी ने किसानों से 3,453 क्विंटल ग्रीष्मकालीन प्याज खरीदकर NAFED को आपूर्ति किया। किसानों को बाजार समिति दर से कम से कम ₹2 प्रति किलो अधिक मिला, जिससे प्रत्येक ट्रॉली पर लगभग ₹5,000 अतिरिक्त आय हुई।','3,453 क्विंटल खरीद, 150+ किसानों को प्रत्यक्ष लाभ','hi',3,'published','2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00');
INSERT INTO company_timelines VALUES(33,'2023','उन्हाळी कांदा खरेदी','पहिल्या वर्षी कंपनीने शेतकऱ्यांकडून 3,453 क्विंटल उन्हाळी कांदा खरेदी करून NAFED ला पुरवठा केला. शेतकऱ्यांना बाजार समिती दरापेक्षा किमान ₹2 प्रति किलो जास्त दर मिळाला, ज्यामुळे प्रत्येक ट्रॉलीमागे अंदाजे ₹5,000 अधिक उत्पन्न झाले.','3,453 क्विंटल खरेदी, 150+ शेतकऱ्यांना थेट लाभ','mr',3,'published','2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00');
INSERT INTO company_timelines VALUES(34,'2023','लाल प्याज खरीद','बाद में कंपनी को लाल प्याज खरीद का अवसर मिला। इस गतिविधि में 5,861 क्विंटल प्याज खरीदा गया और 200 से अधिक किसानों को बेहतर मूल्य मिला। किसानों को औसतन ₹4 प्रति किलो अधिक मिला, जिससे संतुष्टि और सदस्यता मजबूत हुई।','5,861 क्विंटल खरीद, 200+ किसानों को लाभ','hi',4,'published','2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00');
INSERT INTO company_timelines VALUES(35,'2023','लाल कांदा खरेदी','नंतर कंपनीला लाल कांदा खरेदीची संधी मिळाली. या उपक्रमात 5,861 क्विंटल कांदा खरेदी करण्यात आला आणि 200 पेक्षा जास्त शेतकऱ्यांना चांगला दर मिळाला. शेतकऱ्यांना सरासरी ₹4 प्रति किलो अधिक मिळाल्याने समाधान आणि सदस्यता मजबूत झाली.','5,861 क्विंटल खरेदी, 200+ शेतकऱ्यांना लाभ','mr',4,'published','2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00');
INSERT INTO company_timelines VALUES(36,'2023','सदस्यता वृद्धि','सफल प्याज खरीद गतिविधियों के बाद किसान कंपनी के सदस्य बने और सदस्य संख्या 323 तक पहुंच गई।','323 सदस्य','hi',5,'published','2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00');
INSERT INTO company_timelines VALUES(37,'2023','सदस्यता वाढ','यशस्वी कांदा खरेदी उपक्रमांनंतर शेतकरी कंपनीचे सदस्य झाले आणि सदस्य संख्या 323 पर्यंत वाढली.','323 सदस्य','mr',5,'published','2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00');
INSERT INTO company_timelines VALUES(38,'2023','पहले वर्ष का कारोबार','इन खरीद गतिविधियों के कारण कंपनी ने पहले वर्ष में लगभग ₹2 करोड़ का कारोबार किया। सभी किसानों का भुगतान सीधे उनके बैंक खातों में ऑनलाइन किया गया।','₹2 करोड़ पहले वर्ष का कारोबार','hi',6,'published','2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00');
INSERT INTO company_timelines VALUES(39,'2023','पहिल्या वर्षाचा उलाढाल','या खरेदी उपक्रमांमुळे कंपनीने पहिल्या वर्षात अंदाजे ₹2 कोटींची उलाढाल साध्य केली. सर्व शेतकरी देयके थेट त्यांच्या बँक खात्यात ऑनलाइन जमा करण्यात आली.','₹2 कोटी पहिल्या वर्षाची उलाढाल','mr',6,'published','2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00');
INSERT INTO company_timelines VALUES(40,'2024','स्वतंत्र खरीद जारी','सरकारी और NAFED खरीद नीतियों में बदलाव तथा महाकिसान वृद्धि फेडरेशन से भुगतान में देरी के कारण कंपनी को आगे सरकारी प्याज खरीद कार्य नहीं मिला। फिर भी ग्रीन विंग्स ने स्थानीय स्तर पर स्वतंत्र खरीद गतिविधियां जारी रखीं।','स्वतंत्र खरीद गतिविधियां जारी','hi',7,'published','2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00');
INSERT INTO company_timelines VALUES(41,'2024','स्वतंत्र खरेदी सुरूच','सरकारी आणि NAFED खरेदी धोरणांतील बदल तसेच महाकिसान वृद्धी फेडरेशनकडून देयक विलंबामुळे कंपनीला पुढील सरकारी कांदा खरेदीचे काम मिळाले नाही. तरीही ग्रीन विंग्सने स्थानिक पातळीवर स्वतंत्र खरेदी सुरू ठेवली.','स्वतंत्र खरेदी गतिविधी सुरू','mr',7,'published','2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00');
INSERT INTO company_timelines VALUES(42,'2024','बीज और जैविक खाद सहायता','कंपनी ने किसानों को बीज और जैविक खाद उपलब्ध कराकर महत्वपूर्ण कृषि इनपुट तक पहुंच में सहयोग जारी रखा।','किसान इनपुट सहायता जारी','hi',8,'published','2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00');
INSERT INTO company_timelines VALUES(43,'2024','बियाणे आणि सेंद्रिय खत सहाय्य','कंपनीने शेतकऱ्यांना बियाणे आणि सेंद्रिय खते पुरवून महत्त्वाच्या कृषी इनपुटपर्यंतची मदत सुरू ठेवली.','शेतकरी इनपुट सहाय्य सुरू','mr',8,'published','2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00');
INSERT INTO company_timelines VALUES(44,'2025','सदस्यता 600+ पार','लगातार किसान सहायता, खरीद गतिविधियों और इनपुट आपूर्ति सेवाओं के माध्यम से ग्रीन विंग्स फार्मर्स प्रोड्यूसर कंपनी ने अपनी सदस्य संख्या 600 से अधिक कर ली।','600+ सदस्य','hi',9,'published','2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00');
INSERT INTO company_timelines VALUES(45,'2025','सदस्यता 600+ पार','सातत्यपूर्ण शेतकरी सहाय्य, खरेदी उपक्रम आणि इनपुट पुरवठा सेवांद्वारे ग्रीन विंग्स फार्मर्स प्रोड्यूसर कंपनीची सदस्य संख्या 600 पेक्षा जास्त झाली.','600+ सदस्य','mr',9,'published','2026-06-21T11:19:10+00:00','2026-06-21T11:19:10+00:00');
