INSERT INTO success_stories VALUES(1,'Mr. Pravin Malhari Jadhav','','Organic Fertilizer Improved Onion Yield','pravin-malhari-jadhav-onion-yield','Jalgaon Neur, Yeola, Nashik','Jalgaon Neur','Nashik','Onion, Papaya, Maize, Pomegranate','15 gunthas comparison plots','Input Support','The organic fertilizer helped us increase onion yield from 30 quintals to 40 quintals on the same land area.','Mr. Pravin Malhari Jadhav compared regular chemical fertilizer with Ichhamani Organic Fertilizer on equal onion plots and saw a clear yield improvement.',unistr('In the first year, Mr. Pravin Malhari Jadhav cultivated onions on 15 gunthas of land using the regular chemical fertilizers commonly recommended in the area. The yield obtained from this plot was 30 quintals of onions.\u000a\u000aOn another plot of the same size, he used Ichhamani Organic Fertilizer supplied by the company. The yield from this plot increased to 40 quintals, showing a clear improvement compared to the chemical fertilizer plot.\u000a\u000aAfter seeing these results, he started using Ichhamani Organic Fertilizer regularly on papaya, maize, onion and pomegranate. The treated crops showed better growth, vigor and overall field performance.\u000a\u000aDuring the Kharif season of 2025, the company also supplied maize seed. The crop performance was excellent, with higher productivity than other maize varieties commonly grown in the area.'),'The farmer was using regular chemical fertilizers and wanted better crop growth, stronger plants and improved productivity without increasing land area.','GreenWings supplied Ichhamani Organic Fertilizer and later supported the farmer with the company''s maize seed variety during the Kharif season.','Onion yield improved from 30 quintals to 40 quintals on the same 15 guntha plot size, and other crops showed better growth and vigor.','30 quintals onion yield','40 quintals onion yield','10 quintals higher onion output on the same area','Improved productivity potential across onion, papaya, maize and pomegranate crops','Ichhamani Organic Fertilizer','Company maize seed variety','Input guidance and crop-performance support','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/real/Pravin_Malhari_Jadhav.jpeg','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/real/Pravin_Malhari_Jadhav.jpeg','en',1,1,'published','2026-06-21T15:44:48+00:00','2026-06-21T15:44:48+00:00',NULL);
INSERT INTO success_stories VALUES(2,'Mr. Gorakhanath Namdeorao Shelke','','Dragon Fruit Yield and Market Price Improved','gorakhanath-shelke-dragon-fruit-market-access','Yeola, Nashik','Yeola','Nashik','Dragon Fruit','1 bigha','Market Access','With Ichhamani Organic Fertilizer and company marketing support, dragon fruit yield increased and we received a better selling price.','Mr. Gorakhanath Shelke improved dragon fruit yield from 12 quintals to 20 quintals and received ₹2-3 per kg above prevailing market prices through company support.',unistr('Mr. Gorakhanath Namdeorao Shelke cultivates dragon fruit on 1 bigha of land. In the previous year, he used other organic fertilizers and obtained 12 quintals of dragon fruit from the same area.\u000a\u000aThis year, after using Ichhamani Organic Fertilizer, the yield increased significantly to 20 quintals from the same 1 bigha field.\u000a\u000aAlong with improved production, the company helped arrange marketing and sale of the produce. Through this support, he secured a selling price that was ₹2-3 per kilogram higher than the prevailing market rate.\u000a\u000aThe improved yield, better market access and transparent sales support helped increase overall farm profitability.'),'The farmer needed stronger productivity in dragon fruit cultivation and better support for selling produce at a fair market price.','GreenWings supported the crop with Ichhamani Organic Fertilizer and helped arrange marketing and sale of the produce.','Dragon fruit yield improved from 12 quintals to 20 quintals on the same land area, with ₹2-3 per kg better selling price.','12 quintals dragon fruit yield','20 quintals dragon fruit yield','₹2-3 per kg higher than prevailing market rate','Higher farm profitability through improved yield and better market access','Ichhamani Organic Fertilizer','','Marketing arrangement and sale support','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/real/Gorakhnath%20Shelke.jpeg','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/real/Gorakhnath%20Shelke.jpeg','en',2,1,'published','2026-06-21T15:44:48+00:00','2026-06-21T15:44:48+00:00',NULL);
INSERT INTO success_stories VALUES(3,'Mr. Pravin Malhari Jadhav','','जैविक खाद से प्याज उत्पादन में वृद्धि','pravin-malhari-jadhav-onion-yield','Jalgaon Neur, Yeola, Nashik','Jalgaon Neur','Nashik','Onion, Papaya, Maize, Pomegranate','15 gunthas comparison plots','इनपुट सहयोग','इसी भूमि क्षेत्र में जैविक खाद से प्याज उत्पादन 30 क्विंटल से बढ़कर 40 क्विंटल हुआ।','श्री प्रवीण मल्हारी जाधव ने समान आकार के प्याज प्लॉट में रासायनिक खाद और इच्छामणि जैविक खाद की तुलना की और स्पष्ट उत्पादन वृद्धि देखी।',unistr('पहले वर्ष में श्री प्रवीण मल्हारी जाधव ने 15 गुंठे भूमि पर सामान्य रासायनिक खादों का उपयोग कर प्याज की खेती की। इस प्लॉट से 30 क्विंटल प्याज उत्पादन मिला।\u000a\u000aइसी आकार के दूसरे प्लॉट में उन्होंने कंपनी द्वारा उपलब्ध कराई गई इच्छामणि जैविक खाद का उपयोग किया। इस प्लॉट से उत्पादन 40 क्विंटल तक बढ़ गया।\u000a\u000aइन परिणामों के बाद उन्होंने पपीता, मक्का, प्याज और अनार में इच्छामणि जैविक खाद का नियमित उपयोग शुरू किया। फसलों में बेहतर बढ़वार, ताकत और प्रदर्शन दिखाई दिया।\u000a\u000aखरीफ 2025 में कंपनी ने मक्का बीज भी उपलब्ध कराया, जिससे क्षेत्र की अन्य किस्मों की तुलना में बेहतर उत्पादकता मिली।'),'किसान बेहतर फसल बढ़वार और अधिक उत्पादकता चाहते थे, लेकिन भूमि क्षेत्र वही रखना था।','ग्रीनविंग्स ने इच्छामणि जैविक खाद और खरीफ मौसम में कंपनी की मक्का बीज किस्म उपलब्ध कराई।','समान 15 गुंठे क्षेत्र में प्याज उत्पादन 30 क्विंटल से बढ़कर 40 क्विंटल हुआ।','30 क्विंटल प्याज उत्पादन','40 क्विंटल प्याज उत्पादन','उसी क्षेत्र में 10 क्विंटल अधिक उत्पादन','प्याज, पपीता, मक्का और अनार में बेहतर उत्पादकता की संभावना','Ichhamani Organic Fertilizer','Company maize seed variety','इनपुट मार्गदर्शन और फसल प्रदर्शन सहयोग','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/real/Pravin_Malhari_Jadhav.jpeg','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/real/Pravin_Malhari_Jadhav.jpeg','hi',1,1,'published','2026-06-21T15:44:48+00:00','2026-06-21T15:44:48+00:00',NULL);
INSERT INTO success_stories VALUES(4,'Mr. Gorakhanath Namdeorao Shelke','','ड्रैगन फ्रूट उत्पादन और बाजार मूल्य में सुधार','gorakhanath-shelke-dragon-fruit-market-access','Yeola, Nashik','Yeola','Nashik','Dragon Fruit','1 bigha','बाजार पहुंच','इच्छामणि जैविक खाद और कंपनी के विपणन सहयोग से उत्पादन बढ़ा और बेहतर बिक्री मूल्य मिला।','श्री गोरखनाथ शेलके का ड्रैगन फ्रूट उत्पादन 12 क्विंटल से 20 क्विंटल हुआ और कंपनी सहयोग से ₹2-3 प्रति किलो अधिक भाव मिला।',unistr('श्री गोरखनाथ नामदेवराव शेलके 1 बीघा भूमि पर ड्रैगन फ्रूट की खेती करते हैं। पिछले वर्ष अन्य जैविक खादों से 12 क्विंटल उत्पादन मिला था।\u000a\u000aइस वर्ष इच्छामणि जैविक खाद के उपयोग के बाद उसी 1 बीघा क्षेत्र से उत्पादन 20 क्विंटल तक बढ़ गया।\u000a\u000aकंपनी ने उपज की बिक्री और विपणन व्यवस्था में भी सहयोग किया, जिससे उन्हें बाजार दर से ₹2-3 प्रति किलो अधिक भाव मिला।\u000a\u000aबेहतर उत्पादन, बाजार पहुंच और पारदर्शी बिक्री सहयोग से फार्म की लाभप्रदता बढ़ी।'),'किसान को ड्रैगन फ्रूट में अधिक उत्पादकता और उचित बिक्री मूल्य की आवश्यकता थी।','ग्रीनविंग्स ने इच्छामणि जैविक खाद और उपज की बिक्री व्यवस्था में सहयोग दिया।','उत्पादन 12 क्विंटल से 20 क्विंटल हुआ और ₹2-3 प्रति किलो अधिक भाव मिला।','12 क्विंटल ड्रैगन फ्रूट उत्पादन','20 क्विंटल ड्रैगन फ्रूट उत्पादन','बाजार दर से ₹2-3 प्रति किलो अधिक','बेहतर उत्पादन और बाजार पहुंच से अधिक लाभप्रदता','Ichhamani Organic Fertilizer','','विपणन व्यवस्था और बिक्री सहयोग','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/real/Gorakhnath%20Shelke.jpeg','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/real/Gorakhnath%20Shelke.jpeg','hi',2,1,'published','2026-06-21T15:44:48+00:00','2026-06-21T15:44:48+00:00',NULL);
INSERT INTO success_stories VALUES(5,'Mr. Pravin Malhari Jadhav','','सेंद्रिय खतामुळे कांदा उत्पादनात वाढ','pravin-malhari-jadhav-onion-yield','Jalgaon Neur, Yeola, Nashik','Jalgaon Neur','Nashik','Onion, Papaya, Maize, Pomegranate','15 gunthas comparison plots','इनपुट सहाय्य','त्याच क्षेत्रात सेंद्रिय खतामुळे कांदा उत्पादन 30 क्विंटलवरून 40 क्विंटल झाले.','श्री. प्रवीण मल्हारी जाधव यांनी समान आकाराच्या कांदा प्लॉटमध्ये रासायनिक खत आणि इच्छामणि सेंद्रिय खताची तुलना केली आणि स्पष्ट उत्पादन वाढ पाहिली.',unistr('पहिल्या वर्षी श्री. प्रवीण मल्हारी जाधव यांनी 15 गुंठे जमिनीवर नियमित रासायनिक खतांचा वापर करून कांदा लागवड केली. या प्लॉटमधून 30 क्विंटल कांदा उत्पादन मिळाले.\u000a\u000aत्याच आकाराच्या दुसऱ्या प्लॉटमध्ये त्यांनी कंपनीकडून मिळालेल्या इच्छामणि सेंद्रिय खताचा वापर केला. या प्लॉटमधून उत्पादन 40 क्विंटलपर्यंत वाढले.\u000a\u000aहे परिणाम पाहिल्यानंतर त्यांनी पपई, मका, कांदा आणि डाळिंबामध्ये इच्छामणि सेंद्रिय खताचा नियमित वापर सुरू केला. पिकांमध्ये चांगली वाढ, जोम आणि कामगिरी दिसली.\u000a\u000aखरीप 2025 मध्ये कंपनीने मका बियाणेही उपलब्ध करून दिले, ज्यामुळे परिसरातील इतर वाणांच्या तुलनेत चांगली उत्पादकता मिळाली.'),'शेतकऱ्यांना त्याच जमिनीवर चांगली वाढ आणि अधिक उत्पादकता हवी होती.','ग्रीनविंग्सने इच्छामणि सेंद्रिय खत आणि खरीप हंगामात कंपनीचे मका बियाणे उपलब्ध करून दिले.','त्याच 15 गुंठे क्षेत्रात कांदा उत्पादन 30 क्विंटलवरून 40 क्विंटल झाले.','30 क्विंटल कांदा उत्पादन','40 क्विंटल कांदा उत्पादन','त्याच क्षेत्रात 10 क्विंटल अधिक उत्पादन','कांदा, पपई, मका आणि डाळिंबात चांगल्या उत्पादकतेची संधी','Ichhamani Organic Fertilizer','Company maize seed variety','इनपुट मार्गदर्शन आणि पीक कामगिरी सहाय्य','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/real/Pravin_Malhari_Jadhav.jpeg','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/real/Pravin_Malhari_Jadhav.jpeg','mr',1,1,'published','2026-06-21T15:44:48+00:00','2026-06-21T15:44:48+00:00',NULL);
INSERT INTO success_stories VALUES(6,'Mr. Gorakhanath Namdeorao Shelke','','ड्रॅगन फ्रूट उत्पादन आणि बाजारभावात सुधारणा','gorakhanath-shelke-dragon-fruit-market-access','Yeola, Nashik','Yeola','Nashik','Dragon Fruit','1 bigha','बाजारपेठ प्रवेश','इच्छामणि सेंद्रिय खत आणि कंपनीच्या विपणन सहाय्यामुळे उत्पादन वाढले आणि चांगला दर मिळाला.','श्री. गोरखनाथ शेलके यांचे ड्रॅगन फ्रूट उत्पादन 12 क्विंटलवरून 20 क्विंटल झाले आणि कंपनीच्या सहाय्याने ₹2-3 प्रति किलो जास्त दर मिळाला.',unistr('श्री. गोरखनाथ नामदेवराव शेलके 1 बीघा जमिनीवर ड्रॅगन फ्रूटची लागवड करतात. मागील वर्षी इतर सेंद्रिय खतांनी 12 क्विंटल उत्पादन मिळाले होते.\u000a\u000aया वर्षी इच्छामणि सेंद्रिय खत वापरल्यानंतर त्याच 1 बीघा क्षेत्रातून उत्पादन 20 क्विंटलपर्यंत वाढले.\u000a\u000aकंपनीने उत्पादनाच्या विक्री आणि विपणन व्यवस्थेतही मदत केली, ज्यामुळे त्यांना बाजारभावापेक्षा ₹2-3 प्रति किलो अधिक दर मिळाला.\u000a\u000aचांगले उत्पादन, बाजारपेठ प्रवेश आणि पारदर्शक विक्री सहाय्यामुळे शेतीची नफा क्षमता वाढली.'),'शेतकऱ्यांना ड्रॅगन फ्रूटमध्ये अधिक उत्पादन आणि योग्य विक्री दराची गरज होती.','ग्रीनविंग्सने इच्छामणि सेंद्रिय खत आणि उत्पादन विक्री व्यवस्थेत सहाय्य दिले.','उत्पादन 12 क्विंटलवरून 20 क्विंटल झाले आणि ₹2-3 प्रति किलो जास्त दर मिळाला.','12 क्विंटल ड्रॅगन फ्रूट उत्पादन','20 क्विंटल ड्रॅगन फ्रूट उत्पादन','बाजारभावापेक्षा ₹2-3 प्रति किलो अधिक','चांगले उत्पादन आणि बाजारपेठ प्रवेशामुळे अधिक नफा','Ichhamani Organic Fertilizer','','विपणन व्यवस्था आणि विक्री सहाय्य','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/real/Gorakhnath%20Shelke.jpeg','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/ui-assets/farmers/real/Gorakhnath%20Shelke.jpeg','mr',2,1,'published','2026-06-21T15:44:48+00:00','2026-06-21T15:44:48+00:00',NULL);
