INSERT INTO fertilizers VALUES(1,'local','Neem Coated Urea','Nitrogen fertilizer','National Fertilizers Limited',NULL,'India','Government-approved nitrogen fertilizer designed to release nitrogen gradually and reduce nutrient loss in Indian field conditions.','Nitrogen 46% with neem oil coating for controlled release.','Basal and top dressing nitrogen nutrition for cereals, sugarcane, cotton and vegetables.','Wheat, maize, paddy, sugarcane, cotton, onion and leafy vegetables.','Avoid direct seed contact, waterlogged fields and crops under severe drought stress.','Broadcast evenly and incorporate into moist soil. Split application is recommended for long-duration crops.','Basal dose and active vegetative growth stage.','Kharif and rabi.','18-35 C.','Alluvial, black cotton and medium-textured soils with adequate moisture.','Supports steady vegetative growth, improves nitrogen use efficiency and helps reduce volatilization losses.','Use soil-test based dosage, wear gloves, and do not over-apply near water bodies.','/assets/agri-inputs/local-neem-urea.svg','/resources/neem-coated-urea-guide.txt','Government of India fertilizer control approved category','Recommended across Maharashtra for cereals, sugarcane and onion under guided nutrient plans.',NULL,NULL,'active','2026-06-20T16:26:46+00:00','2026-06-20T16:26:46+00:00',NULL);
INSERT INTO fertilizers VALUES(2,'local','City Compost Organic Manure','Organic fertilizer','Maharashtra Agro Industries Development Corporation',NULL,'India','Organic manure option for soil health improvement, carbon addition and balanced microbial activity in regional farming systems.','Organic carbon, humic matter, secondary nutrients and beneficial microbial activity.','Soil conditioning, organic carbon improvement and pre-planting manure application.','Grapes, pomegranate, banana, vegetables, pulses, cereals and orchard crops.','Avoid fresh application near tender seedlings without proper compost maturity confirmation.','Apply during land preparation and mix well into the root zone.','Before sowing, before transplanting and during orchard basin preparation.','Pre-kharif, pre-rabi and orchard annual nutrition cycle.','15-38 C.','Low-organic-carbon soils, black soils and light soils needing structure improvement.','Improves soil structure, moisture holding, microbial activity and long-term nutrient availability.','Use mature compost only and avoid mixing directly with concentrated chemical fertilizers during storage.','/assets/agri-inputs/local-city-compost.svg','/resources/city-compost-guide.txt','Organic input aligned with government soil health improvement programmes','Useful for Nashik and Yeola orchards where organic carbon rebuilding is a priority.',NULL,NULL,'active','2026-06-20T16:26:46+00:00','2026-06-20T16:26:46+00:00',NULL);
INSERT INTO fertilizers VALUES(3,'imported','YaraMila Complex 12-11-18','NPK complex fertilizer','Yara International','YaraMila','Norway','Premium imported NPK formulation for balanced macronutrient supply and quality-focused crop development.','NPK 12-11-18 with sulphur, magnesium and crop-available micronutrient support.','Balanced nutrition for high-value crops requiring uniform granule quality and predictable nutrient release.','Grapes, pomegranate, banana, vegetables, floriculture and protected cultivation crops.','Avoid salt-sensitive nursery crops and direct placement near tender roots without irrigation.','Apply through soil broadcasting, band placement or fertigation-compatible programmes as advised.','Vegetative growth, flowering support and early fruit development.','Year-round for irrigated high-value crops.','16-34 C.','Well-drained loam, black soil and managed orchard soils.','Supports uniform growth, flowering, fruit size and premium quality output.','Follow crop-specific dosage, avoid mixing with incompatible alkaline materials and store in a dry place.','/assets/agri-inputs/imported-yaramila.svg','/resources/yaramila-product-specification.txt',NULL,NULL,'Importer quality documentation, batch certificate and compliant product labelling required.','European granulation standards with declared nutrient composition and traceability.','active','2026-06-20T16:26:46+00:00','2026-06-20T16:26:46+00:00',NULL);
INSERT INTO fertilizers VALUES(4,'imported','Haifa Multi-K Potassium Nitrate','Water soluble fertilizer','Haifa Group','Multi-K','Israel','High-purity imported potassium nitrate used for precision fertigation, fruit quality and stress-stage nutrition.','Potassium nitrate with nitrate nitrogen and fully water-soluble potassium.','Fertigation, foliar feeding and precision crop nutrition programmes.','Grapes, pomegranate, banana, tomato, chilli, capsicum, cucumber and export-oriented vegetables.','Avoid use on crops under severe water stress or with incompatible calcium-rich tank mixes.','Apply through drip fertigation or foliar spray as per agronomist dosage guidance.','Flowering, fruit setting, fruit sizing and quality development stages.','Irrigated crop cycles and protected cultivation seasons.','14-32 C.','Drip-irrigated soils with managed EC and pH.','Improves fruit size, colour, sugar accumulation and potassium-driven crop quality.','Check water pH and EC, avoid excessive foliar concentration and follow label directions.','/assets/agri-inputs/imported-haifa-multik.svg','/resources/haifa-multik-specification.txt',NULL,NULL,'Product import documentation, certificate of analysis and batch traceability required.','High-purity crystalline water-soluble fertilizer for fertigation systems.','active','2026-06-20T16:26:46+00:00','2026-06-20T16:26:46+00:00',NULL);
INSERT INTO fertilizer_translations VALUES(1,1,'hi','नीम लेपित यूरिया','नाइट्रोजन उर्वरक','सरकार द्वारा अनुमोदित नाइट्रोजन उर्वरक, जो भारतीय खेत परिस्थितियों में नाइट्रोजन को धीरे-धीरे उपलब्ध कराने और पोषक तत्वों की हानि कम करने में मदद करता है।','नियंत्रित रिलीज के लिए नीम तेल लेप के साथ 46% नाइट्रोजन।','अनाज, गन्ना, कपास और सब्जियों में बेसल तथा टॉप ड्रेसिंग नाइट्रोजन पोषण।','स्थिर वानस्पतिक वृद्धि, बेहतर नाइट्रोजन उपयोग दक्षता और वाष्पीकरण हानि में कमी।','मिट्टी परीक्षण आधारित मात्रा का उपयोग करें, दस्ताने पहनें और जल स्रोतों के पास अधिक मात्रा न डालें।','भारत','गेहूं, मक्का, धान, गन्ना, कपास, प्याज और पत्तेदार सब्जियां।','बीज के सीधे संपर्क, जलभराव वाले खेतों और गंभीर सूखे तनाव वाली फसलों में उपयोग से बचें।','नम मिट्टी में समान रूप से छिड़कें और हल्का मिला दें। लंबी अवधि की फसलों में विभाजित मात्रा देना बेहतर है।','बेसल मात्रा और सक्रिय वानस्पतिक वृद्धि अवस्था।','खरीफ और रबी।','18-35 C.','पर्याप्त नमी वाली जलोढ़, काली कपास और मध्यम बनावट की मिट्टी।','भारत सरकार के उर्वरक नियंत्रण अनुमोदित वर्ग के अंतर्गत।','महाराष्ट्र में अनाज, गन्ना और प्याज के लिए मार्गदर्शित पोषण योजना के तहत अनुशंसित।','','','','2026-06-22T07:56:31+00:00','2026-06-27T16:00:30+00:00',NULL);
INSERT INTO fertilizer_translations VALUES(2,1,'mr','नीम लेपित युरिया','नायट्रोजन खत','भारतीय शेती परिस्थितीत नायट्रोजन हळूहळू उपलब्ध करून पोषक घटकांची हानी कमी करण्यासाठी तयार केलेले शासनमान्य नायट्रोजन खत.','नियंत्रित उपलब्धतेसाठी नीम तेलाच्या लेपासह 46% नायट्रोजन.','तृणधान्ये, ऊस, कापूस आणि भाजीपाला पिकांसाठी बेसल व टॉप ड्रेसिंग नायट्रोजन पोषण.','समतोल वाढ, नायट्रोजन वापर कार्यक्षमता आणि उडून जाणारी हानी कमी करण्यास मदत.','माती परीक्षणानुसार मात्रा द्या, हातमोजे वापरा आणि पाणवठ्याजवळ अतिमात्रा टाळा.','भारत','गहू, मका, भात, ऊस, कापूस, कांदा आणि पालेभाज्या.','बियाण्याशी थेट संपर्क, पाणी साचलेली शेते आणि तीव्र दुष्काळ ताण असलेली पिके टाळा.','ओलसर मातीत समप्रमाणात पसरवून हलके मिसळा. दीर्घ कालावधीच्या पिकांसाठी विभागून मात्रा देणे योग्य.','बेसल मात्रा आणि सक्रिय वाढीची अवस्था.','खरीप आणि रबी.','18-35 C.','पुरेशी ओल असलेली गाळाची, काळी कापूस व मध्यम पोताची माती.','भारत सरकारच्या खत नियंत्रण मान्य श्रेणीअंतर्गत.','महाराष्ट्रात तृणधान्ये, ऊस आणि कांदा पिकांसाठी मार्गदर्शित पोषण योजनेत अनुशंसित.','','','','2026-06-22T07:56:31+00:00','2026-06-27T16:00:30+00:00',NULL);
INSERT INTO fertilizer_translations VALUES(3,2,'hi','सिटी कम्पोस्ट जैविक खाद','जैविक उर्वरक','मिट्टी स्वास्थ्य सुधार, कार्बन वृद्धि और क्षेत्रीय खेती प्रणालियों में संतुलित सूक्ष्मजीव गतिविधि के लिए जैविक खाद विकल्प।','जैविक कार्बन, ह्यूमिक पदार्थ, द्वितीयक पोषक तत्व और लाभकारी सूक्ष्मजीव गतिविधि।','मिट्टी सुधार, जैविक कार्बन बढ़ाने और रोपाई/बुवाई से पहले खाद के रूप में।','मिट्टी की संरचना, नमी धारण क्षमता, सूक्ष्मजीव गतिविधि और दीर्घकालीन पोषक उपलब्धता में सुधार।','केवल परिपक्व कम्पोस्ट का उपयोग करें और भंडारण में इसे सघन रासायनिक उर्वरकों के साथ सीधे न मिलाएं।','भारत','अंगूर, अनार, केला, सब्जियां, दलहन, अनाज और बागवानी फसलें।','पूरी तरह पकी खाद की पुष्टि के बिना नाजुक पौधों के पास ताजा उपयोग न करें।','भूमि तैयारी के समय डालें और जड़ क्षेत्र में अच्छी तरह मिलाएं।','बुवाई से पहले, रोपाई से पहले और बागों में बेसिन तैयारी के समय।','पूर्व-खरीफ, पूर्व-रबी और बागों का वार्षिक पोषण चक्र।','15-38 C.','कम जैविक कार्बन वाली, काली और संरचना सुधार की जरूरत वाली हल्की मिट्टियां।','सरकारी मिट्टी स्वास्थ्य सुधार कार्यक्रमों से जुड़ा जैविक इनपुट।','नाशिक और येवला के बागों में जैविक कार्बन पुनर्निर्माण के लिए उपयोगी।','','','','2026-06-22T07:56:31+00:00','2026-06-27T16:00:30+00:00',NULL);
INSERT INTO fertilizer_translations VALUES(4,2,'mr','सिटी कम्पोस्ट सेंद्रिय खत','सेंद्रिय खत','मातीचे आरोग्य सुधारणा, कार्बन वाढ आणि प्रादेशिक शेती पद्धतींमध्ये संतुलित सूक्ष्मजीव क्रियेसाठी सेंद्रिय खताचा पर्याय.','सेंद्रिय कार्बन, ह्युमिक घटक, दुय्यम पोषक घटक आणि उपयुक्त सूक्ष्मजीव क्रिया.','माती सुधारणा, सेंद्रिय कार्बन वाढ आणि लागवडीपूर्व खत म्हणून वापर.','मातीची रचना, ओल धारण क्षमता, सूक्ष्मजीव क्रिया आणि दीर्घकालीन पोषक उपलब्धता सुधारते.','परिपक्व कम्पोस्टच वापरा आणि साठवणीत तीव्र रासायनिक खतांसोबत थेट मिसळू नका.','भारत','द्राक्षे, डाळिंब, केळी, भाजीपाला, कडधान्ये, तृणधान्ये आणि फळबाग पिके.','खत पूर्णपणे परिपक्व असल्याची खात्री नसल्यास कोवळ्या रोपांजवळ ताजा वापर टाळा.','जमीन तयारीच्या वेळी टाका आणि मुळांच्या भागात व्यवस्थित मिसळा.','पेरणीपूर्वी, लागवडीपूर्वी आणि बागेतील बेसिन तयारीच्या वेळी.','पूर्व-खरीप, पूर्व-रबी आणि बागांचा वार्षिक पोषण चक्र.','15-38 C.','कमी सेंद्रिय कार्बन असलेली, काळी आणि रचना सुधारण्याची गरज असलेली हलकी माती.','शासकीय माती आरोग्य सुधार कार्यक्रमांशी सुसंगत सेंद्रिय इनपुट.','नाशिक आणि येवला भागातील बागांसाठी सेंद्रिय कार्बन वाढवण्यास उपयुक्त.','','','','2026-06-22T07:56:31+00:00','2026-06-27T16:00:30+00:00',NULL);
INSERT INTO fertilizer_translations VALUES(5,3,'hi','YaraMila कॉम्प्लेक्स 12-11-18','एनपीके कॉम्प्लेक्स उर्वरक','संतुलित मुख्य पोषक तत्वों और गुणवत्ता-केंद्रित फसल विकास के लिए प्रीमियम आयातित एनपीके फॉर्मुलेशन।','सल्फर, मैग्नीशियम और उपलब्ध सूक्ष्म पोषक समर्थन के साथ NPK 12-11-18।','समान ग्रेन्यूल गुणवत्ता और अनुमानित पोषक रिलीज चाहने वाली उच्च-मूल्य फसलों के लिए संतुलित पोषण।','समान वृद्धि, फूल, फल आकार और प्रीमियम गुणवत्ता उत्पादन में मदद।','फसल-विशिष्ट मात्रा अपनाएं, असंगत क्षारीय सामग्री से मिश्रण न करें और सूखी जगह पर रखें।','नॉर्वे','अंगूर, अनार, केला, सब्जियां, फूलों की खेती और संरक्षित खेती की फसलें।','नमक-संवेदनशील नर्सरी फसलों और सिंचाई के बिना कोमल जड़ों के पास सीधे उपयोग से बचें।','सलाह के अनुसार मिट्टी में छिड़काव, बैंड प्लेसमेंट या फर्टिगेशन कार्यक्रम में उपयोग करें।','वानस्पतिक वृद्धि, फूल समर्थन और प्रारंभिक फल विकास।','सिंचित उच्च-मूल्य फसलों के लिए वर्षभर।','16-34 C.','अच्छी जलनिकासी वाली दोमट, काली और प्रबंधित बाग मिट्टी।','','','YaraMila','आयातक गुणवत्ता दस्तावेज, बैच प्रमाणपत्र और अनुरूप उत्पाद लेबलिंग आवश्यक।','घोषित पोषक संरचना और ट्रेसबिलिटी के साथ यूरोपीय ग्रेनुलेशन मानक।','2026-06-22T07:56:31+00:00','2026-06-27T16:00:30+00:00',NULL);
INSERT INTO fertilizer_translations VALUES(6,3,'mr','YaraMila कॉम्प्लेक्स 12-11-18','एनपीके कॉम्प्लेक्स खत','समतोल मुख्य पोषक पुरवठा आणि गुणवत्तापूर्ण पीक विकासासाठी प्रीमियम आयातित एनपीके फॉर्म्युलेशन.','सल्फर, मॅग्नेशियम आणि उपलब्ध सूक्ष्म पोषक समर्थनासह NPK 12-11-18.','एकसमान दाणेदार गुणवत्ता आणि अंदाजित पोषक उपलब्धता हवी असलेल्या उच्च-मूल्य पिकांसाठी समतोल पोषण.','समतोल वाढ, फुलोरा, फळांचा आकार आणि प्रीमियम दर्जाचे उत्पादन यास मदत.','पीकनिहाय मात्रा पाळा, विसंगत क्षारीय पदार्थांशी मिश्रण टाळा आणि कोरड्या ठिकाणी साठवा.','नॉर्वे','द्राक्षे, डाळिंब, केळी, भाजीपाला, फुलशेती आणि संरक्षित शेतीतील पिके.','मीठ-संवेदनशील नर्सरी पिके आणि सिंचनाशिवाय कोवळ्या मुळांजवळ थेट वापर टाळा.','सल्ल्यानुसार मातीवर पसरवणे, बँड प्लेसमेंट किंवा फर्टिगेशन कार्यक्रमात वापरा.','वानस्पतिक वाढ, फुलोरा समर्थन आणि प्रारंभिक फलधारणा.','सिंचित उच्च-मूल्य पिकांसाठी वर्षभर.','16-34 C.','चांगला निचरा असलेली दोमट, काळी आणि व्यवस्थापित बाग माती.','','','YaraMila','आयात गुणवत्ता कागदपत्रे, बॅच प्रमाणपत्र आणि अनुरूप उत्पादन लेबलिंग आवश्यक.','घोषित पोषक संरचना आणि ट्रेसेबिलिटीसह युरोपीय दाणेदार मानके.','2026-06-22T07:56:31+00:00','2026-06-27T16:00:30+00:00',NULL);
INSERT INTO fertilizer_translations VALUES(7,4,'hi','Haifa Multi-K पोटैशियम नाइट्रेट','जल घुलनशील उर्वरक','प्रिसिजन फर्टिगेशन, फल गुणवत्ता और तनाव अवस्था पोषण के लिए उच्च-शुद्धता आयातित पोटैशियम नाइट्रेट।','नाइट्रेट नाइट्रोजन और पूर्णतः जल-घुलनशील पोटैशियम के साथ पोटैशियम नाइट्रेट।','फर्टिगेशन, पर्णीय छिड़काव और प्रिसिजन फसल पोषण कार्यक्रम।','फल आकार, रंग, शर्करा संचय और पोटैशियम-आधारित गुणवत्ता में सुधार।','पानी का pH और EC जांचें, अधिक पर्णीय सांद्रता से बचें और लेबल निर्देशों का पालन करें।','इजराइल','अंगूर, अनार, केला, टमाटर, मिर्च, शिमला मिर्च, ककड़ी और निर्यात-उन्मुख सब्जियां।','गंभीर जल तनाव वाली फसलों या कैल्शियम-समृद्ध असंगत टैंक मिश्रणों में उपयोग से बचें।','कृषि विशेषज्ञ की मात्रा सलाह के अनुसार ड्रिप फर्टिगेशन या पर्णीय स्प्रे से उपयोग करें।','फूल, फल सेटिंग, फल आकार और गुणवत्ता विकास अवस्था।','सिंचित फसल चक्र और संरक्षित खेती के मौसम।','14-32 C.','प्रबंधित EC और pH वाली ड्रिप-सिंचित मिट्टियां।','','','Multi-K','उत्पाद आयात दस्तावेज, विश्लेषण प्रमाणपत्र और बैच ट्रेसबिलिटी आवश्यक।','फर्टिगेशन प्रणालियों के लिए उच्च-शुद्धता क्रिस्टलीय जल-घुलनशील उर्वरक।','2026-06-22T07:56:31+00:00','2026-06-27T16:00:30+00:00',NULL);
INSERT INTO fertilizer_translations VALUES(8,4,'mr','Haifa Multi-K पोटॅशियम नायट्रेट','पाण्यात विद्रव्य खत','प्रिसिजन फर्टिगेशन, फळ गुणवत्ता आणि ताण अवस्थेतील पोषणासाठी उच्च-शुद्धतेचे आयातित पोटॅशियम नायट्रेट.','नायट्रेट नायट्रोजन आणि पूर्णपणे पाण्यात विद्रव्य पोटॅशियमसह पोटॅशियम नायट्रेट.','फर्टिगेशन, पानांवर फवारणी आणि अचूक पीक पोषण कार्यक्रम.','फळांचा आकार, रंग, साखर संचय आणि पोटॅशियम-आधारित गुणवत्ता सुधारते.','पाण्याचा pH आणि EC तपासा, जास्त पर्णीय सांद्रता टाळा आणि लेबलवरील सूचना पाळा.','इस्रायल','द्राक्षे, डाळिंब, केळी, टोमॅटो, मिरची, ढोबळी मिरची, काकडी आणि निर्याताभिमुख भाजीपाला.','तीव्र पाण्याच्या ताणाखालील पिके किंवा कॅल्शियमयुक्त विसंगत टँक मिश्रणात वापर टाळा.','कृषी तज्ज्ञांच्या मात्रेनुसार ड्रिप फर्टिगेशन किंवा पानांवरील फवारणीद्वारे वापरा.','फुलोरा, फलधारणा, फळ वाढ आणि गुणवत्ता विकास अवस्था.','सिंचित पीक चक्र आणि संरक्षित शेती हंगाम.','14-32 C.','नियंत्रित EC आणि pH असलेली ड्रिप-सिंचित माती.','','','Multi-K','उत्पादन आयात कागदपत्रे, विश्लेषण प्रमाणपत्र आणि बॅच ट्रेसेबिलिटी आवश्यक.','फर्टिगेशन प्रणालींसाठी उच्च-शुद्धतेचे स्फटिकीय पाण्यात विद्रव्य खत.','2026-06-22T07:56:31+00:00','2026-06-27T16:00:30+00:00',NULL);
INSERT INTO crop_category VALUES(1,'Fresh Fruits','Fresh fruits are GreenWings'' premium horticulture category, covering mango, grapes, pomegranate, banana, guava, citrus, papaya, watermelon and other high-demand fruit crops.',NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33',NULL,'fruits','India''s diverse agro-climatic zones support a wide basket of tropical and subtropical fruits. APEDA identifies fresh fruits and vegetables as an important export category, with Indian grapes, pomegranates, mangoes, bananas and citrus fruits finding strong domestic and international demand. GreenWings uses this category for fresh, naturally ripened, quality-graded fruit crops that can serve local markets, retail chains, food processors and export buyers with traceability and careful post-harvest handling.','https://apeda.gov.in/FreshFruitsAndVegetables',1,'active');
INSERT INTO crop_category VALUES(2,'Grains & Cereals','Grains and cereals cover staple crops such as rice, wheat and maize, along with related bulk field crops that support food security and processing markets.',NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33',NULL,'grains','Cereals remain the foundation of India''s food security and a major agricultural trade segment. Rice, wheat and maize are key crops for household consumption, milling, food processing, animal feed and institutional procurement. GreenWings uses this category for staple grains and cereal-linked field crops where quality parameters such as purity, moisture, grain size and end-use performance matter for buyers.','https://apeda.gov.in/OtherCereals;https://apeda.gov.in/MilledProducts',2,'active');
INSERT INTO crop_category VALUES(3,'Millets','Millets include climate-resilient crops such as jowar, bajra, ragi, barnyard millet, kodo millet, little millet and proso millet.',NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33',NULL,'millets','Millets are traditional nutri-cereals valued for resilience under dryland farming, lower water needs and strong nutrition positioning. Indian millet promotion has increased demand across health-food, school nutrition, ready-to-cook and export-oriented specialty channels. GreenWings groups jowar, bajra, ragi and small millets here so farmers and buyers can treat them as a dedicated climate-smart category rather than mixing them into generic grains.','https://apeda.gov.in/milletportal/',3,'active');
INSERT INTO crop_category VALUES(4,'Pulses & Lentils','Pulses and lentils cover protein-rich crops such as chickpea, pigeon pea, black gram and lentil.','','2026-06-27 17:53:35','2026-06-27 18:10:33','','pulses','Pulses are central to Indian diets as plant-protein staples and are widely used as whole pulses, split dal, flour, sprouts and processed ingredients. The category requires careful cleaning, grading, moisture control and variety-level identity because cooking quality, dal recovery and market price differ by crop and type. GreenWings uses this category for chickpea, tur, urad, masoor and related farmer-producer pulse crops.','https://apeda.gov.in/Pulses',4,'active');
INSERT INTO crop_category VALUES(5,'Fresh Vegetables','Fresh vegetables cover onion, tomato, chilli, garlic, ginger, turmeric, coriander, fenugreek and other market-facing vegetable crops.','','2026-06-27 17:53:35','2026-06-27 18:10:33','','vegetables','Fresh vegetables need fast aggregation, grading, packaging and route planning because quality changes quickly after harvest. India''s vegetable basket supports daily retail demand, food service, processing and selected export channels. GreenWings uses this category for perishable vegetable and spice-vegetable crops where freshness, size grading, residue discipline and reliable dispatch timing are critical.','https://apeda.gov.in/FreshFruitsAndVegetables',5,'active');
INSERT INTO crop_category VALUES(6,'Oil Seeds','Oil seeds include groundnut, sesame, soybean and sunflower crops used by edible oil, food, feed and processing industries.','','2026-06-27 17:53:35','2026-06-27 18:10:33','','oilseeds','Oil seeds are important for edible oils, protein-rich meal, food ingredients, feed and industrial applications. Groundnut, sesame, soybean and sunflower require moisture control, aflatoxin awareness where relevant, clean grading and buyer-specific quality parameters. GreenWings uses this category to connect oilseed farmers with processors, bulk buyers and export-oriented value chains.','https://www.iopepc.org/;https://apeda.gov.in/GroundNuts',6,'active');
