INSERT INTO crop VALUES(1,1,1,1,'Mango','Mangifera indica','Maharashtra is one of India''s leading mango-producing states. The Konkan coast is especially famous for Alphonso (Hapus), prized worldwide for its aroma, sweetness, and saffron-orange flesh. Grown across Ratnagiri, Sindhudurg, and Raigad districts. Season: March–June.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/mango/mango_1.jpg',NULL,NULL,1,0,unistr('Maharashtra is one of India''s leading mango-producing states. The Konkan coast is especially famous for Alphonso (Hapus), prized worldwide for its aroma, sweetness, and saffron-orange flesh. Grown across Ratnagiri, Sindhudurg, and Raigad districts. Season: March–June.\u000a\u000aScientific name: Mangifera indica\u000a\u000aCategory: Tropical\u000a\u000aSeason: Zaid\u000a\u000aMarathi name: Amba\u000a\u000aHindi name: Aam\u000a\u000aEnglish name: Mango'),'2026-06-27 16:54:19','2026-06-27 18:10:33','fruits','Fresh Fruits','Zaid','Amba','Aam','Mango','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/mango/mango_1.jpg','active');
INSERT INTO crop VALUES(2,2,1,2,'Grapes','Vitis vinifera','Maharashtra, particularly Nashik district, is India''s largest grape-producing region, accounting for ~70% of national output. Nashik is called the "Wine Capital of India". Grapes are grown from October–November (pruning) with harvest January–March. Major export crop.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/grapes/grapes_1.jpg',NULL,NULL,1,0,unistr('Maharashtra, particularly Nashik district, is India''s largest grape-producing region, accounting for ~70% of national output. Nashik is called the "Wine Capital of India". Grapes are grown from October–November (pruning) with harvest January–March. Major export crop.\u000a\u000aScientific name: Vitis vinifera\u000a\u000aCategory: Tropical\u000a\u000aSeason: Rabi\u000a\u000aMarathi name: Draksha\u000a\u000aHindi name: Angoor\u000a\u000aEnglish name: Grapes'),'2026-06-27 16:54:19','2026-06-27 18:10:33','fruits','Fresh Fruits','Rabi','Draksha','Angoor','Grapes','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/grapes/grapes_1.jpg','active');
INSERT INTO crop VALUES(3,3,1,3,'Orange','Citrus sinensis / Citrus reticulata','Nagpur is the "Orange City"  Maharashtra''s Vidarbha region produces the famous GI-tagged Nagpur Mandarin, India''s most well-known orange variety, harvested November–January.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/orange/orange_1.jpg',NULL,NULL,1,0,unistr('Nagpur is the "Orange City" — Maharashtra''s Vidarbha region produces the famous GI-tagged Nagpur Mandarin, India''s most well-known orange variety, harvested November–January.\u000a\u000aScientific name: Citrus sinensis / Citrus reticulata\u000a\u000aCategory: Citrus\u000a\u000aSeason: Rabi\u000a\u000aMarathi name: Santra\u000a\u000aHindi name: Santra\u000a\u000aEnglish name: Orange'),'2026-06-27 16:54:19','2026-06-27 18:10:33','fruits','Fresh Fruits','Rabi','Santra','Santra','Orange','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/orange/orange_1.jpg','active');
INSERT INTO crop VALUES(4,4,1,4,'Banana','Musa acuminata / Musa balbisiana','Jalgaon district is India''s banana capital — Maharashtra ranks first nationally in banana production. Jalgaon bananas have a GI tag. Bananas are cultivated year-round under drip irrigation.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/banana/banana_1.jpg',NULL,NULL,1,0,unistr('Jalgaon district is India''s banana capital — Maharashtra ranks first nationally in banana production. Jalgaon bananas have a GI tag. Bananas are cultivated year-round under drip irrigation.\u000a\u000aScientific name: Musa acuminata / Musa balbisiana\u000a\u000aCategory: Tropical\u000a\u000aSeason: Year-round\u000a\u000aMarathi name: Kela\u000a\u000aHindi name: Kela\u000a\u000aEnglish name: Banana'),'2026-06-27 16:54:19','2026-06-27 18:10:33','fruits','Fresh Fruits','Year-round','Kela','Kela','Banana','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/banana/banana_1.jpg','active');
INSERT INTO crop VALUES(5,5,1,5,'Guava','Psidium guajava','Guava is widely grown across Nashik, Pune, Solapur and Marathwada districts of Maharashtra. Rich in Vitamin C and lycopene; two crops per year possible.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/guava/guava_1.jpg',NULL,NULL,1,0,unistr('Guava is widely grown across Nashik, Pune, Solapur and Marathwada districts of Maharashtra. Rich in Vitamin C and lycopene; two crops per year possible.\u000a\u000aScientific name: Psidium guajava\u000a\u000aCategory: Tropical\u000a\u000aSeason: Year-round\u000a\u000aMarathi name: Peru\u000a\u000aHindi name: Amrood\u000a\u000aEnglish name: Guava'),'2026-06-27 16:54:19','2026-06-27 18:10:33','fruits','Fresh Fruits','Year-round','Peru','Amrood','Guava','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/guava/guava_1.jpg','active');
INSERT INTO crop VALUES(6,6,1,6,'Pomegranate','Punica granatum','Maharashtra is the largest pomegranate producer in India, contributing ~80% of national output. Solapur, Sangli, Pune, Nashik, Ahmednagar and Osmanabad are major growing districts. Bhagwa variety has a GI tag and is a prized export fruit.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/pomegranate/pomegranate_1.jpg',NULL,NULL,1,0,unistr('Maharashtra is the largest pomegranate producer in India, contributing ~80% of national output. Solapur, Sangli, Pune, Nashik, Ahmednagar and Osmanabad are major growing districts. Bhagwa variety has a GI tag and is a prized export fruit.\u000a\u000aScientific name: Punica granatum\u000a\u000aCategory: Sub-tropical\u000a\u000aSeason: Year-round\u000a\u000aMarathi name: Dalimb\u000a\u000aHindi name: Anar\u000a\u000aEnglish name: Pomegranate'),'2026-06-27 16:54:19','2026-06-27 18:10:33','fruits','Fresh Fruits','Year-round','Dalimb','Anar','Pomegranate','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/pomegranate/pomegranate_1.jpg','active');
INSERT INTO crop VALUES(7,7,1,7,'Custard Apple','Annona squamosa / Annona reticulata','Custard apple is an important commercial fruit in Maharashtra, grown in dry regions of Nashik, Aurangabad, Osmanabad, Solapur and Pune. Season is September–November.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/custard-apple/custard-apple_1.jpg',NULL,NULL,1,0,unistr('Custard apple is an important commercial fruit in Maharashtra, grown in dry regions of Nashik, Aurangabad, Osmanabad, Solapur and Pune. Season is September–November.\u000a\u000aScientific name: Annona squamosa / Annona reticulata\u000a\u000aCategory: Tropical\u000a\u000aSeason: Kharif\u000a\u000aMarathi name: Sitafal\u000a\u000aHindi name: Sitafal\u000a\u000aEnglish name: Custard Apple'),'2026-06-27 16:54:19','2026-06-27 18:10:33','fruits','Fresh Fruits','Kharif','Sitafal','Sitafal','Custard Apple','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/custard-apple/custard-apple_1.jpg','active');
INSERT INTO crop VALUES(8,8,1,8,'Papaya','Carica papaya','Papaya is grown extensively across Maharashtra for fresh fruit and raw papaya processing. Pune, Nashik, Jalgaon and Aurangabad are major producing districts.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/papaya/papaya_1.jpg',NULL,NULL,1,0,unistr('Papaya is grown extensively across Maharashtra for fresh fruit and raw papaya processing. Pune, Nashik, Jalgaon and Aurangabad are major producing districts.\u000a\u000aScientific name: Carica papaya\u000a\u000aCategory: Tropical\u000a\u000aSeason: Year-round\u000a\u000aMarathi name: Papai\u000a\u000aHindi name: Papita\u000a\u000aEnglish name: Papaya'),'2026-06-27 16:54:19','2026-06-27 18:10:33','fruits','Fresh Fruits','Year-round','Papai','Papita','Papaya','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/papaya/papaya_1.jpg','active');
INSERT INTO crop VALUES(9,9,1,9,'Sapota','Manilkara zapota','Maharashtra is a major Sapota producer; Palghar, Nashik, Pune and Thane districts are major growing areas. Fruit is available year-round with peak seasons February–May and August–November.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/sapota/sapota_1.png',NULL,NULL,1,0,unistr('Maharashtra is a major Sapota producer; Palghar, Nashik, Pune and Thane districts are major growing areas. Fruit is available year-round with peak seasons February–May and August–November.\u000a\u000aScientific name: Manilkara zapota\u000a\u000aCategory: Tropical\u000a\u000aSeason: Year-round\u000a\u000aMarathi name: Chiku\u000a\u000aHindi name: Chiku\u000a\u000aEnglish name: Sapota / Chikoo'),'2026-06-27 16:54:19','2026-06-27 18:10:33','fruits','Fresh Fruits','Year-round','Chiku','Chiku','Sapota / Chikoo','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/sapota/sapota_1.png','active');
INSERT INTO crop VALUES(10,10,1,10,'Coconut','Cocos nucifera','Coconut is a major crop of the Konkan coast — Ratnagiri, Sindhudurg, Raigad, Palghar and Thane. Used for copra, oil, tender coconut water, and in Maharashtrian cuisine.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/coconut/coconut_1.png',NULL,NULL,1,0,unistr('Coconut is a major crop of the Konkan coast — Ratnagiri, Sindhudurg, Raigad, Palghar and Thane. Used for copra, oil, tender coconut water, and in Maharashtrian cuisine.\u000a\u000aScientific name: Cocos nucifera\u000a\u000aCategory: Tropical\u000a\u000aSeason: Year-round\u000a\u000aMarathi name: Naral\u000a\u000aHindi name: Nariyal\u000a\u000aEnglish name: Coconut'),'2026-06-27 16:54:19','2026-06-27 18:10:33','fruits','Fresh Fruits','Year-round','Naral','Nariyal','Coconut','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/coconut/coconut_1.png','active');
INSERT INTO crop VALUES(11,11,1,11,'Jackfruit','Artocarpus heterophyllus','Jackfruit grows in the humid Konkan belt; both unripe (vegetable use) and ripe fruit are consumed. Ratnagiri, Sindhudurg, Raigad and Thane are major areas. Season May–August.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/jackfruit/jackfruit_1.jpg',NULL,NULL,1,0,unistr('Jackfruit grows in the humid Konkan belt; both unripe (vegetable use) and ripe fruit are consumed. Ratnagiri, Sindhudurg, Raigad and Thane are major areas. Season May–August.\u000a\u000aScientific name: Artocarpus heterophyllus\u000a\u000aCategory: Tropical\u000a\u000aSeason: Zaid\u000a\u000aMarathi name: Phanas\u000a\u000aHindi name: Kathal\u000a\u000aEnglish name: Jackfruit'),'2026-06-27 16:54:19','2026-06-27 18:10:33','fruits','Fresh Fruits','Zaid','Phanas','Kathal','Jackfruit','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/jackfruit/jackfruit_1.jpg','active');
INSERT INTO crop VALUES(12,12,1,12,'Amla','Phyllanthus emblica','Amla (Indian Gooseberry) is grown in Nashik, Aurangabad, Pune and Marathwada. Richest natural source of Vitamin C; harvested November–February. Important in Ayurveda and food processing (pickles, candy, juice).',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/amla/amla_1.jpg',NULL,NULL,1,0,unistr('Amla (Indian Gooseberry) is grown in Nashik, Aurangabad, Pune and Marathwada. Richest natural source of Vitamin C; harvested November–February. Important in Ayurveda and food processing (pickles, candy, juice).\u000a\u000aScientific name: Phyllanthus emblica\u000a\u000aCategory: Sub-tropical\u000a\u000aSeason: Rabi\u000a\u000aMarathi name: Avala\u000a\u000aHindi name: Amla\u000a\u000aEnglish name: Indian Gooseberry'),'2026-06-27 16:54:19','2026-06-27 18:10:33','fruits','Fresh Fruits','Rabi','Avala','Amla','Indian Gooseberry','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/amla/amla_1.jpg','active');
INSERT INTO crop VALUES(13,13,1,13,'Strawberry','Fragaria × ananassa','Mahabaleshwar (Satara district) and Panchgani produce 85% of India''s strawberries. Cool highland climate (1,400m elevation) ideal; season November–March. GI tag pending; major tourist attraction.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/strawberry/strawberry_1.jpg',NULL,NULL,1,0,unistr('Mahabaleshwar (Satara district) and Panchgani produce 85% of India''s strawberries. Cool highland climate (1,400m elevation) ideal; season November–March. GI tag pending; major tourist attraction.\u000a\u000aScientific name: Fragaria × ananassa\u000a\u000aCategory: Subtropical Highland\u000a\u000aSeason: Rabi\u000a\u000aMarathi name: Strawberry\u000a\u000aHindi name: Strawberry\u000a\u000aEnglish name: Strawberry'),'2026-06-27 16:54:19','2026-06-27 18:10:33','fruits','Fresh Fruits','Rabi','Strawberry','Strawberry','Strawberry','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/strawberry/strawberry_1.jpg','active');
INSERT INTO crop VALUES(14,14,1,14,'Fig','Ficus carica','Pune, particularly Purandar taluka, is the "Fig Capital" of India. Maharashtra has a GI tag for Purandar Fig. Season: January–March (main) and June–August (secondary).',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/fig/fig_1.jpg',NULL,NULL,1,0,unistr('Pune, particularly Purandar taluka, is the "Fig Capital" of India. Maharashtra has a GI tag for Purandar Fig. Season: January–March (main) and June–August (secondary).\u000a\u000aScientific name: Ficus carica\u000a\u000aCategory: Sub-tropical\u000a\u000aSeason: Zaid\u000a\u000aMarathi name: Anjeer\u000a\u000aHindi name: Anjeer\u000a\u000aEnglish name: Fig'),'2026-06-27 16:54:19','2026-06-27 18:10:33','fruits','Fresh Fruits','Zaid','Anjeer','Anjeer','Fig','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/fig/fig_1.jpg','active');
INSERT INTO crop VALUES(15,15,1,15,'Ber','Ziziphus mauritiana','Ber is a drought-tolerant fruit grown in dry zones of Maharashtra — Solapur, Osmanabad, Latur, Aurangabad. Season November–February. Rich in Vitamin C and minerals; good for dry regions.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/ber/ber_1.jpg',NULL,NULL,1,0,unistr('Ber is a drought-tolerant fruit grown in dry zones of Maharashtra — Solapur, Osmanabad, Latur, Aurangabad. Season November–February. Rich in Vitamin C and minerals; good for dry regions.\u000a\u000aScientific name: Ziziphus mauritiana\u000a\u000aCategory: Sub-tropical\u000a\u000aSeason: Rabi\u000a\u000aMarathi name: Bor\u000a\u000aHindi name: Ber\u000a\u000aEnglish name: Indian Jujube / Ber'),'2026-06-27 16:54:19','2026-06-27 18:10:33','fruits','Fresh Fruits','Rabi','Bor','Ber','Indian Jujube / Ber','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/ber/ber_1.jpg','active');
INSERT INTO crop VALUES(16,16,2,16,'Rice','Oryza sativa','Rice is the primary Kharif food grain of Maharashtra, grown mainly in Konkan (Ratnagiri, Sindhudurg, Raigad), Western Ghats foothills, and Vidarbha. Maharashtra grows aromatic traditional varieties alongside high-yielding types. Total area ~1.5 million hectares.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/rice/rice_1.jpg',NULL,NULL,1,0,unistr('Rice is the primary Kharif food grain of Maharashtra, grown mainly in Konkan (Ratnagiri, Sindhudurg, Raigad), Western Ghats foothills, and Vidarbha. Maharashtra grows aromatic traditional varieties alongside high-yielding types. Total area ~1.5 million hectares.\u000a\u000aScientific name: Oryza sativa\u000a\u000aCategory: Cereal\u000a\u000aSeason: Kharif\u000a\u000aMarathi name: Bhat / Tandul\u000a\u000aHindi name: Chawal\u000a\u000aEnglish name: Rice'),'2026-06-27 16:54:19','2026-06-27 18:10:33','grains','Grains & Cereals','Kharif','Bhat / Tandul','Chawal','Rice','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/rice/rice_1.jpg','active');
INSERT INTO crop VALUES(17,17,2,17,'Wheat','Triticum aestivum / Triticum durum','Wheat is Maharashtra''s principal Rabi crop; grown in Nashik, Pune, Ahmednagar, Aurangabad, Solapur and Vidarbha under irrigated conditions. Sown October–November, harvested February–March. Maharashtra grows both bread wheat and durum (for semolina/pasta).',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/wheat/wheat_1.jpg',NULL,NULL,1,0,unistr('Wheat is Maharashtra''s principal Rabi crop; grown in Nashik, Pune, Ahmednagar, Aurangabad, Solapur and Vidarbha under irrigated conditions. Sown October–November, harvested February–March. Maharashtra grows both bread wheat and durum (for semolina/pasta).\u000a\u000aScientific name: Triticum aestivum / Triticum durum\u000a\u000aCategory: Cereal\u000a\u000aSeason: Rabi\u000a\u000aMarathi name: Gahu\u000a\u000aHindi name: Gehun\u000a\u000aEnglish name: Wheat'),'2026-06-27 16:54:19','2026-06-27 18:10:33','grains','Grains & Cereals','Rabi','Gahu','Gehun','Wheat','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/wheat/wheat_1.jpg','active');
INSERT INTO crop VALUES(18,18,3,18,'Jowar','Sorghum bicolor','Maharashtra is India''s largest Jowar-producing state. Jowar (bhakri) is the staple food of rural Maharashtra. Grown in Solapur, Osmanabad, Latur, Aurangabad, Nashik. Kharif and Rabi (sweet sorghum for fodder) seasons. Drought tolerant and rainfed crop.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/jowar/jowar_1.jpg',NULL,NULL,1,0,unistr('Maharashtra is India''s largest Jowar-producing state. Jowar (bhakri) is the staple food of rural Maharashtra. Grown in Solapur, Osmanabad, Latur, Aurangabad, Nashik. Kharif and Rabi (sweet sorghum for fodder) seasons. Drought tolerant and rainfed crop.\u000a\u000aScientific name: Sorghum bicolor\u000a\u000aCategory: Millet / Cereal\u000a\u000aSeason: Kharif\u000a\u000aMarathi name: Jwarī\u000a\u000aHindi name: Jowar\u000a\u000aEnglish name: Sorghum'),'2026-06-27 16:54:19','2026-06-27 18:10:33','millets','Millets','Kharif','Jwarī','Jowar','Sorghum','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/jowar/jowar_1.jpg','active');
INSERT INTO crop VALUES(19,19,3,19,'Bajra','Pennisetum glaucum','Bajra is a major Kharif crop of dry districts of Maharashtra — Nashik, Jalgaon, Dhule, Aurangabad. Very drought tolerant; important for poor rainfall areas. Bhakri (flatbread) is traditional use.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/bajra/bajra_1.jpg',NULL,NULL,1,0,unistr('Bajra is a major Kharif crop of dry districts of Maharashtra — Nashik, Jalgaon, Dhule, Aurangabad. Very drought tolerant; important for poor rainfall areas. Bhakri (flatbread) is traditional use.\u000a\u000aScientific name: Pennisetum glaucum\u000a\u000aCategory: Millet / Cereal\u000a\u000aSeason: Kharif\u000a\u000aMarathi name: Bajrī\u000a\u000aHindi name: Bajra\u000a\u000aEnglish name: Pearl Millet'),'2026-06-27 16:54:19','2026-06-27 18:10:33','millets','Millets','Kharif','Bajrī','Bajra','Pearl Millet','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/bajra/bajra_1.jpg','active');
INSERT INTO crop VALUES(20,20,2,20,'Maize','Zea mays','Maize is an important Kharif crop in Nashik, Pune, Aurangabad, Ahmednagar and Nanded districts. Used for food (corn), poultry feed, starch and ethanol. Maharashtra contributes ~5% of national maize production.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/maize/maize_1.jpg',NULL,NULL,1,0,unistr('Maize is an important Kharif crop in Nashik, Pune, Aurangabad, Ahmednagar and Nanded districts. Used for food (corn), poultry feed, starch and ethanol. Maharashtra contributes ~5% of national maize production.\u000a\u000aScientific name: Zea mays\u000a\u000aCategory: Cereal\u000a\u000aSeason: Kharif\u000a\u000aMarathi name: Makka\u000a\u000aHindi name: Makka\u000a\u000aEnglish name: Maize / Corn'),'2026-06-27 16:54:19','2026-06-27 18:10:33','grains','Grains & Cereals','Kharif','Makka','Makka','Maize / Corn','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/maize/maize_1.jpg','active');
INSERT INTO crop VALUES(21,21,3,21,'Ragi','Eleusine coracana','Ragi (Nachni) is a nutritionally dense millet; grown in hilly and tribal areas of Nashik, Pune (Junnar), Nandurbar and Konkan. Richest grain source of calcium (344 mg/100g). Nachni bhakri and nachni satva (porridge) are traditional foods.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/ragi/ragi_1.jpg',NULL,NULL,1,0,unistr('Ragi (Nachni) is a nutritionally dense millet; grown in hilly and tribal areas of Nashik, Pune (Junnar), Nandurbar and Konkan. Richest grain source of calcium (344 mg/100g). Nachni bhakri and nachni satva (porridge) are traditional foods.\u000a\u000aScientific name: Eleusine coracana\u000a\u000aCategory: Millet\u000a\u000aSeason: Kharif\u000a\u000aMarathi name: Nachni\u000a\u000aHindi name: Ragi / Mandua\u000a\u000aEnglish name: Finger Millet'),'2026-06-27 16:54:19','2026-06-27 18:10:33','millets','Millets','Kharif','Nachni','Ragi / Mandua','Finger Millet','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/ragi/ragi_1.jpg','active');
INSERT INTO crop VALUES(22,22,3,22,'Kodo Millet','Paspalum scrobiculatum','Kodo Millet (Kodra) is a traditional millet grown in tribal/hilly areas of Nashik, Nandurbar, Amravati and Gadchiroli. Drought-tolerant; low input; nutritious; part of the Nutri-Cereal revival initiative in Maharashtra.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/kodo-millet/kodo-millet_1.jpg',NULL,NULL,1,0,unistr('Kodo Millet (Kodra) is a traditional millet grown in tribal/hilly areas of Nashik, Nandurbar, Amravati and Gadchiroli. Drought-tolerant; low input; nutritious; part of the Nutri-Cereal revival initiative in Maharashtra.\u000a\u000aScientific name: Paspalum scrobiculatum\u000a\u000aCategory: Millet\u000a\u000aSeason: Kharif\u000a\u000aMarathi name: Kodra\u000a\u000aHindi name: Kodra\u000a\u000aEnglish name: Kodo Millet'),'2026-06-27 16:54:19','2026-06-27 18:10:33','millets','Millets','Kharif','Kodra','Kodra','Kodo Millet','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/kodo-millet/kodo-millet_1.jpg','active');
INSERT INTO crop VALUES(23,23,3,23,'Little Millet','Panicum sumatrense','Little Millet (Vari) is used during religious fasting in Maharashtra (Ekadashi, Navratri). Grown in tribal belts of Nashik, Nandurbar and Gadchiroli. Reviving due to health consciousness and fasting food markets.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/little-millet/little-millet_1.jpg',NULL,NULL,1,0,unistr('Little Millet (Vari) is used during religious fasting in Maharashtra (Ekadashi, Navratri). Grown in tribal belts of Nashik, Nandurbar and Gadchiroli. Reviving due to health consciousness and fasting food markets.\u000a\u000aScientific name: Panicum sumatrense\u000a\u000aCategory: Millet\u000a\u000aSeason: Kharif\u000a\u000aMarathi name: Vari / Kutki\u000a\u000aHindi name: Kutki\u000a\u000aEnglish name: Little Millet'),'2026-06-27 16:54:19','2026-06-27 18:10:33','millets','Millets','Kharif','Vari / Kutki','Kutki','Little Millet','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/little-millet/little-millet_1.jpg','active');
INSERT INTO crop VALUES(24,24,3,24,'Barnyard Millet','Echinochloa frumentacea','Barnyard Millet (Bhagar) is extremely popular in Maharashtra for religious fasting (Upvasachi bhakri, Bhagar rice). Widely consumed during Ekadashi, Navratri. Grown in Nashik, Aurangabad, Nandurbar. High fibre, low GI.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/barnyard-millet/barnyard-millet_1.jpg',NULL,NULL,1,0,unistr('Barnyard Millet (Bhagar) is extremely popular in Maharashtra for religious fasting (Upvasachi bhakri, Bhagar rice). Widely consumed during Ekadashi, Navratri. Grown in Nashik, Aurangabad, Nandurbar. High fibre, low GI.\u000a\u000aScientific name: Echinochloa frumentacea\u000a\u000aCategory: Millet\u000a\u000aSeason: Kharif\u000a\u000aMarathi name: Bhagar / Sanwa\u000a\u000aHindi name: Sanwa\u000a\u000aEnglish name: Barnyard Millet'),'2026-06-27 16:54:19','2026-06-27 18:10:33','millets','Millets','Kharif','Bhagar / Sanwa','Sanwa','Barnyard Millet','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/barnyard-millet/barnyard-millet_1.jpg','active');
INSERT INTO crop VALUES(25,25,3,25,'Proso Millet','Panicum miliaceum','Proso Millet is an ancient grain with fastest growth cycle (60–75 days) among millets. Grown in dry areas of Maharashtra as an emergency/catch crop. Low water requirement; high nutritional value. Reviving under health and organic food movements.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/proso-millet/proso-millet_1.jpg',NULL,NULL,1,0,unistr('Proso Millet is an ancient grain with fastest growth cycle (60–75 days) among millets. Grown in dry areas of Maharashtra as an emergency/catch crop. Low water requirement; high nutritional value. Reviving under health and organic food movements.\u000a\u000aScientific name: Panicum miliaceum\u000a\u000aCategory: Millet\u000a\u000aSeason: Kharif\u000a\u000aMarathi name: Cheena\u000a\u000aHindi name: Cheena\u000a\u000aEnglish name: Proso Millet / Common Millet'),'2026-06-27 16:54:19','2026-06-27 18:10:33','millets','Millets','Kharif','Cheena','Cheena','Proso Millet / Common Millet','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/proso-millet/proso-millet_1.jpg','active');
INSERT INTO crop VALUES(26,26,4,26,'Tur (Pigeon Pea)','Cajanus cajan','Maharashtra is the largest Tur (pigeon pea) producing state in India. Grown extensively in Latur, Osmanabad, Nanded, Solapur and Marathwada. Staple dal of Maharashtra — tur dal (amti) is fundamental to Maharashtrian thali. Kharif season: sown June–July, harvested January–February.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/tur-pigeon-pea/tur-pigeon-pea_1.jpg',NULL,NULL,1,0,unistr('Maharashtra is the largest Tur (pigeon pea) producing state in India. Grown extensively in Latur, Osmanabad, Nanded, Solapur and Marathwada. Staple dal of Maharashtra — tur dal (amti) is fundamental to Maharashtrian thali. Kharif season: sown June–July, harvested January–February.\u000a\u000aScientific name: Cajanus cajan\u000a\u000aCategory: Pulse\u000a\u000aSeason: Kharif\u000a\u000aMarathi name: Tur\u000a\u000aHindi name: Arhar / Tur\u000a\u000aEnglish name: Pigeon Pea / Red Gram'),'2026-06-27 16:54:19','2026-06-27 18:10:33','pulses','Pulses & Lentils','Kharif','Tur','Arhar / Tur','Pigeon Pea / Red Gram','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/tur-pigeon-pea/tur-pigeon-pea_1.jpg','active');
INSERT INTO crop VALUES(27,27,4,27,'Chickpea','Cicer arietinum','Maharashtra is a leading chickpea-growing state; Marathwada (Latur, Osmanabad, Aurangabad) and Vidarbha are key regions. Both desi (brown) and kabuli (white/large) types grown. Rabi season: sown October–November, harvested January–February.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/chickpea/chickpea_1.jpg',NULL,NULL,1,0,unistr('Maharashtra is a leading chickpea-growing state; Marathwada (Latur, Osmanabad, Aurangabad) and Vidarbha are key regions. Both desi (brown) and kabuli (white/large) types grown. Rabi season: sown October–November, harvested January–February.\u000a\u000aScientific name: Cicer arietinum\u000a\u000aCategory: Pulse\u000a\u000aSeason: Rabi\u000a\u000aMarathi name: Harbhara / Chana\u000a\u000aHindi name: Chana\u000a\u000aEnglish name: Chickpea / Bengal Gram'),'2026-06-27 16:54:19','2026-06-27 18:10:33','pulses','Pulses & Lentils','Rabi','Harbhara / Chana','Chana','Chickpea / Bengal Gram','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/chickpea/chickpea_1.jpg','active');
INSERT INTO crop VALUES(28,28,4,28,'Urad (Black Gram)','Vigna mungo','Urad (Udid) is a Kharif pulse grown in Nanded, Latur, Osmanabad, Aurangabad and parts of Vidarbha. Essential for Maharashtrian vada, idli (batter), and dal. Short-duration; good in mixed cropping with Tur.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/urad-black-gram/urad-black-gram_1.jpg',NULL,NULL,1,0,unistr('Urad (Udid) is a Kharif pulse grown in Nanded, Latur, Osmanabad, Aurangabad and parts of Vidarbha. Essential for Maharashtrian vada, idli (batter), and dal. Short-duration; good in mixed cropping with Tur.\u000a\u000aScientific name: Vigna mungo\u000a\u000aCategory: Pulse\u000a\u000aSeason: Kharif\u000a\u000aMarathi name: Udid\u000a\u000aHindi name: Urad\u000a\u000aEnglish name: Black Gram / Urad'),'2026-06-27 16:54:19','2026-06-27 18:10:33','pulses','Pulses & Lentils','Kharif','Udid','Urad','Black Gram / Urad','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/urad-black-gram/urad-black-gram_1.jpg','active');
INSERT INTO crop VALUES(29,29,4,29,'Masoor (Lentil)','Lens culinaris','Masoor (Red Lentil) is a Rabi pulse grown in Marathwada and Vidarbha — Latur, Osmanabad, Yavatmal. Less common than Tur and Chana but nutritionally important; pink/red split dal used widely in Maharashtrian cuisine.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/masoor-lentil/masoor-lentil_1.jpg',NULL,NULL,1,0,unistr('Masoor (Red Lentil) is a Rabi pulse grown in Marathwada and Vidarbha — Latur, Osmanabad, Yavatmal. Less common than Tur and Chana but nutritionally important; pink/red split dal used widely in Maharashtrian cuisine.\u000a\u000aScientific name: Lens culinaris\u000a\u000aCategory: Pulse\u000a\u000aSeason: Rabi\u000a\u000aMarathi name: Masur\u000a\u000aHindi name: Masoor\u000a\u000aEnglish name: Lentil / Masoor'),'2026-06-27 16:54:19','2026-06-27 18:10:33','pulses','Pulses & Lentils','Rabi','Masur','Masoor','Lentil / Masoor','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/masoor-lentil/masoor-lentil_1.jpg','active');
INSERT INTO crop VALUES(30,30,6,30,'Soybean','Glycine max','Maharashtra is the largest soybean-growing state in India, with ~40% of national acreage. Grown in Vidarbha (Nagpur, Amravati), Marathwada (Latur, Osmanabad) and Nashik. Major oilseed and protein crop. Sown June–July; harvested September–October.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/soybean/soybean_1.webp',NULL,NULL,1,0,unistr('Maharashtra is the largest soybean-growing state in India, with ~40% of national acreage. Grown in Vidarbha (Nagpur, Amravati), Marathwada (Latur, Osmanabad) and Nashik. Major oilseed and protein crop. Sown June–July; harvested September–October.\u000a\u000aScientific name: Glycine max\u000a\u000aCategory: Oilseed\u000a\u000aSeason: Kharif\u000a\u000aMarathi name: Soya\u000a\u000aHindi name: Soya\u000a\u000aEnglish name: Soybean'),'2026-06-27 16:54:19','2026-06-27 18:10:33','oilseeds','Oil Seeds','Kharif','Soya','Soya','Soybean','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/soybean/soybean_1.webp','active');
INSERT INTO crop VALUES(31,31,6,31,'Groundnut','Arachis hypogaea','Groundnut is a major Kharif oilseed and cash crop in Maharashtra — Akola, Amravati, Wardha (Vidarbha) and Nashik, Jalgaon (North Maharashtra). Maharashtra is 4th nationally. Also a Rabi irrigated crop in Solapur. Famous for "Vidarbha shengdana".',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/groundnut/groundnut_1.jpg',NULL,NULL,1,0,unistr('Groundnut is a major Kharif oilseed and cash crop in Maharashtra — Akola, Amravati, Wardha (Vidarbha) and Nashik, Jalgaon (North Maharashtra). Maharashtra is 4th nationally. Also a Rabi irrigated crop in Solapur. Famous for "Vidarbha shengdana".\u000a\u000aScientific name: Arachis hypogaea\u000a\u000aCategory: Oilseed\u000a\u000aSeason: Kharif\u000a\u000aMarathi name: Shengdana\u000a\u000aHindi name: Moongphali\u000a\u000aEnglish name: Groundnut / Peanut'),'2026-06-27 16:54:19','2026-06-27 18:10:33','oilseeds','Oil Seeds','Kharif','Shengdana','Moongphali','Groundnut / Peanut','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/groundnut/groundnut_1.jpg','active');
INSERT INTO crop VALUES(32,32,6,32,'Sesame','Sesamum indicum','Sesame (Til) is a traditional oilseed crop of Maharashtra grown in Aurangabad, Jalgaon, Nashik and Osmanabad. Essential in Maharashtrian sweets — tilgul (sesame-jaggery balls) for Makar Sankranti. High-value crop for domestic and export market.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/sesame/sesame_1.jpg',NULL,NULL,1,0,unistr('Sesame (Til) is a traditional oilseed crop of Maharashtra grown in Aurangabad, Jalgaon, Nashik and Osmanabad. Essential in Maharashtrian sweets — tilgul (sesame-jaggery balls) for Makar Sankranti. High-value crop for domestic and export market.\u000a\u000aScientific name: Sesamum indicum\u000a\u000aCategory: Oilseed\u000a\u000aSeason: Kharif\u000a\u000aMarathi name: Til\u000a\u000aHindi name: Til\u000a\u000aEnglish name: Sesame'),'2026-06-27 16:54:19','2026-06-27 18:10:33','oilseeds','Oil Seeds','Kharif','Til','Til','Sesame','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/sesame/sesame_1.jpg','active');
INSERT INTO crop VALUES(33,33,6,33,'Sunflower','Helianthus annuus','Sunflower is grown as a Rabi crop in Maharashtra — Solapur, Osmanabad, Latur, Aurangabad, Nashik. Good oil crop for light black soils; used as edible oil. Also a Kharif crop in some areas.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/sunflower/sunflower_1.jpg',NULL,NULL,1,0,unistr('Sunflower is grown as a Rabi crop in Maharashtra — Solapur, Osmanabad, Latur, Aurangabad, Nashik. Good oil crop for light black soils; used as edible oil. Also a Kharif crop in some areas.\u000a\u000aScientific name: Helianthus annuus\u000a\u000aCategory: Oilseed\u000a\u000aSeason: Rabi\u000a\u000aMarathi name: Suryafool\u000a\u000aHindi name: Surajmukhi\u000a\u000aEnglish name: Sunflower'),'2026-06-27 16:54:19','2026-06-27 18:10:33','oilseeds','Oil Seeds','Rabi','Suryafool','Surajmukhi','Sunflower','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/sunflower/sunflower_1.jpg','active');
INSERT INTO crop VALUES(34,34,2,34,'Sugarcane','Saccharum officinarum','Maharashtra is India''s second-largest sugarcane and sugar-producing state. The Deccan plateau districts of Pune, Satara, Sangli, Kolhapur, Solapur, Nashik and Ahmednagar form the "Sugar Belt". Over 200 cooperative sugar factories operate. Maharashtra also leads in ethanol production from sugarcane. Crushed October–March after 10–14 months of growth. By-products: bagasse (energy), molasses (ethanol/alcohol), press mud (compost).',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/sugarcane/sugarcane_1.webp',NULL,NULL,1,0,unistr('Maharashtra is India''s second-largest sugarcane and sugar-producing state. The Deccan plateau districts of Pune, Satara, Sangli, Kolhapur, Solapur, Nashik and Ahmednagar form the "Sugar Belt". Over 200 cooperative sugar factories operate. Maharashtra also leads in ethanol production from sugarcane. Crushed October–March after 10–14 months of growth. By-products: bagasse (energy), molasses (ethanol/alcohol), press mud (compost).\u000a\u000aScientific name: Saccharum officinarum\u000a\u000aCategory: Cash Crop / Industrial\u000a\u000aSeason: Year-round\u000a\u000aMarathi name: Oos / Verdi\u000a\u000aHindi name: Ganna\u000a\u000aEnglish name: Sugarcane'),'2026-06-27 16:54:19','2026-06-27 18:10:33','grains','Grains & Cereals','Year-round','Oos / Verdi','Ganna','Sugarcane','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/sugarcane/sugarcane_1.webp','active');
INSERT INTO crop VALUES(35,35,5,35,'Onion','Allium cepa','Maharashtra is India''s largest onion-producing state (~40% national share). Nashik, Pune, Ahmednagar, Solapur and Satara are prime growing districts. Nashik''s Lasalgaon APMC is Asia''s largest onion market. Three crops a year possible: Kharif (June–October), Late Kharif (September–January), and Rabi (January–May). Major export crop to Europe, South-East Asia and Middle East.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/onion/onion_1.jpg',NULL,NULL,1,0,unistr('Maharashtra is India''s largest onion-producing state (~40% national share). Nashik, Pune, Ahmednagar, Solapur and Satara are prime growing districts. Nashik''s Lasalgaon APMC is Asia''s largest onion market. Three crops a year possible: Kharif (June–October), Late Kharif (September–January), and Rabi (January–May). Major export crop to Europe, South-East Asia and Middle East.\u000a\u000aScientific name: Allium cepa\u000a\u000aCategory: Vegetable / Spice\u000a\u000aSeason: Rabi\u000a\u000aMarathi name: Kanda\u000a\u000aHindi name: Pyaaz\u000a\u000aEnglish name: Onion'),'2026-06-27 16:54:19','2026-06-27 18:10:33','vegetables','Fresh Vegetables','Rabi','Kanda','Pyaaz','Onion','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/onion/onion_1.jpg','active');
INSERT INTO crop VALUES(36,36,5,36,'Tomato','Solanum lycopersicum','Maharashtra is a top-3 tomato-producing state. Nashik, Pune, Satara, Ahmednagar and Solapur are major districts. Tomatoes are grown year-round under irrigated conditions; also a major processing crop for puree, paste and ketchup. Narayangaon (Pune) is an important tomato trading hub.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/tomato/tomato_1.jpg',NULL,NULL,1,0,unistr('Maharashtra is a top-3 tomato-producing state. Nashik, Pune, Satara, Ahmednagar and Solapur are major districts. Tomatoes are grown year-round under irrigated conditions; also a major processing crop for puree, paste and ketchup. Narayangaon (Pune) is an important tomato trading hub.\u000a\u000aScientific name: Solanum lycopersicum\u000a\u000aCategory: Vegetable\u000a\u000aSeason: Year-round\u000a\u000aMarathi name: Tomato\u000a\u000aHindi name: Tamatar\u000a\u000aEnglish name: Tomato'),'2026-06-27 16:54:19','2026-06-27 18:10:33','vegetables','Fresh Vegetables','Year-round','Tomato','Tamatar','Tomato','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/tomato/tomato_1.jpg','active');
INSERT INTO crop VALUES(37,37,1,37,'Sweet Lime','Citrus limetta','Sweet Lime (Mosambi) is one of Maharashtra''s most commercially important citrus fruits, distinct from orange. Solapur, Osmanabad, Aurangabad, Pune and Nashik are major growing centres. Extremely popular for fresh juice; sold across India year-round. Maharashtra accounts for ~35% of India''s Mosambi production.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/sweet-lime/sweet-lime_1.png',NULL,NULL,1,0,unistr('Sweet Lime (Mosambi) is one of Maharashtra''s most commercially important citrus fruits, distinct from orange. Solapur, Osmanabad, Aurangabad, Pune and Nashik are major growing centres. Extremely popular for fresh juice; sold across India year-round. Maharashtra accounts for ~35% of India''s Mosambi production.\u000a\u000aScientific name: Citrus limetta\u000a\u000aCategory: Citrus\u000a\u000aSeason: Year-round\u000a\u000aMarathi name: Mosambi\u000a\u000aHindi name: Mosambi\u000a\u000aEnglish name: Sweet Lime / Mosambi'),'2026-06-27 16:54:19','2026-06-27 18:10:33','fruits','Fresh Fruits','Year-round','Mosambi','Mosambi','Sweet Lime / Mosambi','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/sweet-lime/sweet-lime_1.png','active');
INSERT INTO crop VALUES(38,38,5,38,'Garlic','Allium sativum','Garlic is an important Rabi spice crop in Maharashtra — Nashik, Satara, Solapur, Pune, Aurangabad. Maharashtra is among top-5 garlic-producing states. Sown October–November; harvested February–March. Maharashtra garlic is known for its pungency and high allicin content. Major export crop and ingredient in Indian cuisine and Ayurvedic medicine.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/garlic/garlic_1.jpg',NULL,NULL,1,0,unistr('Garlic is an important Rabi spice crop in Maharashtra — Nashik, Satara, Solapur, Pune, Aurangabad. Maharashtra is among top-5 garlic-producing states. Sown October–November; harvested February–March. Maharashtra garlic is known for its pungency and high allicin content. Major export crop and ingredient in Indian cuisine and Ayurvedic medicine.\u000a\u000aScientific name: Allium sativum\u000a\u000aCategory: Vegetable / Spice\u000a\u000aSeason: Rabi\u000a\u000aMarathi name: Lasun\u000a\u000aHindi name: Lahsun\u000a\u000aEnglish name: Garlic'),'2026-06-27 16:54:19','2026-06-27 18:10:33','vegetables','Fresh Vegetables','Rabi','Lasun','Lahsun','Garlic','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/garlic/garlic_1.jpg','active');
INSERT INTO crop VALUES(39,39,5,39,'Turmeric','Curcuma longa','Maharashtra is one of India''s top turmeric-producing states. Sangli, Kolhapur, Satara and Pune are major growing districts. Sangli''s Erande (Yelur) turmeric is GI-tagged and renowned for its high curcumin content (>4.5%). Harvested January–March after 8–9 months. Essential in Maharashtrian cooking, medicine (Ayurveda) and cosmetics. Major export to USA, Japan, EU.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/turmeric/turmeric_1.jpg',NULL,NULL,1,0,unistr('Maharashtra is one of India''s top turmeric-producing states. Sangli, Kolhapur, Satara and Pune are major growing districts. Sangli''s Erande (Yelur) turmeric is GI-tagged and renowned for its high curcumin content (>4.5%). Harvested January–March after 8–9 months. Essential in Maharashtrian cooking, medicine (Ayurveda) and cosmetics. Major export to USA, Japan, EU.\u000a\u000aScientific name: Curcuma longa\u000a\u000aCategory: Spice / Medicinal\u000a\u000aSeason: Kharif\u000a\u000aMarathi name: Halad\u000a\u000aHindi name: Haldi\u000a\u000aEnglish name: Turmeric'),'2026-06-27 16:54:19','2026-06-27 18:10:33','vegetables','Fresh Vegetables','Kharif','Halad','Haldi','Turmeric','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/turmeric/turmeric_1.jpg','active');
INSERT INTO crop VALUES(40,40,5,40,'Chilli','Capsicum annuum','Maharashtra is a major chilli-producing state. Aurangabad, Nashik, Pune, Latur, Osmanabad and Amravati are key districts for dry chilli production. Kolhapur Red Chilli is GI-tagged and one of the hottest and most flavourful in India. Chilli grown for fresh, dry, and powder markets. Key ingredient in Kolhapuri cuisine and Maharashtra masalas.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/chilli/chilli_1.jpg',NULL,NULL,1,0,unistr('Maharashtra is a major chilli-producing state. Aurangabad, Nashik, Pune, Latur, Osmanabad and Amravati are key districts for dry chilli production. Kolhapur Red Chilli is GI-tagged and one of the hottest and most flavourful in India. Chilli grown for fresh, dry, and powder markets. Key ingredient in Kolhapuri cuisine and Maharashtra masalas.\u000a\u000aScientific name: Capsicum annuum\u000a\u000aCategory: Spice / Vegetable\u000a\u000aSeason: Kharif\u000a\u000aMarathi name: Mirchi\u000a\u000aHindi name: Mirch\u000a\u000aEnglish name: Chilli / Hot Pepper'),'2026-06-27 16:54:19','2026-06-27 18:10:33','vegetables','Fresh Vegetables','Kharif','Mirchi','Mirch','Chilli / Hot Pepper','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/chilli/chilli_1.jpg','active');
INSERT INTO crop VALUES(41,41,5,41,'Ginger','Zingiber officinale','Ginger is grown in the high-rainfall Western Ghats districts of Maharashtra — Satara, Kolhapur, Sindhudurg, Pune (Maval). A Kharif crop, sown April–May and harvested November–December. Fresh green ginger and dried soonth (dried ginger powder) both produced. Maharashtra contributes ~8% of India''s ginger output. High value for domestic cooking and pharma/ayurvedic industry.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/ginger/ginger_1.png',NULL,NULL,1,0,unistr('Ginger is grown in the high-rainfall Western Ghats districts of Maharashtra — Satara, Kolhapur, Sindhudurg, Pune (Maval). A Kharif crop, sown April–May and harvested November–December. Fresh green ginger and dried soonth (dried ginger powder) both produced. Maharashtra contributes ~8% of India''s ginger output. High value for domestic cooking and pharma/ayurvedic industry.\u000a\u000aScientific name: Zingiber officinale\u000a\u000aCategory: Spice / Medicinal\u000a\u000aSeason: Kharif\u000a\u000aMarathi name: Aale\u000a\u000aHindi name: Adrak\u000a\u000aEnglish name: Ginger'),'2026-06-27 16:54:19','2026-06-27 18:10:33','vegetables','Fresh Vegetables','Kharif','Aale','Adrak','Ginger','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/ginger/ginger_1.png','active');
INSERT INTO crop VALUES(42,42,1,42,'Tamarind','Tamarindus indica','Tamarind is a perennial tree crop widely found across Maharashtra, especially in Marathwada (Aurangabad, Osmanabad, Latur) and Vidarbha (Amravati, Nagpur). It is a rainfed, low-maintenance crop harvested January–April. Tamarind pulp, seed and shell all have commercial value. Key ingredient in Maharashtra''s chutneys, rasam-style dishes, and the famous Panha drink. Also used in pharmaceuticals, confectionery and food processing.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/tamarind/tamarind_1.jpg',NULL,NULL,1,0,unistr('Tamarind is a perennial tree crop widely found across Maharashtra, especially in Marathwada (Aurangabad, Osmanabad, Latur) and Vidarbha (Amravati, Nagpur). It is a rainfed, low-maintenance crop harvested January–April. Tamarind pulp, seed and shell all have commercial value. Key ingredient in Maharashtra''s chutneys, rasam-style dishes, and the famous Panha drink. Also used in pharmaceuticals, confectionery and food processing.\u000a\u000aScientific name: Tamarindus indica\u000a\u000aCategory: Fruit / Spice\u000a\u000aSeason: Rabi\u000a\u000aMarathi name: Chincha\u000a\u000aHindi name: Imli\u000a\u000aEnglish name: Tamarind'),'2026-06-27 16:54:19','2026-06-27 18:10:33','fruits','Fresh Fruits','Rabi','Chincha','Imli','Tamarind','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/tamarind/tamarind_1.jpg','active');
INSERT INTO crop VALUES(43,43,5,43,'Fenugreek','Trigonella foenum-graecum','Fenugreek (Methi) is grown across Maharashtra as a Rabi crop for its leaves (fresh vegetable) and seeds (spice). Nashik, Pune, Aurangabad and Solapur are major growing areas. The seeds are essential in Maharashtra''s goda masala, pickles and parathas. Rich in fenuside, fibre and iron. Also used medicinally for diabetes and lactation support.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/fenugreek/fenugreek_1.jpg',NULL,NULL,1,0,unistr('Fenugreek (Methi) is grown across Maharashtra as a Rabi crop for its leaves (fresh vegetable) and seeds (spice). Nashik, Pune, Aurangabad and Solapur are major growing areas. The seeds are essential in Maharashtra''s goda masala, pickles and parathas. Rich in fenuside, fibre and iron. Also used medicinally for diabetes and lactation support.\u000a\u000aScientific name: Trigonella foenum-graecum\u000a\u000aCategory: Spice / Vegetable / Medicinal\u000a\u000aSeason: Rabi\u000a\u000aMarathi name: Methi\u000a\u000aHindi name: Methi\u000a\u000aEnglish name: Fenugreek / Methi'),'2026-06-27 16:54:19','2026-06-27 18:10:33','vegetables','Fresh Vegetables','Rabi','Methi','Methi','Fenugreek / Methi','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/fenugreek/fenugreek_1.jpg','active');
INSERT INTO crop VALUES(44,44,5,44,'Coriander','Coriandrum sativum','Coriander is one of Maharashtra''s most important spice crops, grown in Nashik, Pune, Satara, Aurangabad. Used both fresh (green coriander leaves) and dry (dhania seeds). Kothimbir Vadi (coriander fritters) is a signature Maharashtrian snack. Maharashtra is among India''s top-5 coriander-producing states. Season: October–January for leaves; February–March for seeds.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/coriander/coriander_1.jpg',NULL,NULL,1,0,unistr('Coriander is one of Maharashtra''s most important spice crops, grown in Nashik, Pune, Satara, Aurangabad. Used both fresh (green coriander leaves) and dry (dhania seeds). Kothimbir Vadi (coriander fritters) is a signature Maharashtrian snack. Maharashtra is among India''s top-5 coriander-producing states. Season: October–January for leaves; February–March for seeds.\u000a\u000aScientific name: Coriandrum sativum\u000a\u000aCategory: Spice / Herb\u000a\u000aSeason: Rabi\u000a\u000aMarathi name: Kothimbir\u000a\u000aHindi name: Dhaniya\u000a\u000aEnglish name: Coriander / Dhania'),'2026-06-27 16:54:19','2026-06-27 18:10:33','vegetables','Fresh Vegetables','Rabi','Kothimbir','Dhaniya','Coriander / Dhania','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/coriander/coriander_1.jpg','active');
INSERT INTO crop VALUES(45,45,1,45,'Watermelon','Citrullus lanatus','Watermelon is a major summer (Zaid) crop in Maharashtra — Nashik, Aurangabad, Solapur, Latur, Pune. Grown on sandy riverbed soils; sown February–March, harvested April–June. Maharashtra is a leading watermelon-producing state for domestic market. Large fruits preferred in Indian market; seedless hybrids gaining popularity.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/watermelon/watermelon_1.jpg',NULL,NULL,1,0,unistr('Watermelon is a major summer (Zaid) crop in Maharashtra — Nashik, Aurangabad, Solapur, Latur, Pune. Grown on sandy riverbed soils; sown February–March, harvested April–June. Maharashtra is a leading watermelon-producing state for domestic market. Large fruits preferred in Indian market; seedless hybrids gaining popularity.\u000a\u000aScientific name: Citrullus lanatus\u000a\u000aCategory: Cucurbit Fruit\u000a\u000aSeason: Zaid\u000a\u000aMarathi name: Kalingad\u000a\u000aHindi name: Tarbooz\u000a\u000aEnglish name: Watermelon'),'2026-06-27 16:54:19','2026-06-27 18:10:33','fruits','Fresh Fruits','Zaid','Kalingad','Tarbooz','Watermelon','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/watermelon/watermelon_1.jpg','active');
INSERT INTO crop VALUES(46,46,1,46,'Muskmelon','Cucumis melo','Muskmelon (Kharbuj) is an important summer fruit crop in Maharashtra — Nashik, Pune, Solapur, Jalgaon. Grown on sandy loam soils; excellent in Godavari and Bhima river basin. Season March–June. High demand for fresh consumption and cooling drinks.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/muskmelon/muskmelon_1.jpg',NULL,NULL,1,0,unistr('Muskmelon (Kharbuj) is an important summer fruit crop in Maharashtra — Nashik, Pune, Solapur, Jalgaon. Grown on sandy loam soils; excellent in Godavari and Bhima river basin. Season March–June. High demand for fresh consumption and cooling drinks.\u000a\u000aScientific name: Cucumis melo\u000a\u000aCategory: Cucurbit Fruit\u000a\u000aSeason: Zaid\u000a\u000aMarathi name: Kharbuja\u000a\u000aHindi name: Kharbuja\u000a\u000aEnglish name: Muskmelon / Cantaloupe'),'2026-06-27 16:54:19','2026-06-27 18:10:33','fruits','Fresh Fruits','Zaid','Kharbuja','Kharbuja','Muskmelon / Cantaloupe','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/muskmelon/muskmelon_1.jpg','active');
INSERT INTO crop VALUES(47,47,1,47,'Lemon','Citrus limon / Citrus aurantiifolia','Lemon and acid lime are widely grown across Maharashtra — Nashik, Pune, Aurangabad, Vidarbha. A perennial crop with year-round fruiting under irrigation. Widely used in Maharashtrian cuisine (limbu sherbet, chutneys, achaar), street food, and increasing export to the Gulf. Drought-tolerant once established.',NULL,'https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/lemon/lemon_1.jpg',NULL,NULL,1,0,unistr('Lemon and acid lime are widely grown across Maharashtra — Nashik, Pune, Aurangabad, Vidarbha. A perennial crop with year-round fruiting under irrigation. Widely used in Maharashtrian cuisine (limbu sherbet, chutneys, achaar), street food, and increasing export to the Gulf. Drought-tolerant once established.\u000a\u000aScientific name: Citrus limon / Citrus aurantiifolia\u000a\u000aCategory: Citrus\u000a\u000aSeason: Year-round\u000a\u000aMarathi name: Limbu\u000a\u000aHindi name: Nimbu\u000a\u000aEnglish name: Lemon / Lime'),'2026-06-27 16:54:19','2026-06-27 18:10:33','fruits','Fresh Fruits','Year-round','Limbu','Nimbu','Lemon / Lime','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-main/lemon/lemon_1.jpg','active');
INSERT INTO crop_variety VALUES(1,1,1,'Alphonso (Hapus)','Hapus','Maharashtra',NULL,'Sweet, aromatic, rich saffron flavour, low fibre',NULL,NULL,NULL,0,0,0,NULL,NULL,'["https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0001-mango-alphonso-hapus/image_01.png", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0001-mango-alphonso-hapus/image_02.jpg", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0001-mango-alphonso-hapus/image_03.webp", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0001-mango-alphonso-hapus/image_04.jpg", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0001-mango-alphonso-hapus/image_05.jpg", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0001-mango-alphonso-hapus/image_06.png", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0001-mango-alphonso-hapus/image_07.jpg", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0001-mango-alphonso-hapus/image_08.jpg"]','GI-tagged variety from Ratnagiri & Sindhudurg; considered the king of mangoes; peak season April–May; ideal for pulp and fresh consumption.','2026-06-27 16:54:19','2026-06-30 03:29:19','Mangifera indica cv. Alphonso','Hapus','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0001-mango-alphonso-hapus/image_01.png',unistr('GI-tagged variety from Ratnagiri & Sindhudurg; considered the king of mangoes; peak season April–May; ideal for pulp and fresh consumption.\u000a\u000aScientific name: Mangifera indica cv. Alphonso\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: Sweet, aromatic, rich saffron flavour, low fibre\u000a\u000aMarathi name: Hapus'));
INSERT INTO crop_variety VALUES(2,1,2,'Kesar','Kesar','Gujarat/Maharashtra',NULL,'Sweet, less fibrous, deep orange pulp',NULL,NULL,NULL,0,0,0,NULL,NULL,'["https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0002-mango-kesar/image_01.jpg", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0002-mango-kesar/image_02.jpg", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0002-mango-kesar/image_03.jpg", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0002-mango-kesar/image_04.png", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0002-mango-kesar/image_05.jpg", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0002-mango-kesar/image_06.jpg", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0002-mango-kesar/image_07.jpg", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0002-mango-kesar/image_08.jpg"]','Grown in Aurangabad and Marathwada; second most exported variety; saffron-coloured pulp; season May–June.','2026-06-27 16:54:19','2026-06-30 03:29:30','Mangifera indica cv. Kesar','Kesar','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0002-mango-kesar/image_01.jpg',unistr('Grown in Aurangabad and Marathwada; second most exported variety; saffron-coloured pulp; season May–June.\u000a\u000aScientific name: Mangifera indica cv. Kesar\u000a\u000aOrigin: Gujarat/Maharashtra\u000a\u000aTaste profile: Sweet, less fibrous, deep orange pulp\u000a\u000aMarathi name: Kesar'));
INSERT INTO crop_variety VALUES(3,1,3,'Langra','Langra','Uttar Pradesh/Maharashtra',NULL,'Sweet-sour, green skin, rich flavour',NULL,NULL,NULL,0,0,0,NULL,NULL,'["https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0003-mango-langra/image_01.jpg", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0003-mango-langra/image_02.jpg", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0003-mango-langra/image_03.jpg", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0003-mango-langra/image_04.jpg", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0003-mango-langra/image_05.png", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0003-mango-langra/image_06.jpg", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0003-mango-langra/image_07.jpg", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0003-mango-langra/image_08.png"]','Grown in Nashik and Pune regions; medium-large fruit; greenish skin even when ripe.','2026-06-27 16:54:19','2026-06-30 03:29:35','Mangifera indica cv. Langra','Langra','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0003-mango-langra/image_01.jpg',unistr('Grown in Nashik and Pune regions; medium-large fruit; greenish skin even when ripe.\u000a\u000aScientific name: Mangifera indica cv. Langra\u000a\u000aOrigin: Uttar Pradesh/Maharashtra\u000a\u000aTaste profile: Sweet-sour, green skin, rich flavour\u000a\u000aMarathi name: Langra'));
