INSERT INTO crop_variety VALUES(184,47,184,'Phule Saurabh','Phule Saurabh Limbu','Maharashtra',NULL,'Acidic, aromatic, high juice, soft rind',NULL,NULL,NULL,0,0,0,NULL,NULL,'["https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0184-lemon-phule-saurabh/image_01.webp", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0184-lemon-phule-saurabh/image_02.jpg", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0184-lemon-phule-saurabh/image_03.jpg", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0184-lemon-phule-saurabh/image_04.png", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0184-lemon-phule-saurabh/image_05.jpg", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0184-lemon-phule-saurabh/image_06.png", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0184-lemon-phule-saurabh/image_07.jpg", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0184-lemon-phule-saurabh/image_08.jpg"]','MPKV Rahuri; improved lemon variety; suitable for drip-irrigated orchards; Nashik, Aurangabad.','2026-06-27 16:54:19','2026-06-30 03:28:41','Citrus limon cv. Phule Saurabh','Phule Saurabh Limbu','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0184-lemon-phule-saurabh/image_01.webp',unistr('MPKV Rahuri; improved lemon variety; suitable for drip-irrigated orchards; Nashik, Aurangabad.\u000a\u000aScientific name: Citrus limon cv. Phule Saurabh\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: Acidic, aromatic, high juice, soft rind\u000a\u000aMarathi name: Phule Saurabh Limbu'));
INSERT INTO crop_variety VALUES(185,47,185,'Seedless Lime','Bijrahit Limbu','Maharashtra',NULL,'Acidic, thin-skinned, nearly seedless',NULL,NULL,NULL,0,0,0,NULL,NULL,'["https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0185-lemon-seedless-lime/image_01.jpg", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0185-lemon-seedless-lime/image_02.jpg", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0185-lemon-seedless-lime/image_03.jpg", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0185-lemon-seedless-lime/image_04.jpg", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0185-lemon-seedless-lime/image_05.jpg", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0185-lemon-seedless-lime/image_06.jpg", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0185-lemon-seedless-lime/image_07.png", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0185-lemon-seedless-lime/image_08.jpg"]','Acid lime type; Konkan and Pune; very popular for household use and street food vendors.','2026-06-27 16:54:19','2026-06-30 03:28:49','Citrus aurantiifolia (seedless type)','Bijrahit Limbu','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0185-lemon-seedless-lime/image_01.jpg',unistr('Acid lime type; Konkan and Pune; very popular for household use and street food vendors.\u000a\u000aScientific name: Citrus aurantiifolia (seedless type)\u000a\u000aOrigin: Maharashtra\u000a\u000aTaste profile: Acidic, thin-skinned, nearly seedless\u000a\u000aMarathi name: Bijrahit Limbu'));
INSERT INTO crop_variety VALUES(186,47,186,'Eureka Lemon','Eureka Limbu','USA/Maharashtra',NULL,'Strongly acidic, aromatic, thick-skinned',NULL,NULL,NULL,0,0,0,NULL,NULL,'["https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0186-lemon-eureka-lemon/image_01.jpg", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0186-lemon-eureka-lemon/image_02.jpg", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0186-lemon-eureka-lemon/image_03.jpg", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0186-lemon-eureka-lemon/image_04.png", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0186-lemon-eureka-lemon/image_05.jpg", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0186-lemon-eureka-lemon/image_06.jpg", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0186-lemon-eureka-lemon/image_07.jpg", "https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0186-lemon-eureka-lemon/image_08.jpg"]','Introduced variety; grown in Nashik and Pune; export-quality large lemon; increasing adoption.','2026-06-27 16:54:19','2026-06-30 03:28:36','Citrus limon cv. Eureka','Eureka Limbu','https://pub-b4b449ec1942478faeec7dcf924c0abe.r2.dev/crop-varieties/subtype-0186-lemon-eureka-lemon/image_01.jpg',unistr('Introduced variety; grown in Nashik and Pune; export-quality large lemon; increasing adoption.\u000a\u000aScientific name: Citrus limon cv. Eureka\u000a\u000aOrigin: USA/Maharashtra\u000a\u000aTaste profile: Strongly acidic, aromatic, thick-skinned\u000a\u000aMarathi name: Eureka Limbu'));
INSERT INTO crop_translations VALUES(1,1,'hi','आम','ताजे फल','ताजे फल','Zaid','आम GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('आम GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Mangifera indica\u000a\u000aश्रेणी: Tropical\u000a\u000aमौसम: Zaid\u000a\u000aमराठी नाम: Amba\u000a\u000aहिंदी नाम: Aam\u000a\u000aअंग्रेजी नाम: Mango\u000a\u000aमूल डेटासेट विवरण: Maharashtra is one of India''s leading mango-producing states. The Konkan coast is especially famous for Alphonso (Hapus), prized worldwide for its aroma, sweetness, and saffron-orange flesh. Grown across Ratnagiri, Sindhudurg, and Raigad districts. Season: March–June.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(2,1,'mr','आंबा','ताजी फळे','ताजी फळे','Zaid','आंबा हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('आंबा हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Mangifera indica\u000a\u000aश्रेणी: Tropical\u000a\u000aहंगाम: Zaid\u000a\u000aमराठी नाव: Amba\u000a\u000aहिंदी नाव: Aam\u000a\u000aइंग्रजी नाव: Mango\u000a\u000aमूळ डेटासेट तपशील: Maharashtra is one of India''s leading mango-producing states. The Konkan coast is especially famous for Alphonso (Hapus), prized worldwide for its aroma, sweetness, and saffron-orange flesh. Grown across Ratnagiri, Sindhudurg, and Raigad districts. Season: March–June.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(3,2,'hi','अंगूर','ताजे फल','ताजे फल','Rabi','अंगूर GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('अंगूर GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Vitis vinifera\u000a\u000aश्रेणी: Tropical\u000a\u000aमौसम: Rabi\u000a\u000aमराठी नाम: Draksha\u000a\u000aहिंदी नाम: Angoor\u000a\u000aअंग्रेजी नाम: Grapes\u000a\u000aमूल डेटासेट विवरण: Maharashtra, particularly Nashik district, is India''s largest grape-producing region, accounting for ~70% of national output. Nashik is called the "Wine Capital of India". Grapes are grown from October–November (pruning) with harvest January–March. Major export crop.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(4,2,'mr','द्राक्ष','ताजी फळे','ताजी फळे','Rabi','द्राक्ष हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('द्राक्ष हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Vitis vinifera\u000a\u000aश्रेणी: Tropical\u000a\u000aहंगाम: Rabi\u000a\u000aमराठी नाव: Draksha\u000a\u000aहिंदी नाव: Angoor\u000a\u000aइंग्रजी नाव: Grapes\u000a\u000aमूळ डेटासेट तपशील: Maharashtra, particularly Nashik district, is India''s largest grape-producing region, accounting for ~70% of national output. Nashik is called the "Wine Capital of India". Grapes are grown from October–November (pruning) with harvest January–March. Major export crop.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(5,3,'hi','संतरा','ताजे फल','ताजे फल','Rabi','संतरा GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('संतरा GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrus sinensis / Citrus reticulata\u000a\u000aश्रेणी: Citrus\u000a\u000aमौसम: Rabi\u000a\u000aमराठी नाम: Santra\u000a\u000aहिंदी नाम: Santra\u000a\u000aअंग्रेजी नाम: Orange\u000a\u000aमूल डेटासेट विवरण: Nagpur is the "Orange City" — Maharashtra''s Vidarbha region produces the famous GI-tagged Nagpur Mandarin, India''s most well-known orange variety, harvested November–January.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(6,3,'mr','संत्रा','ताजी फळे','ताजी फळे','Rabi','संत्रा हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('संत्रा हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrus sinensis / Citrus reticulata\u000a\u000aश्रेणी: Citrus\u000a\u000aहंगाम: Rabi\u000a\u000aमराठी नाव: Santra\u000a\u000aहिंदी नाव: Santra\u000a\u000aइंग्रजी नाव: Orange\u000a\u000aमूळ डेटासेट तपशील: Nagpur is the "Orange City" — Maharashtra''s Vidarbha region produces the famous GI-tagged Nagpur Mandarin, India''s most well-known orange variety, harvested November–January.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(7,4,'hi','केला','ताजे फल','ताजे फल','Year-round','केला GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('केला GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Musa acuminata / Musa balbisiana\u000a\u000aश्रेणी: Tropical\u000a\u000aमौसम: Year-round\u000a\u000aमराठी नाम: Kela\u000a\u000aहिंदी नाम: Kela\u000a\u000aअंग्रेजी नाम: Banana\u000a\u000aमूल डेटासेट विवरण: Jalgaon district is India''s banana capital — Maharashtra ranks first nationally in banana production. Jalgaon bananas have a GI tag. Bananas are cultivated year-round under drip irrigation.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
