INSERT INTO crop_translations VALUES(9,5,'hi','अमरूद','ताजे फल','ताजे फल','Year-round','अमरूद GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('अमरूद GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Psidium guajava\u000a\u000aश्रेणी: Tropical\u000a\u000aमौसम: Year-round\u000a\u000aमराठी नाम: Peru\u000a\u000aहिंदी नाम: Amrood\u000a\u000aअंग्रेजी नाम: Guava\u000a\u000aमूल डेटासेट विवरण: Guava is widely grown across Nashik, Pune, Solapur and Marathwada districts of Maharashtra. Rich in Vitamin C and lycopene; two crops per year possible.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
