INSERT INTO crop_translations VALUES(11,6,'hi','अनार','ताजे फल','ताजे फल','Year-round','अनार GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('अनार GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Punica granatum\u000a\u000aश्रेणी: Sub-tropical\u000a\u000aमौसम: Year-round\u000a\u000aमराठी नाम: Dalimb\u000a\u000aहिंदी नाम: Anar\u000a\u000aअंग्रेजी नाम: Pomegranate\u000a\u000aमूल डेटासेट विवरण: Maharashtra is the largest pomegranate producer in India, contributing ~80% of national output. Solapur, Sangli, Pune, Nashik, Ahmednagar and Osmanabad are major growing districts. Bhagwa variety has a GI tag and is a prized export fruit.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
