INSERT INTO crop_translations VALUES(13,7,'hi','सीताफल','ताजे फल','ताजे फल','Kharif','सीताफल GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('सीताफल GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Annona squamosa / Annona reticulata\u000a\u000aश्रेणी: Tropical\u000a\u000aमौसम: Kharif\u000a\u000aमराठी नाम: Sitafal\u000a\u000aहिंदी नाम: Sitafal\u000a\u000aअंग्रेजी नाम: Custard Apple\u000a\u000aमूल डेटासेट विवरण: Custard apple is an important commercial fruit in Maharashtra, grown in dry regions of Nashik, Aurangabad, Osmanabad, Solapur and Pune. Season is September–November.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
