INSERT INTO crop_translations VALUES(17,9,'hi','चीकू','ताजे फल','ताजे फल','Year-round','चीकू GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('चीकू GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Manilkara zapota\u000a\u000aश्रेणी: Tropical\u000a\u000aमौसम: Year-round\u000a\u000aमराठी नाम: Chiku\u000a\u000aहिंदी नाम: Chiku\u000a\u000aअंग्रेजी नाम: Sapota / Chikoo\u000a\u000aमूल डेटासेट विवरण: Maharashtra is a major Sapota producer; Palghar, Nashik, Pune and Thane districts are major growing areas. Fruit is available year-round with peak seasons February–May and August–November.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(18,9,'mr','चीकू','ताजी फळे','ताजी फळे','Year-round','चीकू हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('चीकू हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Manilkara zapota\u000a\u000aश्रेणी: Tropical\u000a\u000aहंगाम: Year-round\u000a\u000aमराठी नाव: Chiku\u000a\u000aहिंदी नाव: Chiku\u000a\u000aइंग्रजी नाव: Sapota / Chikoo\u000a\u000aमूळ डेटासेट तपशील: Maharashtra is a major Sapota producer; Palghar, Nashik, Pune and Thane districts are major growing areas. Fruit is available year-round with peak seasons February–May and August–November.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(19,10,'hi','नारियल','ताजे फल','ताजे फल','Year-round','नारियल GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('नारियल GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Cocos nucifera\u000a\u000aश्रेणी: Tropical\u000a\u000aमौसम: Year-round\u000a\u000aमराठी नाम: Naral\u000a\u000aहिंदी नाम: Nariyal\u000a\u000aअंग्रेजी नाम: Coconut\u000a\u000aमूल डेटासेट विवरण: Coconut is a major crop of the Konkan coast — Ratnagiri, Sindhudurg, Raigad, Palghar and Thane. Used for copra, oil, tender coconut water, and in Maharashtrian cuisine.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(20,10,'mr','नारळ','ताजी फळे','ताजी फळे','Year-round','नारळ हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('नारळ हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Cocos nucifera\u000a\u000aश्रेणी: Tropical\u000a\u000aहंगाम: Year-round\u000a\u000aमराठी नाव: Naral\u000a\u000aहिंदी नाव: Nariyal\u000a\u000aइंग्रजी नाव: Coconut\u000a\u000aमूळ डेटासेट तपशील: Coconut is a major crop of the Konkan coast — Ratnagiri, Sindhudurg, Raigad, Palghar and Thane. Used for copra, oil, tender coconut water, and in Maharashtrian cuisine.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(21,11,'hi','कटहल','ताजे फल','ताजे फल','Zaid','कटहल GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('कटहल GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Artocarpus heterophyllus\u000a\u000aश्रेणी: Tropical\u000a\u000aमौसम: Zaid\u000a\u000aमराठी नाम: Phanas\u000a\u000aहिंदी नाम: Kathal\u000a\u000aअंग्रेजी नाम: Jackfruit\u000a\u000aमूल डेटासेट विवरण: Jackfruit grows in the humid Konkan belt; both unripe (vegetable use) and ripe fruit are consumed. Ratnagiri, Sindhudurg, Raigad and Thane are major areas. Season May–August.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
