INSERT INTO crop_translations VALUES(23,12,'hi','आंवला','ताजे फल','ताजे फल','Rabi','आंवला GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('आंवला GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Phyllanthus emblica\u000a\u000aश्रेणी: Sub-tropical\u000a\u000aमौसम: Rabi\u000a\u000aमराठी नाम: Avala\u000a\u000aहिंदी नाम: Amla\u000a\u000aअंग्रेजी नाम: Indian Gooseberry\u000a\u000aमूल डेटासेट विवरण: Amla (Indian Gooseberry) is grown in Nashik, Aurangabad, Pune and Marathwada. Richest natural source of Vitamin C; harvested November–February. Important in Ayurveda and food processing (pickles, candy, juice).'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(24,12,'mr','आवळा','ताजी फळे','ताजी फळे','Rabi','आवळा हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('आवळा हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Phyllanthus emblica\u000a\u000aश्रेणी: Sub-tropical\u000a\u000aहंगाम: Rabi\u000a\u000aमराठी नाव: Avala\u000a\u000aहिंदी नाव: Amla\u000a\u000aइंग्रजी नाव: Indian Gooseberry\u000a\u000aमूळ डेटासेट तपशील: Amla (Indian Gooseberry) is grown in Nashik, Aurangabad, Pune and Marathwada. Richest natural source of Vitamin C; harvested November–February. Important in Ayurveda and food processing (pickles, candy, juice).'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(25,13,'hi','स्ट्रॉबेरी','ताजे फल','ताजे फल','Rabi','स्ट्रॉबेरी GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('स्ट्रॉबेरी GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Fragaria × ananassa\u000a\u000aश्रेणी: Subtropical Highland\u000a\u000aमौसम: Rabi\u000a\u000aमराठी नाम: Strawberry\u000a\u000aहिंदी नाम: Strawberry\u000a\u000aअंग्रेजी नाम: Strawberry\u000a\u000aमूल डेटासेट विवरण: Mahabaleshwar (Satara district) and Panchgani produce 85% of India''s strawberries. Cool highland climate (1,400m elevation) ideal; season November–March. GI tag pending; major tourist attraction.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(26,13,'mr','स्ट्रॉबेरी','ताजी फळे','ताजी फळे','Rabi','स्ट्रॉबेरी हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('स्ट्रॉबेरी हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Fragaria × ananassa\u000a\u000aश्रेणी: Subtropical Highland\u000a\u000aहंगाम: Rabi\u000a\u000aमराठी नाव: Strawberry\u000a\u000aहिंदी नाव: Strawberry\u000a\u000aइंग्रजी नाव: Strawberry\u000a\u000aमूळ डेटासेट तपशील: Mahabaleshwar (Satara district) and Panchgani produce 85% of India''s strawberries. Cool highland climate (1,400m elevation) ideal; season November–March. GI tag pending; major tourist attraction.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(27,14,'hi','अंजीर','ताजे फल','ताजे फल','Zaid','अंजीर GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('अंजीर GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Ficus carica\u000a\u000aश्रेणी: Sub-tropical\u000a\u000aमौसम: Zaid\u000a\u000aमराठी नाम: Anjeer\u000a\u000aहिंदी नाम: Anjeer\u000a\u000aअंग्रेजी नाम: Fig\u000a\u000aमूल डेटासेट विवरण: Pune, particularly Purandar taluka, is the "Fig Capital" of India. Maharashtra has a GI tag for Purandar Fig. Season: January–March (main) and June–August (secondary).'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(28,14,'mr','अंजीर','ताजी फळे','ताजी फळे','Zaid','अंजीर हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('अंजीर हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Ficus carica\u000a\u000aश्रेणी: Sub-tropical\u000a\u000aहंगाम: Zaid\u000a\u000aमराठी नाव: Anjeer\u000a\u000aहिंदी नाव: Anjeer\u000a\u000aइंग्रजी नाव: Fig\u000a\u000aमूळ डेटासेट तपशील: Pune, particularly Purandar taluka, is the "Fig Capital" of India. Maharashtra has a GI tag for Purandar Fig. Season: January–March (main) and June–August (secondary).'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(29,15,'hi','बेर','ताजे फल','ताजे फल','Rabi','बेर GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('बेर GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Ziziphus mauritiana\u000a\u000aश्रेणी: Sub-tropical\u000a\u000aमौसम: Rabi\u000a\u000aमराठी नाम: Bor\u000a\u000aहिंदी नाम: Ber\u000a\u000aअंग्रेजी नाम: Indian Jujube / Ber\u000a\u000aमूल डेटासेट विवरण: Ber is a drought-tolerant fruit grown in dry zones of Maharashtra — Solapur, Osmanabad, Latur, Aurangabad. Season November–February. Rich in Vitamin C and minerals; good for dry regions.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(30,15,'mr','बोर','ताजी फळे','ताजी फळे','Rabi','बोर हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('बोर हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Ziziphus mauritiana\u000a\u000aश्रेणी: Sub-tropical\u000a\u000aहंगाम: Rabi\u000a\u000aमराठी नाव: Bor\u000a\u000aहिंदी नाव: Ber\u000a\u000aइंग्रजी नाव: Indian Jujube / Ber\u000a\u000aमूळ डेटासेट तपशील: Ber is a drought-tolerant fruit grown in dry zones of Maharashtra — Solapur, Osmanabad, Latur, Aurangabad. Season November–February. Rich in Vitamin C and minerals; good for dry regions.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(31,16,'hi','चावल','अनाज और धान्य','अनाज और धान्य','Kharif','चावल GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('चावल GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Oryza sativa\u000a\u000aश्रेणी: Cereal\u000a\u000aमौसम: Kharif\u000a\u000aमराठी नाम: Bhat / Tandul\u000a\u000aहिंदी नाम: Chawal\u000a\u000aअंग्रेजी नाम: Rice\u000a\u000aमूल डेटासेट विवरण: Rice is the primary Kharif food grain of Maharashtra, grown mainly in Konkan (Ratnagiri, Sindhudurg, Raigad), Western Ghats foothills, and Vidarbha. Maharashtra grows aromatic traditional varieties alongside high-yielding types. Total area ~1.5 million hectares.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(32,16,'mr','तांदूळ','धान्य आणि कडधान्य नसलेली अन्नधान्ये','धान्य आणि कडधान्य नसलेली अन्नधान्ये','Kharif','तांदूळ हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('तांदूळ हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Oryza sativa\u000a\u000aश्रेणी: Cereal\u000a\u000aहंगाम: Kharif\u000a\u000aमराठी नाव: Bhat / Tandul\u000a\u000aहिंदी नाव: Chawal\u000a\u000aइंग्रजी नाव: Rice\u000a\u000aमूळ डेटासेट तपशील: Rice is the primary Kharif food grain of Maharashtra, grown mainly in Konkan (Ratnagiri, Sindhudurg, Raigad), Western Ghats foothills, and Vidarbha. Maharashtra grows aromatic traditional varieties alongside high-yielding types. Total area ~1.5 million hectares.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(33,17,'hi','गेहूं','अनाज और धान्य','अनाज और धान्य','Rabi','गेहूं GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('गेहूं GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Triticum aestivum / Triticum durum\u000a\u000aश्रेणी: Cereal\u000a\u000aमौसम: Rabi\u000a\u000aमराठी नाम: Gahu\u000a\u000aहिंदी नाम: Gehun\u000a\u000aअंग्रेजी नाम: Wheat\u000a\u000aमूल डेटासेट विवरण: Wheat is Maharashtra''s principal Rabi crop; grown in Nashik, Pune, Ahmednagar, Aurangabad, Solapur and Vidarbha under irrigated conditions. Sown October–November, harvested February–March. Maharashtra grows both bread wheat and durum (for semolina/pasta).'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(34,17,'mr','गहू','धान्य आणि कडधान्य नसलेली अन्नधान्ये','धान्य आणि कडधान्य नसलेली अन्नधान्ये','Rabi','गहू हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('गहू हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Triticum aestivum / Triticum durum\u000a\u000aश्रेणी: Cereal\u000a\u000aहंगाम: Rabi\u000a\u000aमराठी नाव: Gahu\u000a\u000aहिंदी नाव: Gehun\u000a\u000aइंग्रजी नाव: Wheat\u000a\u000aमूळ डेटासेट तपशील: Wheat is Maharashtra''s principal Rabi crop; grown in Nashik, Pune, Ahmednagar, Aurangabad, Solapur and Vidarbha under irrigated conditions. Sown October–November, harvested February–March. Maharashtra grows both bread wheat and durum (for semolina/pasta).'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(35,18,'hi','ज्वार','मोटे अनाज','मोटे अनाज','Kharif','ज्वार GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('ज्वार GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Sorghum bicolor\u000a\u000aश्रेणी: Millet / Cereal\u000a\u000aमौसम: Kharif\u000a\u000aमराठी नाम: Jwarī\u000a\u000aहिंदी नाम: Jowar\u000a\u000aअंग्रेजी नाम: Sorghum\u000a\u000aमूल डेटासेट विवरण: Maharashtra is India''s largest Jowar-producing state. Jowar (bhakri) is the staple food of rural Maharashtra. Grown in Solapur, Osmanabad, Latur, Aurangabad, Nashik. Kharif and Rabi (sweet sorghum for fodder) seasons. Drought tolerant and rainfed crop.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(36,18,'mr','ज्वारी','मिलेट्स / भरड धान्य','मिलेट्स / भरड धान्य','Kharif','ज्वारी हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('ज्वारी हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Sorghum bicolor\u000a\u000aश्रेणी: Millet / Cereal\u000a\u000aहंगाम: Kharif\u000a\u000aमराठी नाव: Jwarī\u000a\u000aहिंदी नाव: Jowar\u000a\u000aइंग्रजी नाव: Sorghum\u000a\u000aमूळ डेटासेट तपशील: Maharashtra is India''s largest Jowar-producing state. Jowar (bhakri) is the staple food of rural Maharashtra. Grown in Solapur, Osmanabad, Latur, Aurangabad, Nashik. Kharif and Rabi (sweet sorghum for fodder) seasons. Drought tolerant and rainfed crop.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(37,19,'hi','बाजरा','मोटे अनाज','मोटे अनाज','Kharif','बाजरा GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('बाजरा GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Pennisetum glaucum\u000a\u000aश्रेणी: Millet / Cereal\u000a\u000aमौसम: Kharif\u000a\u000aमराठी नाम: Bajrī\u000a\u000aहिंदी नाम: Bajra\u000a\u000aअंग्रेजी नाम: Pearl Millet\u000a\u000aमूल डेटासेट विवरण: Bajra is a major Kharif crop of dry districts of Maharashtra — Nashik, Jalgaon, Dhule, Aurangabad. Very drought tolerant; important for poor rainfall areas. Bhakri (flatbread) is traditional use.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(38,19,'mr','बाजरी','मिलेट्स / भरड धान्य','मिलेट्स / भरड धान्य','Kharif','बाजरी हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('बाजरी हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Pennisetum glaucum\u000a\u000aश्रेणी: Millet / Cereal\u000a\u000aहंगाम: Kharif\u000a\u000aमराठी नाव: Bajrī\u000a\u000aहिंदी नाव: Bajra\u000a\u000aइंग्रजी नाव: Pearl Millet\u000a\u000aमूळ डेटासेट तपशील: Bajra is a major Kharif crop of dry districts of Maharashtra — Nashik, Jalgaon, Dhule, Aurangabad. Very drought tolerant; important for poor rainfall areas. Bhakri (flatbread) is traditional use.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(39,20,'hi','मक्का','अनाज और धान्य','अनाज और धान्य','Kharif','मक्का GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('मक्का GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Zea mays\u000a\u000aश्रेणी: Cereal\u000a\u000aमौसम: Kharif\u000a\u000aमराठी नाम: Makka\u000a\u000aहिंदी नाम: Makka\u000a\u000aअंग्रेजी नाम: Maize / Corn\u000a\u000aमूल डेटासेट विवरण: Maize is an important Kharif crop in Nashik, Pune, Aurangabad, Ahmednagar and Nanded districts. Used for food (corn), poultry feed, starch and ethanol. Maharashtra contributes ~5% of national maize production.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(40,20,'mr','मका','धान्य आणि कडधान्य नसलेली अन्नधान्ये','धान्य आणि कडधान्य नसलेली अन्नधान्ये','Kharif','मका हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('मका हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Zea mays\u000a\u000aश्रेणी: Cereal\u000a\u000aहंगाम: Kharif\u000a\u000aमराठी नाव: Makka\u000a\u000aहिंदी नाव: Makka\u000a\u000aइंग्रजी नाव: Maize / Corn\u000a\u000aमूळ डेटासेट तपशील: Maize is an important Kharif crop in Nashik, Pune, Aurangabad, Ahmednagar and Nanded districts. Used for food (corn), poultry feed, starch and ethanol. Maharashtra contributes ~5% of national maize production.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(41,21,'hi','रागी','मोटे अनाज','मोटे अनाज','Kharif','रागी GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('रागी GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Eleusine coracana\u000a\u000aश्रेणी: Millet\u000a\u000aमौसम: Kharif\u000a\u000aमराठी नाम: Nachni\u000a\u000aहिंदी नाम: Ragi / Mandua\u000a\u000aअंग्रेजी नाम: Finger Millet\u000a\u000aमूल डेटासेट विवरण: Ragi (Nachni) is a nutritionally dense millet; grown in hilly and tribal areas of Nashik, Pune (Junnar), Nandurbar and Konkan. Richest grain source of calcium (344 mg/100g). Nachni bhakri and nachni satva (porridge) are traditional foods.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(42,21,'mr','नाचणी','मिलेट्स / भरड धान्य','मिलेट्स / भरड धान्य','Kharif','नाचणी हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('नाचणी हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Eleusine coracana\u000a\u000aश्रेणी: Millet\u000a\u000aहंगाम: Kharif\u000a\u000aमराठी नाव: Nachni\u000a\u000aहिंदी नाव: Ragi / Mandua\u000a\u000aइंग्रजी नाव: Finger Millet\u000a\u000aमूळ डेटासेट तपशील: Ragi (Nachni) is a nutritionally dense millet; grown in hilly and tribal areas of Nashik, Pune (Junnar), Nandurbar and Konkan. Richest grain source of calcium (344 mg/100g). Nachni bhakri and nachni satva (porridge) are traditional foods.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(43,22,'hi','कोदो','मोटे अनाज','मोटे अनाज','Kharif','कोदो GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('कोदो GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Paspalum scrobiculatum\u000a\u000aश्रेणी: Millet\u000a\u000aमौसम: Kharif\u000a\u000aमराठी नाम: Kodra\u000a\u000aहिंदी नाम: Kodra\u000a\u000aअंग्रेजी नाम: Kodo Millet\u000a\u000aमूल डेटासेट विवरण: Kodo Millet (Kodra) is a traditional millet grown in tribal/hilly areas of Nashik, Nandurbar, Amravati and Gadchiroli. Drought-tolerant; low input; nutritious; part of the Nutri-Cereal revival initiative in Maharashtra.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(44,22,'mr','कोद्रा','मिलेट्स / भरड धान्य','मिलेट्स / भरड धान्य','Kharif','कोद्रा हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('कोद्रा हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Paspalum scrobiculatum\u000a\u000aश्रेणी: Millet\u000a\u000aहंगाम: Kharif\u000a\u000aमराठी नाव: Kodra\u000a\u000aहिंदी नाव: Kodra\u000a\u000aइंग्रजी नाव: Kodo Millet\u000a\u000aमूळ डेटासेट तपशील: Kodo Millet (Kodra) is a traditional millet grown in tribal/hilly areas of Nashik, Nandurbar, Amravati and Gadchiroli. Drought-tolerant; low input; nutritious; part of the Nutri-Cereal revival initiative in Maharashtra.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(45,23,'hi','कुटकी','मोटे अनाज','मोटे अनाज','Kharif','कुटकी GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('कुटकी GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Panicum sumatrense\u000a\u000aश्रेणी: Millet\u000a\u000aमौसम: Kharif\u000a\u000aमराठी नाम: Vari / Kutki\u000a\u000aहिंदी नाम: Kutki\u000a\u000aअंग्रेजी नाम: Little Millet\u000a\u000aमूल डेटासेट विवरण: Little Millet (Vari) is used during religious fasting in Maharashtra (Ekadashi, Navratri). Grown in tribal belts of Nashik, Nandurbar and Gadchiroli. Reviving due to health consciousness and fasting food markets.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(46,23,'mr','वरी / कुटकी','मिलेट्स / भरड धान्य','मिलेट्स / भरड धान्य','Kharif','वरी / कुटकी हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('वरी / कुटकी हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Panicum sumatrense\u000a\u000aश्रेणी: Millet\u000a\u000aहंगाम: Kharif\u000a\u000aमराठी नाव: Vari / Kutki\u000a\u000aहिंदी नाव: Kutki\u000a\u000aइंग्रजी नाव: Little Millet\u000a\u000aमूळ डेटासेट तपशील: Little Millet (Vari) is used during religious fasting in Maharashtra (Ekadashi, Navratri). Grown in tribal belts of Nashik, Nandurbar and Gadchiroli. Reviving due to health consciousness and fasting food markets.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(47,24,'hi','सांवा','मोटे अनाज','मोटे अनाज','Kharif','सांवा GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('सांवा GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Echinochloa frumentacea\u000a\u000aश्रेणी: Millet\u000a\u000aमौसम: Kharif\u000a\u000aमराठी नाम: Bhagar / Sanwa\u000a\u000aहिंदी नाम: Sanwa\u000a\u000aअंग्रेजी नाम: Barnyard Millet\u000a\u000aमूल डेटासेट विवरण: Barnyard Millet (Bhagar) is extremely popular in Maharashtra for religious fasting (Upvasachi bhakri, Bhagar rice). Widely consumed during Ekadashi, Navratri. Grown in Nashik, Aurangabad, Nandurbar. High fibre, low GI.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(48,24,'mr','भगर / सांवा','मिलेट्स / भरड धान्य','मिलेट्स / भरड धान्य','Kharif','भगर / सांवा हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('भगर / सांवा हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Echinochloa frumentacea\u000a\u000aश्रेणी: Millet\u000a\u000aहंगाम: Kharif\u000a\u000aमराठी नाव: Bhagar / Sanwa\u000a\u000aहिंदी नाव: Sanwa\u000a\u000aइंग्रजी नाव: Barnyard Millet\u000a\u000aमूळ डेटासेट तपशील: Barnyard Millet (Bhagar) is extremely popular in Maharashtra for religious fasting (Upvasachi bhakri, Bhagar rice). Widely consumed during Ekadashi, Navratri. Grown in Nashik, Aurangabad, Nandurbar. High fibre, low GI.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(49,25,'hi','चीना','मोटे अनाज','मोटे अनाज','Kharif','चीना GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('चीना GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Panicum miliaceum\u000a\u000aश्रेणी: Millet\u000a\u000aमौसम: Kharif\u000a\u000aमराठी नाम: Cheena\u000a\u000aहिंदी नाम: Cheena\u000a\u000aअंग्रेजी नाम: Proso Millet / Common Millet\u000a\u000aमूल डेटासेट विवरण: Proso Millet is an ancient grain with fastest growth cycle (60–75 days) among millets. Grown in dry areas of Maharashtra as an emergency/catch crop. Low water requirement; high nutritional value. Reviving under health and organic food movements.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(50,25,'mr','चीना','मिलेट्स / भरड धान्य','मिलेट्स / भरड धान्य','Kharif','चीना हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('चीना हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Panicum miliaceum\u000a\u000aश्रेणी: Millet\u000a\u000aहंगाम: Kharif\u000a\u000aमराठी नाव: Cheena\u000a\u000aहिंदी नाव: Cheena\u000a\u000aइंग्रजी नाव: Proso Millet / Common Millet\u000a\u000aमूळ डेटासेट तपशील: Proso Millet is an ancient grain with fastest growth cycle (60–75 days) among millets. Grown in dry areas of Maharashtra as an emergency/catch crop. Low water requirement; high nutritional value. Reviving under health and organic food movements.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(51,26,'hi','तूर / अरहर','दालें और लेंटिल्स','दालें और लेंटिल्स','Kharif','तूर / अरहर GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('तूर / अरहर GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Cajanus cajan\u000a\u000aश्रेणी: Pulse\u000a\u000aमौसम: Kharif\u000a\u000aमराठी नाम: Tur\u000a\u000aहिंदी नाम: Arhar / Tur\u000a\u000aअंग्रेजी नाम: Pigeon Pea / Red Gram\u000a\u000aमूल डेटासेट विवरण: Maharashtra is the largest Tur (pigeon pea) producing state in India. Grown extensively in Latur, Osmanabad, Nanded, Solapur and Marathwada. Staple dal of Maharashtra — tur dal (amti) is fundamental to Maharashtrian thali. Kharif season: sown June–July, harvested January–February.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(52,26,'mr','तूर','कडधान्ये आणि डाळी','कडधान्ये आणि डाळी','Kharif','तूर हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('तूर हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Cajanus cajan\u000a\u000aश्रेणी: Pulse\u000a\u000aहंगाम: Kharif\u000a\u000aमराठी नाव: Tur\u000a\u000aहिंदी नाव: Arhar / Tur\u000a\u000aइंग्रजी नाव: Pigeon Pea / Red Gram\u000a\u000aमूळ डेटासेट तपशील: Maharashtra is the largest Tur (pigeon pea) producing state in India. Grown extensively in Latur, Osmanabad, Nanded, Solapur and Marathwada. Staple dal of Maharashtra — tur dal (amti) is fundamental to Maharashtrian thali. Kharif season: sown June–July, harvested January–February.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(53,27,'hi','चना','दालें और लेंटिल्स','दालें और लेंटिल्स','Rabi','चना GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('चना GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Cicer arietinum\u000a\u000aश्रेणी: Pulse\u000a\u000aमौसम: Rabi\u000a\u000aमराठी नाम: Harbhara / Chana\u000a\u000aहिंदी नाम: Chana\u000a\u000aअंग्रेजी नाम: Chickpea / Bengal Gram\u000a\u000aमूल डेटासेट विवरण: Maharashtra is a leading chickpea-growing state; Marathwada (Latur, Osmanabad, Aurangabad) and Vidarbha are key regions. Both desi (brown) and kabuli (white/large) types grown. Rabi season: sown October–November, harvested January–February.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(54,27,'mr','हरभरा','कडधान्ये आणि डाळी','कडधान्ये आणि डाळी','Rabi','हरभरा हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('हरभरा हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Cicer arietinum\u000a\u000aश्रेणी: Pulse\u000a\u000aहंगाम: Rabi\u000a\u000aमराठी नाव: Harbhara / Chana\u000a\u000aहिंदी नाव: Chana\u000a\u000aइंग्रजी नाव: Chickpea / Bengal Gram\u000a\u000aमूळ डेटासेट तपशील: Maharashtra is a leading chickpea-growing state; Marathwada (Latur, Osmanabad, Aurangabad) and Vidarbha are key regions. Both desi (brown) and kabuli (white/large) types grown. Rabi season: sown October–November, harvested January–February.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(55,28,'hi','उड़द','दालें और लेंटिल्स','दालें और लेंटिल्स','Kharif','उड़द GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('उड़द GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Vigna mungo\u000a\u000aश्रेणी: Pulse\u000a\u000aमौसम: Kharif\u000a\u000aमराठी नाम: Udid\u000a\u000aहिंदी नाम: Urad\u000a\u000aअंग्रेजी नाम: Black Gram / Urad\u000a\u000aमूल डेटासेट विवरण: Urad (Udid) is a Kharif pulse grown in Nanded, Latur, Osmanabad, Aurangabad and parts of Vidarbha. Essential for Maharashtrian vada, idli (batter), and dal. Short-duration; good in mixed cropping with Tur.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(56,28,'mr','उडीद','कडधान्ये आणि डाळी','कडधान्ये आणि डाळी','Kharif','उडीद हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('उडीद हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Vigna mungo\u000a\u000aश्रेणी: Pulse\u000a\u000aहंगाम: Kharif\u000a\u000aमराठी नाव: Udid\u000a\u000aहिंदी नाव: Urad\u000a\u000aइंग्रजी नाव: Black Gram / Urad\u000a\u000aमूळ डेटासेट तपशील: Urad (Udid) is a Kharif pulse grown in Nanded, Latur, Osmanabad, Aurangabad and parts of Vidarbha. Essential for Maharashtrian vada, idli (batter), and dal. Short-duration; good in mixed cropping with Tur.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(57,29,'hi','मसूर','दालें और लेंटिल्स','दालें और लेंटिल्स','Rabi','मसूर GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('मसूर GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Lens culinaris\u000a\u000aश्रेणी: Pulse\u000a\u000aमौसम: Rabi\u000a\u000aमराठी नाम: Masur\u000a\u000aहिंदी नाम: Masoor\u000a\u000aअंग्रेजी नाम: Lentil / Masoor\u000a\u000aमूल डेटासेट विवरण: Masoor (Red Lentil) is a Rabi pulse grown in Marathwada and Vidarbha — Latur, Osmanabad, Yavatmal. Less common than Tur and Chana but nutritionally important; pink/red split dal used widely in Maharashtrian cuisine.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(58,29,'mr','मसूर','कडधान्ये आणि डाळी','कडधान्ये आणि डाळी','Rabi','मसूर हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('मसूर हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Lens culinaris\u000a\u000aश्रेणी: Pulse\u000a\u000aहंगाम: Rabi\u000a\u000aमराठी नाव: Masur\u000a\u000aहिंदी नाव: Masoor\u000a\u000aइंग्रजी नाव: Lentil / Masoor\u000a\u000aमूळ डेटासेट तपशील: Masoor (Red Lentil) is a Rabi pulse grown in Marathwada and Vidarbha — Latur, Osmanabad, Yavatmal. Less common than Tur and Chana but nutritionally important; pink/red split dal used widely in Maharashtrian cuisine.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(59,30,'hi','सोयाबीन','तिलहन','तिलहन','Kharif','सोयाबीन GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('सोयाबीन GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Glycine max\u000a\u000aश्रेणी: Oilseed\u000a\u000aमौसम: Kharif\u000a\u000aमराठी नाम: Soya\u000a\u000aहिंदी नाम: Soya\u000a\u000aअंग्रेजी नाम: Soybean\u000a\u000aमूल डेटासेट विवरण: Maharashtra is the largest soybean-growing state in India, with ~40% of national acreage. Grown in Vidarbha (Nagpur, Amravati), Marathwada (Latur, Osmanabad) and Nashik. Major oilseed and protein crop. Sown June–July; harvested September–October.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(60,30,'mr','सोयाबीन','तेलबिया','तेलबिया','Kharif','सोयाबीन हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('सोयाबीन हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Glycine max\u000a\u000aश्रेणी: Oilseed\u000a\u000aहंगाम: Kharif\u000a\u000aमराठी नाव: Soya\u000a\u000aहिंदी नाव: Soya\u000a\u000aइंग्रजी नाव: Soybean\u000a\u000aमूळ डेटासेट तपशील: Maharashtra is the largest soybean-growing state in India, with ~40% of national acreage. Grown in Vidarbha (Nagpur, Amravati), Marathwada (Latur, Osmanabad) and Nashik. Major oilseed and protein crop. Sown June–July; harvested September–October.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(61,31,'hi','मूंगफली','तिलहन','तिलहन','Kharif','मूंगफली GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('मूंगफली GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Arachis hypogaea\u000a\u000aश्रेणी: Oilseed\u000a\u000aमौसम: Kharif\u000a\u000aमराठी नाम: Shengdana\u000a\u000aहिंदी नाम: Moongphali\u000a\u000aअंग्रेजी नाम: Groundnut / Peanut\u000a\u000aमूल डेटासेट विवरण: Groundnut is a major Kharif oilseed and cash crop in Maharashtra — Akola, Amravati, Wardha (Vidarbha) and Nashik, Jalgaon (North Maharashtra). Maharashtra is 4th nationally. Also a Rabi irrigated crop in Solapur. Famous for "Vidarbha shengdana".'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(62,31,'mr','शेंगदाणा','तेलबिया','तेलबिया','Kharif','शेंगदाणा हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('शेंगदाणा हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Arachis hypogaea\u000a\u000aश्रेणी: Oilseed\u000a\u000aहंगाम: Kharif\u000a\u000aमराठी नाव: Shengdana\u000a\u000aहिंदी नाव: Moongphali\u000a\u000aइंग्रजी नाव: Groundnut / Peanut\u000a\u000aमूळ डेटासेट तपशील: Groundnut is a major Kharif oilseed and cash crop in Maharashtra — Akola, Amravati, Wardha (Vidarbha) and Nashik, Jalgaon (North Maharashtra). Maharashtra is 4th nationally. Also a Rabi irrigated crop in Solapur. Famous for "Vidarbha shengdana".'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(63,32,'hi','तिल','तिलहन','तिलहन','Kharif','तिल GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('तिल GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Sesamum indicum\u000a\u000aश्रेणी: Oilseed\u000a\u000aमौसम: Kharif\u000a\u000aमराठी नाम: Til\u000a\u000aहिंदी नाम: Til\u000a\u000aअंग्रेजी नाम: Sesame\u000a\u000aमूल डेटासेट विवरण: Sesame (Til) is a traditional oilseed crop of Maharashtra grown in Aurangabad, Jalgaon, Nashik and Osmanabad. Essential in Maharashtrian sweets — tilgul (sesame-jaggery balls) for Makar Sankranti. High-value crop for domestic and export market.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(64,32,'mr','तीळ','तेलबिया','तेलबिया','Kharif','तीळ हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('तीळ हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Sesamum indicum\u000a\u000aश्रेणी: Oilseed\u000a\u000aहंगाम: Kharif\u000a\u000aमराठी नाव: Til\u000a\u000aहिंदी नाव: Til\u000a\u000aइंग्रजी नाव: Sesame\u000a\u000aमूळ डेटासेट तपशील: Sesame (Til) is a traditional oilseed crop of Maharashtra grown in Aurangabad, Jalgaon, Nashik and Osmanabad. Essential in Maharashtrian sweets — tilgul (sesame-jaggery balls) for Makar Sankranti. High-value crop for domestic and export market.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(65,33,'hi','सूरजमुखी','तिलहन','तिलहन','Rabi','सूरजमुखी GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('सूरजमुखी GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Helianthus annuus\u000a\u000aश्रेणी: Oilseed\u000a\u000aमौसम: Rabi\u000a\u000aमराठी नाम: Suryafool\u000a\u000aहिंदी नाम: Surajmukhi\u000a\u000aअंग्रेजी नाम: Sunflower\u000a\u000aमूल डेटासेट विवरण: Sunflower is grown as a Rabi crop in Maharashtra — Solapur, Osmanabad, Latur, Aurangabad, Nashik. Good oil crop for light black soils; used as edible oil. Also a Kharif crop in some areas.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(66,33,'mr','सूर्यफूल','तेलबिया','तेलबिया','Rabi','सूर्यफूल हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('सूर्यफूल हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Helianthus annuus\u000a\u000aश्रेणी: Oilseed\u000a\u000aहंगाम: Rabi\u000a\u000aमराठी नाव: Suryafool\u000a\u000aहिंदी नाव: Surajmukhi\u000a\u000aइंग्रजी नाव: Sunflower\u000a\u000aमूळ डेटासेट तपशील: Sunflower is grown as a Rabi crop in Maharashtra — Solapur, Osmanabad, Latur, Aurangabad, Nashik. Good oil crop for light black soils; used as edible oil. Also a Kharif crop in some areas.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(67,34,'hi','गन्ना','अनाज और धान्य','अनाज और धान्य','Year-round','गन्ना GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('गन्ना GreenWings कैटलॉग का एक महत्वपूर्ण अनाज उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Saccharum officinarum\u000a\u000aश्रेणी: Cash Crop / Industrial\u000a\u000aमौसम: Year-round\u000a\u000aमराठी नाम: Oos / Verdi\u000a\u000aहिंदी नाम: Ganna\u000a\u000aअंग्रेजी नाम: Sugarcane\u000a\u000aमूल डेटासेट विवरण: Maharashtra is India''s second-largest sugarcane and sugar-producing state. The Deccan plateau districts of Pune, Satara, Sangli, Kolhapur, Solapur, Nashik and Ahmednagar form the "Sugar Belt". Over 200 cooperative sugar factories operate. Maharashtra also leads in ethanol production from sugarcane. Crushed October–March after 10–14 months of growth. By-products: bagasse (energy), molasses (ethanol/alcohol), press mud (compost).'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(68,34,'mr','ऊस','धान्य आणि कडधान्य नसलेली अन्नधान्ये','धान्य आणि कडधान्य नसलेली अन्नधान्ये','Year-round','ऊस हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('ऊस हे GreenWings कॅटलॉगमधील महत्त्वाचे धान्य उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Saccharum officinarum\u000a\u000aश्रेणी: Cash Crop / Industrial\u000a\u000aहंगाम: Year-round\u000a\u000aमराठी नाव: Oos / Verdi\u000a\u000aहिंदी नाव: Ganna\u000a\u000aइंग्रजी नाव: Sugarcane\u000a\u000aमूळ डेटासेट तपशील: Maharashtra is India''s second-largest sugarcane and sugar-producing state. The Deccan plateau districts of Pune, Satara, Sangli, Kolhapur, Solapur, Nashik and Ahmednagar form the "Sugar Belt". Over 200 cooperative sugar factories operate. Maharashtra also leads in ethanol production from sugarcane. Crushed October–March after 10–14 months of growth. By-products: bagasse (energy), molasses (ethanol/alcohol), press mud (compost).'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(69,35,'hi','प्याज','ताजी सब्जियां','ताजी सब्जियां','Rabi','प्याज GreenWings कैटलॉग का एक महत्वपूर्ण vegetable उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('प्याज GreenWings कैटलॉग का एक महत्वपूर्ण vegetable उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Allium cepa\u000a\u000aश्रेणी: Vegetable / Spice\u000a\u000aमौसम: Rabi\u000a\u000aमराठी नाम: Kanda\u000a\u000aहिंदी नाम: Pyaaz\u000a\u000aअंग्रेजी नाम: Onion\u000a\u000aमूल डेटासेट विवरण: Maharashtra is India''s largest onion-producing state (~40% national share). Nashik, Pune, Ahmednagar, Solapur and Satara are prime growing districts. Nashik''s Lasalgaon APMC is Asia''s largest onion market. Three crops a year possible: Kharif (June–October), Late Kharif (September–January), and Rabi (January–May). Major export crop to Europe, South-East Asia and Middle East.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(70,35,'mr','कांदा','ताज्या भाज्या','ताज्या भाज्या','Rabi','कांदा हे GreenWings कॅटलॉगमधील महत्त्वाचे vegetable उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('कांदा हे GreenWings कॅटलॉगमधील महत्त्वाचे vegetable उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Allium cepa\u000a\u000aश्रेणी: Vegetable / Spice\u000a\u000aहंगाम: Rabi\u000a\u000aमराठी नाव: Kanda\u000a\u000aहिंदी नाव: Pyaaz\u000a\u000aइंग्रजी नाव: Onion\u000a\u000aमूळ डेटासेट तपशील: Maharashtra is India''s largest onion-producing state (~40% national share). Nashik, Pune, Ahmednagar, Solapur and Satara are prime growing districts. Nashik''s Lasalgaon APMC is Asia''s largest onion market. Three crops a year possible: Kharif (June–October), Late Kharif (September–January), and Rabi (January–May). Major export crop to Europe, South-East Asia and Middle East.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(71,36,'hi','टमाटर','ताजी सब्जियां','ताजी सब्जियां','Year-round','टमाटर GreenWings कैटलॉग का एक महत्वपूर्ण vegetable उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('टमाटर GreenWings कैटलॉग का एक महत्वपूर्ण vegetable उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Solanum lycopersicum\u000a\u000aश्रेणी: Vegetable\u000a\u000aमौसम: Year-round\u000a\u000aमराठी नाम: Tomato\u000a\u000aहिंदी नाम: Tamatar\u000a\u000aअंग्रेजी नाम: Tomato\u000a\u000aमूल डेटासेट विवरण: Maharashtra is a top-3 tomato-producing state. Nashik, Pune, Satara, Ahmednagar and Solapur are major districts. Tomatoes are grown year-round under irrigated conditions; also a major processing crop for puree, paste and ketchup. Narayangaon (Pune) is an important tomato trading hub.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(72,36,'mr','टोमॅटो','ताज्या भाज्या','ताज्या भाज्या','Year-round','टोमॅटो हे GreenWings कॅटलॉगमधील महत्त्वाचे vegetable उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('टोमॅटो हे GreenWings कॅटलॉगमधील महत्त्वाचे vegetable उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Solanum lycopersicum\u000a\u000aश्रेणी: Vegetable\u000a\u000aहंगाम: Year-round\u000a\u000aमराठी नाव: Tomato\u000a\u000aहिंदी नाव: Tamatar\u000a\u000aइंग्रजी नाव: Tomato\u000a\u000aमूळ डेटासेट तपशील: Maharashtra is a top-3 tomato-producing state. Nashik, Pune, Satara, Ahmednagar and Solapur are major districts. Tomatoes are grown year-round under irrigated conditions; also a major processing crop for puree, paste and ketchup. Narayangaon (Pune) is an important tomato trading hub.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(73,37,'hi','मोसंबी','ताजे फल','ताजे फल','Year-round','मोसंबी GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('मोसंबी GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrus limetta\u000a\u000aश्रेणी: Citrus\u000a\u000aमौसम: Year-round\u000a\u000aमराठी नाम: Mosambi\u000a\u000aहिंदी नाम: Mosambi\u000a\u000aअंग्रेजी नाम: Sweet Lime / Mosambi\u000a\u000aमूल डेटासेट विवरण: Sweet Lime (Mosambi) is one of Maharashtra''s most commercially important citrus fruits, distinct from orange. Solapur, Osmanabad, Aurangabad, Pune and Nashik are major growing centres. Extremely popular for fresh juice; sold across India year-round. Maharashtra accounts for ~35% of India''s Mosambi production.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(74,37,'mr','मोसंबी','ताजी फळे','ताजी फळे','Year-round','मोसंबी हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('मोसंबी हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrus limetta\u000a\u000aश्रेणी: Citrus\u000a\u000aहंगाम: Year-round\u000a\u000aमराठी नाव: Mosambi\u000a\u000aहिंदी नाव: Mosambi\u000a\u000aइंग्रजी नाव: Sweet Lime / Mosambi\u000a\u000aमूळ डेटासेट तपशील: Sweet Lime (Mosambi) is one of Maharashtra''s most commercially important citrus fruits, distinct from orange. Solapur, Osmanabad, Aurangabad, Pune and Nashik are major growing centres. Extremely popular for fresh juice; sold across India year-round. Maharashtra accounts for ~35% of India''s Mosambi production.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(75,38,'hi','लहसुन','ताजी सब्जियां','ताजी सब्जियां','Rabi','लहसुन GreenWings कैटलॉग का एक महत्वपूर्ण vegetable उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('लहसुन GreenWings कैटलॉग का एक महत्वपूर्ण vegetable उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Allium sativum\u000a\u000aश्रेणी: Vegetable / Spice\u000a\u000aमौसम: Rabi\u000a\u000aमराठी नाम: Lasun\u000a\u000aहिंदी नाम: Lahsun\u000a\u000aअंग्रेजी नाम: Garlic\u000a\u000aमूल डेटासेट विवरण: Garlic is an important Rabi spice crop in Maharashtra — Nashik, Satara, Solapur, Pune, Aurangabad. Maharashtra is among top-5 garlic-producing states. Sown October–November; harvested February–March. Maharashtra garlic is known for its pungency and high allicin content. Major export crop and ingredient in Indian cuisine and Ayurvedic medicine.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(76,38,'mr','लसूण','ताज्या भाज्या','ताज्या भाज्या','Rabi','लसूण हे GreenWings कॅटलॉगमधील महत्त्वाचे vegetable उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('लसूण हे GreenWings कॅटलॉगमधील महत्त्वाचे vegetable उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Allium sativum\u000a\u000aश्रेणी: Vegetable / Spice\u000a\u000aहंगाम: Rabi\u000a\u000aमराठी नाव: Lasun\u000a\u000aहिंदी नाव: Lahsun\u000a\u000aइंग्रजी नाव: Garlic\u000a\u000aमूळ डेटासेट तपशील: Garlic is an important Rabi spice crop in Maharashtra — Nashik, Satara, Solapur, Pune, Aurangabad. Maharashtra is among top-5 garlic-producing states. Sown October–November; harvested February–March. Maharashtra garlic is known for its pungency and high allicin content. Major export crop and ingredient in Indian cuisine and Ayurvedic medicine.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(77,39,'hi','हल्दी','ताजी सब्जियां','ताजी सब्जियां','Kharif','हल्दी GreenWings कैटलॉग का एक महत्वपूर्ण vegetable उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('हल्दी GreenWings कैटलॉग का एक महत्वपूर्ण vegetable उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Curcuma longa\u000a\u000aश्रेणी: Spice / Medicinal\u000a\u000aमौसम: Kharif\u000a\u000aमराठी नाम: Halad\u000a\u000aहिंदी नाम: Haldi\u000a\u000aअंग्रेजी नाम: Turmeric\u000a\u000aमूल डेटासेट विवरण: Maharashtra is one of India''s top turmeric-producing states. Sangli, Kolhapur, Satara and Pune are major growing districts. Sangli''s Erande (Yelur) turmeric is GI-tagged and renowned for its high curcumin content (>4.5%). Harvested January–March after 8–9 months. Essential in Maharashtrian cooking, medicine (Ayurveda) and cosmetics. Major export to USA, Japan, EU.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(78,39,'mr','हळद','ताज्या भाज्या','ताज्या भाज्या','Kharif','हळद हे GreenWings कॅटलॉगमधील महत्त्वाचे vegetable उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('हळद हे GreenWings कॅटलॉगमधील महत्त्वाचे vegetable उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Curcuma longa\u000a\u000aश्रेणी: Spice / Medicinal\u000a\u000aहंगाम: Kharif\u000a\u000aमराठी नाव: Halad\u000a\u000aहिंदी नाव: Haldi\u000a\u000aइंग्रजी नाव: Turmeric\u000a\u000aमूळ डेटासेट तपशील: Maharashtra is one of India''s top turmeric-producing states. Sangli, Kolhapur, Satara and Pune are major growing districts. Sangli''s Erande (Yelur) turmeric is GI-tagged and renowned for its high curcumin content (>4.5%). Harvested January–March after 8–9 months. Essential in Maharashtrian cooking, medicine (Ayurveda) and cosmetics. Major export to USA, Japan, EU.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(79,40,'hi','मिर्च','ताजी सब्जियां','ताजी सब्जियां','Kharif','मिर्च GreenWings कैटलॉग का एक महत्वपूर्ण vegetable उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('मिर्च GreenWings कैटलॉग का एक महत्वपूर्ण vegetable उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Capsicum annuum\u000a\u000aश्रेणी: Spice / Vegetable\u000a\u000aमौसम: Kharif\u000a\u000aमराठी नाम: Mirchi\u000a\u000aहिंदी नाम: Mirch\u000a\u000aअंग्रेजी नाम: Chilli / Hot Pepper\u000a\u000aमूल डेटासेट विवरण: Maharashtra is a major chilli-producing state. Aurangabad, Nashik, Pune, Latur, Osmanabad and Amravati are key districts for dry chilli production. Kolhapur Red Chilli is GI-tagged and one of the hottest and most flavourful in India. Chilli grown for fresh, dry, and powder markets. Key ingredient in Kolhapuri cuisine and Maharashtra masalas.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(80,40,'mr','मिरची','ताज्या भाज्या','ताज्या भाज्या','Kharif','मिरची हे GreenWings कॅटलॉगमधील महत्त्वाचे vegetable उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('मिरची हे GreenWings कॅटलॉगमधील महत्त्वाचे vegetable उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Capsicum annuum\u000a\u000aश्रेणी: Spice / Vegetable\u000a\u000aहंगाम: Kharif\u000a\u000aमराठी नाव: Mirchi\u000a\u000aहिंदी नाव: Mirch\u000a\u000aइंग्रजी नाव: Chilli / Hot Pepper\u000a\u000aमूळ डेटासेट तपशील: Maharashtra is a major chilli-producing state. Aurangabad, Nashik, Pune, Latur, Osmanabad and Amravati are key districts for dry chilli production. Kolhapur Red Chilli is GI-tagged and one of the hottest and most flavourful in India. Chilli grown for fresh, dry, and powder markets. Key ingredient in Kolhapuri cuisine and Maharashtra masalas.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(81,41,'hi','अदरक','ताजी सब्जियां','ताजी सब्जियां','Kharif','अदरक GreenWings कैटलॉग का एक महत्वपूर्ण vegetable उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('अदरक GreenWings कैटलॉग का एक महत्वपूर्ण vegetable उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Zingiber officinale\u000a\u000aश्रेणी: Spice / Medicinal\u000a\u000aमौसम: Kharif\u000a\u000aमराठी नाम: Aale\u000a\u000aहिंदी नाम: Adrak\u000a\u000aअंग्रेजी नाम: Ginger\u000a\u000aमूल डेटासेट विवरण: Ginger is grown in the high-rainfall Western Ghats districts of Maharashtra — Satara, Kolhapur, Sindhudurg, Pune (Maval). A Kharif crop, sown April–May and harvested November–December. Fresh green ginger and dried soonth (dried ginger powder) both produced. Maharashtra contributes ~8% of India''s ginger output. High value for domestic cooking and pharma/ayurvedic industry.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(82,41,'mr','आले','ताज्या भाज्या','ताज्या भाज्या','Kharif','आले हे GreenWings कॅटलॉगमधील महत्त्वाचे vegetable उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('आले हे GreenWings कॅटलॉगमधील महत्त्वाचे vegetable उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Zingiber officinale\u000a\u000aश्रेणी: Spice / Medicinal\u000a\u000aहंगाम: Kharif\u000a\u000aमराठी नाव: Aale\u000a\u000aहिंदी नाव: Adrak\u000a\u000aइंग्रजी नाव: Ginger\u000a\u000aमूळ डेटासेट तपशील: Ginger is grown in the high-rainfall Western Ghats districts of Maharashtra — Satara, Kolhapur, Sindhudurg, Pune (Maval). A Kharif crop, sown April–May and harvested November–December. Fresh green ginger and dried soonth (dried ginger powder) both produced. Maharashtra contributes ~8% of India''s ginger output. High value for domestic cooking and pharma/ayurvedic industry.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(83,42,'hi','इमली','ताजे फल','ताजे फल','Rabi','इमली GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('इमली GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Tamarindus indica\u000a\u000aश्रेणी: Fruit / Spice\u000a\u000aमौसम: Rabi\u000a\u000aमराठी नाम: Chincha\u000a\u000aहिंदी नाम: Imli\u000a\u000aअंग्रेजी नाम: Tamarind\u000a\u000aमूल डेटासेट विवरण: Tamarind is a perennial tree crop widely found across Maharashtra, especially in Marathwada (Aurangabad, Osmanabad, Latur) and Vidarbha (Amravati, Nagpur). It is a rainfed, low-maintenance crop harvested January–April. Tamarind pulp, seed and shell all have commercial value. Key ingredient in Maharashtra''s chutneys, rasam-style dishes, and the famous Panha drink. Also used in pharmaceuticals, confectionery and food processing.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(84,42,'mr','चिंच','ताजी फळे','ताजी फळे','Rabi','चिंच हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('चिंच हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Tamarindus indica\u000a\u000aश्रेणी: Fruit / Spice\u000a\u000aहंगाम: Rabi\u000a\u000aमराठी नाव: Chincha\u000a\u000aहिंदी नाव: Imli\u000a\u000aइंग्रजी नाव: Tamarind\u000a\u000aमूळ डेटासेट तपशील: Tamarind is a perennial tree crop widely found across Maharashtra, especially in Marathwada (Aurangabad, Osmanabad, Latur) and Vidarbha (Amravati, Nagpur). It is a rainfed, low-maintenance crop harvested January–April. Tamarind pulp, seed and shell all have commercial value. Key ingredient in Maharashtra''s chutneys, rasam-style dishes, and the famous Panha drink. Also used in pharmaceuticals, confectionery and food processing.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(85,43,'hi','मेथी','ताजी सब्जियां','ताजी सब्जियां','Rabi','मेथी GreenWings कैटलॉग का एक महत्वपूर्ण vegetable उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('मेथी GreenWings कैटलॉग का एक महत्वपूर्ण vegetable उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Trigonella foenum-graecum\u000a\u000aश्रेणी: Spice / Vegetable / Medicinal\u000a\u000aमौसम: Rabi\u000a\u000aमराठी नाम: Methi\u000a\u000aहिंदी नाम: Methi\u000a\u000aअंग्रेजी नाम: Fenugreek / Methi\u000a\u000aमूल डेटासेट विवरण: Fenugreek (Methi) is grown across Maharashtra as a Rabi crop for its leaves (fresh vegetable) and seeds (spice). Nashik, Pune, Aurangabad and Solapur are major growing areas. The seeds are essential in Maharashtra''s goda masala, pickles and parathas. Rich in fenuside, fibre and iron. Also used medicinally for diabetes and lactation support.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(86,43,'mr','मेथी','ताज्या भाज्या','ताज्या भाज्या','Rabi','मेथी हे GreenWings कॅटलॉगमधील महत्त्वाचे vegetable उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('मेथी हे GreenWings कॅटलॉगमधील महत्त्वाचे vegetable उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Trigonella foenum-graecum\u000a\u000aश्रेणी: Spice / Vegetable / Medicinal\u000a\u000aहंगाम: Rabi\u000a\u000aमराठी नाव: Methi\u000a\u000aहिंदी नाव: Methi\u000a\u000aइंग्रजी नाव: Fenugreek / Methi\u000a\u000aमूळ डेटासेट तपशील: Fenugreek (Methi) is grown across Maharashtra as a Rabi crop for its leaves (fresh vegetable) and seeds (spice). Nashik, Pune, Aurangabad and Solapur are major growing areas. The seeds are essential in Maharashtra''s goda masala, pickles and parathas. Rich in fenuside, fibre and iron. Also used medicinally for diabetes and lactation support.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(87,44,'hi','धनिया','ताजी सब्जियां','ताजी सब्जियां','Rabi','धनिया GreenWings कैटलॉग का एक महत्वपूर्ण vegetable उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('धनिया GreenWings कैटलॉग का एक महत्वपूर्ण vegetable उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Coriandrum sativum\u000a\u000aश्रेणी: Spice / Herb\u000a\u000aमौसम: Rabi\u000a\u000aमराठी नाम: Kothimbir\u000a\u000aहिंदी नाम: Dhaniya\u000a\u000aअंग्रेजी नाम: Coriander / Dhania\u000a\u000aमूल डेटासेट विवरण: Coriander is one of Maharashtra''s most important spice crops, grown in Nashik, Pune, Satara, Aurangabad. Used both fresh (green coriander leaves) and dry (dhania seeds). Kothimbir Vadi (coriander fritters) is a signature Maharashtrian snack. Maharashtra is among India''s top-5 coriander-producing states. Season: October–January for leaves; February–March for seeds.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(88,44,'mr','कोथिंबीर','ताज्या भाज्या','ताज्या भाज्या','Rabi','कोथिंबीर हे GreenWings कॅटलॉगमधील महत्त्वाचे vegetable उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('कोथिंबीर हे GreenWings कॅटलॉगमधील महत्त्वाचे vegetable उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Coriandrum sativum\u000a\u000aश्रेणी: Spice / Herb\u000a\u000aहंगाम: Rabi\u000a\u000aमराठी नाव: Kothimbir\u000a\u000aहिंदी नाव: Dhaniya\u000a\u000aइंग्रजी नाव: Coriander / Dhania\u000a\u000aमूळ डेटासेट तपशील: Coriander is one of Maharashtra''s most important spice crops, grown in Nashik, Pune, Satara, Aurangabad. Used both fresh (green coriander leaves) and dry (dhania seeds). Kothimbir Vadi (coriander fritters) is a signature Maharashtrian snack. Maharashtra is among India''s top-5 coriander-producing states. Season: October–January for leaves; February–March for seeds.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(89,45,'hi','तरबूज','ताजे फल','ताजे फल','Zaid','तरबूज GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('तरबूज GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrullus lanatus\u000a\u000aश्रेणी: Cucurbit Fruit\u000a\u000aमौसम: Zaid\u000a\u000aमराठी नाम: Kalingad\u000a\u000aहिंदी नाम: Tarbooz\u000a\u000aअंग्रेजी नाम: Watermelon\u000a\u000aमूल डेटासेट विवरण: Watermelon is a major summer (Zaid) crop in Maharashtra — Nashik, Aurangabad, Solapur, Latur, Pune. Grown on sandy riverbed soils; sown February–March, harvested April–June. Maharashtra is a leading watermelon-producing state for domestic market. Large fruits preferred in Indian market; seedless hybrids gaining popularity.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(90,45,'mr','कलिंगड','ताजी फळे','ताजी फळे','Zaid','कलिंगड हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('कलिंगड हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrullus lanatus\u000a\u000aश्रेणी: Cucurbit Fruit\u000a\u000aहंगाम: Zaid\u000a\u000aमराठी नाव: Kalingad\u000a\u000aहिंदी नाव: Tarbooz\u000a\u000aइंग्रजी नाव: Watermelon\u000a\u000aमूळ डेटासेट तपशील: Watermelon is a major summer (Zaid) crop in Maharashtra — Nashik, Aurangabad, Solapur, Latur, Pune. Grown on sandy riverbed soils; sown February–March, harvested April–June. Maharashtra is a leading watermelon-producing state for domestic market. Large fruits preferred in Indian market; seedless hybrids gaining popularity.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(91,46,'hi','खरबूजा','ताजे फल','ताजे फल','Zaid','खरबूजा GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('खरबूजा GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Cucumis melo\u000a\u000aश्रेणी: Cucurbit Fruit\u000a\u000aमौसम: Zaid\u000a\u000aमराठी नाम: Kharbuja\u000a\u000aहिंदी नाम: Kharbuja\u000a\u000aअंग्रेजी नाम: Muskmelon / Cantaloupe\u000a\u000aमूल डेटासेट विवरण: Muskmelon (Kharbuj) is an important summer fruit crop in Maharashtra — Nashik, Pune, Solapur, Jalgaon. Grown on sandy loam soils; excellent in Godavari and Bhima river basin. Season March–June. High demand for fresh consumption and cooling drinks.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(92,46,'mr','खरबूज','ताजी फळे','ताजी फळे','Zaid','खरबूज हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('खरबूज हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Cucumis melo\u000a\u000aश्रेणी: Cucurbit Fruit\u000a\u000aहंगाम: Zaid\u000a\u000aमराठी नाव: Kharbuja\u000a\u000aहिंदी नाव: Kharbuja\u000a\u000aइंग्रजी नाव: Muskmelon / Cantaloupe\u000a\u000aमूळ डेटासेट तपशील: Muskmelon (Kharbuj) is an important summer fruit crop in Maharashtra — Nashik, Pune, Solapur, Jalgaon. Grown on sandy loam soils; excellent in Godavari and Bhima river basin. Season March–June. High demand for fresh consumption and cooling drinks.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(93,47,'hi','नींबू','ताजे फल','ताजे फल','Year-round','नींबू GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.',unistr('नींबू GreenWings कैटलॉग का एक महत्वपूर्ण फल उत्पाद है. इस रिकॉर्ड में किसान, खरीदार और भागीदारों के लिए किस्म, मौसम, श्रेणी और बाजार उपयोग की मुख्य जानकारी दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrus limon / Citrus aurantiifolia\u000a\u000aश्रेणी: Citrus\u000a\u000aमौसम: Year-round\u000a\u000aमराठी नाम: Limbu\u000a\u000aहिंदी नाम: Nimbu\u000a\u000aअंग्रेजी नाम: Lemon / Lime\u000a\u000aमूल डेटासेट विवरण: Lemon and acid lime are widely grown across Maharashtra — Nashik, Pune, Aurangabad, Vidarbha. A perennial crop with year-round fruiting under irrigation. Widely used in Maharashtrian cuisine (limbu sherbet, chutneys, achaar), street food, and increasing export to the Gulf. Drought-tolerant once established.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_translations VALUES(94,47,'mr','लिंबू','ताजी फळे','ताजी फळे','Year-round','लिंबू हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.',unistr('लिंबू हे GreenWings कॅटलॉगमधील महत्त्वाचे फळ उत्पादन आहे. या नोंदीमध्ये शेतकरी, खरेदीदार आणि भागीदारांसाठी वाण, हंगाम, श्रेणी आणि बाजारपेठेची मुख्य माहिती दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrus limon / Citrus aurantiifolia\u000a\u000aश्रेणी: Citrus\u000a\u000aहंगाम: Year-round\u000a\u000aमराठी नाव: Limbu\u000a\u000aहिंदी नाव: Nimbu\u000a\u000aइंग्रजी नाव: Lemon / Lime\u000a\u000aमूळ डेटासेट तपशील: Lemon and acid lime are widely grown across Maharashtra — Nashik, Pune, Aurangabad, Vidarbha. A perennial crop with year-round fruiting under irrigation. Widely used in Maharashtrian cuisine (limbu sherbet, chutneys, achaar), street food, and increasing export to the Gulf. Drought-tolerant once established.'),NULL,'2026-06-27 16:54:19','2026-06-27 18:10:33');
INSERT INTO crop_variety_translations VALUES(1,1,'hi','Alphonso (Hapus)','Maharashtra','Sweet, aromatic, rich saffron flavour, low fibre','Alphonso (Hapus) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Alphonso (Hapus) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Mangifera indica cv. Alphonso\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, aromatic, rich saffron flavour, low fibre\u000a\u000aमराठी नाम: Hapus\u000a\u000aमूल डेटासेट विवरण: GI-tagged variety from Ratnagiri & Sindhudurg; considered the king of mangoes; peak season April–May; ideal for pulp and fresh consumption.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(2,1,'mr','Hapus','Maharashtra','Sweet, aromatic, rich saffron flavour, low fibre','Hapus ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Hapus ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Mangifera indica cv. Alphonso\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, aromatic, rich saffron flavour, low fibre\u000a\u000aमराठी नाव: Hapus\u000a\u000aमूळ डेटासेट तपशील: GI-tagged variety from Ratnagiri & Sindhudurg; considered the king of mangoes; peak season April–May; ideal for pulp and fresh consumption.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(3,2,'hi','Kesar','Gujarat/Maharashtra','Sweet, less fibrous, deep orange pulp','Kesar इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Kesar इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Mangifera indica cv. Kesar\u000a\u000aउत्पत्ति क्षेत्र: Gujarat/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, less fibrous, deep orange pulp\u000a\u000aमराठी नाम: Kesar\u000a\u000aमूल डेटासेट विवरण: Grown in Aurangabad and Marathwada; second most exported variety; saffron-coloured pulp; season May–June.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(4,2,'mr','Kesar','Gujarat/Maharashtra','Sweet, less fibrous, deep orange pulp','Kesar ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Kesar ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Mangifera indica cv. Kesar\u000a\u000aउत्पत्ती क्षेत्र: Gujarat/Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, less fibrous, deep orange pulp\u000a\u000aमराठी नाव: Kesar\u000a\u000aमूळ डेटासेट तपशील: Grown in Aurangabad and Marathwada; second most exported variety; saffron-coloured pulp; season May–June.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(5,3,'hi','Langra','Uttar Pradesh/Maharashtra','Sweet-sour, green skin, rich flavour','Langra इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Langra इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Mangifera indica cv. Langra\u000a\u000aउत्पत्ति क्षेत्र: Uttar Pradesh/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet-sour, green skin, rich flavour\u000a\u000aमराठी नाम: Langra\u000a\u000aमूल डेटासेट विवरण: Grown in Nashik and Pune regions; medium-large fruit; greenish skin even when ripe.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(6,3,'mr','Langra','Uttar Pradesh/Maharashtra','Sweet-sour, green skin, rich flavour','Langra ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Langra ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Mangifera indica cv. Langra\u000a\u000aउत्पत्ती क्षेत्र: Uttar Pradesh/Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet-sour, green skin, rich flavour\u000a\u000aमराठी नाव: Langra\u000a\u000aमूळ डेटासेट तपशील: Grown in Nashik and Pune regions; medium-large fruit; greenish skin even when ripe.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(7,4,'hi','Dasheri','Uttar Pradesh/Maharashtra','Sweet, fibrous, aromatic','Dasheri इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Dasheri इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Mangifera indica cv. Dasheri\u000a\u000aउत्पत्ति क्षेत्र: Uttar Pradesh/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, fibrous, aromatic\u000a\u000aमराठी नाम: Dasheri\u000a\u000aमूल डेटासेट विवरण: Long fruit with thin skin; grown in Vidarbha; season June–July.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(8,4,'mr','Dasheri','Uttar Pradesh/Maharashtra','Sweet, fibrous, aromatic','Dasheri ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Dasheri ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Mangifera indica cv. Dasheri\u000a\u000aउत्पत्ती क्षेत्र: Uttar Pradesh/Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, fibrous, aromatic\u000a\u000aमराठी नाव: Dasheri\u000a\u000aमूळ डेटासेट तपशील: Long fruit with thin skin; grown in Vidarbha; season June–July.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(9,5,'hi','Totapuri','South India/Maharashtra','Mildly sweet, tangy, firm, low fibre','Totapuri इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Totapuri इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Mangifera indica cv. Totapuri\u000a\u000aउत्पत्ति क्षेत्र: South India/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Mildly sweet, tangy, firm, low fibre\u000a\u000aमराठी नाम: Totapuri\u000a\u000aमूल डेटासेट विवरण: Large, elongated beak-shaped fruit; widely processed into mango pulp and pickle; grown in Solapur and Osmanabad.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(10,5,'mr','Totapuri','South India/Maharashtra','Mildly sweet, tangy, firm, low fibre','Totapuri ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Totapuri ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Mangifera indica cv. Totapuri\u000a\u000aउत्पत्ती क्षेत्र: South India/Maharashtra\u000a\u000aचव वैशिष्ट्य: Mildly sweet, tangy, firm, low fibre\u000a\u000aमराठी नाव: Totapuri\u000a\u000aमूळ डेटासेट तपशील: Large, elongated beak-shaped fruit; widely processed into mango pulp and pickle; grown in Solapur and Osmanabad.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(11,6,'hi','Pairi','Maharashtra','Sweet, juicy, mild sour notes','Pairi इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Pairi इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Mangifera indica cv. Pairi\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, juicy, mild sour notes\u000a\u000aमराठी नाम: Pairi\u000a\u000aमूल डेटासेट विवरण: Early season variety from Konkan; oval fruit; eaten fresh; also called Pyari.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(12,6,'mr','Pairi','Maharashtra','Sweet, juicy, mild sour notes','Pairi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Pairi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Mangifera indica cv. Pairi\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, juicy, mild sour notes\u000a\u000aमराठी नाव: Pairi\u000a\u000aमूळ डेटासेट तपशील: Early season variety from Konkan; oval fruit; eaten fresh; also called Pyari.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(13,7,'hi','Ratna','Maharashtra','Very sweet, aromatic, less fibrous','Ratna इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Ratna इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Mangifera indica cv. Ratna\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very sweet, aromatic, less fibrous\u000a\u000aमराठी नाम: Ratna\u000a\u000aमूल डेटासेट विवरण: Hybrid developed at Dr BSKKV Dapoli; Alphonso × Neelum cross; regular bearer; popular in Konkan.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(14,7,'mr','Ratna','Maharashtra','Very sweet, aromatic, less fibrous','Ratna ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Ratna ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Mangifera indica cv. Ratna\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Very sweet, aromatic, less fibrous\u000a\u000aमराठी नाव: Ratna\u000a\u000aमूळ डेटासेट तपशील: Hybrid developed at Dr BSKKV Dapoli; Alphonso × Neelum cross; regular bearer; popular in Konkan.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(15,8,'hi','Sindhu','Maharashtra','Sweet, aromatic, low fibre, long shelf life','Sindhu इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Sindhu इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Mangifera indica cv. Sindhu\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, aromatic, low fibre, long shelf life\u000a\u000aमराठी नाम: Sindhu\u000a\u000aमूल डेटासेट विवरण: Hybrid (Ratna × Alphonso) developed at Vengurle; excellent export quality; shelf life 10–12 days.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(16,8,'mr','Sindhu','Maharashtra','Sweet, aromatic, low fibre, long shelf life','Sindhu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Sindhu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Mangifera indica cv. Sindhu\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, aromatic, low fibre, long shelf life\u000a\u000aमराठी नाव: Sindhu\u000a\u000aमूळ डेटासेट तपशील: Hybrid (Ratna × Alphonso) developed at Vengurle; excellent export quality; shelf life 10–12 days.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(17,9,'hi','Neelum','Tamil Nadu/Maharashtra','Sweet, mild, fibrous','Neelum इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Neelum इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Mangifera indica cv. Neelum\u000a\u000aउत्पत्ति क्षेत्र: Tamil Nadu/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, mild, fibrous\u000a\u000aमराठी नाम: Nilam\u000a\u000aमूल डेटासेट विवरण: Late season variety (June–August); grown in Marathwada and Vidarbha; small-medium fruit, yellow skin.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(18,9,'mr','Nilam','Tamil Nadu/Maharashtra','Sweet, mild, fibrous','Nilam ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Nilam ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Mangifera indica cv. Neelum\u000a\u000aउत्पत्ती क्षेत्र: Tamil Nadu/Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, mild, fibrous\u000a\u000aमराठी नाव: Nilam\u000a\u000aमूळ डेटासेट तपशील: Late season variety (June–August); grown in Marathwada and Vidarbha; small-medium fruit, yellow skin.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(19,10,'hi','Amrapali','Maharashtra','Very sweet, deep red-orange flesh','Amrapali इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Amrapali इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Mangifera indica cv. Amrapali\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very sweet, deep red-orange flesh\u000a\u000aमराठी नाम: Amrapali\u000a\u000aमूल डेटासेट विवरण: Dwarf hybrid; suitable for high-density planting; grown in Nashik and Jalgaon.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(20,10,'mr','Amrapali','Maharashtra','Very sweet, deep red-orange flesh','Amrapali ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Amrapali ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Mangifera indica cv. Amrapali\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Very sweet, deep red-orange flesh\u000a\u000aमराठी नाव: Amrapali\u000a\u000aमूळ डेटासेट तपशील: Dwarf hybrid; suitable for high-density planting; grown in Nashik and Jalgaon.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(21,11,'hi','Mallika','Maharashtra','Sweet, juicy, long shelf life','Mallika इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Mallika इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Mangifera indica cv. Mallika\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, juicy, long shelf life\u000a\u000aमराठी नाम: Mallika\u000a\u000aमूल डेटासेट विवरण: Neelum × Dasheri hybrid; regular bearer; wide adaptability; popular in export markets.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(22,11,'mr','Mallika','Maharashtra','Sweet, juicy, long shelf life','Mallika ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Mallika ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Mangifera indica cv. Mallika\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, juicy, long shelf life\u000a\u000aमराठी नाव: Mallika\u000a\u000aमूळ डेटासेट तपशील: Neelum × Dasheri hybrid; regular bearer; wide adaptability; popular in export markets.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(23,12,'hi','Vanraj','Gujarat/Maharashtra','Sweet, mild, fibrous','Vanraj इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Vanraj इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Mangifera indica cv. Vanraj\u000a\u000aउत्पत्ति क्षेत्र: Gujarat/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, mild, fibrous\u000a\u000aमराठी नाम: Vanraj\u000a\u000aमूल डेटासेट विवरण: Developed at NAU Gujarat; grown in Nashik, Dhule; tolerant to adverse conditions.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(24,12,'mr','Vanraj','Gujarat/Maharashtra','Sweet, mild, fibrous','Vanraj ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Vanraj ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Mangifera indica cv. Vanraj\u000a\u000aउत्पत्ती क्षेत्र: Gujarat/Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, mild, fibrous\u000a\u000aमराठी नाव: Vanraj\u000a\u000aमूळ डेटासेट तपशील: Developed at NAU Gujarat; grown in Nashik, Dhule; tolerant to adverse conditions.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(25,13,'hi','Thompson Seedless','Maharashtra','Sweet, mild, crisp, seedless','Thompson Seedless इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Thompson Seedless इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Vitis vinifera cv. Thompson Seedless\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, mild, crisp, seedless\u000a\u000aमराठी नाम: Thompson Seedless\u000a\u000aमूल डेटासेट विवरण: Most widely grown table and raisin grape in Nashik, Sangli, Pune; green-gold colour; dominant export variety; also base for wine.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(26,13,'mr','Thompson Seedless','Maharashtra','Sweet, mild, crisp, seedless','Thompson Seedless ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Thompson Seedless ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Vitis vinifera cv. Thompson Seedless\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, mild, crisp, seedless\u000a\u000aमराठी नाव: Thompson Seedless\u000a\u000aमूळ डेटासेट तपशील: Most widely grown table and raisin grape in Nashik, Sangli, Pune; green-gold colour; dominant export variety; also base for wine.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(27,14,'hi','Tas-A-Ganesh','Maharashtra','Sweet, firm, large berries, seedless','Tas-A-Ganesh इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Tas-A-Ganesh इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Vitis vinifera cv. Tas-A-Ganesh\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, firm, large berries, seedless\u000a\u000aमराठी नाम: Tas-A-Ganesh\u000a\u000aमूल डेटासेट विवरण: Early maturing mutation of Thompson; large elongated berries; popular in domestic and export market; Nashik and Sangli.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(28,14,'mr','Tas-A-Ganesh','Maharashtra','Sweet, firm, large berries, seedless','Tas-A-Ganesh ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Tas-A-Ganesh ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Vitis vinifera cv. Tas-A-Ganesh\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, firm, large berries, seedless\u000a\u000aमराठी नाव: Tas-A-Ganesh\u000a\u000aमूळ डेटासेट तपशील: Early maturing mutation of Thompson; large elongated berries; popular in domestic and export market; Nashik and Sangli.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(29,15,'hi','Sonaka','Maharashtra','Sweet, firm, elongated, seedless','Sonaka इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Sonaka इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Vitis vinifera cv. Sonaka\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, firm, elongated, seedless\u000a\u000aमराठी नाम: Sonaka\u000a\u000aमूल डेटासेट विवरण: Developed in Maharashtra; excellent export quality; long shelf life; grown in Nashik, Pune; superior post-harvest quality.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(30,15,'mr','Sonaka','Maharashtra','Sweet, firm, elongated, seedless','Sonaka ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Sonaka ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Vitis vinifera cv. Sonaka\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, firm, elongated, seedless\u000a\u000aमराठी नाव: Sonaka\u000a\u000aमूळ डेटासेट तपशील: Developed in Maharashtra; excellent export quality; long shelf life; grown in Nashik, Pune; superior post-harvest quality.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(31,16,'hi','Sharad Seedless','Maharashtra','Sweet, crisp, medium size, seedless','Sharad Seedless इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Sharad Seedless इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Vitis vinifera cv. Sharad Seedless\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, crisp, medium size, seedless\u000a\u000aमराठी नाम: Sharad Seedless\u000a\u000aमूल डेटासेट विवरण: Late-maturing variety; Nashik; green-white berries; popular raisin grape.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(32,16,'mr','Sharad Seedless','Maharashtra','Sweet, crisp, medium size, seedless','Sharad Seedless ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Sharad Seedless ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Vitis vinifera cv. Sharad Seedless\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, crisp, medium size, seedless\u000a\u000aमराठी नाव: Sharad Seedless\u000a\u000aमूळ डेटासेट तपशील: Late-maturing variety; Nashik; green-white berries; popular raisin grape.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(33,17,'hi','Flame Seedless','USA/Maharashtra','Sweet, slightly tart, red, seedless','Flame Seedless इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Flame Seedless इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Vitis vinifera cv. Flame Seedless\u000a\u000aउत्पत्ति क्षेत्र: USA/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, slightly tart, red, seedless\u000a\u000aमराठी नाम: Flame Seedless\u000a\u000aमूल डेटासेट विवरण: Red-berry seedless variety; grown in Nashik; attractive colour; export variety.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(34,17,'mr','Flame Seedless','USA/Maharashtra','Sweet, slightly tart, red, seedless','Flame Seedless ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Flame Seedless ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Vitis vinifera cv. Flame Seedless\u000a\u000aउत्पत्ती क्षेत्र: USA/Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, slightly tart, red, seedless\u000a\u000aमराठी नाव: Flame Seedless\u000a\u000aमूळ डेटासेट तपशील: Red-berry seedless variety; grown in Nashik; attractive colour; export variety.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(35,18,'hi','Crimson Seedless','USA/Maharashtra','Sweet, firm, dark red, seedless','Crimson Seedless इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Crimson Seedless इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Vitis vinifera cv. Crimson Seedless\u000a\u000aउत्पत्ति क्षेत्र: USA/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, firm, dark red, seedless\u000a\u000aमराठी नाम: Crimson Seedless\u000a\u000aमूल डेटासेट विवरण: Large red berries; late season; high sugar content; export quality; Nashik.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(36,18,'mr','Crimson Seedless','USA/Maharashtra','Sweet, firm, dark red, seedless','Crimson Seedless ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Crimson Seedless ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Vitis vinifera cv. Crimson Seedless\u000a\u000aउत्पत्ती क्षेत्र: USA/Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, firm, dark red, seedless\u000a\u000aमराठी नाव: Crimson Seedless\u000a\u000aमूळ डेटासेट तपशील: Large red berries; late season; high sugar content; export quality; Nashik.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(37,19,'hi','Manik Chaman','Maharashtra','Sweet, large berries, red-black, seeded','Manik Chaman इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Manik Chaman इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Vitis vinifera cv. Manik Chaman\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, large berries, red-black, seeded\u000a\u000aमराठी नाम: Manik Chaman\u000a\u000aमूल डेटासेट विवरण: Also called Beauty Seedless; grown in Nashik, Sangli; large berries; domestic market.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(38,19,'mr','Manik Chaman','Maharashtra','Sweet, large berries, red-black, seeded','Manik Chaman ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Manik Chaman ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Vitis vinifera cv. Manik Chaman\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, large berries, red-black, seeded\u000a\u000aमराठी नाव: Manik Chaman\u000a\u000aमूळ डेटासेट तपशील: Also called Beauty Seedless; grown in Nashik, Sangli; large berries; domestic market.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(39,20,'hi','Nagpur Orange','Maharashtra','Sweet-tangy, juicy, aromatic, thin skin','Nagpur Orange इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Nagpur Orange इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrus reticulata cv. Nagpur Mandarin\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet-tangy, juicy, aromatic, thin skin\u000a\u000aमराठी नाम: Nagpur Santra\u000a\u000aमूल डेटासेट विवरण: GI-tagged; grown in Nagpur, Amravati, Wardha; season Nov–Jan; star export variety; deep orange colour.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(40,20,'mr','Nagpur Santra','Maharashtra','Sweet-tangy, juicy, aromatic, thin skin','Nagpur Santra ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Nagpur Santra ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrus reticulata cv. Nagpur Mandarin\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet-tangy, juicy, aromatic, thin skin\u000a\u000aमराठी नाव: Nagpur Santra\u000a\u000aमूळ डेटासेट तपशील: GI-tagged; grown in Nagpur, Amravati, Wardha; season Nov–Jan; star export variety; deep orange colour.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(41,21,'hi','Valencia Orange','Maharashtra','Sweet, juicy, low seeds','Valencia Orange इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Valencia Orange इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrus sinensis cv. Valencia\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, juicy, low seeds\u000a\u000aमराठी नाम: Valencia Santra\u000a\u000aमूल डेटासेट विवरण: Sweet orange type; grown in Marathwada; used for juice.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(42,21,'mr','Valencia Santra','Maharashtra','Sweet, juicy, low seeds','Valencia Santra ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Valencia Santra ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrus sinensis cv. Valencia\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, juicy, low seeds\u000a\u000aमराठी नाव: Valencia Santra\u000a\u000aमूळ डेटासेट तपशील: Sweet orange type; grown in Marathwada; used for juice.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(43,22,'hi','Mosambi (Sweet Lime)','Maharashtra','Mildly sweet, low acid','Mosambi (Sweet Lime) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Mosambi (Sweet Lime) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrus limetta\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Mildly sweet, low acid\u000a\u000aमराठी नाम: Mosambi\u000a\u000aमूल डेटासेट विवरण: Sweet lime; highly popular for juice; grown in Pune, Solapur, Aurangabad; year-round availability.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(44,22,'mr','Mosambi','Maharashtra','Mildly sweet, low acid','Mosambi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Mosambi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrus limetta\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Mildly sweet, low acid\u000a\u000aमराठी नाव: Mosambi\u000a\u000aमूळ डेटासेट तपशील: Sweet lime; highly popular for juice; grown in Pune, Solapur, Aurangabad; year-round availability.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(45,23,'hi','Hamlin Orange','Maharashtra','Sweet, juicy, early season','Hamlin Orange इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Hamlin Orange इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrus sinensis cv. Hamlin\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, juicy, early season\u000a\u000aमराठी नाम: Hamlin Santra\u000a\u000aमूल डेटासेट विवरण: Early-bearing sweet orange; Marathwada and Vidarbha.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(46,23,'mr','Hamlin Santra','Maharashtra','Sweet, juicy, early season','Hamlin Santra ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Hamlin Santra ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrus sinensis cv. Hamlin\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, juicy, early season\u000a\u000aमराठी नाव: Hamlin Santra\u000a\u000aमूळ डेटासेट तपशील: Early-bearing sweet orange; Marathwada and Vidarbha.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(47,24,'hi','Grand Naine','Maharashtra','Sweet, firm, long shelf life','Grand Naine इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Grand Naine इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Musa acuminata cv. Grand Naine\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, firm, long shelf life\u000a\u000aमराठी नाम: Grand Naine\u000a\u000aमूल डेटासेट विवरण: Most commercially grown; Jalgaon, Nandurbar; GI-tagged Jalgaon banana; export quality; tall plant, medium bunch.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(48,24,'mr','Grand Naine','Maharashtra','Sweet, firm, long shelf life','Grand Naine ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Grand Naine ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Musa acuminata cv. Grand Naine\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, firm, long shelf life\u000a\u000aमराठी नाव: Grand Naine\u000a\u000aमूळ डेटासेट तपशील: Most commercially grown; Jalgaon, Nandurbar; GI-tagged Jalgaon banana; export quality; tall plant, medium bunch.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(49,25,'hi','Dwarf Cavendish','Maharashtra','Sweet, creamy, slightly tangy','Dwarf Cavendish इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Dwarf Cavendish इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Musa acuminata cv. Dwarf Cavendish\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, creamy, slightly tangy\u000a\u000aमराठी नाम: Dwarf Kela\u000a\u000aमूल डेटासेट विवरण: Short statured; wind resistant; Jalgaon, Pune; widely used commercially and domestically.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(50,25,'mr','Dwarf Kela','Maharashtra','Sweet, creamy, slightly tangy','Dwarf Kela ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Dwarf Kela ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Musa acuminata cv. Dwarf Cavendish\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, creamy, slightly tangy\u000a\u000aमराठी नाव: Dwarf Kela\u000a\u000aमूळ डेटासेट तपशील: Short statured; wind resistant; Jalgaon, Pune; widely used commercially and domestically.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(51,26,'hi','Robusta','Maharashtra','Sweet, aromatic, medium-large fruit','Robusta इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Robusta इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Musa acuminata cv. Robusta\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, aromatic, medium-large fruit\u000a\u000aमराठी नाम: Robusta Kela\u000a\u000aमूल डेटासेट विवरण: Taller than Dwarf Cavendish; widely grown in Maharashtra; good disease resistance.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(52,26,'mr','Robusta Kela','Maharashtra','Sweet, aromatic, medium-large fruit','Robusta Kela ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Robusta Kela ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Musa acuminata cv. Robusta\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, aromatic, medium-large fruit\u000a\u000aमराठी नाव: Robusta Kela\u000a\u000aमूळ डेटासेट तपशील: Taller than Dwarf Cavendish; widely grown in Maharashtra; good disease resistance.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(53,27,'hi','Shrimanthi','Maharashtra','Very sweet, soft, small fruit','Shrimanthi इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Shrimanthi इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Musa acuminata cv. Shrimanthi\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very sweet, soft, small fruit\u000a\u000aमराठी नाम: Shrimanthi\u000a\u000aमूल डेटासेट विवरण: Local traditional variety from Konkan and Kolhapur; festival use; aromatic.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(54,27,'mr','Shrimanthi','Maharashtra','Very sweet, soft, small fruit','Shrimanthi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Shrimanthi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Musa acuminata cv. Shrimanthi\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Very sweet, soft, small fruit\u000a\u000aमराठी नाव: Shrimanthi\u000a\u000aमूळ डेटासेट तपशील: Local traditional variety from Konkan and Kolhapur; festival use; aromatic.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(55,28,'hi','Basrai','Maharashtra','Sweet, aromatic, plump','Basrai इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Basrai इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Musa acuminata cv. Basrai\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, aromatic, plump\u000a\u000aमराठी नाम: Basrai Kela\u000a\u000aमूल डेटासेट विवरण: Traditional Jalgaon variety; basis of Jalgaon''s banana fame; good yield and flavour.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(56,28,'mr','Basrai Kela','Maharashtra','Sweet, aromatic, plump','Basrai Kela ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Basrai Kela ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Musa acuminata cv. Basrai\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, aromatic, plump\u000a\u000aमराठी नाव: Basrai Kela\u000a\u000aमूळ डेटासेट तपशील: Traditional Jalgaon variety; basis of Jalgaon''s banana fame; good yield and flavour.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(57,29,'hi','Allahabad Safeda','Uttar Pradesh/Maharashtra','Sweet, white pulp, mild flavour','Allahabad Safeda इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Allahabad Safeda इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Psidium guajava cv. Allahabad Safeda\u000a\u000aउत्पत्ति क्षेत्र: Uttar Pradesh/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, white pulp, mild flavour\u000a\u000aमराठी नाम: Safeda Peru\u000a\u000aमूल डेटासेट विवरण: Most popular commercial variety; grown across Maharashtra; white flesh; high yield; good shelf life.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(58,29,'mr','Safeda Peru','Uttar Pradesh/Maharashtra','Sweet, white pulp, mild flavour','Safeda Peru ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Safeda Peru ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Psidium guajava cv. Allahabad Safeda\u000a\u000aउत्पत्ती क्षेत्र: Uttar Pradesh/Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, white pulp, mild flavour\u000a\u000aमराठी नाव: Safeda Peru\u000a\u000aमूळ डेटासेट तपशील: Most popular commercial variety; grown across Maharashtra; white flesh; high yield; good shelf life.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(59,30,'hi','Lalit','Maharashtra','Sweet, pink pulp, aromatic','Lalit इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Lalit इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Psidium guajava cv. Lalit\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, pink pulp, aromatic\u000a\u000aमराठी नाम: Lalit Peru\u000a\u000aमूल डेटासेट विवरण: Developed at IARI; pink-fleshed; high Vitamin C; grown in Nashik, Pune.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(60,30,'mr','Lalit Peru','Maharashtra','Sweet, pink pulp, aromatic','Lalit Peru ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Lalit Peru ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Psidium guajava cv. Lalit\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, pink pulp, aromatic\u000a\u000aमराठी नाव: Lalit Peru\u000a\u000aमूळ डेटासेट तपशील: Developed at IARI; pink-fleshed; high Vitamin C; grown in Nashik, Pune.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(61,31,'hi','Shweta','Maharashtra','Sweet, soft, white pulp','Shweta इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Shweta इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Psidium guajava cv. Shweta\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, soft, white pulp\u000a\u000aमराठी नाम: Shweta Peru\u000a\u000aमूल डेटासेट विवरण: High-yielding variety; good post-harvest quality; Nashik.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(62,31,'mr','Shweta Peru','Maharashtra','Sweet, soft, white pulp','Shweta Peru ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Shweta Peru ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Psidium guajava cv. Shweta\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, soft, white pulp\u000a\u000aमराठी नाव: Shweta Peru\u000a\u000aमूळ डेटासेट तपशील: High-yielding variety; good post-harvest quality; Nashik.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(63,32,'hi','Lucknow-49 (Sardar)','Uttar Pradesh/Maharashtra','Sweet, juicy, white-yellow pulp','Lucknow-49 (Sardar) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Lucknow-49 (Sardar) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Psidium guajava cv. L-49\u000a\u000aउत्पत्ति क्षेत्र: Uttar Pradesh/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, juicy, white-yellow pulp\u000a\u000aमराठी नाम: Lucknow Peru\u000a\u000aमूल डेटासेट विवरण: Very popular; round fruit; widely adapted; grown across Maharashtra.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(64,32,'mr','Lucknow Peru','Uttar Pradesh/Maharashtra','Sweet, juicy, white-yellow pulp','Lucknow Peru ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Lucknow Peru ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Psidium guajava cv. L-49\u000a\u000aउत्पत्ती क्षेत्र: Uttar Pradesh/Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, juicy, white-yellow pulp\u000a\u000aमराठी नाव: Lucknow Peru\u000a\u000aमूळ डेटासेट तपशील: Very popular; round fruit; widely adapted; grown across Maharashtra.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(65,33,'hi','Bhagwa','Maharashtra','Sweet, deep red arils, low seed hardness, juicy','Bhagwa इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Bhagwa इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Punica granatum cv. Bhagwa\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, deep red arils, low seed hardness, juicy\u000a\u000aमराठी नाम: Bhagwa Dalimb\u000a\u000aमूल डेटासेट विवरण: GI-tagged; grown in Solapur, Sangli, Nashik, Pune; saffron-red thick skin; 65–70% aril weight; top export variety to Middle East, Europe.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(66,33,'mr','Bhagwa Dalimb','Maharashtra','Sweet, deep red arils, low seed hardness, juicy','Bhagwa Dalimb ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Bhagwa Dalimb ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Punica granatum cv. Bhagwa\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, deep red arils, low seed hardness, juicy\u000a\u000aमराठी नाव: Bhagwa Dalimb\u000a\u000aमूळ डेटासेट तपशील: GI-tagged; grown in Solapur, Sangli, Nashik, Pune; saffron-red thick skin; 65–70% aril weight; top export variety to Middle East, Europe.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(67,34,'hi','Ganesh','Maharashtra','Sweet, mild, pink arils','Ganesh इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Ganesh इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Punica granatum cv. Ganesh\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, mild, pink arils\u000a\u000aमराठी नाम: Ganesh Dalimb\u000a\u000aमूल डेटासेट विवरण: Traditional variety; Pune and Nashik; large soft-seeded fruit; good for fresh market.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(68,34,'mr','Ganesh Dalimb','Maharashtra','Sweet, mild, pink arils','Ganesh Dalimb ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Ganesh Dalimb ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Punica granatum cv. Ganesh\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, mild, pink arils\u000a\u000aमराठी नाव: Ganesh Dalimb\u000a\u000aमूळ डेटासेट तपशील: Traditional variety; Pune and Nashik; large soft-seeded fruit; good for fresh market.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(69,35,'hi','Mridula','Karnataka/Maharashtra','Very sweet, deep red, soft seeds','Mridula इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Mridula इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Punica granatum cv. Mridula\u000a\u000aउत्पत्ति क्षेत्र: Karnataka/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very sweet, deep red, soft seeds\u000a\u000aमराठी नाम: Mridula Dalimb\u000a\u000aमूल डेटासेट विवरण: Deep red attractive arils; grown in Solapur and Osmanabad; early-bearing.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(70,35,'mr','Mridula Dalimb','Karnataka/Maharashtra','Very sweet, deep red, soft seeds','Mridula Dalimb ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Mridula Dalimb ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Punica granatum cv. Mridula\u000a\u000aउत्पत्ती क्षेत्र: Karnataka/Maharashtra\u000a\u000aचव वैशिष्ट्य: Very sweet, deep red, soft seeds\u000a\u000aमराठी नाव: Mridula Dalimb\u000a\u000aमूळ डेटासेट तपशील: Deep red attractive arils; grown in Solapur and Osmanabad; early-bearing.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(71,36,'hi','Arakta','Karnataka/Maharashtra','Sweet, deep red, attractive appearance','Arakta इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Arakta इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Punica granatum cv. Arakta\u000a\u000aउत्पत्ति क्षेत्र: Karnataka/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, deep red, attractive appearance\u000a\u000aमराठी नाम: Arakta Dalimb\u000a\u000aमूल डेटासेट विवरण: Large fruit; bright red skin; grown in Marathwada and Nashik; good export potential.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(72,36,'mr','Arakta Dalimb','Karnataka/Maharashtra','Sweet, deep red, attractive appearance','Arakta Dalimb ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Arakta Dalimb ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Punica granatum cv. Arakta\u000a\u000aउत्पत्ती क्षेत्र: Karnataka/Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, deep red, attractive appearance\u000a\u000aमराठी नाव: Arakta Dalimb\u000a\u000aमूळ डेटासेट तपशील: Large fruit; bright red skin; grown in Marathwada and Nashik; good export potential.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(73,37,'hi','Balanagar','Telangana/Maharashtra','Sweet, creamy, white flesh, low seeds','Balanagar इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Balanagar इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Annona squamosa cv. Balanagar\u000a\u000aउत्पत्ति क्षेत्र: Telangana/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, creamy, white flesh, low seeds\u000a\u000aमराठी नाम: Balanagar Sitafal\u000a\u000aमूल डेटासेट विवरण: Most popular commercial variety in Maharashtra; Nashik, Aurangabad; large fruit; high pulp recovery.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(74,37,'mr','Balanagar Sitafal','Telangana/Maharashtra','Sweet, creamy, white flesh, low seeds','Balanagar Sitafal ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Balanagar Sitafal ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Annona squamosa cv. Balanagar\u000a\u000aउत्पत्ती क्षेत्र: Telangana/Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, creamy, white flesh, low seeds\u000a\u000aमराठी नाव: Balanagar Sitafal\u000a\u000aमूळ डेटासेट तपशील: Most popular commercial variety in Maharashtra; Nashik, Aurangabad; large fruit; high pulp recovery.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(75,38,'hi','Red Sitafal','Maharashtra','Very sweet, soft, aromatic, reddish skin','Red Sitafal इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Red Sitafal इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Annona reticulata\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very sweet, soft, aromatic, reddish skin\u000a\u000aमराठी नाम: Lal Sitafal\u000a\u000aमूल डेटासेट विवरण: Bullock''s heart variety; red skin; higher sweetness; Nashik and Marathwada.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(76,38,'mr','Lal Sitafal','Maharashtra','Very sweet, soft, aromatic, reddish skin','Lal Sitafal ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Lal Sitafal ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Annona reticulata\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Very sweet, soft, aromatic, reddish skin\u000a\u000aमराठी नाव: Lal Sitafal\u000a\u000aमूळ डेटासेट तपशील: Bullock''s heart variety; red skin; higher sweetness; Nashik and Marathwada.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(77,39,'hi','Red Lady','Taiwan/Maharashtra','Very sweet, red-orange flesh, firm','Red Lady इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Red Lady इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Carica papaya cv. Red Lady\u000a\u000aउत्पत्ति क्षेत्र: Taiwan/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very sweet, red-orange flesh, firm\u000a\u000aमराठी नाम: Red Lady Papai\u000a\u000aमूल डेटासेट विवरण: F1 hybrid; most popular commercial variety; Pune, Nashik; gynoecious; high yield; disease resistant.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(78,39,'mr','Red Lady Papai','Taiwan/Maharashtra','Very sweet, red-orange flesh, firm','Red Lady Papai ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Red Lady Papai ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Carica papaya cv. Red Lady\u000a\u000aउत्पत्ती क्षेत्र: Taiwan/Maharashtra\u000a\u000aचव वैशिष्ट्य: Very sweet, red-orange flesh, firm\u000a\u000aमराठी नाव: Red Lady Papai\u000a\u000aमूळ डेटासेट तपशील: F1 hybrid; most popular commercial variety; Pune, Nashik; gynoecious; high yield; disease resistant.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(79,40,'hi','Taiwan','Taiwan/Maharashtra','Sweet, orange flesh, medium size','Taiwan इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Taiwan इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Carica papaya cv. Taiwan 786\u000a\u000aउत्पत्ति क्षेत्र: Taiwan/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, orange flesh, medium size\u000a\u000aमराठी नाम: Taiwan Papai\u000a\u000aमूल डेटासेट विवरण: Widely grown hybrid; dual purpose (fruit + raw); Jalgaon and Nashik; year-round production.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(80,40,'mr','Taiwan Papai','Taiwan/Maharashtra','Sweet, orange flesh, medium size','Taiwan Papai ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Taiwan Papai ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Carica papaya cv. Taiwan 786\u000a\u000aउत्पत्ती क्षेत्र: Taiwan/Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, orange flesh, medium size\u000a\u000aमराठी नाव: Taiwan Papai\u000a\u000aमूळ डेटासेट तपशील: Widely grown hybrid; dual purpose (fruit + raw); Jalgaon and Nashik; year-round production.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(81,41,'hi','Kalipatti','Maharashtra','Very sweet, granular, brown flesh','Kalipatti इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Kalipatti इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Manilkara zapota cv. Kalipatti\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very sweet, granular, brown flesh\u000a\u000aमराठी नाम: Kalipatti Chiku\u000a\u000aमूल डेटासेट विवरण: Most popular commercial variety; Palghar, Nashik; oval shape; high yield; good shelf life.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(82,41,'mr','Kalipatti Chiku','Maharashtra','Very sweet, granular, brown flesh','Kalipatti Chiku ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Kalipatti Chiku ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Manilkara zapota cv. Kalipatti\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Very sweet, granular, brown flesh\u000a\u000aमराठी नाव: Kalipatti Chiku\u000a\u000aमूळ डेटासेट तपशील: Most popular commercial variety; Palghar, Nashik; oval shape; high yield; good shelf life.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(83,42,'hi','Cricket Ball','Maharashtra','Sweet, large, round, high sugar','Cricket Ball इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Cricket Ball इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Manilkara zapota cv. Cricket Ball\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, large, round, high sugar\u000a\u000aमराठी नाम: Cricket Ball Chiku\u000a\u000aमूल डेटासेट विवरण: Round large fruit; high market value; Pune and Nashik.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(84,42,'mr','Cricket Ball Chiku','Maharashtra','Sweet, large, round, high sugar','Cricket Ball Chiku ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Cricket Ball Chiku ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Manilkara zapota cv. Cricket Ball\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, large, round, high sugar\u000a\u000aमराठी नाव: Cricket Ball Chiku\u000a\u000aमूळ डेटासेट तपशील: Round large fruit; high market value; Pune and Nashik.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(85,43,'hi','West Coast Tall','Maharashtra','Rich coconut water, thick white copra','West Coast Tall इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('West Coast Tall इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Cocos nucifera cv. West Coast Tall\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Rich coconut water, thick white copra\u000a\u000aमराठी नाम: Konkan Naral\u000a\u000aमूल डेटासेट विवरण: Tall variety; most widely grown in Konkan; high copra yield; drought tolerant once established.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(86,43,'mr','Konkan Naral','Maharashtra','Rich coconut water, thick white copra','Konkan Naral ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Konkan Naral ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Cocos nucifera cv. West Coast Tall\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Rich coconut water, thick white copra\u000a\u000aमराठी नाव: Konkan Naral\u000a\u000aमूळ डेटासेट तपशील: Tall variety; most widely grown in Konkan; high copra yield; drought tolerant once established.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(87,44,'hi','Dwarf','Maharashtra','Sweet tender water, thin husk','Dwarf इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Dwarf इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Cocos nucifera var. nana\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet tender water, thin husk\u000a\u000aमराठी नाम: Bodka Naral\u000a\u000aमूल डेटासेट विवरण: Early bearing; tender coconut market; Ratnagiri and Sindhudurg; shorter lifespan than tall.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(88,44,'mr','Bodka Naral','Maharashtra','Sweet tender water, thin husk','Bodka Naral ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Bodka Naral ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Cocos nucifera var. nana\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet tender water, thin husk\u000a\u000aमराठी नाव: Bodka Naral\u000a\u000aमूळ डेटासेट तपशील: Early bearing; tender coconut market; Ratnagiri and Sindhudurg; shorter lifespan than tall.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(89,45,'hi','Local Konkan','Maharashtra','Sweet, aromatic, orange-yellow flesh','Local Konkan इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Local Konkan इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Artocarpus heterophyllus (local)\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, aromatic, orange-yellow flesh\u000a\u000aमराठी नाम: Konkan Phanas\u000a\u000aमूल डेटासेट विवरण: Traditional variety from Konkan; high-quality sweet bulbs; used raw as vegetable and ripe as fruit.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(90,45,'mr','Konkan Phanas','Maharashtra','Sweet, aromatic, orange-yellow flesh','Konkan Phanas ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Konkan Phanas ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Artocarpus heterophyllus (local)\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, aromatic, orange-yellow flesh\u000a\u000aमराठी नाव: Konkan Phanas\u000a\u000aमूळ डेटासेट तपशील: Traditional variety from Konkan; high-quality sweet bulbs; used raw as vegetable and ripe as fruit.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(91,46,'hi','Singapore','Malaysia/Maharashtra','Sweet, firm, less sticky','Singapore इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Singapore इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Artocarpus heterophyllus cv. Singapore\u000a\u000aउत्पत्ति क्षेत्र: Malaysia/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, firm, less sticky\u000a\u000aमराठी नाम: Singapore Phanas\u000a\u000aमूल डेटासेट विवरण: Less latex; firmer bulbs; good for processing; grown in Konkan.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(92,46,'mr','Singapore Phanas','Malaysia/Maharashtra','Sweet, firm, less sticky','Singapore Phanas ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Singapore Phanas ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Artocarpus heterophyllus cv. Singapore\u000a\u000aउत्पत्ती क्षेत्र: Malaysia/Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, firm, less sticky\u000a\u000aमराठी नाव: Singapore Phanas\u000a\u000aमूळ डेटासेट तपशील: Less latex; firmer bulbs; good for processing; grown in Konkan.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(93,47,'hi','NA-7','Maharashtra','Sour, astringent, large fruit','NA-7 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('NA-7 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Phyllanthus emblica cv. NA-7\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sour, astringent, large fruit\u000a\u000aमराठी नाम: NA-7 Avala\u000a\u000aमूल डेटासेट विवरण: Most popular commercial variety in Maharashtra; large fruit; Nashik and Aurangabad; high Vitamin C.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(94,47,'mr','NA-7 Avala','Maharashtra','Sour, astringent, large fruit','NA-7 Avala ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('NA-7 Avala ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Phyllanthus emblica cv. NA-7\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sour, astringent, large fruit\u000a\u000aमराठी नाव: NA-7 Avala\u000a\u000aमूळ डेटासेट तपशील: Most popular commercial variety in Maharashtra; large fruit; Nashik and Aurangabad; high Vitamin C.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(95,48,'hi','Krishna','Maharashtra','Sour, medium size, firm','Krishna इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Krishna इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Phyllanthus emblica cv. Krishna\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sour, medium size, firm\u000a\u000aमराठी नाम: Krishna Avala\u000a\u000aमूल डेटासेट विवरण: High yielding; grown in Marathwada; good for processing.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(96,48,'mr','Krishna Avala','Maharashtra','Sour, medium size, firm','Krishna Avala ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Krishna Avala ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Phyllanthus emblica cv. Krishna\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sour, medium size, firm\u000a\u000aमराठी नाव: Krishna Avala\u000a\u000aमूळ डेटासेट तपशील: High yielding; grown in Marathwada; good for processing.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(97,49,'hi','Kanchan','Maharashtra','Mildly sour, attractive appearance','Kanchan इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Kanchan इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Phyllanthus emblica cv. Kanchan\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Mildly sour, attractive appearance\u000a\u000aमराठी नाम: Kanchan Avala\u000a\u000aमूल डेटासेट विवरण: Regular bearer; Nashik; good for candy and pickle industry.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(98,49,'mr','Kanchan Avala','Maharashtra','Mildly sour, attractive appearance','Kanchan Avala ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Kanchan Avala ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Phyllanthus emblica cv. Kanchan\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Mildly sour, attractive appearance\u000a\u000aमराठी नाव: Kanchan Avala\u000a\u000aमूळ डेटासेट तपशील: Regular bearer; Nashik; good for candy and pickle industry.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(99,50,'hi','Camarosa','USA/Maharashtra','Sweet-tart, firm, bright red','Camarosa इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Camarosa इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Fragaria × ananassa cv. Camarosa\u000a\u000aउत्पत्ति क्षेत्र: USA/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet-tart, firm, bright red\u000a\u000aमराठी नाम: Camarosa Strawberry\u000a\u000aमूल डेटासेट विवरण: Most popular variety in Mahabaleshwar; large berry; good shelf life; high yield; fresh market and processing.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(100,50,'mr','Camarosa Strawberry','USA/Maharashtra','Sweet-tart, firm, bright red','Camarosa Strawberry ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Camarosa Strawberry ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Fragaria × ananassa cv. Camarosa\u000a\u000aउत्पत्ती क्षेत्र: USA/Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet-tart, firm, bright red\u000a\u000aमराठी नाव: Camarosa Strawberry\u000a\u000aमूळ डेटासेट तपशील: Most popular variety in Mahabaleshwar; large berry; good shelf life; high yield; fresh market and processing.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(101,51,'hi','Festival','USA/Maharashtra','Very sweet, aromatic, deep red','Festival इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Festival इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Fragaria × ananassa cv. Festival\u000a\u000aउत्पत्ति क्षेत्र: USA/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very sweet, aromatic, deep red\u000a\u000aमराठी नाम: Festival Strawberry\u000a\u000aमूल डेटासेट विवरण: Sweet flavour; Mahabaleshwar and Panchgani; popular with tourists.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(102,51,'mr','Festival Strawberry','USA/Maharashtra','Very sweet, aromatic, deep red','Festival Strawberry ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Festival Strawberry ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Fragaria × ananassa cv. Festival\u000a\u000aउत्पत्ती क्षेत्र: USA/Maharashtra\u000a\u000aचव वैशिष्ट्य: Very sweet, aromatic, deep red\u000a\u000aमराठी नाव: Festival Strawberry\u000a\u000aमूळ डेटासेट तपशील: Sweet flavour; Mahabaleshwar and Panchgani; popular with tourists.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(103,52,'hi','Sweet Charlie','USA/Maharashtra','Very sweet, aromatic, early season','Sweet Charlie इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Sweet Charlie इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Fragaria × ananassa cv. Sweet Charlie\u000a\u000aउत्पत्ति क्षेत्र: USA/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very sweet, aromatic, early season\u000a\u000aमराठी नाम: Sweet Charlie Strawberry\u000a\u000aमूल डेटासेट विवरण: Early bearing; soft fruit; excellent flavour; Mahabaleshwar.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(104,52,'mr','Sweet Charlie Strawberry','USA/Maharashtra','Very sweet, aromatic, early season','Sweet Charlie Strawberry ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Sweet Charlie Strawberry ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Fragaria × ananassa cv. Sweet Charlie\u000a\u000aउत्पत्ती क्षेत्र: USA/Maharashtra\u000a\u000aचव वैशिष्ट्य: Very sweet, aromatic, early season\u000a\u000aमराठी नाव: Sweet Charlie Strawberry\u000a\u000aमूळ डेटासेट तपशील: Early bearing; soft fruit; excellent flavour; Mahabaleshwar.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(105,53,'hi','Poona Fig (Dinkar)','Maharashtra','Very sweet, golden-green skin, soft, aromatic','Poona Fig (Dinkar) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Poona Fig (Dinkar) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Ficus carica cv. Poona\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very sweet, golden-green skin, soft, aromatic\u000a\u000aमराठी नाम: Poona Anjeer\u000a\u000aमूल डेटासेट विवरण: GI-tagged Purandar fig; unique sweetness; grown exclusively in Purandar, Pune; best eaten fresh; limited production, premium price.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(106,53,'mr','Poona Anjeer','Maharashtra','Very sweet, golden-green skin, soft, aromatic','Poona Anjeer ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Poona Anjeer ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Ficus carica cv. Poona\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Very sweet, golden-green skin, soft, aromatic\u000a\u000aमराठी नाव: Poona Anjeer\u000a\u000aमूळ डेटासेट तपशील: GI-tagged Purandar fig; unique sweetness; grown exclusively in Purandar, Pune; best eaten fresh; limited production, premium price.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(107,54,'hi','Umran','Rajasthan/Maharashtra','Sweet, large, firm, low acidity','Umran इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Umran इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Ziziphus mauritiana cv. Umran\u000a\u000aउत्पत्ति क्षेत्र: Rajasthan/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, large, firm, low acidity\u000a\u000aमराठी नाम: Umran Bor\u000a\u000aमूल डेटासेट विवरण: Most popular commercial variety; large oval fruit; good shelf life; Solapur, Aurangabad.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(108,54,'mr','Umran Bor','Rajasthan/Maharashtra','Sweet, large, firm, low acidity','Umran Bor ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Umran Bor ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Ziziphus mauritiana cv. Umran\u000a\u000aउत्पत्ती क्षेत्र: Rajasthan/Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, large, firm, low acidity\u000a\u000aमराठी नाव: Umran Bor\u000a\u000aमूळ डेटासेट तपशील: Most popular commercial variety; large oval fruit; good shelf life; Solapur, Aurangabad.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(109,55,'hi','Gola','Maharashtra','Sweet-sour, round, medium size','Gola इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Gola इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Ziziphus mauritiana cv. Gola\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet-sour, round, medium size\u000a\u000aमराठी नाम: Gola Bor\u000a\u000aमूल डेटासेट विवरण: Traditional variety; good domestic market; Marathwada and Vidarbha.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(110,55,'mr','Gola Bor','Maharashtra','Sweet-sour, round, medium size','Gola Bor ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Gola Bor ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Ziziphus mauritiana cv. Gola\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet-sour, round, medium size\u000a\u000aमराठी नाव: Gola Bor\u000a\u000aमूळ डेटासेट तपशील: Traditional variety; good domestic market; Marathwada and Vidarbha.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(111,56,'hi','Indrayani','Maharashtra','Aromatic, soft, sticky when cooked','Indrayani इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Indrayani इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Oryza sativa cv. Indrayani\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Aromatic, soft, sticky when cooked\u000a\u000aमराठी नाम: Indrayani Tandul\u000a\u000aमूल डेटासेट विवरण: GI-tagged; developed at Dr BSKKV, Dapoli; grown in Pune, Nashik and Konkan; premium price; very popular in Pune city market.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(112,56,'mr','Indrayani Tandul','Maharashtra','Aromatic, soft, sticky when cooked','Indrayani Tandul ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Indrayani Tandul ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Oryza sativa cv. Indrayani\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Aromatic, soft, sticky when cooked\u000a\u000aमराठी नाव: Indrayani Tandul\u000a\u000aमूळ डेटासेट तपशील: GI-tagged; developed at Dr BSKKV, Dapoli; grown in Pune, Nashik and Konkan; premium price; very popular in Pune city market.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(113,57,'hi','Ambemohar','Maharashtra','Highly aromatic (mango blossom scent), soft, short grain','Ambemohar इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Ambemohar इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Oryza sativa cv. Ambemohar\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Highly aromatic (mango blossom scent), soft, short grain\u000a\u000aमराठी नाम: Ambemohar Tandul\u000a\u000aमूल डेटासेट विवरण: Heritage aromatic variety; Pune and Konkan hills; named for its mango-blossom aroma; slow cooking; festival and high-value rice.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(114,57,'mr','Ambemohar Tandul','Maharashtra','Highly aromatic (mango blossom scent), soft, short grain','Ambemohar Tandul ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Ambemohar Tandul ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Oryza sativa cv. Ambemohar\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Highly aromatic (mango blossom scent), soft, short grain\u000a\u000aमराठी नाव: Ambemohar Tandul\u000a\u000aमूळ डेटासेट तपशील: Heritage aromatic variety; Pune and Konkan hills; named for its mango-blossom aroma; slow cooking; festival and high-value rice.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(115,58,'hi','Kolam','Maharashtra','Slightly aromatic, slender, fluffy on cooking','Kolam इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Kolam इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Oryza sativa cv. Kolam\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Slightly aromatic, slender, fluffy on cooking\u000a\u000aमराठी नाम: Kolam Tandul\u000a\u000aमूल डेटासेट विवरण: Very popular in Mumbai-Pune; medium-slender grain; widely used for daily cooking; Nashik, Konkan.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(116,58,'mr','Kolam Tandul','Maharashtra','Slightly aromatic, slender, fluffy on cooking','Kolam Tandul ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Kolam Tandul ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Oryza sativa cv. Kolam\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Slightly aromatic, slender, fluffy on cooking\u000a\u000aमराठी नाव: Kolam Tandul\u000a\u000aमूळ डेटासेट तपशील: Very popular in Mumbai-Pune; medium-slender grain; widely used for daily cooking; Nashik, Konkan.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(117,59,'hi','HMT','India','Mild aroma, long grain, non-sticky','HMT इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('HMT इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Oryza sativa cv. HMT\u000a\u000aउत्पत्ति क्षेत्र: India\u000a\u000aस्वाद प्रोफाइल: Mild aroma, long grain, non-sticky\u000a\u000aमराठी नाम: HMT Tandul\u000a\u000aमूल डेटासेट विवरण: Named for its resemblance to HMT watches (long slim grain); popular across Maharashtra; biryani rice.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(118,59,'mr','HMT Tandul','India','Mild aroma, long grain, non-sticky','HMT Tandul ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('HMT Tandul ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Oryza sativa cv. HMT\u000a\u000aउत्पत्ती क्षेत्र: India\u000a\u000aचव वैशिष्ट्य: Mild aroma, long grain, non-sticky\u000a\u000aमराठी नाव: HMT Tandul\u000a\u000aमूळ डेटासेट तपशील: Named for its resemblance to HMT watches (long slim grain); popular across Maharashtra; biryani rice.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(119,60,'hi','Jaya','India (IRRI origin)','Plain, non-aromatic, high-yield','Jaya इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Jaya इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Oryza sativa cv. Jaya\u000a\u000aउत्पत्ति क्षेत्र: India (IRRI origin)\u000a\u000aस्वाद प्रोफाइल: Plain, non-aromatic, high-yield\u000a\u000aमराठी नाम: Jaya Tandul\u000a\u000aमूल डेटासेट विवरण: High-yielding semi-dwarf; widely grown in irrigated areas of Vidarbha and Marathwada.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(120,60,'mr','Jaya Tandul','India (IRRI origin)','Plain, non-aromatic, high-yield','Jaya Tandul ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Jaya Tandul ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Oryza sativa cv. Jaya\u000a\u000aउत्पत्ती क्षेत्र: India (IRRI origin)\u000a\u000aचव वैशिष्ट्य: Plain, non-aromatic, high-yield\u000a\u000aमराठी नाव: Jaya Tandul\u000a\u000aमूळ डेटासेट तपशील: High-yielding semi-dwarf; widely grown in irrigated areas of Vidarbha and Marathwada.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(121,61,'hi','Swarna','India','Non-aromatic, medium-bold, high yield','Swarna इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Swarna इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Oryza sativa cv. Swarna (MTU 7029)\u000a\u000aउत्पत्ति क्षेत्र: India\u000a\u000aस्वाद प्रोफाइल: Non-aromatic, medium-bold, high yield\u000a\u000aमराठी नाम: Swarna Tandul\u000a\u000aमूल डेटासेट विवरण: Most widely grown HYV rice in Maharashtra; Vidarbha; flood tolerant; rainfed and irrigated.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(122,61,'mr','Swarna Tandul','India','Non-aromatic, medium-bold, high yield','Swarna Tandul ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Swarna Tandul ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Oryza sativa cv. Swarna (MTU 7029)\u000a\u000aउत्पत्ती क्षेत्र: India\u000a\u000aचव वैशिष्ट्य: Non-aromatic, medium-bold, high yield\u000a\u000aमराठी नाव: Swarna Tandul\u000a\u000aमूळ डेटासेट तपशील: Most widely grown HYV rice in Maharashtra; Vidarbha; flood tolerant; rainfed and irrigated.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(123,62,'hi','Basmati','India','Very aromatic, extra long slender grain, fluffy','Basmati इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Basmati इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Oryza sativa cv. Basmati\u000a\u000aउत्पत्ति क्षेत्र: India\u000a\u000aस्वाद प्रोफाइल: Very aromatic, extra long slender grain, fluffy\u000a\u000aमराठी नाम: Basmati Tandul\u000a\u000aमूल डेटासेट विवरण: Grown in Nashik and parts of Marathwada; mostly for export and premium market.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(124,62,'mr','Basmati Tandul','India','Very aromatic, extra long slender grain, fluffy','Basmati Tandul ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Basmati Tandul ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Oryza sativa cv. Basmati\u000a\u000aउत्पत्ती क्षेत्र: India\u000a\u000aचव वैशिष्ट्य: Very aromatic, extra long slender grain, fluffy\u000a\u000aमराठी नाव: Basmati Tandul\u000a\u000aमूळ डेटासेट तपशील: Grown in Nashik and parts of Marathwada; mostly for export and premium market.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(125,63,'hi','Karjat-4','Maharashtra','Aromatic, short-bold, good palatability','Karjat-4 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Karjat-4 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Oryza sativa cv. Karjat-4\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Aromatic, short-bold, good palatability\u000a\u000aमराठी नाम: Karjat Tandul\u000a\u000aमूल डेटासेट विवरण: Developed at Regional Agricultural Research Station, Karjat; adapted to Konkan; medium duration.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(126,63,'mr','Karjat Tandul','Maharashtra','Aromatic, short-bold, good palatability','Karjat Tandul ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Karjat Tandul ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Oryza sativa cv. Karjat-4\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Aromatic, short-bold, good palatability\u000a\u000aमराठी नाव: Karjat Tandul\u000a\u000aमूळ डेटासेट तपशील: Developed at Regional Agricultural Research Station, Karjat; adapted to Konkan; medium duration.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(127,64,'hi','Phule Samruddhi','Maharashtra','High yield, medium grain, good cooking quality','Phule Samruddhi इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Phule Samruddhi इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Oryza sativa cv. Phule Samruddhi\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: High yield, medium grain, good cooking quality\u000a\u000aमराठी नाम: Phule Samruddhi Tandul\u000a\u000aमूल डेटासेट विवरण: Developed by MPKV Rahuri; high-yielding; suitable for Konkan and Western Maharashtra.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(128,64,'mr','Phule Samruddhi Tandul','Maharashtra','High yield, medium grain, good cooking quality','Phule Samruddhi Tandul ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Phule Samruddhi Tandul ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Oryza sativa cv. Phule Samruddhi\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: High yield, medium grain, good cooking quality\u000a\u000aमराठी नाव: Phule Samruddhi Tandul\u000a\u000aमूळ डेटासेट तपशील: Developed by MPKV Rahuri; high-yielding; suitable for Konkan and Western Maharashtra.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(129,65,'hi','Lokwan','Maharashtra','Nutty, slightly sweet, good chapati quality','Lokwan इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Lokwan इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Triticum aestivum cv. Lokwan\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Nutty, slightly sweet, good chapati quality\u000a\u000aमराठी नाम: Lokwan Gahu\u000a\u000aमूल डेटासेट विवरण: Heritage wheat of Maharashtra; famous for chapati quality; medium yield; lower gluten than modern varieties; Nashik, Pune, Aurangabad.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(130,65,'mr','Lokwan Gahu','Maharashtra','Nutty, slightly sweet, good chapati quality','Lokwan Gahu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Lokwan Gahu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Triticum aestivum cv. Lokwan\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Nutty, slightly sweet, good chapati quality\u000a\u000aमराठी नाव: Lokwan Gahu\u000a\u000aमूळ डेटासेट तपशील: Heritage wheat of Maharashtra; famous for chapati quality; medium yield; lower gluten than modern varieties; Nashik, Pune, Aurangabad.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(131,66,'hi','HD-2189','India','Plain, high gluten, good milling quality','HD-2189 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('HD-2189 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Triticum aestivum cv. HD-2189\u000a\u000aउत्पत्ति क्षेत्र: India\u000a\u000aस्वाद प्रोफाइल: Plain, high gluten, good milling quality\u000a\u000aमराठी नाम: HD-2189 Gahu\u000a\u000aमूल डेटासेट विवरण: Widely grown HYV; adaptable; Nashik and Aurangabad irrigated zones.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(132,66,'mr','HD-2189 Gahu','India','Plain, high gluten, good milling quality','HD-2189 Gahu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('HD-2189 Gahu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Triticum aestivum cv. HD-2189\u000a\u000aउत्पत्ती क्षेत्र: India\u000a\u000aचव वैशिष्ट्य: Plain, high gluten, good milling quality\u000a\u000aमराठी नाव: HD-2189 Gahu\u000a\u000aमूळ डेटासेट तपशील: Widely grown HYV; adaptable; Nashik and Aurangabad irrigated zones.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(133,67,'hi','HD-2967','India','Mild, high yield, good chapati quality','HD-2967 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('HD-2967 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Triticum aestivum cv. HD-2967\u000a\u000aउत्पत्ति क्षेत्र: India\u000a\u000aस्वाद प्रोफाइल: Mild, high yield, good chapati quality\u000a\u000aमराठी नाम: HD-2967 Gahu\u000a\u000aमूल डेटासेट विवरण: One of most popular wheats in Maharashtra; rust-resistant; Nashik, Pune, Vidarbha.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(134,67,'mr','HD-2967 Gahu','India','Mild, high yield, good chapati quality','HD-2967 Gahu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('HD-2967 Gahu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Triticum aestivum cv. HD-2967\u000a\u000aउत्पत्ती क्षेत्र: India\u000a\u000aचव वैशिष्ट्य: Mild, high yield, good chapati quality\u000a\u000aमराठी नाव: HD-2967 Gahu\u000a\u000aमूळ डेटासेट तपशील: One of most popular wheats in Maharashtra; rust-resistant; Nashik, Pune, Vidarbha.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(135,68,'hi','NIAW-34','Maharashtra','Mild flavour, high yield, semi-dwarf','NIAW-34 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('NIAW-34 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Triticum aestivum cv. NIAW-34\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Mild flavour, high yield, semi-dwarf\u000a\u000aमराठी नाम: NIAW-34 Gahu\u000a\u000aमूल डेटासेट विवरण: Developed at NIPHAD, Nashik; well adapted to Maharashtra; good tillering.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(136,68,'mr','NIAW-34 Gahu','Maharashtra','Mild flavour, high yield, semi-dwarf','NIAW-34 Gahu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('NIAW-34 Gahu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Triticum aestivum cv. NIAW-34\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Mild flavour, high yield, semi-dwarf\u000a\u000aमराठी नाव: NIAW-34 Gahu\u000a\u000aमूळ डेटासेट तपशील: Developed at NIPHAD, Nashik; well adapted to Maharashtra; good tillering.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(137,69,'hi','NIAW-917','Maharashtra','Good chapati quality, heat tolerant','NIAW-917 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('NIAW-917 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Triticum aestivum cv. NIAW-917\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Good chapati quality, heat tolerant\u000a\u000aमराठी नाम: NIAW-917 Gahu\u000a\u000aमूल डेटासेट विवरण: Heat-tolerant variety for Maharashtra; late sowing conditions; Marathwada.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(138,69,'mr','NIAW-917 Gahu','Maharashtra','Good chapati quality, heat tolerant','NIAW-917 Gahu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('NIAW-917 Gahu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Triticum aestivum cv. NIAW-917\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Good chapati quality, heat tolerant\u000a\u000aमराठी नाव: NIAW-917 Gahu\u000a\u000aमूळ डेटासेट तपशील: Heat-tolerant variety for Maharashtra; late sowing conditions; Marathwada.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(139,70,'hi','MACS-6222','Maharashtra','High protein, good chapati quality','MACS-6222 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('MACS-6222 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Triticum aestivum cv. MACS-6222\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: High protein, good chapati quality\u000a\u000aमराठी नाम: MACS-6222 Gahu\u000a\u000aमूल डेटासेट विवरण: Developed at ARI, Pune; high-yielding; Nashik, Pune, Solapur.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(140,70,'mr','MACS-6222 Gahu','Maharashtra','High protein, good chapati quality','MACS-6222 Gahu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('MACS-6222 Gahu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Triticum aestivum cv. MACS-6222\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: High protein, good chapati quality\u000a\u000aमराठी नाव: MACS-6222 Gahu\u000a\u000aमूळ डेटासेट तपशील: Developed at ARI, Pune; high-yielding; Nashik, Pune, Solapur.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(141,71,'hi','AKAW-4627','Maharashtra','Durum type, high protein, golden semolina','AKAW-4627 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('AKAW-4627 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Triticum durum cv. AKAW-4627\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Durum type, high protein, golden semolina\u000a\u000aमराठी नाम: AKAW Gahu\u000a\u000aमूल डेटासेट विवरण: Durum wheat; Akola series; Vidarbha and Marathwada; used for semolina (rawa/suji).'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(142,71,'mr','AKAW Gahu','Maharashtra','Durum type, high protein, golden semolina','AKAW Gahu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('AKAW Gahu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Triticum durum cv. AKAW-4627\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Durum type, high protein, golden semolina\u000a\u000aमराठी नाव: AKAW Gahu\u000a\u000aमूळ डेटासेट तपशील: Durum wheat; Akola series; Vidarbha and Marathwada; used for semolina (rawa/suji).'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(143,72,'hi','Maldandi','Maharashtra','Bold, white grain, excellent bhakri quality','Maldandi इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Maldandi इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Sorghum bicolor cv. Maldandi 35-1\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Bold, white grain, excellent bhakri quality\u000a\u000aमराठी नाम: Maldandi Jwarī\u000a\u000aमूल डेटासेट विवरण: Heritage rabi sorghum; Solapur is the heartland; world-famous grain quality; GI tag sought; premium price; iconic Maharashtrian grain.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(144,72,'mr','Maldandi Jwarī','Maharashtra','Bold, white grain, excellent bhakri quality','Maldandi Jwarī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Maldandi Jwarī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Sorghum bicolor cv. Maldandi 35-1\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Bold, white grain, excellent bhakri quality\u000a\u000aमराठी नाव: Maldandi Jwarī\u000a\u000aमूळ डेटासेट तपशील: Heritage rabi sorghum; Solapur is the heartland; world-famous grain quality; GI tag sought; premium price; iconic Maharashtrian grain.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(145,73,'hi','Dagadi Jowar','Maharashtra','Nutty, hard grain, very drought tolerant','Dagadi Jowar इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Dagadi Jowar इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Sorghum bicolor (local landrace)\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Nutty, hard grain, very drought tolerant\u000a\u000aमराठी नाम: Dagadi Jwarī\u000a\u000aमूल डेटासेट विवरण: Traditional hard-grain Kharif variety; Marathwada and Vidarbha; grown without irrigation.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(146,73,'mr','Dagadi Jwarī','Maharashtra','Nutty, hard grain, very drought tolerant','Dagadi Jwarī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Dagadi Jwarī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Sorghum bicolor (local landrace)\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Nutty, hard grain, very drought tolerant\u000a\u000aमराठी नाव: Dagadi Jwarī\u000a\u000aमूळ डेटासेट तपशील: Traditional hard-grain Kharif variety; Marathwada and Vidarbha; grown without irrigation.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(147,74,'hi','Phule Vasudha','Maharashtra','High yield, white grain, good quality','Phule Vasudha इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Phule Vasudha इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Sorghum bicolor cv. Phule Vasudha\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: High yield, white grain, good quality\u000a\u000aमराठी नाम: Phule Vasudha Jwarī\u000a\u000aमूल डेटासेट विवरण: Developed by MPKV; Rabi season; Nashik, Pune, Aurangabad; dual purpose (grain + fodder).'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(148,74,'mr','Phule Vasudha Jwarī','Maharashtra','High yield, white grain, good quality','Phule Vasudha Jwarī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Phule Vasudha Jwarī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Sorghum bicolor cv. Phule Vasudha\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: High yield, white grain, good quality\u000a\u000aमराठी नाव: Phule Vasudha Jwarī\u000a\u000aमूळ डेटासेट तपशील: Developed by MPKV; Rabi season; Nashik, Pune, Aurangabad; dual purpose (grain + fodder).'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(149,75,'hi','CSV-15','India (ICRISAT)','Bold white grain, high yield','CSV-15 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('CSV-15 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Sorghum bicolor cv. CSV-15\u000a\u000aउत्पत्ति क्षेत्र: India (ICRISAT)\u000a\u000aस्वाद प्रोफाइल: Bold white grain, high yield\u000a\u000aमराठी नाम: CSV-15 Jwarī\u000a\u000aमूल डेटासेट विवरण: ICRISAT-developed; widely adapted; Maharashtra, Karnataka; Kharif.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(150,75,'mr','CSV-15 Jwarī','India (ICRISAT)','Bold white grain, high yield','CSV-15 Jwarī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('CSV-15 Jwarī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Sorghum bicolor cv. CSV-15\u000a\u000aउत्पत्ती क्षेत्र: India (ICRISAT)\u000a\u000aचव वैशिष्ट्य: Bold white grain, high yield\u000a\u000aमराठी नाव: CSV-15 Jwarī\u000a\u000aमूळ डेटासेट तपशील: ICRISAT-developed; widely adapted; Maharashtra, Karnataka; Kharif.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(151,76,'hi','CSV-20','India (ICRISAT)','White grain, good yield, disease resistant','CSV-20 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('CSV-20 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Sorghum bicolor cv. CSV-20\u000a\u000aउत्पत्ति क्षेत्र: India (ICRISAT)\u000a\u000aस्वाद प्रोफाइल: White grain, good yield, disease resistant\u000a\u000aमराठी नाम: CSV-20 Jwarī\u000a\u000aमूल डेटासेट विवरण: Improved variety; Marathwada and Vidarbha.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(152,76,'mr','CSV-20 Jwarī','India (ICRISAT)','White grain, good yield, disease resistant','CSV-20 Jwarī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('CSV-20 Jwarī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Sorghum bicolor cv. CSV-20\u000a\u000aउत्पत्ती क्षेत्र: India (ICRISAT)\u000a\u000aचव वैशिष्ट्य: White grain, good yield, disease resistant\u000a\u000aमराठी नाव: CSV-20 Jwarī\u000a\u000aमूळ डेटासेट तपशील: Improved variety; Marathwada and Vidarbha.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(153,77,'hi','CSV-27','India (ICRISAT)','White grain, drought tolerant, medium yield','CSV-27 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('CSV-27 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Sorghum bicolor cv. CSV-27\u000a\u000aउत्पत्ति क्षेत्र: India (ICRISAT)\u000a\u000aस्वाद प्रोफाइल: White grain, drought tolerant, medium yield\u000a\u000aमराठी नाम: CSV-27 Jwarī\u000a\u000aमूल डेटासेट विवरण: Latest release; suitable for Kharif; Maharashtra.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(154,77,'mr','CSV-27 Jwarī','India (ICRISAT)','White grain, drought tolerant, medium yield','CSV-27 Jwarī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('CSV-27 Jwarī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Sorghum bicolor cv. CSV-27\u000a\u000aउत्पत्ती क्षेत्र: India (ICRISAT)\u000a\u000aचव वैशिष्ट्य: White grain, drought tolerant, medium yield\u000a\u000aमराठी नाव: CSV-27 Jwarī\u000a\u000aमूळ डेटासेट तपशील: Latest release; suitable for Kharif; Maharashtra.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(155,78,'hi','CSH-14','India','High yield, bold grain, hybrid vigour','CSH-14 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('CSH-14 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Sorghum bicolor cv. CSH-14\u000a\u000aउत्पत्ति क्षेत्र: India\u000a\u000aस्वाद प्रोफाइल: High yield, bold grain, hybrid vigour\u000a\u000aमराठी नाम: CSH-14 Jwarī\u000a\u000aमूल डेटासेट विवरण: Popular hybrid; Kharif; Vidarbha and Marathwada; good fodder value.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(156,78,'mr','CSH-14 Jwarī','India','High yield, bold grain, hybrid vigour','CSH-14 Jwarī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('CSH-14 Jwarī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Sorghum bicolor cv. CSH-14\u000a\u000aउत्पत्ती क्षेत्र: India\u000a\u000aचव वैशिष्ट्य: High yield, bold grain, hybrid vigour\u000a\u000aमराठी नाव: CSH-14 Jwarī\u000a\u000aमूळ डेटासेट तपशील: Popular hybrid; Kharif; Vidarbha and Marathwada; good fodder value.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(157,79,'hi','CSH-16','India','Very high yield, white grain, hybrid','CSH-16 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('CSH-16 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Sorghum bicolor cv. CSH-16\u000a\u000aउत्पत्ति क्षेत्र: India\u000a\u000aस्वाद प्रोफाइल: Very high yield, white grain, hybrid\u000a\u000aमराठी नाम: CSH-16 Jwarī\u000a\u000aमूल डेटासेट विवरण: Widely grown hybrid; Kharif and Rabi; Maharashtra and Andhra Pradesh.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(158,79,'mr','CSH-16 Jwarī','India','Very high yield, white grain, hybrid','CSH-16 Jwarī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('CSH-16 Jwarī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Sorghum bicolor cv. CSH-16\u000a\u000aउत्पत्ती क्षेत्र: India\u000a\u000aचव वैशिष्ट्य: Very high yield, white grain, hybrid\u000a\u000aमराठी नाव: CSH-16 Jwarī\u000a\u000aमूळ डेटासेट तपशील: Widely grown hybrid; Kharif and Rabi; Maharashtra and Andhra Pradesh.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(159,80,'hi','ICTP-8203','India (ICRISAT)','Grey-white grain, good taste, nutritious','ICTP-8203 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('ICTP-8203 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Pennisetum glaucum cv. ICTP-8203\u000a\u000aउत्पत्ति क्षेत्र: India (ICRISAT)\u000a\u000aस्वाद प्रोफाइल: Grey-white grain, good taste, nutritious\u000a\u000aमराठी नाम: ICTP Bajrī\u000a\u000aमूल डेटासेट विवरण: Open-pollinated variety; widely adopted in Maharashtra; drought-tolerant; ICRISAT developed.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(160,80,'mr','ICTP Bajrī','India (ICRISAT)','Grey-white grain, good taste, nutritious','ICTP Bajrī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('ICTP Bajrī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Pennisetum glaucum cv. ICTP-8203\u000a\u000aउत्पत्ती क्षेत्र: India (ICRISAT)\u000a\u000aचव वैशिष्ट्य: Grey-white grain, good taste, nutritious\u000a\u000aमराठी नाव: ICTP Bajrī\u000a\u000aमूळ डेटासेट तपशील: Open-pollinated variety; widely adopted in Maharashtra; drought-tolerant; ICRISAT developed.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(161,81,'hi','Shanti','Maharashtra','White grain, mild flavour, high yield','Shanti इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Shanti इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Pennisetum glaucum cv. Shanti\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: White grain, mild flavour, high yield\u000a\u000aमराठी नाम: Shanti Bajrī\u000a\u000aमूल डेटासेट विवरण: MPKV Rahuri; well adapted to dry zones of Nashik, Aurangabad; Kharif.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(162,81,'mr','Shanti Bajrī','Maharashtra','White grain, mild flavour, high yield','Shanti Bajrī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Shanti Bajrī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Pennisetum glaucum cv. Shanti\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: White grain, mild flavour, high yield\u000a\u000aमराठी नाव: Shanti Bajrī\u000a\u000aमूळ डेटासेट तपशील: MPKV Rahuri; well adapted to dry zones of Nashik, Aurangabad; Kharif.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(163,82,'hi','Saburi','Maharashtra','Good grain quality, medium yield','Saburi इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Saburi इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Pennisetum glaucum cv. Saburi\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Good grain quality, medium yield\u000a\u000aमराठी नाम: Saburi Bajrī\u000a\u000aमूल डेटासेट विवरण: MPKV variety; Maharashtra; dual purpose.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(164,82,'mr','Saburi Bajrī','Maharashtra','Good grain quality, medium yield','Saburi Bajrī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Saburi Bajrī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Pennisetum glaucum cv. Saburi\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Good grain quality, medium yield\u000a\u000aमराठी नाव: Saburi Bajrī\u000a\u000aमूळ डेटासेट तपशील: MPKV variety; Maharashtra; dual purpose.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(165,83,'hi','Phule Mahashakti','Maharashtra','High protein, bold grain, high yield','Phule Mahashakti इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Phule Mahashakti इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Pennisetum glaucum cv. Phule Mahashakti\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: High protein, bold grain, high yield\u000a\u000aमराठी नाम: Phule Mahashakti Bajrī\u000a\u000aमूल डेटासेट विवरण: Biofortified; high iron and zinc; MPKV; Nashik, Dhule, Jalgaon.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(166,83,'mr','Phule Mahashakti Bajrī','Maharashtra','High protein, bold grain, high yield','Phule Mahashakti Bajrī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Phule Mahashakti Bajrī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Pennisetum glaucum cv. Phule Mahashakti\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: High protein, bold grain, high yield\u000a\u000aमराठी नाव: Phule Mahashakti Bajrī\u000a\u000aमूळ डेटासेट तपशील: Biofortified; high iron and zinc; MPKV; Nashik, Dhule, Jalgaon.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(167,84,'hi','HHB-67','India','Bold grey grain, very high yield, hybrid','HHB-67 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('HHB-67 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Pennisetum glaucum cv. HHB-67\u000a\u000aउत्पत्ति क्षेत्र: India\u000a\u000aस्वाद प्रोफाइल: Bold grey grain, very high yield, hybrid\u000a\u000aमराठी नाम: HHB-67 Bajrī\u000a\u000aमूल डेटासेट विवरण: Most popular hybrid in Maharashtra; CCSHAU Hisar; Nashik, Jalgaon, Dhule.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(168,84,'mr','HHB-67 Bajrī','India','Bold grey grain, very high yield, hybrid','HHB-67 Bajrī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('HHB-67 Bajrī ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Pennisetum glaucum cv. HHB-67\u000a\u000aउत्पत्ती क्षेत्र: India\u000a\u000aचव वैशिष्ट्य: Bold grey grain, very high yield, hybrid\u000a\u000aमराठी नाव: HHB-67 Bajrī\u000a\u000aमूळ डेटासेट तपशील: Most popular hybrid in Maharashtra; CCSHAU Hisar; Nashik, Jalgaon, Dhule.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(169,85,'hi','African Tall','Maharashtra','Plain, starchy, large cob, open-pollinated','African Tall इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('African Tall इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Zea mays cv. African Tall\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Plain, starchy, large cob, open-pollinated\u000a\u000aमराठी नाम: African Tall Makka\u000a\u000aमूल डेटासेट विवरण: Traditional OPV; tall plant; widely grown in Nashik and Pune; good for food and fodder.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(170,85,'mr','African Tall Makka','Maharashtra','Plain, starchy, large cob, open-pollinated','African Tall Makka ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('African Tall Makka ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Zea mays cv. African Tall\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Plain, starchy, large cob, open-pollinated\u000a\u000aमराठी नाव: African Tall Makka\u000a\u000aमूळ डेटासेट तपशील: Traditional OPV; tall plant; widely grown in Nashik and Pune; good for food and fodder.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(171,86,'hi','Vijay Composite','India','Good flavour, medium yield','Vijay Composite इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Vijay Composite इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Zea mays cv. Vijay\u000a\u000aउत्पत्ति क्षेत्र: India\u000a\u000aस्वाद प्रोफाइल: Good flavour, medium yield\u000a\u000aमराठी नाम: Vijay Makka\u000a\u000aमूल डेटासेट विवरण: Open-pollinated; IARI developed; adaptable to Maharashtra; Kharif.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
