INSERT INTO crop_variety_translations VALUES(173,87,'hi','Deccan Hybrid-101','Maharashtra','Good flavour, high yield, hybrid vigour','Deccan Hybrid-101 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Deccan Hybrid-101 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Zea mays cv. Deccan-101\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Good flavour, high yield, hybrid vigour\u000a\u000aमराठी नाम: Deccan Makka\u000a\u000aमूल डेटासेट विवरण: Local hybrid; Pune and Nashik; food and fodder use.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(174,87,'mr','Deccan Makka','Maharashtra','Good flavour, high yield, hybrid vigour','Deccan Makka ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Deccan Makka ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Zea mays cv. Deccan-101\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Good flavour, high yield, hybrid vigour\u000a\u000aमराठी नाव: Deccan Makka\u000a\u000aमूळ डेटासेट तपशील: Local hybrid; Pune and Nashik; food and fodder use.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(175,88,'hi','HQPM-1','India','High protein (QPM), sweet-nutty flavour','HQPM-1 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('HQPM-1 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Zea mays cv. HQPM-1\u000a\u000aउत्पत्ति क्षेत्र: India\u000a\u000aस्वाद प्रोफाइल: High protein (QPM), sweet-nutty flavour\u000a\u000aमराठी नाम: HQPM-1 Makka\u000a\u000aमूल डेटासेट विवरण: Quality Protein Maize; IARI; high lysine and tryptophan; nutritionally superior; poultry and food.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(176,88,'mr','HQPM-1 Makka','India','High protein (QPM), sweet-nutty flavour','HQPM-1 Makka ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('HQPM-1 Makka ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Zea mays cv. HQPM-1\u000a\u000aउत्पत्ती क्षेत्र: India\u000a\u000aचव वैशिष्ट्य: High protein (QPM), sweet-nutty flavour\u000a\u000aमराठी नाव: HQPM-1 Makka\u000a\u000aमूळ डेटासेट तपशील: Quality Protein Maize; IARI; high lysine and tryptophan; nutritionally superior; poultry and food.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(177,89,'hi','Bioseed 9681','Maharashtra','Very high yield, bold grain, hybrid','Bioseed 9681 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Bioseed 9681 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Zea mays cv. Bioseed 9681\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very high yield, bold grain, hybrid\u000a\u000aमराठी नाम: Bioseed Makka\u000a\u000aमूल डेटासेट विवरण: Commercial hybrid; Nashik, Pune; widely used by contract farmers.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(178,89,'mr','Bioseed Makka','Maharashtra','Very high yield, bold grain, hybrid','Bioseed Makka ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Bioseed Makka ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Zea mays cv. Bioseed 9681\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Very high yield, bold grain, hybrid\u000a\u000aमराठी नाव: Bioseed Makka\u000a\u000aमूळ डेटासेट तपशील: Commercial hybrid; Nashik, Pune; widely used by contract farmers.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(179,90,'hi','Dapoli-1','Maharashtra','Brown grain, earthy, nutritious','Dapoli-1 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Dapoli-1 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Eleusine coracana cv. Dapoli-1\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Brown grain, earthy, nutritious\u000a\u000aमराठी नाम: Dapoli Nachni\u000a\u000aमूल डेटासेट विवरण: Developed at BSKKV Dapoli; adapted to Konkan; Kharif; good yield.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(180,90,'mr','Dapoli Nachni','Maharashtra','Brown grain, earthy, nutritious','Dapoli Nachni ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Dapoli Nachni ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Eleusine coracana cv. Dapoli-1\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Brown grain, earthy, nutritious\u000a\u000aमराठी नाव: Dapoli Nachni\u000a\u000aमूळ डेटासेट तपशील: Developed at BSKKV Dapoli; adapted to Konkan; Kharif; good yield.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(181,91,'hi','GPU-28','Karnataka/Maharashtra','Brown-black grain, high yield','GPU-28 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('GPU-28 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Eleusine coracana cv. GPU-28\u000a\u000aउत्पत्ति क्षेत्र: Karnataka/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Brown-black grain, high yield\u000a\u000aमराठी नाम: GPU-28 Nachni\u000a\u000aमूल डेटासेट विवरण: One of most popular varieties; GKVK Bengaluru; widely adapted to Maharashtra.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(182,91,'mr','GPU-28 Nachni','Karnataka/Maharashtra','Brown-black grain, high yield','GPU-28 Nachni ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('GPU-28 Nachni ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Eleusine coracana cv. GPU-28\u000a\u000aउत्पत्ती क्षेत्र: Karnataka/Maharashtra\u000a\u000aचव वैशिष्ट्य: Brown-black grain, high yield\u000a\u000aमराठी नाव: GPU-28 Nachni\u000a\u000aमूळ डेटासेट तपशील: One of most popular varieties; GKVK Bengaluru; widely adapted to Maharashtra.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(183,92,'hi','GPU-67','Karnataka/Maharashtra','Brown grain, blast-resistant, high yield','GPU-67 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('GPU-67 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Eleusine coracana cv. GPU-67\u000a\u000aउत्पत्ति क्षेत्र: Karnataka/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Brown grain, blast-resistant, high yield\u000a\u000aमराठी नाम: GPU-67 Nachni\u000a\u000aमूल डेटासेट विवरण: Disease resistant; good yield; Nashik hills and Nandurbar.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(184,92,'mr','GPU-67 Nachni','Karnataka/Maharashtra','Brown grain, blast-resistant, high yield','GPU-67 Nachni ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('GPU-67 Nachni ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Eleusine coracana cv. GPU-67\u000a\u000aउत्पत्ती क्षेत्र: Karnataka/Maharashtra\u000a\u000aचव वैशिष्ट्य: Brown grain, blast-resistant, high yield\u000a\u000aमराठी नाव: GPU-67 Nachni\u000a\u000aमूळ डेटासेट तपशील: Disease resistant; good yield; Nashik hills and Nandurbar.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(185,93,'hi','Indaf-5','India','Dark brown, higher protein content','Indaf-5 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Indaf-5 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Eleusine coracana cv. Indaf-5\u000a\u000aउत्पत्ति क्षेत्र: India\u000a\u000aस्वाद प्रोफाइल: Dark brown, higher protein content\u000a\u000aमराठी नाम: Indaf Nachni\u000a\u000aमूल डेटासेट विवरण: ICAR developed; high yielding; used widely in Maharashtra tribal districts.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(186,93,'mr','Indaf Nachni','India','Dark brown, higher protein content','Indaf Nachni ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Indaf Nachni ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Eleusine coracana cv. Indaf-5\u000a\u000aउत्पत्ती क्षेत्र: India\u000a\u000aचव वैशिष्ट्य: Dark brown, higher protein content\u000a\u000aमराठी नाव: Indaf Nachni\u000a\u000aमूळ डेटासेट तपशील: ICAR developed; high yielding; used widely in Maharashtra tribal districts.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(187,94,'hi','Local Kodra','Maharashtra','Earthy, nutty, slightly bitter if unhulled','Local Kodra इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Local Kodra इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Paspalum scrobiculatum (local landrace)\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Earthy, nutty, slightly bitter if unhulled\u000a\u000aमराठी नाम: Sthanik Kodra\u000a\u000aमूल डेटासेट विवरण: Indigenous landraces grown in Nashik and Nandurbar tribal belts; integral to tribal food culture.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(188,94,'mr','Sthanik Kodra','Maharashtra','Earthy, nutty, slightly bitter if unhulled','Sthanik Kodra ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Sthanik Kodra ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Paspalum scrobiculatum (local landrace)\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Earthy, nutty, slightly bitter if unhulled\u000a\u000aमराठी नाव: Sthanik Kodra\u000a\u000aमूळ डेटासेट तपशील: Indigenous landraces grown in Nashik and Nandurbar tribal belts; integral to tribal food culture.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(189,95,'hi','Kutki (Local)','Maharashtra','Mild, slightly nutty, soft when cooked','Kutki (Local) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Kutki (Local) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Panicum sumatrense (local)\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Mild, slightly nutty, soft when cooked\u000a\u000aमराठी नाम: Sthanik Vari\u000a\u000aमूल डेटासेट विवरण: Traditional landrace; Nashik and Nandurbar; used for vari chi bhakri and khichdi during fasting.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(190,95,'mr','Sthanik Vari','Maharashtra','Mild, slightly nutty, soft when cooked','Sthanik Vari ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Sthanik Vari ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Panicum sumatrense (local)\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Mild, slightly nutty, soft when cooked\u000a\u000aमराठी नाव: Sthanik Vari\u000a\u000aमूळ डेटासेट तपशील: Traditional landrace; Nashik and Nandurbar; used for vari chi bhakri and khichdi during fasting.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(191,96,'hi','Bhagar (Local)','Maharashtra','Mild, fluffy, slightly chewy','Bhagar (Local) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Bhagar (Local) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Echinochloa frumentacea (local)\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Mild, fluffy, slightly chewy\u000a\u000aमराठी नाम: Sthanik Bhagar\u000a\u000aमूल डेटासेट विवरण: Traditional local variety; grown across Maharashtra; essential fasting food; khichdi and bhakri.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
