INSERT INTO crop_variety_translations VALUES(193,97,'hi','PRJ-1','Maharashtra','Good grain quality, high yield','PRJ-1 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('PRJ-1 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Echinochloa frumentacea cv. PRJ-1\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Good grain quality, high yield\u000a\u000aमराठी नाम: PRJ-1 Bhagar\u000a\u000aमूल डेटासेट विवरण: Improved variety; BSKKV Dapoli; Konkan and Nashik.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(194,97,'mr','PRJ-1 Bhagar','Maharashtra','Good grain quality, high yield','PRJ-1 Bhagar ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('PRJ-1 Bhagar ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Echinochloa frumentacea cv. PRJ-1\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Good grain quality, high yield\u000a\u000aमराठी नाव: PRJ-1 Bhagar\u000a\u000aमूळ डेटासेट तपशील: Improved variety; BSKKV Dapoli; Konkan and Nashik.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(195,98,'hi','Cheena (Local)','Maharashtra','Mild, bland, soft when cooked','Cheena (Local) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Cheena (Local) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Panicum miliaceum (local landrace)\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Mild, bland, soft when cooked\u000a\u000aमराठी नाम: Sthanik Cheena\u000a\u000aमूल डेटासेट विवरण: Local varieties; Marathwada and Vidarbha; very short duration; used for khichdi and upma.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(196,98,'mr','Sthanik Cheena','Maharashtra','Mild, bland, soft when cooked','Sthanik Cheena ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Sthanik Cheena ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Panicum miliaceum (local landrace)\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Mild, bland, soft when cooked\u000a\u000aमराठी नाव: Sthanik Cheena\u000a\u000aमूळ डेटासेट तपशील: Local varieties; Marathwada and Vidarbha; very short duration; used for khichdi and upma.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(197,99,'hi','BSMR-736 (Vipula)','Maharashtra','Good cooking quality, earthy flavour','BSMR-736 (Vipula) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('BSMR-736 (Vipula) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Cajanus cajan cv. BSMR-736\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Good cooking quality, earthy flavour\u000a\u000aमराठी नाम: Vipula Tur\u000a\u000aमूल डेटासेट विवरण: Wilt and sterility mosaic resistant; MPKV Rahuri; Marathwada and Vidarbha; medium duration.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(198,99,'mr','Vipula Tur','Maharashtra','Good cooking quality, earthy flavour','Vipula Tur ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Vipula Tur ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Cajanus cajan cv. BSMR-736\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Good cooking quality, earthy flavour\u000a\u000aमराठी नाव: Vipula Tur\u000a\u000aमूळ डेटासेट तपशील: Wilt and sterility mosaic resistant; MPKV Rahuri; Marathwada and Vidarbha; medium duration.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(199,100,'hi','Asha (ICPL-87119)','India (ICRISAT)','Good flavour, medium-bold grain','Asha (ICPL-87119) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Asha (ICPL-87119) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Cajanus cajan cv. Asha\u000a\u000aउत्पत्ति क्षेत्र: India (ICRISAT)\u000a\u000aस्वाद प्रोफाइल: Good flavour, medium-bold grain\u000a\u000aमराठी नाम: Asha Tur\u000a\u000aमूल डेटासेट विवरण: Wilt-resistant; widely adapted; popular in Latur, Osmanabad; medium duration.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(200,100,'mr','Asha Tur','India (ICRISAT)','Good flavour, medium-bold grain','Asha Tur ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Asha Tur ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Cajanus cajan cv. Asha\u000a\u000aउत्पत्ती क्षेत्र: India (ICRISAT)\u000a\u000aचव वैशिष्ट्य: Good flavour, medium-bold grain\u000a\u000aमराठी नाव: Asha Tur\u000a\u000aमूळ डेटासेट तपशील: Wilt-resistant; widely adapted; popular in Latur, Osmanabad; medium duration.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(201,101,'hi','Maruti','Maharashtra','Large seed, good dal recovery, bold grain','Maruti इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Maruti इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Cajanus cajan cv. Maruti\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Large seed, good dal recovery, bold grain\u000a\u000aमराठी नाम: Maruti Tur\u000a\u000aमूल डेटासेट विवरण: Bold-seeded variety; Marathwada; high market value; good for commercial dal production.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(202,101,'mr','Maruti Tur','Maharashtra','Large seed, good dal recovery, bold grain','Maruti Tur ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Maruti Tur ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Cajanus cajan cv. Maruti\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Large seed, good dal recovery, bold grain\u000a\u000aमराठी नाव: Maruti Tur\u000a\u000aमूळ डेटासेट तपशील: Bold-seeded variety; Marathwada; high market value; good for commercial dal production.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(203,102,'hi','ICPL-87119','India (ICRISAT)','Medium grain, disease resistant','ICPL-87119 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('ICPL-87119 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Cajanus cajan cv. ICPL-87119\u000a\u000aउत्पत्ति क्षेत्र: India (ICRISAT)\u000a\u000aस्वाद प्रोफाइल: Medium grain, disease resistant\u000a\u000aमराठी नाम: Prabhat Tur\u000a\u000aमूल डेटासेट विवरण: Extra-early variety; ICRISAT; Marathwada; good for areas with short seasons.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(204,102,'mr','Prabhat Tur','India (ICRISAT)','Medium grain, disease resistant','Prabhat Tur ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Prabhat Tur ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Cajanus cajan cv. ICPL-87119\u000a\u000aउत्पत्ती क्षेत्र: India (ICRISAT)\u000a\u000aचव वैशिष्ट्य: Medium grain, disease resistant\u000a\u000aमराठी नाव: Prabhat Tur\u000a\u000aमूळ डेटासेट तपशील: Extra-early variety; ICRISAT; Marathwada; good for areas with short seasons.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(205,103,'hi','Vijay','Maharashtra','Earthy, creamy, desi type, medium seed','Vijay इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Vijay इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Cicer arietinum cv. Vijay\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Earthy, creamy, desi type, medium seed\u000a\u000aमराठी नाम: Vijay Harbhara\u000a\u000aमूल डेटासेट विवरण: Wilt-resistant desi variety; MPKV Rahuri; widely grown in Marathwada.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(206,103,'mr','Vijay Harbhara','Maharashtra','Earthy, creamy, desi type, medium seed','Vijay Harbhara ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Vijay Harbhara ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Cicer arietinum cv. Vijay\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Earthy, creamy, desi type, medium seed\u000a\u000aमराठी नाव: Vijay Harbhara\u000a\u000aमूळ डेटासेट तपशील: Wilt-resistant desi variety; MPKV Rahuri; widely grown in Marathwada.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(207,104,'hi','Digvijay','Maharashtra','Good cooking quality, desi type','Digvijay इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Digvijay इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Cicer arietinum cv. Digvijay\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Good cooking quality, desi type\u000a\u000aमराठी नाम: Digvijay Harbhara\u000a\u000aमूल डेटासेट विवरण: High yielding; Marathwada; rust and wilt tolerant.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
