INSERT INTO crop_variety_translations VALUES(223,112,'hi','KLS-218','Maharashtra','Brown-red seed, good yield','KLS-218 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('KLS-218 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Lens culinaris cv. KLS-218\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Brown-red seed, good yield\u000a\u000aमराठी नाम: KLS-218 Masur\u000a\u000aमूल डेटासेट विवरण: MPKV variety; Latur, Osmanabad; rust-tolerant.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(224,112,'mr','KLS-218 Masur','Maharashtra','Brown-red seed, good yield','KLS-218 Masur ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('KLS-218 Masur ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Lens culinaris cv. KLS-218\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Brown-red seed, good yield\u000a\u000aमराठी नाव: KLS-218 Masur\u000a\u000aमूळ डेटासेट तपशील: MPKV variety; Latur, Osmanabad; rust-tolerant.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(225,113,'hi','JS-335','Madhya Pradesh/Maharashtra','Neutral, beany, high protein and oil','JS-335 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('JS-335 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Glycine max cv. JS-335\u000a\u000aउत्पत्ति क्षेत्र: Madhya Pradesh/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Neutral, beany, high protein and oil\u000a\u000aमराठी नाम: JS-335 Soya\u000a\u000aमूल डेटासेट विवरण: Most widely grown variety in Maharashtra for decades; Vidarbha and Marathwada; good yield and oil content.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(226,113,'mr','JS-335 Soya','Madhya Pradesh/Maharashtra','Neutral, beany, high protein and oil','JS-335 Soya ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('JS-335 Soya ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Glycine max cv. JS-335\u000a\u000aउत्पत्ती क्षेत्र: Madhya Pradesh/Maharashtra\u000a\u000aचव वैशिष्ट्य: Neutral, beany, high protein and oil\u000a\u000aमराठी नाव: JS-335 Soya\u000a\u000aमूळ डेटासेट तपशील: Most widely grown variety in Maharashtra for decades; Vidarbha and Marathwada; good yield and oil content.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(227,114,'hi','JS-9305','India','High yield, good oil content','JS-9305 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('JS-9305 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Glycine max cv. JS-9305\u000a\u000aउत्पत्ति क्षेत्र: India\u000a\u000aस्वाद प्रोफाइल: High yield, good oil content\u000a\u000aमराठी नाम: JS-9305 Soya\u000a\u000aमूल डेटासेट विवरण: Improved variety; Vidarbha; pod shatter resistant; Kharif.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
