INSERT INTO crop_variety_translations VALUES(229,115,'hi','MAUS-71','Maharashtra','High yield, good protein content','MAUS-71 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('MAUS-71 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Glycine max cv. MAUS-71\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: High yield, good protein content\u000a\u000aमराठी नाम: MAUS-71 Soya\u000a\u000aमूल डेटासेट विवरण: MPKV Rahuri; widely adapted to Maharashtra; moderate disease resistance.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
