INSERT INTO crop_variety_translations VALUES(235,118,'hi','TAG-24','India','Good oil content, bold kernel, Spanish','TAG-24 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('TAG-24 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Arachis hypogaea cv. TAG-24\u000a\u000aउत्पत्ति क्षेत्र: India\u000a\u000aस्वाद प्रोफाइल: Good oil content, bold kernel, Spanish\u000a\u000aमराठी नाम: TAG-24 Shengdana\u000a\u000aमूल डेटासेट विवरण: Tilakar Agri; drought-tolerant; Marathwada, Vidarbha; Kharif.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
