INSERT INTO crop_variety_translations VALUES(239,120,'hi','Phule Pragati','Maharashtra','Bold kernel, high oil, good yield','Phule Pragati इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Phule Pragati इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Arachis hypogaea cv. Phule Pragati\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Bold kernel, high oil, good yield\u000a\u000aमराठी नाम: Phule Pragati Shengdana\u000a\u000aमूल डेटासेट विवरण: MPKV Rahuri; improved variety; dual purpose (oil + fresh nut); Maharashtra.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(240,120,'mr','Phule Pragati Shengdana','Maharashtra','Bold kernel, high oil, good yield','Phule Pragati Shengdana ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Phule Pragati Shengdana ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Arachis hypogaea cv. Phule Pragati\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Bold kernel, high oil, good yield\u000a\u000aमराठी नाव: Phule Pragati Shengdana\u000a\u000aमूळ डेटासेट तपशील: MPKV Rahuri; improved variety; dual purpose (oil + fresh nut); Maharashtra.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(241,121,'hi','AKT-64','Maharashtra','White seed, nutty, high oil (50–54%)','AKT-64 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('AKT-64 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Sesamum indicum cv. AKT-64\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: White seed, nutty, high oil (50–54%)\u000a\u000aमराठी नाम: AKT-64 Til\u000a\u000aमूल डेटासेट विवरण: Akola series; Vidarbha and Marathwada; white-seeded; high oil; good export quality.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(242,121,'mr','AKT-64 Til','Maharashtra','White seed, nutty, high oil (50–54%)','AKT-64 Til ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('AKT-64 Til ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Sesamum indicum cv. AKT-64\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: White seed, nutty, high oil (50–54%)\u000a\u000aमराठी नाव: AKT-64 Til\u000a\u000aमूळ डेटासेट तपशील: Akola series; Vidarbha and Marathwada; white-seeded; high oil; good export quality.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(243,122,'hi','JLT-7','Maharashtra','White seed, good oil content','JLT-7 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('JLT-7 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Sesamum indicum cv. JLT-7\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: White seed, good oil content\u000a\u000aमराठी नाम: JLT-7 Til\u000a\u000aमूल डेटासेट विवरण: MPKV Jalgaon variety; North Maharashtra; Kharif; medium yield.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(244,122,'mr','JLT-7 Til','Maharashtra','White seed, good oil content','JLT-7 Til ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('JLT-7 Til ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Sesamum indicum cv. JLT-7\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: White seed, good oil content\u000a\u000aमराठी नाव: JLT-7 Til\u000a\u000aमूळ डेटासेट तपशील: MPKV Jalgaon variety; North Maharashtra; Kharif; medium yield.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(245,123,'hi','Phule Til-1','Maharashtra','White seed, high oil, improved variety','Phule Til-1 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Phule Til-1 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Sesamum indicum cv. Phule Til-1\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: White seed, high oil, improved variety\u000a\u000aमराठी नाम: Phule Til\u000a\u000aमूल डेटासेट विवरण: MPKV Rahuri; widely recommended for Maharashtra; good yield under rainfed conditions.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(246,123,'mr','Phule Til','Maharashtra','White seed, high oil, improved variety','Phule Til ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Phule Til ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Sesamum indicum cv. Phule Til-1\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: White seed, high oil, improved variety\u000a\u000aमराठी नाव: Phule Til\u000a\u000aमूळ डेटासेट तपशील: MPKV Rahuri; widely recommended for Maharashtra; good yield under rainfed conditions.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(247,124,'hi','Morden','Canada/Maharashtra','High oil content, open-pollinated','Morden इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Morden इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Helianthus annuus cv. Morden\u000a\u000aउत्पत्ति क्षेत्र: Canada/Maharashtra\u000a\u000aस्वाद प्रोफाइल: High oil content, open-pollinated\u000a\u000aमराठी नाम: Morden Suryafool\u000a\u000aमूल डेटासेट विवरण: OPV; adapted to dry conditions in Marathwada; medium height; good oil (40–45%).'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(248,124,'mr','Morden Suryafool','Canada/Maharashtra','High oil content, open-pollinated','Morden Suryafool ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Morden Suryafool ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Helianthus annuus cv. Morden\u000a\u000aउत्पत्ती क्षेत्र: Canada/Maharashtra\u000a\u000aचव वैशिष्ट्य: High oil content, open-pollinated\u000a\u000aमराठी नाव: Morden Suryafool\u000a\u000aमूळ डेटासेट तपशील: OPV; adapted to dry conditions in Marathwada; medium height; good oil (40–45%).'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(249,125,'hi','KBSH-1','Karnataka/Maharashtra','High oil (42–45%), hybrid, high yield','KBSH-1 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('KBSH-1 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Helianthus annuus cv. KBSH-1\u000a\u000aउत्पत्ति क्षेत्र: Karnataka/Maharashtra\u000a\u000aस्वाद प्रोफाइल: High oil (42–45%), hybrid, high yield\u000a\u000aमराठी नाम: KBSH-1 Suryafool\u000a\u000aमूल डेटासेट विवरण: Hybrid; UASD Dharwad; most popular sunflower hybrid in Maharashtra; Solapur, Latur.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(250,125,'mr','KBSH-1 Suryafool','Karnataka/Maharashtra','High oil (42–45%), hybrid, high yield','KBSH-1 Suryafool ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('KBSH-1 Suryafool ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Helianthus annuus cv. KBSH-1\u000a\u000aउत्पत्ती क्षेत्र: Karnataka/Maharashtra\u000a\u000aचव वैशिष्ट्य: High oil (42–45%), hybrid, high yield\u000a\u000aमराठी नाव: KBSH-1 Suryafool\u000a\u000aमूळ डेटासेट तपशील: Hybrid; UASD Dharwad; most popular sunflower hybrid in Maharashtra; Solapur, Latur.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(251,126,'hi','KBSH-44','Karnataka/Maharashtra','Very high oil, large head, hybrid','KBSH-44 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('KBSH-44 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Helianthus annuus cv. KBSH-44\u000a\u000aउत्पत्ति क्षेत्र: Karnataka/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very high oil, large head, hybrid\u000a\u000aमराठी नाम: KBSH-44 Suryafool\u000a\u000aमूल डेटासेट विवरण: Improved hybrid; UASD; downy mildew resistant; Maharashtra dry zones.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(252,126,'mr','KBSH-44 Suryafool','Karnataka/Maharashtra','Very high oil, large head, hybrid','KBSH-44 Suryafool ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('KBSH-44 Suryafool ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Helianthus annuus cv. KBSH-44\u000a\u000aउत्पत्ती क्षेत्र: Karnataka/Maharashtra\u000a\u000aचव वैशिष्ट्य: Very high oil, large head, hybrid\u000a\u000aमराठी नाव: KBSH-44 Suryafool\u000a\u000aमूळ डेटासेट तपशील: Improved hybrid; UASD; downy mildew resistant; Maharashtra dry zones.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(253,127,'hi','Co-86032','Maharashtra','High sugar (CCS 12–13%), medium-thick cane','Co-86032 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Co-86032 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Saccharum officinarum cv. Co-86032\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: High sugar (CCS 12–13%), medium-thick cane\u000a\u000aमराठी नाम: Co-86032 Oos\u000a\u000aमूल डेटासेट विवरण: Most widely grown variety in Maharashtra sugar belt; high sucrose; Pune, Satara, Sangli, Kolhapur.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(254,127,'mr','Co-86032 Oos','Maharashtra','High sugar (CCS 12–13%), medium-thick cane','Co-86032 Oos ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Co-86032 Oos ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Saccharum officinarum cv. Co-86032\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: High sugar (CCS 12–13%), medium-thick cane\u000a\u000aमराठी नाव: Co-86032 Oos\u000a\u000aमूळ डेटासेट तपशील: Most widely grown variety in Maharashtra sugar belt; high sucrose; Pune, Satara, Sangli, Kolhapur.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(255,128,'hi','CoC-671 (Karuppan)','Tamil Nadu/Maharashtra','Very high sugar, thick cane','CoC-671 (Karuppan) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('CoC-671 (Karuppan) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Saccharum officinarum cv. CoC-671\u000a\u000aउत्पत्ति क्षेत्र: Tamil Nadu/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very high sugar, thick cane\u000a\u000aमराठी नाम: CoC-671 Oos\u000a\u000aमूल डेटासेट विवरण: Red cane; high CCS; drought-tolerant; Marathwada and Solapur belt.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(256,128,'mr','CoC-671 Oos','Tamil Nadu/Maharashtra','Very high sugar, thick cane','CoC-671 Oos ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('CoC-671 Oos ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Saccharum officinarum cv. CoC-671\u000a\u000aउत्पत्ती क्षेत्र: Tamil Nadu/Maharashtra\u000a\u000aचव वैशिष्ट्य: Very high sugar, thick cane\u000a\u000aमराठी नाव: CoC-671 Oos\u000a\u000aमूळ डेटासेट तपशील: Red cane; high CCS; drought-tolerant; Marathwada and Solapur belt.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(257,129,'hi','Co-94012','Maharashtra','High yield, high sugar, thin-medium cane','Co-94012 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Co-94012 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Saccharum officinarum cv. Co-94012\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: High yield, high sugar, thin-medium cane\u000a\u000aमराठी नाम: Co-94012 Oos\u000a\u000aमूल डेटासेट विवरण: Developed for Maharashtra; resistant to red rot; Nashik, Ahmednagar, Pune.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(258,129,'mr','Co-94012 Oos','Maharashtra','High yield, high sugar, thin-medium cane','Co-94012 Oos ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Co-94012 Oos ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Saccharum officinarum cv. Co-94012\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: High yield, high sugar, thin-medium cane\u000a\u000aमराठी नाव: Co-94012 Oos\u000a\u000aमूळ डेटासेट तपशील: Developed for Maharashtra; resistant to red rot; Nashik, Ahmednagar, Pune.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(259,130,'hi','Phule-265 (VSI-434)','Maharashtra','High sugar, high yield, mid-late variety','Phule-265 (VSI-434) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Phule-265 (VSI-434) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Saccharum officinarum cv. Phule-265\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: High sugar, high yield, mid-late variety\u000a\u000aमराठी नाम: Phule Oos\u000a\u000aमूल डेटासेट विवरण: Developed at Vasantdada Sugar Institute, Pune; ideal for cooperative factories; Pune, Satara.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(260,130,'mr','Phule Oos','Maharashtra','High sugar, high yield, mid-late variety','Phule Oos ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Phule Oos ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Saccharum officinarum cv. Phule-265\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: High sugar, high yield, mid-late variety\u000a\u000aमराठी नाव: Phule Oos\u000a\u000aमूळ डेटासेट तपशील: Developed at Vasantdada Sugar Institute, Pune; ideal for cooperative factories; Pune, Satara.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(261,131,'hi','Co-740','Maharashtra','Early maturity, good sugar recovery','Co-740 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Co-740 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Saccharum officinarum cv. Co-740\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Early maturity, good sugar recovery\u000a\u000aमराठी नाम: Co-740 Oos\u000a\u000aमूल डेटासेट विवरण: Early variety; once the most grown in Maharashtra; being replaced by newer hybrids.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(262,131,'mr','Co-740 Oos','Maharashtra','Early maturity, good sugar recovery','Co-740 Oos ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Co-740 Oos ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Saccharum officinarum cv. Co-740\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Early maturity, good sugar recovery\u000a\u000aमराठी नाव: Co-740 Oos\u000a\u000aमूळ डेटासेट तपशील: Early variety; once the most grown in Maharashtra; being replaced by newer hybrids.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(263,132,'hi','MS-10001 (Phule Mahadhan)','Maharashtra','Very high yield, high CCS','MS-10001 (Phule Mahadhan) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('MS-10001 (Phule Mahadhan) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Saccharum officinarum cv. MS-10001\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very high yield, high CCS\u000a\u000aमराठी नाम: Phule Mahadhan Oos\u000a\u000aमूल डेटासेट विवरण: Latest high-yield release by MPKV and VSI; Pune, Satara, Sangli; water-efficient under drip.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(264,132,'mr','Phule Mahadhan Oos','Maharashtra','Very high yield, high CCS','Phule Mahadhan Oos ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Phule Mahadhan Oos ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Saccharum officinarum cv. MS-10001\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Very high yield, high CCS\u000a\u000aमराठी नाव: Phule Mahadhan Oos\u000a\u000aमूळ डेटासेट तपशील: Latest high-yield release by MPKV and VSI; Pune, Satara, Sangli; water-efficient under drip.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(265,133,'hi','Bhima Raj','Maharashtra','Mild-pungent, red-purple, firm, long shelf life','Bhima Raj इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Bhima Raj इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Allium cepa cv. Bhima Raj\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Mild-pungent, red-purple, firm, long shelf life\u000a\u000aमराठी नाम: Bhima Raj Kanda\u000a\u000aमूल डेटासेट विवरण: ICAR-DOGR Pune; most popular commercial variety; excellent storage and export quality; Nashik, Pune, Ahmednagar; Rabi.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(266,133,'mr','Bhima Raj Kanda','Maharashtra','Mild-pungent, red-purple, firm, long shelf life','Bhima Raj Kanda ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Bhima Raj Kanda ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Allium cepa cv. Bhima Raj\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Mild-pungent, red-purple, firm, long shelf life\u000a\u000aमराठी नाव: Bhima Raj Kanda\u000a\u000aमूळ डेटासेट तपशील: ICAR-DOGR Pune; most popular commercial variety; excellent storage and export quality; Nashik, Pune, Ahmednagar; Rabi.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(267,134,'hi','Bhima Super','Maharashtra','Pungent, dark red, globular, good yield','Bhima Super इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Bhima Super इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Allium cepa cv. Bhima Super\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Pungent, dark red, globular, good yield\u000a\u000aमराठी नाम: Bhima Super Kanda\u000a\u000aमूल डेटासेट विवरण: ICAR-DOGR; high yield; Rabi and Late Kharif; good storage; Nashik, Solapur.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(268,134,'mr','Bhima Super Kanda','Maharashtra','Pungent, dark red, globular, good yield','Bhima Super Kanda ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Bhima Super Kanda ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Allium cepa cv. Bhima Super\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Pungent, dark red, globular, good yield\u000a\u000aमराठी नाव: Bhima Super Kanda\u000a\u000aमूळ डेटासेट तपशील: ICAR-DOGR; high yield; Rabi and Late Kharif; good storage; Nashik, Solapur.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(269,135,'hi','Bhima Kiran','Maharashtra','Pungent, reddish, high yield, Kharif','Bhima Kiran इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Bhima Kiran इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Allium cepa cv. Bhima Kiran\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Pungent, reddish, high yield, Kharif\u000a\u000aमराठी नाम: Bhima Kiran Kanda\u000a\u000aमूल डेटासेट विवरण: Kharif/Late Kharif specialist; ICAR-DOGR; resistant to purple blotch; Pune, Nashik.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(270,135,'mr','Bhima Kiran Kanda','Maharashtra','Pungent, reddish, high yield, Kharif','Bhima Kiran Kanda ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Bhima Kiran Kanda ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Allium cepa cv. Bhima Kiran\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Pungent, reddish, high yield, Kharif\u000a\u000aमराठी नाव: Bhima Kiran Kanda\u000a\u000aमूळ डेटासेट तपशील: Kharif/Late Kharif specialist; ICAR-DOGR; resistant to purple blotch; Pune, Nashik.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(271,136,'hi','N-2-4-1 (NHRDF)','Maharashtra','Mild pungent, red, medium bulb, Rabi','N-2-4-1 (NHRDF) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('N-2-4-1 (NHRDF) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Allium cepa cv. N-2-4-1\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Mild pungent, red, medium bulb, Rabi\u000a\u000aमराठी नाम: N-2-4-1 Kanda\u000a\u000aमूल डेटासेट विवरण: NHRDF variety; popular for Rabi; Maharashtra and Karnataka; export quality; Nashik.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(272,136,'mr','N-2-4-1 Kanda','Maharashtra','Mild pungent, red, medium bulb, Rabi','N-2-4-1 Kanda ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('N-2-4-1 Kanda ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Allium cepa cv. N-2-4-1\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Mild pungent, red, medium bulb, Rabi\u000a\u000aमराठी नाव: N-2-4-1 Kanda\u000a\u000aमूळ डेटासेट तपशील: NHRDF variety; popular for Rabi; Maharashtra and Karnataka; export quality; Nashik.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(273,137,'hi','Agrifound Light Red','Maharashtra','Mild pungent, light red, good export','Agrifound Light Red इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Agrifound Light Red इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Allium cepa cv. Agrifound Light Red\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Mild pungent, light red, good export\u000a\u000aमराठी नाम: Phikka Lal Kanda\u000a\u000aमूल डेटासेट विवरण: NHRDF; light-red colour preferred in Europe; export-grade; Nashik, Pune.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(274,137,'mr','Phikka Lal Kanda','Maharashtra','Mild pungent, light red, good export','Phikka Lal Kanda ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Phikka Lal Kanda ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Allium cepa cv. Agrifound Light Red\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Mild pungent, light red, good export\u000a\u000aमराठी नाव: Phikka Lal Kanda\u000a\u000aमूळ डेटासेट तपशील: NHRDF; light-red colour preferred in Europe; export-grade; Nashik, Pune.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(275,138,'hi','Phule Samarth','Maharashtra','Pungent, deep red, high yield, hybrid','Phule Samarth इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Phule Samarth इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Allium cepa cv. Phule Samarth\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Pungent, deep red, high yield, hybrid\u000a\u000aमराठी नाम: Phule Samarth Kanda\u000a\u000aमूल डेटासेट विवरण: MPKV Rahuri F1 hybrid; very high yield; Rabi; excellent storage; recommended for export belt.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(276,138,'mr','Phule Samarth Kanda','Maharashtra','Pungent, deep red, high yield, hybrid','Phule Samarth Kanda ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Phule Samarth Kanda ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Allium cepa cv. Phule Samarth\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Pungent, deep red, high yield, hybrid\u000a\u000aमराठी नाव: Phule Samarth Kanda\u000a\u000aमूळ डेटासेट तपशील: MPKV Rahuri F1 hybrid; very high yield; Rabi; excellent storage; recommended for export belt.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(277,139,'hi','Nasik Red (Local)','Maharashtra','Very pungent, classic red, traditional variety','Nasik Red (Local) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Nasik Red (Local) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Allium cepa (local landrace)\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very pungent, classic red, traditional variety\u000a\u000aमराठी नाम: Nashik Lal Kanda\u000a\u000aमूल डेटासेट विवरण: Traditional Nashik landrace; smaller bulb; intense flavour; preferred in domestic market and for export dehydration.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(278,139,'mr','Nashik Lal Kanda','Maharashtra','Very pungent, classic red, traditional variety','Nashik Lal Kanda ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Nashik Lal Kanda ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Allium cepa (local landrace)\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Very pungent, classic red, traditional variety\u000a\u000aमराठी नाव: Nashik Lal Kanda\u000a\u000aमूळ डेटासेट तपशील: Traditional Nashik landrace; smaller bulb; intense flavour; preferred in domestic market and for export dehydration.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(279,140,'hi','Phule Raja','Maharashtra','Firm, red, medium-large, good shelf life','Phule Raja इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Phule Raja इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Solanum lycopersicum cv. Phule Raja\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Firm, red, medium-large, good shelf life\u000a\u000aमराठी नाम: Phule Raja Tomato\u000a\u000aमूल डेटासेट विवरण: MPKV Rahuri; popular commercial variety; suitable for fresh market and processing; Maharashtra Rabi/summer.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(280,140,'mr','Phule Raja Tomato','Maharashtra','Firm, red, medium-large, good shelf life','Phule Raja Tomato ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Phule Raja Tomato ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Solanum lycopersicum cv. Phule Raja\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Firm, red, medium-large, good shelf life\u000a\u000aमराठी नाव: Phule Raja Tomato\u000a\u000aमूळ डेटासेट तपशील: MPKV Rahuri; popular commercial variety; suitable for fresh market and processing; Maharashtra Rabi/summer.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(281,141,'hi','Namdhari NS-5252','Maharashtra','Firm, uniform red, hybrid, long shelf life','Namdhari NS-5252 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Namdhari NS-5252 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Solanum lycopersicum cv. NS-5252\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Firm, uniform red, hybrid, long shelf life\u000a\u000aमराठी नाम: NS-5252 Tomato\u000a\u000aमूल डेटासेट विवरण: Namdhari Seeds F1 hybrid; widely grown in Nashik, Pune; good for transport and export.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(282,141,'mr','NS-5252 Tomato','Maharashtra','Firm, uniform red, hybrid, long shelf life','NS-5252 Tomato ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('NS-5252 Tomato ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Solanum lycopersicum cv. NS-5252\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Firm, uniform red, hybrid, long shelf life\u000a\u000aमराठी नाव: NS-5252 Tomato\u000a\u000aमूळ डेटासेट तपशील: Namdhari Seeds F1 hybrid; widely grown in Nashik, Pune; good for transport and export.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(283,142,'hi','Syngenta Naveen','Maharashtra','Bright red, firm, medium, disease tolerant','Syngenta Naveen इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Syngenta Naveen इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Solanum lycopersicum cv. Naveen\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Bright red, firm, medium, disease tolerant\u000a\u000aमराठी नाम: Naveen Tomato\u000a\u000aमूल डेटासेट विवरण: Popular hybrid; resistance to ToMV; Nashik, Satara; early bearing.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(284,142,'mr','Naveen Tomato','Maharashtra','Bright red, firm, medium, disease tolerant','Naveen Tomato ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Naveen Tomato ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Solanum lycopersicum cv. Naveen\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Bright red, firm, medium, disease tolerant\u000a\u000aमराठी नाव: Naveen Tomato\u000a\u000aमूळ डेटासेट तपशील: Popular hybrid; resistance to ToMV; Nashik, Satara; early bearing.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(285,143,'hi','Pusa Ruby','India','Medium red, slightly acidic, open-pollinated','Pusa Ruby इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Pusa Ruby इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Solanum lycopersicum cv. Pusa Ruby\u000a\u000aउत्पत्ति क्षेत्र: India\u000a\u000aस्वाद प्रोफाइल: Medium red, slightly acidic, open-pollinated\u000a\u000aमराठी नाम: Pusa Ruby Tomato\u000a\u000aमूल डेटासेट विवरण: IARI variety; OPV; widely grown; Nashik, Pune; good for home gardens and subsistence farming.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(286,143,'mr','Pusa Ruby Tomato','India','Medium red, slightly acidic, open-pollinated','Pusa Ruby Tomato ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Pusa Ruby Tomato ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Solanum lycopersicum cv. Pusa Ruby\u000a\u000aउत्पत्ती क्षेत्र: India\u000a\u000aचव वैशिष्ट्य: Medium red, slightly acidic, open-pollinated\u000a\u000aमराठी नाव: Pusa Ruby Tomato\u000a\u000aमूळ डेटासेट तपशील: IARI variety; OPV; widely grown; Nashik, Pune; good for home gardens and subsistence farming.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(287,144,'hi','Arka Vikas','Maharashtra','Large, red, firm, good yield, OPV','Arka Vikas इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Arka Vikas इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Solanum lycopersicum cv. Arka Vikas\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Large, red, firm, good yield, OPV\u000a\u000aमराठी नाम: Arka Vikas Tomato\u000a\u000aमूल डेटासेट विवरण: IIHR Bengaluru; adapted to Maharashtra; suitable for rainy season; wilt-tolerant.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(288,144,'mr','Arka Vikas Tomato','Maharashtra','Large, red, firm, good yield, OPV','Arka Vikas Tomato ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Arka Vikas Tomato ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Solanum lycopersicum cv. Arka Vikas\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Large, red, firm, good yield, OPV\u000a\u000aमराठी नाव: Arka Vikas Tomato\u000a\u000aमूळ डेटासेट तपशील: IIHR Bengaluru; adapted to Maharashtra; suitable for rainy season; wilt-tolerant.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(289,145,'hi','Sathgudi','Andhra Pradesh/Maharashtra','Mildly sweet, very juicy, thin skin','Sathgudi इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Sathgudi इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrus limetta cv. Sathgudi\u000a\u000aउत्पत्ति क्षेत्र: Andhra Pradesh/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Mildly sweet, very juicy, thin skin\u000a\u000aमराठी नाम: Sathgudi Mosambi\u000a\u000aमूल डेटासेट विवरण: Most widely grown Mosambi variety in Maharashtra; Solapur, Osmanabad; high juice content; year-round availability.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(290,145,'mr','Sathgudi Mosambi','Andhra Pradesh/Maharashtra','Mildly sweet, very juicy, thin skin','Sathgudi Mosambi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Sathgudi Mosambi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrus limetta cv. Sathgudi\u000a\u000aउत्पत्ती क्षेत्र: Andhra Pradesh/Maharashtra\u000a\u000aचव वैशिष्ट्य: Mildly sweet, very juicy, thin skin\u000a\u000aमराठी नाव: Sathgudi Mosambi\u000a\u000aमूळ डेटासेट तपशील: Most widely grown Mosambi variety in Maharashtra; Solapur, Osmanabad; high juice content; year-round availability.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(291,146,'hi','Phule Mosambi-1','Maharashtra','Sweet, juicy, good rind colour','Phule Mosambi-1 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Phule Mosambi-1 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrus limetta cv. Phule Mosambi-1\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, juicy, good rind colour\u000a\u000aमराठी नाम: Phule Mosambi\u000a\u000aमूल डेटासेट विवरण: MPKV Rahuri developed; suitable for Maharashtra''s dry zones; good adaptation.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(292,146,'mr','Phule Mosambi','Maharashtra','Sweet, juicy, good rind colour','Phule Mosambi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Phule Mosambi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrus limetta cv. Phule Mosambi-1\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, juicy, good rind colour\u000a\u000aमराठी नाव: Phule Mosambi\u000a\u000aमूळ डेटासेट तपशील: MPKV Rahuri developed; suitable for Maharashtra''s dry zones; good adaptation.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(293,147,'hi','Seedless Mosambi (Local)','Maharashtra','Sweet, nearly seedless, smooth skin','Seedless Mosambi (Local) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Seedless Mosambi (Local) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrus limetta (seedless type)\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, nearly seedless, smooth skin\u000a\u000aमराठी नाम: Bijrahit Mosambi\u000a\u000aमूल डेटासेट विवरण: Seedless selections grown in Pune and Solapur; premium market; limited production.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(294,147,'mr','Bijrahit Mosambi','Maharashtra','Sweet, nearly seedless, smooth skin','Bijrahit Mosambi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Bijrahit Mosambi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrus limetta (seedless type)\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, nearly seedless, smooth skin\u000a\u000aमराठी नाव: Bijrahit Mosambi\u000a\u000aमूळ डेटासेट तपशील: Seedless selections grown in Pune and Solapur; premium market; limited production.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(295,148,'hi','Yamuna Safed (G-1)','India','Strongly pungent, white, large cloves','Yamuna Safed (G-1) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Yamuna Safed (G-1) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Allium sativum cv. Yamuna Safed\u000a\u000aउत्पत्ति क्षेत्र: India\u000a\u000aस्वाद प्रोफाइल: Strongly pungent, white, large cloves\u000a\u000aमराठी नाम: Yamuna Safed Lasun\u000a\u000aमूल डेटासेट विवरण: NHRDF variety; most popular in Maharashtra; large white bulb; good storage; Nashik, Pune.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(296,148,'mr','Yamuna Safed Lasun','India','Strongly pungent, white, large cloves','Yamuna Safed Lasun ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Yamuna Safed Lasun ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Allium sativum cv. Yamuna Safed\u000a\u000aउत्पत्ती क्षेत्र: India\u000a\u000aचव वैशिष्ट्य: Strongly pungent, white, large cloves\u000a\u000aमराठी नाव: Yamuna Safed Lasun\u000a\u000aमूळ डेटासेट तपशील: NHRDF variety; most popular in Maharashtra; large white bulb; good storage; Nashik, Pune.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(297,149,'hi','Phule Bahugunak','Maharashtra','Very pungent, big bulb, long shelf life','Phule Bahugunak इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Phule Bahugunak इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Allium sativum cv. Phule Bahugunak\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very pungent, big bulb, long shelf life\u000a\u000aमराठी नाम: Phule Bahugunak Lasun\u000a\u000aमूल डेटासेट विवरण: MPKV Rahuri; specifically bred for Maharashtra conditions; high yield; Nashik, Satara.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(298,149,'mr','Phule Bahugunak Lasun','Maharashtra','Very pungent, big bulb, long shelf life','Phule Bahugunak Lasun ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Phule Bahugunak Lasun ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Allium sativum cv. Phule Bahugunak\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Very pungent, big bulb, long shelf life\u000a\u000aमराठी नाव: Phule Bahugunak Lasun\u000a\u000aमूळ डेटासेट तपशील: MPKV Rahuri; specifically bred for Maharashtra conditions; high yield; Nashik, Satara.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(299,150,'hi','Agrifound White (G-41)','Maharashtra','Pungent, white, medium bulb, export quality','Agrifound White (G-41) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Agrifound White (G-41) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Allium sativum cv. G-41\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Pungent, white, medium bulb, export quality\u000a\u000aमराठी नाम: Safed Lasun\u000a\u000aमूल डेटासेट विवरण: NHRDF; export-grade white garlic; Maharashtra and Rajasthan; Nashik, Solapur.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(300,150,'mr','Safed Lasun','Maharashtra','Pungent, white, medium bulb, export quality','Safed Lasun ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Safed Lasun ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Allium sativum cv. G-41\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Pungent, white, medium bulb, export quality\u000a\u000aमराठी नाव: Safed Lasun\u000a\u000aमूळ डेटासेट तपशील: NHRDF; export-grade white garlic; Maharashtra and Rajasthan; Nashik, Solapur.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(301,151,'hi','Desi Kali (Local Black Garlic)','Maharashtra','Strongly pungent, purple-tinged cloves','Desi Kali (Local Black Garlic) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Desi Kali (Local Black Garlic) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Allium sativum (local landrace)\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Strongly pungent, purple-tinged cloves\u000a\u000aमराठी नाम: Desi Kali Lasun\u000a\u000aमूल डेटासेट विवरण: Indigenous variety; smaller bulb; intense flavour; drought tolerant; grown without irrigation in Marathwada.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(302,151,'mr','Desi Kali Lasun','Maharashtra','Strongly pungent, purple-tinged cloves','Desi Kali Lasun ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Desi Kali Lasun ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Allium sativum (local landrace)\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Strongly pungent, purple-tinged cloves\u000a\u000aमराठी नाव: Desi Kali Lasun\u000a\u000aमूळ डेटासेट तपशील: Indigenous variety; smaller bulb; intense flavour; drought tolerant; grown without irrigation in Marathwada.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(303,152,'hi','Sangli Turmeric (Erande/Rajapuri)','Maharashtra','High curcumin (>4.5%), intense golden, earthy-bitter','Sangli Turmeric (Erande/Rajapuri) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Sangli Turmeric (Erande/Rajapuri) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Curcuma longa cv. Rajapuri\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: High curcumin (>4.5%), intense golden, earthy-bitter\u000a\u000aमराठी नाम: Sangli Halad\u000a\u000aमूल डेटासेट विवरण: GI-tagged; grown in Sangli, Kolhapur, Satara; premium price; thick rhizome; dry and polished for export. Best curcumin content in world.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(304,152,'mr','Sangli Halad','Maharashtra','High curcumin (>4.5%), intense golden, earthy-bitter','Sangli Halad ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Sangli Halad ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Curcuma longa cv. Rajapuri\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: High curcumin (>4.5%), intense golden, earthy-bitter\u000a\u000aमराठी नाव: Sangli Halad\u000a\u000aमूळ डेटासेट तपशील: GI-tagged; grown in Sangli, Kolhapur, Satara; premium price; thick rhizome; dry and polished for export. Best curcumin content in world.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(305,153,'hi','Phule Swarnim','Maharashtra','High curcumin, good yield, improved variety','Phule Swarnim इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Phule Swarnim इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Curcuma longa cv. Phule Swarnim\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: High curcumin, good yield, improved variety\u000a\u000aमराठी नाम: Phule Swarnim Halad\u000a\u000aमूल डेटासेट विवरण: MPKV Rahuri; specifically bred for Maharashtra; high curcumin and yield; Sangli, Satara.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(306,153,'mr','Phule Swarnim Halad','Maharashtra','High curcumin, good yield, improved variety','Phule Swarnim Halad ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Phule Swarnim Halad ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Curcuma longa cv. Phule Swarnim\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: High curcumin, good yield, improved variety\u000a\u000aमराठी नाव: Phule Swarnim Halad\u000a\u000aमूळ डेटासेट तपशील: MPKV Rahuri; specifically bred for Maharashtra; high curcumin and yield; Sangli, Satara.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(307,154,'hi','Selam','Tamil Nadu/Maharashtra','Medium curcumin, round finger, good yield','Selam इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Selam इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Curcuma longa cv. Salem\u000a\u000aउत्पत्ति क्षेत्र: Tamil Nadu/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Medium curcumin, round finger, good yield\u000a\u000aमराठी नाम: Salem Halad\u000a\u000aमूल डेटासेट विवरण: Salem type; popular in Pune, Nashik; early maturing; bright yellow colour.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(308,154,'mr','Salem Halad','Tamil Nadu/Maharashtra','Medium curcumin, round finger, good yield','Salem Halad ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Salem Halad ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Curcuma longa cv. Salem\u000a\u000aउत्पत्ती क्षेत्र: Tamil Nadu/Maharashtra\u000a\u000aचव वैशिष्ट्य: Medium curcumin, round finger, good yield\u000a\u000aमराठी नाव: Salem Halad\u000a\u000aमूळ डेटासेट तपशील: Salem type; popular in Pune, Nashik; early maturing; bright yellow colour.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(309,155,'hi','Sugandham','Maharashtra','Aromatic, high oil, good curcumin','Sugandham इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Sugandham इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Curcuma longa cv. Sugandham\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Aromatic, high oil, good curcumin\u000a\u000aमराठी नाम: Sugandhi Halad\u000a\u000aमूल डेटासेट विवरण: Aromatic variety; IISR Kozhikode; adapted to Maharashtra; good for value-added products.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(310,155,'mr','Sugandhi Halad','Maharashtra','Aromatic, high oil, good curcumin','Sugandhi Halad ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Sugandhi Halad ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Curcuma longa cv. Sugandham\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Aromatic, high oil, good curcumin\u000a\u000aमराठी नाव: Sugandhi Halad\u000a\u000aमूळ डेटासेट तपशील: Aromatic variety; IISR Kozhikode; adapted to Maharashtra; good for value-added products.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(311,156,'hi','Pratibha','Maharashtra','High curcumin (4–5%), bold rhizome','Pratibha इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Pratibha इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Curcuma longa cv. Pratibha\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: High curcumin (4–5%), bold rhizome\u000a\u000aमराठी नाम: Pratibha Halad\u000a\u000aमूल डेटासेट विवरण: MPKV variety; Sangli and Kolhapur; high export value; disease-tolerant.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(312,156,'mr','Pratibha Halad','Maharashtra','High curcumin (4–5%), bold rhizome','Pratibha Halad ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Pratibha Halad ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Curcuma longa cv. Pratibha\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: High curcumin (4–5%), bold rhizome\u000a\u000aमराठी नाव: Pratibha Halad\u000a\u000aमूळ डेटासेट तपशील: MPKV variety; Sangli and Kolhapur; high export value; disease-tolerant.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(313,157,'hi','Kolhapuri Chilli (Lavangi)','Maharashtra','Extremely hot, deep red, smoky-earthy','Kolhapuri Chilli (Lavangi) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Kolhapuri Chilli (Lavangi) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Capsicum annuum cv. Lavangi\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Extremely hot, deep red, smoky-earthy\u000a\u000aमराठी नाम: Lavangi Mirchi\u000a\u000aमूल डेटासेट विवरण: GI-tagged; Kolhapur and Sangli; small, thin chilli; very high Scoville (>100,000 SHU); essential for Kolhapuri masala and dry red chilli powder; prized export variety.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(314,157,'mr','Lavangi Mirchi','Maharashtra','Extremely hot, deep red, smoky-earthy','Lavangi Mirchi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Lavangi Mirchi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Capsicum annuum cv. Lavangi\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Extremely hot, deep red, smoky-earthy\u000a\u000aमराठी नाव: Lavangi Mirchi\u000a\u000aमूळ डेटासेट तपशील: GI-tagged; Kolhapur and Sangli; small, thin chilli; very high Scoville (>100,000 SHU); essential for Kolhapuri masala and dry red chilli powder; prized export variety.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(315,158,'hi','Phule Jyoti','Maharashtra','Medium hot, bright red, high yield','Phule Jyoti इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Phule Jyoti इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Capsicum annuum cv. Phule Jyoti\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Medium hot, bright red, high yield\u000a\u000aमराठी नाम: Phule Jyoti Mirchi\u000a\u000aमूल डेटासेट विवरण: MPKV Rahuri; popular commercial variety; Maharashtra Kharif; good for fresh and dry use.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(316,158,'mr','Phule Jyoti Mirchi','Maharashtra','Medium hot, bright red, high yield','Phule Jyoti Mirchi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Phule Jyoti Mirchi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Capsicum annuum cv. Phule Jyoti\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Medium hot, bright red, high yield\u000a\u000aमराठी नाव: Phule Jyoti Mirchi\u000a\u000aमूळ डेटासेट तपशील: MPKV Rahuri; popular commercial variety; Maharashtra Kharif; good for fresh and dry use.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(317,159,'hi','Byadgi Chilli','Karnataka/Maharashtra','Mildly hot, deep red, high colour (ASTA)','Byadgi Chilli इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Byadgi Chilli इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Capsicum annuum cv. Byadgi\u000a\u000aउत्पत्ति क्षेत्र: Karnataka/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Mildly hot, deep red, high colour (ASTA)\u000a\u000aमराठी नाम: Byadgi Mirchi\u000a\u000aमूल डेटासेट विवरण: Grown in Aurangabad and Osmanabad; bright colour without high pungency; ideal for colour-extraction and masala powders; high export demand.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(318,159,'mr','Byadgi Mirchi','Karnataka/Maharashtra','Mildly hot, deep red, high colour (ASTA)','Byadgi Mirchi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Byadgi Mirchi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Capsicum annuum cv. Byadgi\u000a\u000aउत्पत्ती क्षेत्र: Karnataka/Maharashtra\u000a\u000aचव वैशिष्ट्य: Mildly hot, deep red, high colour (ASTA)\u000a\u000aमराठी नाव: Byadgi Mirchi\u000a\u000aमूळ डेटासेट तपशील: Grown in Aurangabad and Osmanabad; bright colour without high pungency; ideal for colour-extraction and masala powders; high export demand.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(319,160,'hi','Kashmiri Chilli (Maharashtra Grown)','Maharashtra','Very mild, deep red, high colour','Kashmiri Chilli (Maharashtra Grown) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Kashmiri Chilli (Maharashtra Grown) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Capsicum annuum cv. K-2\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very mild, deep red, high colour\u000a\u000aमराठी नाम: Kashmiri Mirchi\u000a\u000aमूल डेटासेट विवरण: Low-pungency variety grown in Maharashtra for colour; used in tandoori, butter chicken; Nashik and Aurangabad.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(320,160,'mr','Kashmiri Mirchi','Maharashtra','Very mild, deep red, high colour','Kashmiri Mirchi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Kashmiri Mirchi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Capsicum annuum cv. K-2\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Very mild, deep red, high colour\u000a\u000aमराठी नाव: Kashmiri Mirchi\u000a\u000aमूळ डेटासेट तपशील: Low-pungency variety grown in Maharashtra for colour; used in tandoori, butter chicken; Nashik and Aurangabad.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(321,161,'hi','Arka Meghana','Maharashtra','Hot, bold red fruit, high yield, hybrid','Arka Meghana इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Arka Meghana इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Capsicum annuum cv. Arka Meghana\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Hot, bold red fruit, high yield, hybrid\u000a\u000aमराठी नाम: Arka Meghana Mirchi\u000a\u000aमूल डेटासेट विवरण: IIHR Bengaluru F1 hybrid; adapted to Maharashtra; wilt and virus resistant; Nashik, Pune.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(322,161,'mr','Arka Meghana Mirchi','Maharashtra','Hot, bold red fruit, high yield, hybrid','Arka Meghana Mirchi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Arka Meghana Mirchi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Capsicum annuum cv. Arka Meghana\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Hot, bold red fruit, high yield, hybrid\u000a\u000aमराठी नाव: Arka Meghana Mirchi\u000a\u000aमूळ डेटासेट तपशील: IIHR Bengaluru F1 hybrid; adapted to Maharashtra; wilt and virus resistant; Nashik, Pune.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(323,162,'hi','Pusa Jwala','India','Very hot, green to red, thin-walled, aromatic','Pusa Jwala इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Pusa Jwala इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Capsicum annuum cv. Pusa Jwala\u000a\u000aउत्पत्ति क्षेत्र: India\u000a\u000aस्वाद प्रोफाइल: Very hot, green to red, thin-walled, aromatic\u000a\u000aमराठी नाम: Pusa Jwala Mirchi\u000a\u000aमूल डेटासेट विवरण: IARI variety; widely grown across Maharashtra; popular for fresh green and dry red market; Nashik, Aurangabad.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(324,162,'mr','Pusa Jwala Mirchi','India','Very hot, green to red, thin-walled, aromatic','Pusa Jwala Mirchi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Pusa Jwala Mirchi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Capsicum annuum cv. Pusa Jwala\u000a\u000aउत्पत्ती क्षेत्र: India\u000a\u000aचव वैशिष्ट्य: Very hot, green to red, thin-walled, aromatic\u000a\u000aमराठी नाव: Pusa Jwala Mirchi\u000a\u000aमूळ डेटासेट तपशील: IARI variety; widely grown across Maharashtra; popular for fresh green and dry red market; Nashik, Aurangabad.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(325,163,'hi','Mahadeo (Local Konkan)','Maharashtra','Very pungent, aromatic, high oil, spicy','Mahadeo (Local Konkan) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Mahadeo (Local Konkan) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Zingiber officinale (local landrace)\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very pungent, aromatic, high oil, spicy\u000a\u000aमराठी नाम: Konkan Aale\u000a\u000aमूल डेटासेट विवरण: Traditional high-oil landrace from Western Ghats; Satara, Kolhapur, Sindhudurg; premium dried ginger (Soonth); high gingerol content.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(326,163,'mr','Konkan Aale','Maharashtra','Very pungent, aromatic, high oil, spicy','Konkan Aale ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Konkan Aale ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Zingiber officinale (local landrace)\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Very pungent, aromatic, high oil, spicy\u000a\u000aमराठी नाव: Konkan Aale\u000a\u000aमूळ डेटासेट तपशील: Traditional high-oil landrace from Western Ghats; Satara, Kolhapur, Sindhudurg; premium dried ginger (Soonth); high gingerol content.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(327,164,'hi','Suprabha','India (IISR)','Pungent, high yield, good oleoresin','Suprabha इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Suprabha इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Zingiber officinale cv. Suprabha\u000a\u000aउत्पत्ति क्षेत्र: India (IISR)\u000a\u000aस्वाद प्रोफाइल: Pungent, high yield, good oleoresin\u000a\u000aमराठी नाम: Suprabha Aale\u000a\u000aमूल डेटासेट विवरण: ICAR-IISR Kozhikode; adapted to Maharashtra; high yield; good for fresh and processing market.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(328,164,'mr','Suprabha Aale','India (IISR)','Pungent, high yield, good oleoresin','Suprabha Aale ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Suprabha Aale ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Zingiber officinale cv. Suprabha\u000a\u000aउत्पत्ती क्षेत्र: India (IISR)\u000a\u000aचव वैशिष्ट्य: Pungent, high yield, good oleoresin\u000a\u000aमराठी नाव: Suprabha Aale\u000a\u000aमूळ डेटासेट तपशील: ICAR-IISR Kozhikode; adapted to Maharashtra; high yield; good for fresh and processing market.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(329,165,'hi','Himgiri','Himachal Pradesh/Maharashtra','Medium pungent, high yield, large rhizome','Himgiri इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Himgiri इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Zingiber officinale cv. Himgiri\u000a\u000aउत्पत्ति क्षेत्र: Himachal Pradesh/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Medium pungent, high yield, large rhizome\u000a\u000aमराठी नाम: Himgiri Aale\u000a\u000aमूल डेटासेट विवरण: Adapted to highlands; Satara and Pune hills; good fresh ginger yield.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(330,165,'mr','Himgiri Aale','Himachal Pradesh/Maharashtra','Medium pungent, high yield, large rhizome','Himgiri Aale ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Himgiri Aale ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Zingiber officinale cv. Himgiri\u000a\u000aउत्पत्ती क्षेत्र: Himachal Pradesh/Maharashtra\u000a\u000aचव वैशिष्ट्य: Medium pungent, high yield, large rhizome\u000a\u000aमराठी नाव: Himgiri Aale\u000a\u000aमूळ डेटासेट तपशील: Adapted to highlands; Satara and Pune hills; good fresh ginger yield.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(331,166,'hi','Rio-de-Janeiro','Brazil/Maharashtra','Mild pungent, plump rhizome, high fresh weight','Rio-de-Janeiro इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Rio-de-Janeiro इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Zingiber officinale cv. Rio-de-Janeiro\u000a\u000aउत्पत्ति क्षेत्र: Brazil/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Mild pungent, plump rhizome, high fresh weight\u000a\u000aमराठी नाम: Rio Aale\u000a\u000aमूल डेटासेट विवरण: Low fibre; preferred for fresh vegetable use; grown in Pune and Nashik irrigated areas.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(332,166,'mr','Rio Aale','Brazil/Maharashtra','Mild pungent, plump rhizome, high fresh weight','Rio Aale ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Rio Aale ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Zingiber officinale cv. Rio-de-Janeiro\u000a\u000aउत्पत्ती क्षेत्र: Brazil/Maharashtra\u000a\u000aचव वैशिष्ट्य: Mild pungent, plump rhizome, high fresh weight\u000a\u000aमराठी नाव: Rio Aale\u000a\u000aमूळ डेटासेट तपशील: Low fibre; preferred for fresh vegetable use; grown in Pune and Nashik irrigated areas.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(333,167,'hi','Pragati','Maharashtra','Sweet-sour, thick pulp, low seed, high yield','Pragati इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Pragati इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Tamarindus indica cv. Pragati\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet-sour, thick pulp, low seed, high yield\u000a\u000aमराठी नाम: Pragati Chincha\u000a\u000aमूल डेटासेट विवरण: Improved selection; high pulp-to-seed ratio; Maharashtra''s Marathwada belt; grafted plants available from MPKV.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(334,167,'mr','Pragati Chincha','Maharashtra','Sweet-sour, thick pulp, low seed, high yield','Pragati Chincha ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Pragati Chincha ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Tamarindus indica cv. Pragati\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet-sour, thick pulp, low seed, high yield\u000a\u000aमराठी नाव: Pragati Chincha\u000a\u000aमूळ डेटासेट तपशील: Improved selection; high pulp-to-seed ratio; Maharashtra''s Marathwada belt; grafted plants available from MPKV.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(335,168,'hi','PKM-1','Tamil Nadu/Maharashtra','Sour-sweet, fleshy, low fibre, high pulp','PKM-1 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('PKM-1 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Tamarindus indica cv. PKM-1\u000a\u000aउत्पत्ति क्षेत्र: Tamil Nadu/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sour-sweet, fleshy, low fibre, high pulp\u000a\u000aमराठी नाम: PKM-1 Chincha\u000a\u000aमूल डेटासेट विवरण: Tamil Nadu variety adopted in Maharashtra; high yield; early bearing grafted plants; Nashik, Aurangabad.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(336,168,'mr','PKM-1 Chincha','Tamil Nadu/Maharashtra','Sour-sweet, fleshy, low fibre, high pulp','PKM-1 Chincha ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('PKM-1 Chincha ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Tamarindus indica cv. PKM-1\u000a\u000aउत्पत्ती क्षेत्र: Tamil Nadu/Maharashtra\u000a\u000aचव वैशिष्ट्य: Sour-sweet, fleshy, low fibre, high pulp\u000a\u000aमराठी नाव: PKM-1 Chincha\u000a\u000aमूळ डेटासेट तपशील: Tamil Nadu variety adopted in Maharashtra; high yield; early bearing grafted plants; Nashik, Aurangabad.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(337,169,'hi','Urigam (Local)','Maharashtra','Sour, traditional, deep brown pulp','Urigam (Local) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Urigam (Local) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Tamarindus indica (local landrace)\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sour, traditional, deep brown pulp\u000a\u000aमराठी नाम: Sthanik Chincha\u000a\u000aमूल डेटासेट विवरण: Wild-type landraces grown along roads and forest margins; Marathwada; fruiting December–March; traditional harvest.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(338,169,'mr','Sthanik Chincha','Maharashtra','Sour, traditional, deep brown pulp','Sthanik Chincha ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Sthanik Chincha ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Tamarindus indica (local landrace)\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sour, traditional, deep brown pulp\u000a\u000aमराठी नाव: Sthanik Chincha\u000a\u000aमूळ डेटासेट तपशील: Wild-type landraces grown along roads and forest margins; Marathwada; fruiting December–March; traditional harvest.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(339,170,'hi','Pusa Early Bunching','India','Mildly bitter, leafy, quick to bolt','Pusa Early Bunching इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Pusa Early Bunching इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Trigonella foenum-graecum cv. Pusa Early Bunching\u000a\u000aउत्पत्ति क्षेत्र: India\u000a\u000aस्वाद प्रोफाइल: Mildly bitter, leafy, quick to bolt\u000a\u000aमराठी नाम: Lavkar Methi\u000a\u000aमूल डेटासेट विवरण: IARI; popular for fresh leaf market; short duration; Maharashtra Rabi; continuous harvest possible.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(340,170,'mr','Lavkar Methi','India','Mildly bitter, leafy, quick to bolt','Lavkar Methi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Lavkar Methi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Trigonella foenum-graecum cv. Pusa Early Bunching\u000a\u000aउत्पत्ती क्षेत्र: India\u000a\u000aचव वैशिष्ट्य: Mildly bitter, leafy, quick to bolt\u000a\u000aमराठी नाव: Lavkar Methi\u000a\u000aमूळ डेटासेट तपशील: IARI; popular for fresh leaf market; short duration; Maharashtra Rabi; continuous harvest possible.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(341,171,'hi','Kasuri Methi (IARI-PEB)','India','Strongly aromatic, small leaf, dried use','Kasuri Methi (IARI-PEB) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Kasuri Methi (IARI-PEB) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Trigonella foenum-graecum cv. Kasuri\u000a\u000aउत्पत्ति क्षेत्र: India\u000a\u000aस्वाद प्रोफाइल: Strongly aromatic, small leaf, dried use\u000a\u000aमराठी नाम: Kasuri Methi\u000a\u000aमूल डेटासेट विवरण: Small-leafed aromatic variety; dried for culinary use; grown in Nashik and Pune; premium quality.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(342,171,'mr','Kasuri Methi','India','Strongly aromatic, small leaf, dried use','Kasuri Methi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Kasuri Methi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Trigonella foenum-graecum cv. Kasuri\u000a\u000aउत्पत्ती क्षेत्र: India\u000a\u000aचव वैशिष्ट्य: Strongly aromatic, small leaf, dried use\u000a\u000aमराठी नाव: Kasuri Methi\u000a\u000aमूळ डेटासेट तपशील: Small-leafed aromatic variety; dried for culinary use; grown in Nashik and Pune; premium quality.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(343,172,'hi','RMt-1 (Rajasthan)','Rajasthan/Maharashtra','Bitter seeds, good leaf yield','RMt-1 (Rajasthan) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('RMt-1 (Rajasthan) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Trigonella foenum-graecum cv. RMt-1\u000a\u000aउत्पत्ति क्षेत्र: Rajasthan/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Bitter seeds, good leaf yield\u000a\u000aमराठी नाम: RMt-1 Methi\u000a\u000aमूल डेटासेट विवरण: Good seed yield; adapted to Maharashtra Rabi; Nashik, Aurangabad; used for seed and fresh leaf both.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(344,172,'mr','RMt-1 Methi','Rajasthan/Maharashtra','Bitter seeds, good leaf yield','RMt-1 Methi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('RMt-1 Methi ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Trigonella foenum-graecum cv. RMt-1\u000a\u000aउत्पत्ती क्षेत्र: Rajasthan/Maharashtra\u000a\u000aचव वैशिष्ट्य: Bitter seeds, good leaf yield\u000a\u000aमराठी नाव: RMt-1 Methi\u000a\u000aमूळ डेटासेट तपशील: Good seed yield; adapted to Maharashtra Rabi; Nashik, Aurangabad; used for seed and fresh leaf both.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(345,173,'hi','CO-1','Maharashtra','Aromatic, high leaf yield, fresh market','CO-1 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('CO-1 इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Coriandrum sativum cv. CO-1\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Aromatic, high leaf yield, fresh market\u000a\u000aमराठी नाम: CO-1 Kothimbir\u000a\u000aमूल डेटासेट विवरण: Tall plant; high green leaf yield; Nashik, Pune, Satara; widely grown for leaf market; successive harvests.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(346,173,'mr','CO-1 Kothimbir','Maharashtra','Aromatic, high leaf yield, fresh market','CO-1 Kothimbir ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('CO-1 Kothimbir ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Coriandrum sativum cv. CO-1\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Aromatic, high leaf yield, fresh market\u000a\u000aमराठी नाव: CO-1 Kothimbir\u000a\u000aमूळ डेटासेट तपशील: Tall plant; high green leaf yield; Nashik, Pune, Satara; widely grown for leaf market; successive harvests.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(347,174,'hi','Phule Suvarna','Maharashtra','Good seed yield, aromatic, dual purpose','Phule Suvarna इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Phule Suvarna इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Coriandrum sativum cv. Phule Suvarna\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Good seed yield, aromatic, dual purpose\u000a\u000aमराठी नाम: Phule Suvarna Kothimbir\u000a\u000aमूल डेटासेट विवरण: MPKV Rahuri; dual-purpose (leaf + seed); Nashik; Rabi; popular with cooperative farms.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(348,174,'mr','Phule Suvarna Kothimbir','Maharashtra','Good seed yield, aromatic, dual purpose','Phule Suvarna Kothimbir ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Phule Suvarna Kothimbir ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Coriandrum sativum cv. Phule Suvarna\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Good seed yield, aromatic, dual purpose\u000a\u000aमराठी नाव: Phule Suvarna Kothimbir\u000a\u000aमूळ डेटासेट तपशील: MPKV Rahuri; dual-purpose (leaf + seed); Nashik; Rabi; popular with cooperative farms.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(349,175,'hi','Rajendra Swati','Maharashtra','High seed yield, aromatic, good oil','Rajendra Swati इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Rajendra Swati इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Coriandrum sativum cv. Rajendra Swati\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: High seed yield, aromatic, good oil\u000a\u000aमराठी नाम: Rajendra Swati Kothimbir\u000a\u000aमूल डेटासेट विवरण: RAU Bihar; adapted to Maharashtra; high dhania (seed) yield; Nashik, Aurangabad.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(350,175,'mr','Rajendra Swati Kothimbir','Maharashtra','High seed yield, aromatic, good oil','Rajendra Swati Kothimbir ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Rajendra Swati Kothimbir ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Coriandrum sativum cv. Rajendra Swati\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: High seed yield, aromatic, good oil\u000a\u000aमराठी नाव: Rajendra Swati Kothimbir\u000a\u000aमूळ डेटासेट तपशील: RAU Bihar; adapted to Maharashtra; high dhania (seed) yield; Nashik, Aurangabad.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(351,176,'hi','Sugar Baby','USA/Maharashtra','Very sweet (Brix 10–12), dark green, small round','Sugar Baby इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Sugar Baby इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrullus lanatus cv. Sugar Baby\u000a\u000aउत्पत्ति क्षेत्र: USA/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very sweet (Brix 10–12), dark green, small round\u000a\u000aमराठी नाम: Sugar Baby Kalingad\u000a\u000aमूल डेटासेट विवरण: Most popular variety in Maharashtra; compact fruit; deep red flesh; sold widely in Nashik, Nashik, Solapur.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(352,176,'mr','Sugar Baby Kalingad','USA/Maharashtra','Very sweet (Brix 10–12), dark green, small round','Sugar Baby Kalingad ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Sugar Baby Kalingad ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrullus lanatus cv. Sugar Baby\u000a\u000aउत्पत्ती क्षेत्र: USA/Maharashtra\u000a\u000aचव वैशिष्ट्य: Very sweet (Brix 10–12), dark green, small round\u000a\u000aमराठी नाव: Sugar Baby Kalingad\u000a\u000aमूळ डेटासेट तपशील: Most popular variety in Maharashtra; compact fruit; deep red flesh; sold widely in Nashik, Nashik, Solapur.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(353,177,'hi','Arka Manik','India (IIHR)','Sweet, firm red flesh, high yield','Arka Manik इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Arka Manik इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrullus lanatus cv. Arka Manik\u000a\u000aउत्पत्ति क्षेत्र: India (IIHR)\u000a\u000aस्वाद प्रोफाइल: Sweet, firm red flesh, high yield\u000a\u000aमराठी नाम: Arka Manik Kalingad\u000a\u000aमूल डेटासेट विवरण: IIHR Bengaluru; striped green fruit; high sugar; 5–8 kg fruit; Nashik, Aurangabad.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(354,177,'mr','Arka Manik Kalingad','India (IIHR)','Sweet, firm red flesh, high yield','Arka Manik Kalingad ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Arka Manik Kalingad ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrullus lanatus cv. Arka Manik\u000a\u000aउत्पत्ती क्षेत्र: India (IIHR)\u000a\u000aचव वैशिष्ट्य: Sweet, firm red flesh, high yield\u000a\u000aमराठी नाव: Arka Manik Kalingad\u000a\u000aमूळ डेटासेट तपशील: IIHR Bengaluru; striped green fruit; high sugar; 5–8 kg fruit; Nashik, Aurangabad.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(355,178,'hi','Phule Indrayani (Seedless)','Maharashtra','Sweet, seedless, crisp','Phule Indrayani (Seedless) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Phule Indrayani (Seedless) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrullus lanatus cv. Phule Indrayani\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, seedless, crisp\u000a\u000aमराठी नाम: Bijrahit Kalingad\u000a\u000aमूल डेटासेट विवरण: MPKV Rahuri seedless hybrid; premium market; Nashik valley; polliniser plants required.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(356,178,'mr','Bijrahit Kalingad','Maharashtra','Sweet, seedless, crisp','Bijrahit Kalingad ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Bijrahit Kalingad ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrullus lanatus cv. Phule Indrayani\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, seedless, crisp\u000a\u000aमराठी नाव: Bijrahit Kalingad\u000a\u000aमूळ डेटासेट तपशील: MPKV Rahuri seedless hybrid; premium market; Nashik valley; polliniser plants required.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(357,179,'hi','NS-295 (Namdhari)','Maharashtra','Very sweet, oblong, striped, red flesh','NS-295 (Namdhari) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('NS-295 (Namdhari) इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrullus lanatus cv. NS-295\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Very sweet, oblong, striped, red flesh\u000a\u000aमराठी नाम: NS-295 Kalingad\u000a\u000aमूल डेटासेट विवरण: Namdhari Seeds F1; very high yield; Nashik, Solapur; excellent transport quality; large 8–10 kg fruit.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(358,179,'mr','NS-295 Kalingad','Maharashtra','Very sweet, oblong, striped, red flesh','NS-295 Kalingad ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('NS-295 Kalingad ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrullus lanatus cv. NS-295\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Very sweet, oblong, striped, red flesh\u000a\u000aमराठी नाव: NS-295 Kalingad\u000a\u000aमूळ डेटासेट तपशील: Namdhari Seeds F1; very high yield; Nashik, Solapur; excellent transport quality; large 8–10 kg fruit.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(359,180,'hi','Arka Rajhans','India (IIHR)','Very sweet, orange flesh, aromatic, netted skin','Arka Rajhans इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Arka Rajhans इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Cucumis melo cv. Arka Rajhans\u000a\u000aउत्पत्ति क्षेत्र: India (IIHR)\u000a\u000aस्वाद प्रोफाइल: Very sweet, orange flesh, aromatic, netted skin\u000a\u000aमराठी नाम: Arka Rajhans Kharbuja\u000a\u000aमूल डेटासेट विवरण: IIHR Bengaluru; popular in Maharashtra; cantaloupe type; netted rind; high Brix 12–14.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(360,180,'mr','Arka Rajhans Kharbuja','India (IIHR)','Very sweet, orange flesh, aromatic, netted skin','Arka Rajhans Kharbuja ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Arka Rajhans Kharbuja ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Cucumis melo cv. Arka Rajhans\u000a\u000aउत्पत्ती क्षेत्र: India (IIHR)\u000a\u000aचव वैशिष्ट्य: Very sweet, orange flesh, aromatic, netted skin\u000a\u000aमराठी नाव: Arka Rajhans Kharbuja\u000a\u000aमूळ डेटासेट तपशील: IIHR Bengaluru; popular in Maharashtra; cantaloupe type; netted rind; high Brix 12–14.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(361,181,'hi','Hara Madhu','India','Sweet, green flesh, smooth skin','Hara Madhu इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Hara Madhu इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Cucumis melo cv. Hara Madhu\u000a\u000aउत्पत्ति क्षेत्र: India\u000a\u000aस्वाद प्रोफाइल: Sweet, green flesh, smooth skin\u000a\u000aमराठी नाम: Hara Madhu Kharbuja\u000a\u000aमूल डेटासेट विवरण: Pale green smooth skin; classic Indian muskmelon; grown across Maharashtra; affordable and popular.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(362,181,'mr','Hara Madhu Kharbuja','India','Sweet, green flesh, smooth skin','Hara Madhu Kharbuja ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Hara Madhu Kharbuja ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Cucumis melo cv. Hara Madhu\u000a\u000aउत्पत्ती क्षेत्र: India\u000a\u000aचव वैशिष्ट्य: Sweet, green flesh, smooth skin\u000a\u000aमराठी नाव: Hara Madhu Kharbuja\u000a\u000aमूळ डेटासेट तपशील: Pale green smooth skin; classic Indian muskmelon; grown across Maharashtra; affordable and popular.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(363,182,'hi','Phule Shreshtha','Maharashtra','Sweet, high yield, good keeping quality','Phule Shreshtha इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Phule Shreshtha इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Cucumis melo cv. Phule Shreshtha\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Sweet, high yield, good keeping quality\u000a\u000aमराठी नाम: Phule Shreshtha Kharbuja\u000a\u000aमूल डेटासेट विवरण: MPKV Rahuri; recommended for Maharashtra summer; Nashik, Pune; medium-large fruit.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(364,182,'mr','Phule Shreshtha Kharbuja','Maharashtra','Sweet, high yield, good keeping quality','Phule Shreshtha Kharbuja ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Phule Shreshtha Kharbuja ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Cucumis melo cv. Phule Shreshtha\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Sweet, high yield, good keeping quality\u000a\u000aमराठी नाव: Phule Shreshtha Kharbuja\u000a\u000aमूळ डेटासेट तपशील: MPKV Rahuri; recommended for Maharashtra summer; Nashik, Pune; medium-large fruit.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(365,183,'hi','Sai Sharbati','Maharashtra','Acidic, juicy, thin-skinned, aromatic','Sai Sharbati इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Sai Sharbati इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrus limon cv. Sai Sharbati\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Acidic, juicy, thin-skinned, aromatic\u000a\u000aमराठी नाम: Sai Sharbati Limbu\u000a\u000aमूल डेटासेट विवरण: Popular commercial variety in Maharashtra; Nashik, Pune; high juice content; year-round fruiting.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(366,183,'mr','Sai Sharbati Limbu','Maharashtra','Acidic, juicy, thin-skinned, aromatic','Sai Sharbati Limbu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Sai Sharbati Limbu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrus limon cv. Sai Sharbati\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Acidic, juicy, thin-skinned, aromatic\u000a\u000aमराठी नाव: Sai Sharbati Limbu\u000a\u000aमूळ डेटासेट तपशील: Popular commercial variety in Maharashtra; Nashik, Pune; high juice content; year-round fruiting.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(367,184,'hi','Phule Saurabh','Maharashtra','Acidic, aromatic, high juice, soft rind','Phule Saurabh इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Phule Saurabh इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrus limon cv. Phule Saurabh\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Acidic, aromatic, high juice, soft rind\u000a\u000aमराठी नाम: Phule Saurabh Limbu\u000a\u000aमूल डेटासेट विवरण: MPKV Rahuri; improved lemon variety; suitable for drip-irrigated orchards; Nashik, Aurangabad.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(368,184,'mr','Phule Saurabh Limbu','Maharashtra','Acidic, aromatic, high juice, soft rind','Phule Saurabh Limbu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Phule Saurabh Limbu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrus limon cv. Phule Saurabh\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Acidic, aromatic, high juice, soft rind\u000a\u000aमराठी नाव: Phule Saurabh Limbu\u000a\u000aमूळ डेटासेट तपशील: MPKV Rahuri; improved lemon variety; suitable for drip-irrigated orchards; Nashik, Aurangabad.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(369,185,'hi','Seedless Lime','Maharashtra','Acidic, thin-skinned, nearly seedless','Seedless Lime इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Seedless Lime इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrus aurantiifolia (seedless type)\u000a\u000aउत्पत्ति क्षेत्र: Maharashtra\u000a\u000aस्वाद प्रोफाइल: Acidic, thin-skinned, nearly seedless\u000a\u000aमराठी नाम: Bijrahit Limbu\u000a\u000aमूल डेटासेट विवरण: Acid lime type; Konkan and Pune; very popular for household use and street food vendors.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(370,185,'mr','Bijrahit Limbu','Maharashtra','Acidic, thin-skinned, nearly seedless','Bijrahit Limbu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Bijrahit Limbu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrus aurantiifolia (seedless type)\u000a\u000aउत्पत्ती क्षेत्र: Maharashtra\u000a\u000aचव वैशिष्ट्य: Acidic, thin-skinned, nearly seedless\u000a\u000aमराठी नाव: Bijrahit Limbu\u000a\u000aमूळ डेटासेट तपशील: Acid lime type; Konkan and Pune; very popular for household use and street food vendors.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(371,186,'hi','Eureka Lemon','USA/Maharashtra','Strongly acidic, aromatic, thick-skinned','Eureka Lemon इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.',unistr('Eureka Lemon इस उत्पाद की एक महत्वपूर्ण किस्म/उपप्रकार है. इसकी उत्पत्ति, स्वाद प्रोफाइल, वैज्ञानिक पहचान और उपयोग की जानकारी सरल रूप में दी गई है.\u000a\u000aवैज्ञानिक नाम: Citrus limon cv. Eureka\u000a\u000aउत्पत्ति क्षेत्र: USA/Maharashtra\u000a\u000aस्वाद प्रोफाइल: Strongly acidic, aromatic, thick-skinned\u000a\u000aमराठी नाम: Eureka Limbu\u000a\u000aमूल डेटासेट विवरण: Introduced variety; grown in Nashik and Pune; export-quality large lemon; increasing adoption.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_variety_translations VALUES(372,186,'mr','Eureka Limbu','USA/Maharashtra','Strongly acidic, aromatic, thick-skinned','Eureka Limbu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.',unistr('Eureka Limbu ही या उत्पादनाची महत्त्वाची जात/उपप्रकार आहे. तिचे उत्पत्ती क्षेत्र, चव, शास्त्रीय ओळख आणि वापर यांची माहिती सोप्या स्वरूपात दिली आहे.\u000a\u000aशास्त्रीय नाव: Citrus limon cv. Eureka\u000a\u000aउत्पत्ती क्षेत्र: USA/Maharashtra\u000a\u000aचव वैशिष्ट्य: Strongly acidic, aromatic, thick-skinned\u000a\u000aमराठी नाव: Eureka Limbu\u000a\u000aमूळ डेटासेट तपशील: Introduced variety; grown in Nashik and Pune; export-quality large lemon; increasing adoption.'),NULL,'2026-06-27 16:54:19','2026-06-27 16:54:19');
INSERT INTO crop_category_translations VALUES(1,1,'hi','ताजे फल','ताजे फल GreenWings की premium horticulture category है, जिसमें आम, अंगूर, अनार, केला, अमरूद, citrus, पपीता, तरबूज और अन्य high-demand फल फसलें शामिल हैं.','भारत के विविध agro-climatic zones tropical और subtropical fruits की विस्तृत basket को support करते हैं. APEDA fresh fruits और vegetables को important export category मानता है, जिसमें Indian grapes, pomegranates, mangoes, bananas और citrus fruits की domestic तथा international demand मजबूत है. GreenWings इस category का उपयोग fresh, naturally ripened और quality-graded फल फसलों के लिए करता है.','','2026-06-27 17:53:35','2026-06-27 18:10:33');
INSERT INTO crop_category_translations VALUES(2,1,'mr','ताजी फळे','ताजी फळे ही GreenWings ची premium horticulture category आहे, ज्यात आंबा, द्राक्षे, डाळिंब, केळी, पेरू, citrus, पपई, टरबूज आणि इतर high-demand फळ पिके येतात.','भारताच्या विविध agro-climatic zones मुळे tropical आणि subtropical fruits ची मोठी basket तयार होते. APEDA fresh fruits आणि vegetables ला महत्त्वाची export category मानते, ज्यात Indian grapes, pomegranates, mangoes, bananas आणि citrus fruits ला domestic व international demand आहे. GreenWings ही category fresh, naturally ripened आणि quality-graded फळ पिकांसाठी वापरते.','','2026-06-27 17:53:35','2026-06-27 18:10:33');
INSERT INTO crop_category_translations VALUES(3,2,'hi','अनाज और धान्य','अनाज और धान्य category में rice, wheat, maize जैसे staple crops और food security तथा processing markets को support करने वाली field crops शामिल हैं.','Cereals भारत की food security का आधार और agricultural trade का प्रमुख segment हैं. Rice, wheat और maize household consumption, milling, food processing, animal feed और institutional procurement के लिए महत्वपूर्ण हैं. GreenWings इस category का उपयोग purity, moisture, grain size और end-use performance जैसे buyer parameters के लिए करता है.','','2026-06-27 17:53:35','2026-06-27 18:10:33');
INSERT INTO crop_category_translations VALUES(4,2,'mr','धान्य आणि कडधान्य नसलेली अन्नधान्ये','Grains & Cereals category मध्ये rice, wheat, maize सारखी staple crops आणि food security व processing markets ला support करणारी field crops समाविष्ट आहेत.','Cereals भारताच्या food security चा पाया आणि agricultural trade चा मोठा segment आहेत. Rice, wheat आणि maize household consumption, milling, food processing, animal feed आणि institutional procurement साठी महत्त्वाचे आहेत. GreenWings ही category purity, moisture, grain size आणि end-use performance अशा buyer parameters साठी वापरते.','','2026-06-27 17:53:35','2026-06-27 18:10:33');
INSERT INTO crop_category_translations VALUES(5,3,'hi','मोटे अनाज','Millets में ज्वार, बाजरा, रागी, barnyard millet, kodo millet, little millet और proso millet जैसे climate-resilient crops शामिल हैं.','Millets traditional nutri-cereals हैं जिन्हें dryland farming में resilience, कम water requirement और nutrition value के लिए महत्व दिया जाता है. Health-food, school nutrition, ready-to-cook और specialty export channels में demand बढ़ रही है. GreenWings ज्वार, बाजरा, रागी और small millets को अलग climate-smart category के रूप में रखता है.','','2026-06-27 17:53:35','2026-06-27 18:10:33');
INSERT INTO crop_category_translations VALUES(6,3,'mr','मिलेट्स / भरड धान्य','Millets मध्ये ज्वारी, बाजरी, नाचणी, barnyard millet, kodo millet, little millet आणि proso millet यांसारखी climate-resilient पिके येतात.','Millets हे traditional nutri-cereals असून dryland farming मधील resilience, कमी पाण्याची गरज आणि nutrition value यासाठी महत्त्वाचे आहेत. Health-food, school nutrition, ready-to-cook आणि specialty export channels मध्ये demand वाढत आहे. GreenWings ज्वारी, बाजरी, नाचणी आणि small millets ला स्वतंत्र climate-smart category म्हणून ठेवते.','','2026-06-27 17:53:35','2026-06-27 18:10:33');
INSERT INTO crop_category_translations VALUES(7,4,'hi','दालें और लेंटिल्स','Pulses & Lentils में chickpea, pigeon pea, black gram और lentil जैसी protein-rich crops शामिल हैं.','Pulses भारतीय आहार में plant-protein staples हैं और whole pulses, split dal, flour, sprouts तथा processed ingredients के रूप में उपयोग होते हैं. इस category में cleaning, grading, moisture control और variety identity महत्वपूर्ण है क्योंकि cooking quality, dal recovery और market price crop और type के अनुसार बदलते हैं.','','2026-06-27 17:53:35','2026-06-27 18:10:33');
INSERT INTO crop_category_translations VALUES(8,4,'mr','कडधान्ये आणि डाळी','Pulses & Lentils मध्ये chickpea, pigeon pea, black gram आणि lentil सारखी protein-rich पिके येतात.','Pulses भारतीय आहारातील plant-protein staples आहेत आणि whole pulses, split dal, flour, sprouts व processed ingredients म्हणून वापरले जातात. या category मध्ये cleaning, grading, moisture control आणि variety identity महत्त्वाची आहे, कारण cooking quality, dal recovery आणि market price crop व type नुसार बदलतात.','','2026-06-27 17:53:35','2026-06-27 18:10:33');
INSERT INTO crop_category_translations VALUES(9,5,'hi','ताजी सब्जियां','Fresh Vegetables में onion, tomato, chilli, garlic, ginger, turmeric, coriander, fenugreek और अन्य market-facing vegetable crops शामिल हैं.','Fresh vegetables में harvest के बाद quality जल्दी बदलती है, इसलिए fast aggregation, grading, packaging और route planning जरूरी है. India''s vegetable basket daily retail demand, food service, processing और selected export channels को support करती है. GreenWings इस category का उपयोग freshness, size grading, residue discipline और dispatch timing के लिए करता है.','','2026-06-27 17:53:35','2026-06-27 18:10:33');
INSERT INTO crop_category_translations VALUES(10,5,'mr','ताज्या भाज्या','Fresh Vegetables मध्ये onion, tomato, chilli, garlic, ginger, turmeric, coriander, fenugreek आणि इतर market-facing vegetable crops येतात.','Fresh vegetables मध्ये harvest नंतर quality लवकर बदलते, त्यामुळे fast aggregation, grading, packaging आणि route planning आवश्यक असते. India''s vegetable basket daily retail demand, food service, processing आणि selected export channels ला support करते. GreenWings ही category freshness, size grading, residue discipline आणि dispatch timing साठी वापरते.','','2026-06-27 17:53:35','2026-06-27 18:10:33');
INSERT INTO crop_category_translations VALUES(11,6,'hi','तिलहन','Oil Seeds में groundnut, sesame, soybean और sunflower जैसी crops शामिल हैं जिनका उपयोग edible oil, food, feed और processing industries में होता है.','Oil seeds edible oils, protein-rich meal, food ingredients, feed और industrial applications के लिए महत्वपूर्ण हैं. Groundnut, sesame, soybean और sunflower में moisture control, relevant aflatoxin awareness, clean grading और buyer-specific quality parameters जरूरी होते हैं. GreenWings इस category से oilseed farmers को processors, bulk buyers और export-oriented value chains से जोड़ता है.','','2026-06-27 17:53:35','2026-06-27 18:10:33');
INSERT INTO crop_category_translations VALUES(12,6,'mr','तेलबिया','Oil Seeds मध्ये groundnut, sesame, soybean आणि sunflower पिके येतात, जी edible oil, food, feed आणि processing industries मध्ये वापरली जातात.','Oil seeds edible oils, protein-rich meal, food ingredients, feed आणि industrial applications साठी महत्त्वाचे आहेत. Groundnut, sesame, soybean आणि sunflower मध्ये moisture control, relevant aflatoxin awareness, clean grading आणि buyer-specific quality parameters आवश्यक असतात. GreenWings या category मधून oilseed farmers ना processors, bulk buyers आणि export-oriented value chains शी जोडते.','','2026-06-27 17:53:35','2026-06-27 18:10:33');
