PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE produce (
          produce_id INTEGER PRIMARY KEY AUTOINCREMENT,
          type TEXT NOT NULL,
          name TEXT NOT NULL UNIQUE,
          scientific_name TEXT,
          category TEXT,
          season TEXT,
          marathi_name TEXT,
          hindi_name TEXT,
          english_name TEXT,
          description TEXT,
          info TEXT NOT NULL
        , status TEXT NOT NULL DEFAULT 'active', image_link TEXT);
CREATE TABLE produce_translations (
          produce_id INTEGER NOT NULL REFERENCES produce(produce_id),
          language TEXT NOT NULL,
          display_name TEXT NOT NULL,
          display_type TEXT NOT NULL,
          category TEXT NOT NULL,
          season TEXT NOT NULL,
          description TEXT NOT NULL,
          info TEXT NOT NULL,
          PRIMARY KEY (produce_id, language)
        );
CREATE TABLE subtypes (
          subtype_id INTEGER PRIMARY KEY AUTOINCREMENT,
          produce_id INTEGER NOT NULL REFERENCES produce(produce_id),
          subtype_name TEXT NOT NULL,
          origin_state TEXT,
          taste_profile TEXT,
          scientific_name TEXT,
          marathi_name TEXT,
          description TEXT,
          info TEXT NOT NULL
        , image_link TEXT);
CREATE TABLE subtype_translations (
          subtype_id INTEGER NOT NULL REFERENCES subtypes(subtype_id),
          language TEXT NOT NULL,
          display_name TEXT NOT NULL,
          origin_state TEXT NOT NULL,
          taste_profile TEXT NOT NULL,
          description TEXT NOT NULL,
          info TEXT NOT NULL,
          PRIMARY KEY (subtype_id, language)
        );
CREATE TABLE users (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                firstName TEXT NOT NULL,
                lastName TEXT NOT NULL,
                mobileNumber TEXT NOT NULL,
                email TEXT NOT NULL UNIQUE,
                passwordHash TEXT NOT NULL,
                interest TEXT NOT NULL,
                enquiryQuestion TEXT,
                address TEXT NOT NULL,
                state TEXT NOT NULL,
                country TEXT NOT NULL,
                role TEXT NOT NULL DEFAULT 'USER',
                emailVerified INTEGER NOT NULL DEFAULT 0,
                createdAt TEXT NOT NULL,
                updatedAt TEXT NOT NULL
            );
CREATE TABLE enquiries (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                enquiryId TEXT NOT NULL UNIQUE,
                userId INTEGER NOT NULL,
                subject TEXT NOT NULL,
                category TEXT NOT NULL,
                description TEXT NOT NULL,
                priority TEXT NOT NULL DEFAULT 'NORMAL',
                status TEXT NOT NULL DEFAULT 'NEW',
                createdAt TEXT NOT NULL,
                updatedAt TEXT NOT NULL,
                FOREIGN KEY (userId) REFERENCES users(id)
            );
CREATE TABLE website_visits (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                visitorId TEXT NOT NULL,
                sessionId TEXT NOT NULL,
                pagePath TEXT NOT NULL,
                referrer TEXT,
                userAgent TEXT,
                ipAddressHash TEXT NOT NULL,
                country TEXT,
                deviceType TEXT,
                browser TEXT,
                visitedAt TEXT NOT NULL,
                createdAt TEXT NOT NULL
            );
CREATE TABLE local_fertilizers (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                name TEXT NOT NULL,
                category TEXT NOT NULL,
                manufacturer TEXT NOT NULL,
                countryOfOrigin TEXT NOT NULL DEFAULT 'India',
                description TEXT NOT NULL,
                content TEXT NOT NULL,
                uses TEXT NOT NULL,
                applyOnCrops TEXT NOT NULL,
                doNotApplyOn TEXT NOT NULL,
                applicationMethod TEXT NOT NULL,
                recommendedStage TEXT NOT NULL,
                season TEXT NOT NULL,
                temperatureRange TEXT NOT NULL,
                soilType TEXT NOT NULL,
                benefits TEXT NOT NULL,
                precautions TEXT NOT NULL,
                imageUrl TEXT,
                status TEXT NOT NULL DEFAULT 'active',
                documentUrl TEXT,
                approvalBody TEXT,
                regionalRecommendations TEXT,
                createdAt TEXT NOT NULL,
                updatedAt TEXT NOT NULL
            );
CREATE TABLE imported_fertilizers (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                name TEXT NOT NULL,
                category TEXT NOT NULL,
                manufacturer TEXT NOT NULL,
                countryOfOrigin TEXT NOT NULL,
                description TEXT NOT NULL,
                content TEXT NOT NULL,
                uses TEXT NOT NULL,
                applyOnCrops TEXT NOT NULL,
                doNotApplyOn TEXT NOT NULL,
                applicationMethod TEXT NOT NULL,
                recommendedStage TEXT NOT NULL,
                season TEXT NOT NULL,
                temperatureRange TEXT NOT NULL,
                soilType TEXT NOT NULL,
                benefits TEXT NOT NULL,
                precautions TEXT NOT NULL,
                imageUrl TEXT,
                status TEXT NOT NULL DEFAULT 'active',
                documentUrl TEXT,
                brand TEXT,
                importCertifications TEXT,
                internationalSpecifications TEXT,
                createdAt TEXT NOT NULL,
                updatedAt TEXT NOT NULL
            );
CREATE TABLE local_fertilizer_translations (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                fertilizerId INTEGER NOT NULL,
                language TEXT NOT NULL,
                name TEXT,
                category TEXT,
                description TEXT,
                content TEXT,
                uses TEXT,
                benefits TEXT,
                precautions TEXT,
                createdAt TEXT NOT NULL,
                updatedAt TEXT NOT NULL, countryOfOrigin TEXT, applyOnCrops TEXT, doNotApplyOn TEXT, applicationMethod TEXT, recommendedStage TEXT, season TEXT, temperatureRange TEXT, soilType TEXT, approvalBody TEXT, regionalRecommendations TEXT, brand TEXT, importCertifications TEXT, internationalSpecifications TEXT,
                UNIQUE(fertilizerId, language),
                FOREIGN KEY (fertilizerId) REFERENCES local_fertilizers(id)
            );
CREATE TABLE imported_fertilizer_translations (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                fertilizerId INTEGER NOT NULL,
                language TEXT NOT NULL,
                name TEXT,
                category TEXT,
                description TEXT,
                content TEXT,
                uses TEXT,
                benefits TEXT,
                precautions TEXT,
                createdAt TEXT NOT NULL,
                updatedAt TEXT NOT NULL, countryOfOrigin TEXT, applyOnCrops TEXT, doNotApplyOn TEXT, applicationMethod TEXT, recommendedStage TEXT, season TEXT, temperatureRange TEXT, soilType TEXT, approvalBody TEXT, regionalRecommendations TEXT, brand TEXT, importCertifications TEXT, internationalSpecifications TEXT,
                UNIQUE(fertilizerId, language),
                FOREIGN KEY (fertilizerId) REFERENCES imported_fertilizers(id)
            );
CREATE TABLE company_stories (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                title TEXT NOT NULL,
                slug TEXT NOT NULL,
                language TEXT NOT NULL,
                content TEXT NOT NULL,
                featuredImage TEXT,
                displayOrder INTEGER NOT NULL DEFAULT 0,
                status TEXT NOT NULL DEFAULT 'published',
                createdAt TEXT NOT NULL,
                updatedAt TEXT NOT NULL,
                UNIQUE(slug, language)
            );
CREATE TABLE company_milestones (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                year TEXT NOT NULL,
                title TEXT NOT NULL,
                description TEXT NOT NULL,
                image TEXT,
                displayOrder INTEGER NOT NULL DEFAULT 0,
                createdAt TEXT NOT NULL,
                updatedAt TEXT NOT NULL
            , impactMetric TEXT, language TEXT NOT NULL DEFAULT 'en', status TEXT NOT NULL DEFAULT 'published');
CREATE TABLE company_milestone_translations (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                milestoneId INTEGER NOT NULL,
                language TEXT NOT NULL,
                title TEXT,
                description TEXT,
                createdAt TEXT NOT NULL,
                updatedAt TEXT NOT NULL, impactMetric TEXT,
                UNIQUE(milestoneId, language),
                FOREIGN KEY (milestoneId) REFERENCES company_milestones(id)
            );
CREATE TABLE leadership_members (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                fullName TEXT NOT NULL,
                designation TEXT NOT NULL,
                biography TEXT NOT NULL,
                image TEXT,
                displayOrder INTEGER NOT NULL DEFAULT 0,
                active INTEGER NOT NULL DEFAULT 1,
                createdAt TEXT NOT NULL,
                updatedAt TEXT NOT NULL
            , roleDescription TEXT, imageUrl TEXT, language TEXT NOT NULL DEFAULT 'en');
CREATE TABLE leadership_member_translations (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                leadershipMemberId INTEGER NOT NULL,
                language TEXT NOT NULL,
                designation TEXT,
                biography TEXT,
                createdAt TEXT NOT NULL,
                updatedAt TEXT NOT NULL,
                UNIQUE(leadershipMemberId, language),
                FOREIGN KEY (leadershipMemberId) REFERENCES leadership_members(id)
            );
CREATE TABLE company_contents (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                sectionKey TEXT NOT NULL,
                title TEXT NOT NULL,
                subtitle TEXT,
                content TEXT NOT NULL,
                language TEXT NOT NULL DEFAULT 'en',
                displayOrder INTEGER NOT NULL DEFAULT 0,
                status TEXT NOT NULL DEFAULT 'published',
                createdAt TEXT NOT NULL,
                updatedAt TEXT NOT NULL,
                UNIQUE(sectionKey, language)
            );
CREATE TABLE company_timelines (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                year TEXT NOT NULL,
                title TEXT NOT NULL,
                description TEXT NOT NULL,
                impactMetric TEXT,
                language TEXT NOT NULL DEFAULT 'en',
                displayOrder INTEGER NOT NULL DEFAULT 0,
                status TEXT NOT NULL DEFAULT 'published',
                createdAt TEXT NOT NULL,
                updatedAt TEXT NOT NULL,
                UNIQUE(year, title, language)
            );
CREATE TABLE homepage_statistics (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                label TEXT NOT NULL,
                value TEXT NOT NULL,
                description TEXT,
                displayOrder INTEGER NOT NULL DEFAULT 0,
                active INTEGER NOT NULL DEFAULT 1,
                createdAt TEXT NOT NULL,
                updatedAt TEXT NOT NULL,
                UNIQUE(label)
            );
CREATE TABLE success_stories (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                farmerName TEXT NOT NULL,
                farmerPhone TEXT,
                title TEXT NOT NULL,
                slug TEXT NOT NULL,
                location TEXT,
                village TEXT,
                district TEXT,
                cropType TEXT,
                landArea TEXT,
                storyCategory TEXT,
                shortQuote TEXT,
                shortSummary TEXT,
                fullStory TEXT NOT NULL,
                challenge TEXT,
                solution TEXT,
                result TEXT,
                yieldBefore TEXT,
                yieldAfter TEXT,
                priceBenefit TEXT,
                additionalIncome TEXT,
                fertilizerUsed TEXT,
                seedUsed TEXT,
                marketSupport TEXT,
                profileImage TEXT,
                coverImage TEXT,
                language TEXT NOT NULL DEFAULT 'en',
                displayOrder INTEGER NOT NULL DEFAULT 0,
                featured INTEGER NOT NULL DEFAULT 0,
                status TEXT NOT NULL DEFAULT 'published',
                createdAt TEXT NOT NULL,
                updatedAt TEXT NOT NULL, user_id INTEGER,
                UNIQUE(slug, language)
            );
CREATE TABLE success_story_media (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                successStoryId INTEGER NOT NULL,
                mediaType TEXT NOT NULL DEFAULT 'image',
                mediaUrl TEXT NOT NULL,
                caption TEXT,
                displayOrder INTEGER NOT NULL DEFAULT 0,
                createdAt TEXT NOT NULL,
                updatedAt TEXT NOT NULL,
                FOREIGN KEY (successStoryId) REFERENCES success_stories(id) ON DELETE CASCADE
            );
CREATE TABLE fertilizers (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                fertilizer_type TEXT NOT NULL DEFAULT 'local' CHECK (fertilizer_type IN ('local','imported')),
                name TEXT NOT NULL,
                category TEXT,
                manufacturer TEXT,
                brand TEXT,
                countryOfOrigin TEXT,
                description TEXT,
                content TEXT,
                uses TEXT,
                applyOnCrops TEXT,
                doNotApplyOn TEXT,
                applicationMethod TEXT,
                recommendedStage TEXT,
                season TEXT,
                temperatureRange TEXT,
                soilType TEXT,
                benefits TEXT,
                precautions TEXT,
                imageUrl TEXT,
                documentUrl TEXT,
                approvalBody TEXT,
                regionalRecommendations TEXT,
                importCertifications TEXT,
                internationalSpecifications TEXT,
                status TEXT NOT NULL DEFAULT 'active',
                createdAt TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
                updatedAt TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
            , image_link TEXT);
CREATE TABLE fertilizer_translations (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                fertilizer_id INTEGER NOT NULL,
                language TEXT NOT NULL,
                name TEXT,
                category TEXT,
                description TEXT,
                content TEXT,
                uses TEXT,
                benefits TEXT,
                precautions TEXT,
                countryOfOrigin TEXT,
                applyOnCrops TEXT,
                doNotApplyOn TEXT,
                applicationMethod TEXT,
                recommendedStage TEXT,
                season TEXT,
                temperatureRange TEXT,
                soilType TEXT,
                approvalBody TEXT,
                regionalRecommendations TEXT,
                brand TEXT,
                importCertifications TEXT,
                internationalSpecifications TEXT,
                createdAt TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
                updatedAt TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, image_link TEXT,
                UNIQUE(fertilizer_id, language),
                FOREIGN KEY (fertilizer_id) REFERENCES fertilizers(id) ON DELETE CASCADE ON UPDATE CASCADE
            );
CREATE TABLE crop_category (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            name TEXT NOT NULL UNIQUE,
            description TEXT,
            icon_url TEXT,
            created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
            updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
        , image_link TEXT, slug TEXT, info TEXT, source_urls TEXT, display_order INTEGER NOT NULL DEFAULT 0, status TEXT NOT NULL DEFAULT 'active');
CREATE TABLE crop_taxonomy (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            kingdom TEXT DEFAULT 'Plantae',
            phylum TEXT,
            class_name TEXT,
            order_name TEXT,
            family TEXT,
            genus TEXT,
            species TEXT,
            cultivar_group TEXT,
            created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
            updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, image_link TEXT,
            UNIQUE(genus, species)
        );
CREATE TABLE region (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            name TEXT NOT NULL,
            country TEXT,
            state_province TEXT,
            climate_zone TEXT,
            soil_type TEXT,
            avg_rainfall_mm REAL,
            avg_temp_celsius REAL,
            latitude REAL,
            longitude REAL,
            created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
            updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, image_link TEXT,
            UNIQUE(name, country, state_province)
        );
CREATE TABLE crop (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            produce_id INTEGER,
            category_id INTEGER,
            taxonomy_id INTEGER,
            common_name TEXT NOT NULL,
            scientific_name TEXT,
            description TEXT,
            origin_region TEXT,
            image_url TEXT,
            growth_habit TEXT,
            lifecycle_type TEXT,
            is_edible INTEGER NOT NULL DEFAULT 1,
            is_commercial INTEGER NOT NULL DEFAULT 0,
            notes TEXT,
            created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
            updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, type TEXT, category TEXT, season TEXT, marathi_name TEXT, hindi_name TEXT, english_name TEXT, image_link TEXT, status TEXT NOT NULL DEFAULT 'active',
            FOREIGN KEY (produce_id) REFERENCES produce(produce_id) ON DELETE SET NULL ON UPDATE CASCADE,
            FOREIGN KEY (category_id) REFERENCES crop_category(id) ON DELETE SET NULL ON UPDATE CASCADE,
            FOREIGN KEY (taxonomy_id) REFERENCES crop_taxonomy(id) ON DELETE SET NULL ON UPDATE CASCADE
        );
CREATE TABLE crop_variety (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            crop_id INTEGER NOT NULL,
            subtype_id INTEGER,
            variety_name TEXT NOT NULL,
            local_name TEXT,
            region_of_origin TEXT,
            season_type TEXT,
            flavor_profile TEXT,
            color TEXT,
            texture TEXT,
            size_description TEXT,
            is_hybrid INTEGER NOT NULL DEFAULT 0,
            is_heirloom INTEGER NOT NULL DEFAULT 0,
            is_gmo INTEGER NOT NULL DEFAULT 0,
            development_year TEXT,
            developed_by TEXT,
            image_url TEXT,
            description TEXT,
            created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
            updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, scientific_name TEXT, marathi_name TEXT, image_link TEXT, notes TEXT,
            FOREIGN KEY (crop_id) REFERENCES crop(id) ON DELETE CASCADE ON UPDATE CASCADE,
            FOREIGN KEY (subtype_id) REFERENCES subtypes(subtype_id) ON DELETE SET NULL ON UPDATE CASCADE,
            UNIQUE(crop_id, variety_name)
        );
CREATE TABLE nutritional_profile (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            crop_id INTEGER NOT NULL UNIQUE,
            calories_per_100g REAL,
            carbs_g REAL,
            protein_g REAL,
            fat_g REAL,
            fiber_g REAL,
            sugar_g REAL,
            vitamin_c_mg REAL,
            vitamin_a_mcg REAL,
            potassium_mg REAL,
            calcium_mg REAL,
            iron_mg REAL,
            other_micronutrients TEXT,
            data_source TEXT,
            created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
            updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, image_link TEXT,
            FOREIGN KEY (crop_id) REFERENCES crop(id) ON DELETE CASCADE ON UPDATE CASCADE
        );
CREATE TABLE crop_uses (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            crop_id INTEGER NOT NULL,
            use_type TEXT NOT NULL,
            description TEXT,
            processing_method TEXT,
            by_products TEXT,
            created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
            updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, image_link TEXT,
            FOREIGN KEY (crop_id) REFERENCES crop(id) ON DELETE CASCADE ON UPDATE CASCADE
        );
CREATE TABLE pests_and_diseases (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            crop_id INTEGER NOT NULL,
            name TEXT NOT NULL,
            type TEXT,
            symptoms TEXT,
            prevention TEXT,
            treatment TEXT,
            severity_level TEXT,
            created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
            updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, image_link TEXT,
            FOREIGN KEY (crop_id) REFERENCES crop(id) ON DELETE CASCADE ON UPDATE CASCADE
        );
CREATE TABLE growing_season (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            variety_id INTEGER NOT NULL,
            region_id INTEGER NOT NULL,
            season_name TEXT,
            sow_month_start TEXT,
            sow_month_end TEXT,
            harvest_month_start TEXT,
            harvest_month_end TEXT,
            days_to_maturity INTEGER,
            climate_suitability TEXT,
            notes TEXT,
            created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
            updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, image_link TEXT,
            FOREIGN KEY (variety_id) REFERENCES crop_variety(id) ON DELETE CASCADE ON UPDATE CASCADE,
            FOREIGN KEY (region_id) REFERENCES region(id) ON DELETE CASCADE ON UPDATE CASCADE
        );
CREATE TABLE cultivation_guide (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            variety_id INTEGER NOT NULL UNIQUE,
            soil_type_preferred TEXT,
            soil_ph_range TEXT,
            irrigation_type TEXT,
            water_req_mm_per_week REAL,
            sunlight_requirement TEXT,
            spacing_cm TEXT,
            fertilizer_type TEXT,
            pesticide_notes TEXT,
            pruning_info TEXT,
            pollination_type TEXT,
            special_care_notes TEXT,
            created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
            updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, image_link TEXT,
            FOREIGN KEY (variety_id) REFERENCES crop_variety(id) ON DELETE CASCADE ON UPDATE CASCADE
        );
CREATE TABLE market_info (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            variety_id INTEGER NOT NULL,
            region_id INTEGER NOT NULL,
            avg_price_per_kg REAL,
            price_currency TEXT NOT NULL DEFAULT 'INR',
            peak_supply_months TEXT,
            major_producers TEXT,
            major_exporters TEXT,
            market_notes TEXT,
            recorded_year TEXT,
            created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
            updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, image_link TEXT,
            FOREIGN KEY (variety_id) REFERENCES crop_variety(id) ON DELETE CASCADE ON UPDATE CASCADE,
            FOREIGN KEY (region_id) REFERENCES region(id) ON DELETE CASCADE ON UPDATE CASCADE,
            UNIQUE(variety_id, region_id, recorded_year)
        );
CREATE TABLE crop_translations (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            crop_id INTEGER NOT NULL,
            language TEXT NOT NULL,
            display_name TEXT NOT NULL,
            display_type TEXT,
            category TEXT,
            season TEXT,
            description TEXT,
            notes TEXT,
            image_link TEXT,
            created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
            updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
            UNIQUE(crop_id, language),
            FOREIGN KEY (crop_id) REFERENCES crop(id) ON DELETE CASCADE ON UPDATE CASCADE
        );
CREATE TABLE crop_variety_translations (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            crop_variety_id INTEGER NOT NULL,
            language TEXT NOT NULL,
            display_name TEXT NOT NULL,
            region_of_origin TEXT,
            flavor_profile TEXT,
            description TEXT,
            notes TEXT,
            image_link TEXT,
            created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
            updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
            UNIQUE(crop_variety_id, language),
            FOREIGN KEY (crop_variety_id) REFERENCES crop_variety(id) ON DELETE CASCADE ON UPDATE CASCADE
        );
CREATE TABLE crop_category_translations (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            category_id INTEGER NOT NULL,
            language TEXT NOT NULL,
            name TEXT NOT NULL,
            description TEXT,
            info TEXT,
            image_link TEXT,
            created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
            updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
            UNIQUE(category_id, language),
            FOREIGN KEY (category_id) REFERENCES crop_category(id) ON DELETE CASCADE ON UPDATE CASCADE
        );
PRAGMA writable_schema=ON;
CREATE TABLE IF NOT EXISTS sqlite_sequence(name,seq);
DELETE FROM sqlite_sequence;
CREATE VIEW crop_category_variety_view AS
        SELECT
            cc.id AS category_id,
            cc.name AS category_name,
            cc.slug AS category_slug,
            c.id AS crop_id,
            c.common_name AS crop_name,
            cv.id AS crop_variety_id,
            cv.variety_name,
            cv.subtype_id,
            cv.region_of_origin,
            cv.image_link AS variety_image_link
        FROM crop_category cc
        JOIN crop c ON c.category_id = cc.id
        LEFT JOIN crop_variety cv ON cv.crop_id = c.id;
CREATE INDEX idx_produce_type ON produce(type);
CREATE INDEX idx_subtypes_produce ON subtypes(produce_id);
CREATE INDEX idx_produce_translations_language ON produce_translations(language);
CREATE INDEX idx_subtype_translations_language ON subtype_translations(language);
CREATE INDEX idx_users_email ON users(email);
CREATE INDEX idx_enquiries_user ON enquiries(userId);
CREATE INDEX idx_enquiries_status ON enquiries(status);
CREATE INDEX idx_website_visits_visitor ON website_visits(visitorId);
CREATE INDEX idx_website_visits_page ON website_visits(pagePath);
CREATE INDEX idx_website_visits_date ON website_visits(visitedAt);
CREATE INDEX idx_local_fertilizers_status ON local_fertilizers(status);
CREATE INDEX idx_imported_fertilizers_status ON imported_fertilizers(status);
CREATE INDEX idx_local_fertilizers_category ON local_fertilizers(category);
CREATE INDEX idx_imported_fertilizers_category ON imported_fertilizers(category);
CREATE INDEX idx_company_stories_lookup ON company_stories(language, status, displayOrder);
CREATE INDEX idx_company_milestones_order ON company_milestones(displayOrder);
CREATE INDEX idx_leadership_members_active ON leadership_members(active, displayOrder);
CREATE INDEX idx_company_contents_lookup ON company_contents(language, status, displayOrder);
CREATE INDEX idx_company_timelines_lookup ON company_timelines(language, status, displayOrder);
CREATE INDEX idx_homepage_statistics_active ON homepage_statistics(active, displayOrder);
CREATE INDEX idx_success_stories_lookup ON success_stories(language, status, featured, displayOrder);
CREATE INDEX idx_success_story_media_story ON success_story_media(successStoryId, displayOrder);
CREATE UNIQUE INDEX uq_fertilizers_type_name_manufacturer
                ON fertilizers(fertilizer_type, name, COALESCE(manufacturer, ''));
CREATE INDEX idx_users_role ON users(role);
CREATE INDEX idx_produce_status ON produce(status);
CREATE INDEX idx_fert_type ON fertilizers(fertilizer_type);
CREATE INDEX idx_fert_status ON fertilizers(status);
CREATE INDEX idx_crop_category ON crop(category_id);
CREATE INDEX idx_crop_taxonomy ON crop(taxonomy_id);
CREATE INDEX idx_crop_produce ON crop(produce_id);
CREATE INDEX idx_variety_crop ON crop_variety(crop_id);
CREATE INDEX idx_variety_subtype ON crop_variety(subtype_id);
CREATE UNIQUE INDEX uq_crop_produce_id ON crop(produce_id) WHERE produce_id IS NOT NULL;
CREATE UNIQUE INDEX uq_crop_variety_subtype_id ON crop_variety(subtype_id) WHERE subtype_id IS NOT NULL;
CREATE INDEX idx_crop_type ON crop(type);
CREATE INDEX idx_crop_status ON crop(status);
CREATE INDEX idx_crop_translations_language ON crop_translations(language);
CREATE INDEX idx_crop_variety_crop ON crop_variety(crop_id);
CREATE INDEX idx_crop_variety_subtype ON crop_variety(subtype_id);
CREATE INDEX idx_crop_variety_translations_language ON crop_variety_translations(language);
CREATE INDEX idx_fert_translations_language ON fertilizer_translations(language);
CREATE INDEX idx_crop_category_translations_language ON crop_category_translations(language);
CREATE UNIQUE INDEX uq_crop_category_slug ON crop_category(slug) WHERE slug IS NOT NULL;
PRAGMA writable_schema=OFF;
COMMIT;
